-- Poems batch 442
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuding-20','酬鴻臚裴主簿雨後睢陽北樓見贈之作','高適','唐','御定全唐诗','yuding','','[]','暮霞照新晴，歸雲猶相逐。有懷晨昏暇，相見登眺目。',120,'御定全唐詩/json/211.json','["暮霞照新晴，歸雲猶相逐。有懷晨昏暇，相見登眺目。", "問禮侍彤襜，題詩訪茅屋。高樓多古今，陳事滿陵穀。", "地久微子封，台餘孝王築。裴回顧霄漢，豁達俯川陸。", "遠水對秋城，長天向喬木。公門何清淨，列戟森已肅。", "不歎攜手稀，恒思著鞭速。終當拂羽翰，輕舉隨鴻鵠。"]'),
('yuding-21','酬裴員外以詩代書','高適','唐','御定全唐诗','yuding','','[]','少時方浩蕩，遇物猶塵埃。脫略身外事，交遊天下才。',564,'御定全唐詩/json/211.json','["少時方浩蕩，遇物猶塵埃。脫略身外事，交遊天下才。", "單車入燕趙，獨立心悠哉。甯知戎馬間，忽展平生懷。", "且欣清論高，豈顧夕陽頹。題詩碣石館，縱酒燕王台。", "北望沙漠垂，漫天雪皚皚。臨邊無策略，覽古空裴回。", "樂毅吾所憐，拔齊翻見猜。荊卿吾所悲，適秦不復回。", "然諾多死地，公忠成禍胎。與君從此辭，每恐流年催。", "如何俱老大，始複忘形骸。兄弟真二陸，聲名連八裴。", "乙未將星變，賊臣候天災。胡騎犯龍山，乘輿經馬嵬。", "千官無倚著，萬姓徒悲哀。誅呂鬼神動，安劉天地開。", "奔波走風塵，倏忽值雲雷。擁旄出淮甸，入幕征楚材。", "誓當剪鯨鯢，永以竭駑駘。小人胡不仁，讒我成死灰。", "賴得日月明，照耀無不該。留司洛陽宮，詹府唯蒿萊。", "是時掃氛祲，尚未殲渠魁。背河列長圍，師老將亦乖。", "歸軍劇風火，散卒爭椎埋。一夕瀍洛空，生靈悲曝腮。", "衣冠投草莽，予欲馳江淮。登頓宛葉下，棲遑襄鄧隈。", "城池何蕭條，邑屋更崩摧。縱橫荊棘叢，但見瓦礫堆。", "行人無血色，戰骨多青苔。遂除彭門守，因得朝玉階。", "激昂仰鵷鷺，獻替欣鹽梅。驅傳及遠蕃，憂思鬱難排。", "罷人紛爭訟，賦稅如山崖。所思在畿甸，曾是魯宓儕。", "自從拜郎官，列宿煥天街。那能訪遐僻，還複寄瓊瑰。", "金玉本高價，塤篪終易諧。朗詠臨清秋，涼風下庭槐。", "何意寇盜間，獨稱名義偕。辛酸陳侯誄，歎息季鷹杯。", "白日屢分手，青春不再來。臥看中散論，愁憶太常齋。", "酬贈徒為爾，長歌還自咍。"]'),
('yuding-22','酬龐十兵曹','高適','唐','御定全唐诗','yuding','','[]','憶昔游京華，自言生羽翼。懷書訪知己，末路空相識。',156,'御定全唐詩/json/211.json','["憶昔游京華，自言生羽翼。懷書訪知己，末路空相識。", "許國不成名，還家有慚色。托身從畎畝，浪跡初自得。", "雨澤感天時，耕耘忘帝力。同人洛陽至，問我睢水北。", "遂爾款津涯，淨然見胸臆。高談懸物象，逸韻投翰墨。", "別岸迥無垠，海鶴鳴不息。梁城多古意，攜手共淒惻。", "懷賢想鄒枚，登高思荊棘。世情惡疵賤，之子憐孤直。", "酬贈感並深，離憂豈終極。"]'),
('yuding-23','同呂員外酬田著作幕門軍西宿盤山秋夜作','高適','唐','御定全唐诗','yuding','','[]','磧路天早秋，邊城夜應永。遙傳戎旅作，已報關山冷。',132,'御定全唐詩/json/211.json','["磧路天早秋，邊城夜應永。遙傳戎旅作，已報關山冷。", "上將頓盤阪，諸軍遍泉井。綢繆閫外書，慷慨幕中請。", "能使勳業高，動令氛霧屏。遠途能自致，短步終難騁。", "羽翮時一看，窮愁始三省。人生感然諾，何啻若形影。", "白髮知苦心，陽春見佳境。星河連塞絡，刁鬥兼山靜。", "憶君霜露時，使我空引領。"]'),
('yuding-24','酬秘書弟兼寄幕下諸公','高適','唐','御定全唐诗','yuding','','[]','亞相膺時傑，群才遇良工。翩翩幕下來，拜賜甘泉宮。',312,'御定全唐詩/json/211.json','["亞相膺時傑，群才遇良工。翩翩幕下來，拜賜甘泉宮。", "信知命世奇，適會非常功。侍禦執邦憲，清詞煥春叢。", "末路望繡衣，他時常發蒙。孰雲三軍壯，懼我彈射雄。", "誰謂萬里遙，在我樽俎中。光祿經濟器，精微自深衷。", "前席屢榮問，長城兼在躬。高縱激頹波，逸翮馳蒼穹。", "將副節制籌，欲令沙漠空。司業志應徐，雅度思沖融。", "相思三十年，憶昨猶兒童。今來抱青紫，忽若披鵷鴻。", "說劍增慷慨，論交持始終。秘書即吾門，虛白無不通。", "多才陸平原，碩學鄭司農。獻封到關西，獨步歸山東。", "永意久知處，嘉言能亢宗。客從梁宋來，行役隨轉蓬。", "酬贈欣元弟，憶賢瞻數公。遊鱗戲滄浪，鳴鳳棲梧桐。", "並負垂天翼，俱乘破浪風。眈眈天府間，偃仰誰敢同。", "何意構廣廈，翻然顧雕蟲。應知阮步兵，惆悵此途窮。"]'),
('yuding-25','淇上酬薛三據，兼寄郭少府微','高適','唐','御定全唐诗','yuding','','[]','自從別京華，我心乃蕭索。十年守章句，萬事空寥落。',240,'御定全唐詩/json/211.json','["自從別京華，我心乃蕭索。十年守章句，萬事空寥落。", "北上登薊門，茫茫見沙漠。倚劍對風塵，慨然思衛霍。", "拂衣去燕趙，驅馬悵不樂。天長滄洲路，日暮邯鄲郭。", "酒肆或淹留，漁潭屢棲泊。獨行備艱險，所見窮善惡。", "永願拯芻蕘，孰雲幹鼎鑊。皇情念淳古，時俗何浮薄。", "理道資任賢，安人在求瘼。故交負靈奇，逸氣抱謇諤。", "隱軫經濟具，縱橫建安作。才望忽先鳴，風期無宿諾。", "飄颻勞州縣，迢遞限言謔。東馳眇貝丘，西顧彌虢略。", "淇水徒自流，浮雲不堪托。吾謀適可用，天路豈寥廓。", "不然買山田，一身與耕鑿。且欲同鷦鷯，焉能志鴻鵠。"]'),
('yuding-26','酬岑二十主簿秋夜見贈之作','高適','唐','御定全唐诗','yuding','','[]','捨下蛩亂鳴，居然自蕭索。緬懷高秋興，忽枉清夜作。',96,'御定全唐詩/json/211.json','["捨下蛩亂鳴，居然自蕭索。緬懷高秋興，忽枉清夜作。", "感物我心勞，涼風驚二毛。池枯菡萏死，月出梧桐高。", "如何異鄉縣，複得交才彥。汩沒嗟後時，蹉跎恥相見。", "箕山別來久，魏闕誰不戀。獨有江海心，悠悠未嘗倦。"]'),
('yuding-27','答侯少府','高適','唐','御定全唐诗','yuding','','[]','常日好讀書，晚年學垂綸。漆園多喬木，睢水清粼粼。',324,'御定全唐詩/json/211.json','["常日好讀書，晚年學垂綸。漆園多喬木，睢水清粼粼。", "詔書下柴門，天命敢逡巡。赫赫三伏時，十日到咸秦。", "褐衣不得見，黃綬翻在身。吏道頓羈束，生涯難重陳。", "北使經大寒，關山饒苦辛。邊兵若芻狗，戰骨成埃塵。", "行矣勿複言，歸歟傷我神。如何燕趙陲，忽遇平生親。", "開館納征騎，彈弦娛遠賓。飄颻天地間，一別方茲晨。", "東道有佳作，南朝無此人。性靈出萬象，風骨超常倫。", "吾党謝王粲，群賢推郤詵。明時取秀才，落日過蒲津。", "節苦名已富，祿微家轉貧。相逢愧薄遊，撫己荷陶鈞。", "心事正堪盡，離居寧太頻。兩河歸路遙，二月芳草新。", "柳接滹沱暗，鶯連渤海春。誰謂行路難，猥當希代珍。", "提握每終日，相思猶比鄰。江海有扁舟，丘園有角巾。", "君意定何適，我懷知所遵。浮沉各異宜，老大貴全真。", "莫作雲霄計，遑遑隨縉紳。"]'),
('yuding-28','宋中別周、梁、李三子','高適','唐','御定全唐诗','yuding','','[]','曾是不得意，適來兼別離。如何一尊酒，翻作滿堂悲。',156,'御定全唐詩/json/211.json','["曾是不得意，適來兼別離。如何一尊酒，翻作滿堂悲。", "周子負高價，梁生多逸詞。周旋梁宋間，感激建安時。", "白雪正如此，青雲無自疑。李侯懷英雄，骯髒乃天資。", "方寸且無間，衣冠當在斯。俱為千里遊，忽念兩鄉辭。", "且見壯心在，莫嗟攜手遲。涼風吹北原，落日滿西陂。", "露下草初白，天長雲屢滋。我心不可問，君去定何之。", "京洛多知己，誰能憶左思。"]'),
('yuding-29','宋中別李八','高適','唐','御定全唐诗','yuding','','[]','歲晏誰不歸，君歸意可說。將趨倚門望，還念同人別。',84,'御定全唐詩/json/211.json','["歲晏誰不歸，君歸意可說。將趨倚門望，還念同人別。", "駐馬臨長亭，飄然事明發。蒼茫眺千里，正值苦寒節。", "舊國多轉蓬，平臺下明月。世情薄疵賤，夫子懷賢哲。", "行矣各勉旃，吾當挹餘烈。"]'),
('yuding-30','別王徹','高適','唐','御定全唐诗','yuding','','[]','歸客自南楚，悵然思北林。蕭條秋風暮，回首江淮深。',96,'御定全唐詩/json/211.json','["歸客自南楚，悵然思北林。蕭條秋風暮，回首江淮深。", "留君終日歡，或為梁父吟。時輩想鵬舉，他人嗟陸沉。", "載酒登平臺，贈君千里心。浮雲暗長路，落日有歸禽。", "離別未足悲，辛勤當自任。吾知十年後，季子多黃金。"]'),
('yuding-31','送蕭十八與房侍禦回還','高適','唐','御定全唐诗','yuding','','[]','常苦古人遠，今見斯人古。澹泊遺聲華，周旋必鄒魯。',96,'御定全唐詩/json/211.json','["常苦古人遠，今見斯人古。澹泊遺聲華，周旋必鄒魯。", "故交在梁宋，游方出庭戶。匹馬鳴朔風，一身濟河滸。", "辛勤采蘭詠，款曲翰林主。歲月催別離，庭闈遠風土。", "寥寥寒煙靜，莽莽夕陰吐。明發不在茲，青天眇難睹。"]'),
('yuding-32','宋中送族侄式顏','高適','唐','御定全唐诗','yuding','','[]','大夫擊東胡，胡塵不敢起。胡人山下哭，胡馬海邊死。',204,'御定全唐詩/json/211.json','["大夫擊東胡，胡塵不敢起。胡人山下哭，胡馬海邊死。", "部曲盡公侯，輿台亦朱紫。當時有勳業，末路遭讒毀。", "轉旆燕趙間，剖符括蒼裏。弟兄莫相見，親族遠枌梓。", "不改青雲心，仍招布衣士。平生懷感激，本欲候知己。", "去矣難重陳，飄然自茲始。游梁且未遇，適越今何以。", "鄉山西北愁，竹箭東南美。崢嶸縉雲外，蒼莽幾千里。", "旅雁悲啾啾，朝昏孰雲已。登臨多瘴癘，動息在風水。", "雖有賢主人，終為客行子。我攜一尊酒，滿酌聊勸爾。", "勸爾惟一言，家聲勿淪滓。"]'),
('yuding-33','又送族侄式顏','高適','唐','御定全唐诗','yuding','','[]','惜君才未遇，愛君才若此。世上五百年，吾家一千里。',48,'御定全唐詩/json/211.json','["惜君才未遇，愛君才若此。世上五百年，吾家一千里。", "俱遊帝城下，忽在梁園裏。我今行山東，離憂不能已。"]'),
('yuding-34','贈別王十七管記','高適','唐','御定全唐诗','yuding','','[]','故交吾未測，薄宦空年歲。晚節蹤曩賢，雄詞冠當世。',336,'御定全唐詩/json/211.json','["故交吾未測，薄宦空年歲。晚節蹤曩賢，雄詞冠當世。", "堂中皆食客，門外多酒債。產業曾未言，衣裘與人敝。", "飄颻戎幕下，出入關山際。轉戰輕壯心，立談有邊計。", "雲沙自回合，天海空迢遞。星高漢將驕，月盛胡兵銳。", "沙深冷陘斷，雪暗遼陽閉。亦謂掃欃槍，旋驚陷蜂蠆。", "歸旌告東捷，鬥騎傳西敗。遙飛絕漢書，已築長安第。", "畫龍俱在葉，寵鶴先居衛。勿辭部曲勳，不藉將軍勢。", "相逢季冬月，悵望窮海裔。折劍留贈人，嚴裝遂雲邁。", "我行將悠緬，及此還羈滯。曾非濟代謀，且有臨深誡。", "隨波混清濁，與物同醜麗。眇憶青岩棲，寧忘褐衣拜。", "自言愛水石，本欲親蘭蕙。何意薄松筠，翻然重菅蒯。", "恒深取與分，孰慢平生契。款曲雞黍期，酸辛別離袂。", "逢時愧名節，遇坎悲淪替。適趙非解紛，游燕往無說。", "浩歌方振盪，逸翮思淩勵。倏若異鵬摶，吾當學蟬蛻。"]'),
('yuding-35','漣上別王秀才','高適','唐','御定全唐诗','yuding','','[]','飄颻經遠道，客思滿窮秋。浩蕩對長漣，君行殊未休。',108,'御定全唐詩/json/211.json','["飄颻經遠道，客思滿窮秋。浩蕩對長漣，君行殊未休。", "崎嶇山海側，想像無前儔。何意照乘珠，忽然欲暗投。", "東路方簫條，楚歌複悲愁。暮帆使人感，去鳥兼離憂。", "行矣當自愛，壯年莫悠悠。餘亦從此辭，異鄉難久留。", "贈言豈終極，慎勿滯滄洲。"]'),
('yuding-36','贈別沈四逸人','高適','唐','御定全唐诗','yuding','','[]','沈侯未可測，其況信浮沉。十載常獨坐，幾人知此心。',108,'御定全唐詩/json/211.json','["沈侯未可測，其況信浮沉。十載常獨坐，幾人知此心。", "乘舟蹈滄海，買劍投黃金。世務不足煩，有田西山岑。", "我來遇知己，遂得開清襟。何意閫閾間，沛然江海深。", "疾風掃秋樹，濮上多鳴砧。耿耿尊酒前，聯雁飛愁音。", "平生重離別，感激對孤琴。"]'),
('yuding-37','送韓九','高適','唐','御定全唐诗','yuding','','[]','惆悵別離日，裴回歧路前。歸人望獨樹，匹馬隨秋蟬。',48,'御定全唐詩/json/211.json','["惆悵別離日，裴回歧路前。歸人望獨樹，匹馬隨秋蟬。", "常與天下士，許君兄弟賢。良時正可用，行矣莫徒然。"]'),
('yuding-38','送崔錄事赴宣城','高適','唐','御定全唐诗','yuding','','[]','大國非不理，小官皆用才。欲行宣城印，住飲洛陽杯。',60,'御定全唐詩/json/211.json','["大國非不理，小官皆用才。欲行宣城印，住飲洛陽杯。", "晚景為人別，長天無鳥回。舉帆風波渺，倚棹江山來。", "羨爾兼乘興，蕪湖千里開。"]'),
('yuding-39','別張少府','高適','唐','御定全唐诗','yuding','','[]','歸客留不住，朝雲縱複橫。馬頭向春草，斗柄臨高城。',48,'御定全唐詩/json/211.json','["歸客留不住，朝雲縱複橫。馬頭向春草，斗柄臨高城。", "嗟我久離別，羨君看弟兄。歸心更難道，回首一傷情。"]'),
('yuding-40','淇上別劉少府子英','高適','唐','御定全唐诗','yuding','','[]','近來住淇上，蕭條惟空林。又非耕種時，閒散多自任。',120,'御定全唐詩/json/211.json','["近來住淇上，蕭條惟空林。又非耕種時，閒散多自任。", "伊君獨知我，驅馬欲招尋。千里忽攜手，十年同苦心。", "求仁見交態，于道喜甘臨。逸思乃天縱，微才應陸沉。", "飄然歸故鄉，不復問離襟。南登黎陽渡，莽蒼寒雲陰。", "桑葉原上起，河淩山下深。途窮更遠別，相對益悲吟。"]'),
('yuding-41','別耿都尉','高適','唐','御定全唐诗','yuding','','[]','四十能學劍，時人無此心。如何耿夫子，感激投知音。',48,'御定全唐詩/json/211.json','["四十能學劍，時人無此心。如何耿夫子，感激投知音。", "翩翩白馬來，二月青草深。別易小千里，興酣傾百金。"]'),
('yuding-0','宋中遇林慮楊十七山人，因而有別','高適','唐','御定全唐诗','yuding','','[]','昔余涉漳水，驅車行鄴西。遙見林慮山，蒼蒼戛天倪。',180,'御定全唐詩/json/212.json','["昔余涉漳水，驅車行鄴西。遙見林慮山，蒼蒼戛天倪。", "邂逅逢爾曹，說君彼岩棲。蘿徑垂野蔓，石房倚雲梯。", "秋韭何青青，藥苗數百畦。栗林隘穀口，栝樹森回溪。", "耕耘有山田，紡績有山妻。人生苟如此，何必組與珪。", "誰謂遠相訪，曩情殊不迷。簷前舉醇醪，灶下烹只雞。", "朔風忽振盪，昨夜寒螿啼。遊子益思歸，罷琴傷解攜。", "出門盡原野，白日黯已低。始驚道路難，終念言笑暌。", "因聲謝岑壑，歲暮一攀躋。"]'),
('yuding-1','酬別薛三、蔡大，留簡韓十四主簿','高適','唐','御定全唐诗','yuding','','[]','迢遞辭京華，辛勤異鄉縣。登高俯滄海，回首淚如霰。',156,'御定全唐詩/json/212.json','["迢遞辭京華，辛勤異鄉縣。登高俯滄海，回首淚如霰。", "同人久離別，失路還相見。薛侯懷直道，德業應時選。", "蔡子負清才，當年擢賓薦。韓公有奇節，詞賦淩群彥。", "讀書嵩岑間，作吏滄海甸。伊餘寡棲托，感激多慍見。", "縱誕非爾情，飄淪任疵賤。忽枉瓊瑤作，乃深平生眷。", "始謂吾道存，終嗟客遊倦。歸心無晝夜，別事除言宴。", "複值涼風時，蒼茫夏雲變。"]'),
('yuding-2','送虞城劉明府謁魏郡苗太守','高適','唐','御定全唐诗','yuding','','[]','天官蒼生望，出入承明廬。肅肅領舊藩，皇皇降璽書。',132,'御定全唐詩/json/212.json','["天官蒼生望，出入承明廬。肅肅領舊藩，皇皇降璽書。", "茂宰多感激，良將複吹噓。永懷一言合，誰謂千里疏。", "對酒忽命駕，茲情何起予。炎天晝如火，極目無行車。", "長路出雷澤，浮雲歸孟諸。魏郡十萬家，歌鐘喧裏閭。", "傳道賢君至，閉關常晏如。君將挹高論，定是問樵漁。", "今日逢明聖，吾為陶隱居。"]'),
('yuding-3','途中酬李少府贈別之作','高適','唐','御定全唐诗','yuding','','[]','西上逢節換，東征私自憐。故人今臥疾，欲別還留連。',252,'御定全唐詩/json/212.json','["西上逢節換，東征私自憐。故人今臥疾，欲別還留連。", "舉酒臨南軒，夕陽滿中筵。甯知江上興，乃在河梁偏。", "行李多光輝，劄翰忽相鮮。誰謂歲月晚，交情尚貞堅。", "終嗟州縣勞，官謗複迍邅。雖負忠信美，其如方寸懸。", "連帥扇清風，千里猶眼前。曾是趨藻鏡，不應翻棄捐。", "日來知自強，風氣殊未痊。可以加藥物，胡為輒憂煎。", "驅馬出大樑，原野一悠然。柳色感行客，雲陰愁遠天。", "皇明燭幽遐，德澤普照宣。鵷鴻列霄漢，燕雀何翩翩。", "餘亦愜所從，漁樵十二年。種瓜漆園裏，鑿井盧門邊。", "去去勿重陳，生涯難勉旃。或期遇春事，與爾複周旋。", "投報空回首，狂歌謝比肩。"]'),
('yuding-4','睢陽酬別暢大判官','高適','唐','御定全唐诗','yuding','','[]','吾友遇知己，策名逢聖朝。高才擅白雪，逸翰懷青霄。',216,'御定全唐詩/json/212.json','["吾友遇知己，策名逢聖朝。高才擅白雪，逸翰懷青霄。", "承詔選嘉賓，慨然即馳軺。清晝下公館，尺書忽相邀。", "留歡惜別離，畢景駐行鑣。言及沙漠事，益令胡馬驕。", "丈夫拔東蕃，聲冠霍嫖姚。兜鍪沖矢石，鐵甲生風飆。", "諸將出冷陘，連營濟石橋。酋豪盡俘馘，子弟輸征徭。", "邊庭絕刁鬥，戰地成漁樵。榆關夜不扃，塞口長蕭蕭。", "降胡滿薊門，一一能射雕。軍中多宴樂，馬上何輕趫。", "戎狄本無厭，羈縻非一朝。饑附誠足用，飽飛安可招。", "李牧制儋藍，遺風豈寂寥。君還謝幕府，慎勿輕芻蕘。"]'),
('yuding-5','宴韋司戶山亭院','高適','唐','御定全唐诗','yuding','','[]','人幽想靈山，意愜憐遠水。習靜務為適，所居還複爾。',84,'御定全唐詩/json/212.json','["人幽想靈山，意愜憐遠水。習靜務為適，所居還複爾。", "汲流漲華池，開酌宴君子。苔徑試窺踐，石屏可攀倚。", "入門見中峰，攜手如萬里。橫琴了無事，垂釣應有以。", "高館何沉沉，颯然涼風起。"]'),
('yuding-6','同諸公登慈恩寺浮圖','高適','唐','御定全唐诗','yuding','','[]','香界泯群有，浮圖豈諸相。登臨駭孤高，披拂欣大壯。',108,'御定全唐詩/json/212.json','["香界泯群有，浮圖豈諸相。登臨駭孤高，披拂欣大壯。", "言是羽翼生，迥出虛空上。頓疑身世別，乃覺形神王。", "宮闕皆戶前，山河盡簷向。秋風昨夜至，秦塞多清曠。", "千里何蒼蒼，五陵鬱相望。盛時慚阮步，末宦知周防。", "輸效獨無因，斯焉可遊放。"]'),
('yuding-7','同薛司直諸公秋霽曲江俯見南山作','高適','唐','御定全唐诗','yuding','','[]','南山郁初霽，曲江湛不流。若臨瑤池前，想望昆侖丘。',120,'御定全唐詩/json/212.json','["南山郁初霽，曲江湛不流。若臨瑤池前，想望昆侖丘。", "回首見黛色，眇然波上秋。深沉俯崢嶸，清淺延阻修。", "連潭萬木影，插岸千岩幽。杳靄信難測，淵淪無暗投。", "片雲對漁父，獨鳥隨虛舟。我心寄青霞，世事慚白鷗。", "得意在乘興，忘懷非外求。良辰自多暇，欣與數子遊。"]'),
('yuding-8','登廣陵棲靈寺塔','高適','唐','御定全唐诗','yuding','','[]','淮南富登臨，茲塔信奇最。直上造雲族，憑虛納天籟。',108,'御定全唐詩/json/212.json','["淮南富登臨，茲塔信奇最。直上造雲族，憑虛納天籟。", "迥然碧海西，獨立飛鳥外。始知高興盡，適與賞心會。", "連山黯吳門，喬木吞楚塞。城池滿窗下，物象歸掌內。", "遠思駐江帆，暮時結春靄。軒車疑蠢動，造化資大塊。", "何必了無身，然後知所退。"]'),
('yuding-9','登百丈峰二首','高適','唐','御定全唐诗','yuding','','[]','朝登百丈峰，遙望燕支道。漢壘青冥間，胡天白如掃。',120,'御定全唐詩/json/212.json','["朝登百丈峰，遙望燕支道。漢壘青冥間，胡天白如掃。", "憶昔霍將軍，連年此征討。匈奴終不滅，寒山徒草草。", "唯見鴻雁飛，令人傷懷抱。", "晉武輕後事，惠皇終已昏。豺狼塞瀍洛，胡羯爭乾坤。", "四海如鼎沸，五原徒自尊。而今白庭路，猶對青陽門。", "朝市不足問，君臣隨草根。"]'),
('yuding-10','同群公秋登琴台','高適','唐','御定全唐诗','yuding','','[]','古跡使人感，琴台空寂寥。靜然顧遺塵，千載如昨朝。',120,'御定全唐詩/json/212.json','["古跡使人感，琴台空寂寥。靜然顧遺塵，千載如昨朝。", "臨眺自茲始，群賢久相邀。德與形神高，孰知天地遙。", "四時何倏忽，六月鳴秋蜩。萬象歸白帝，平川橫赤霄。", "猶是對夏伏，幾時有涼飆。燕雀滿簷楹，鴻鵠摶扶搖。", "物性各自得，我心在漁樵。兀然還複醉，尚握尊中瓢。"]'),
('yuding-11','同群公出獵海上','高適','唐','御定全唐诗','yuding','','[]','畋獵自古昔，況伊心賞俱。偶與群公遊，曠然出平蕪。',120,'御定全唐詩/json/212.json','["畋獵自古昔，況伊心賞俱。偶與群公遊，曠然出平蕪。", "層陰漲溟海，殺氣窮幽都。鷹隼何翩翩，馳驟相傳呼。", "豺狼竄榛莽，麋鹿罹艱虞。高鳥下騂弓，困獸鬥匹夫。", "塵驚大澤晦，火燎深林枯。失之有餘恨，獲者無全驅。", "咄彼工拙間，恨非指蹤徒。猶懷老氏訓，感歎此歡娛。"]'),
('yuding-12','同群公題鄭少府田家','高適','唐','御定全唐诗','yuding','','[]','鄭侯應悽惶，五十頭盡白。昔為南昌尉，今作東郡客。',84,'御定全唐詩/json/212.json','["鄭侯應悽惶，五十頭盡白。昔為南昌尉，今作東郡客。", "與語多遠情，論心知所益。秋林既清曠，窮巷空淅瀝。", "蝶舞園更閑，雞鳴日雲夕。男兒未稱意，其道固無適。", "勸君且杜門，勿歎人事隔。"]'),
('yuding-13','同群公題中山寺','高適','唐','御定全唐诗','yuding','','[]','平原十裏外，稍稍雲岩深。遂及清淨所，都無人世心。',72,'御定全唐詩/json/212.json','["平原十裏外，稍稍雲岩深。遂及清淨所，都無人世心。", "名僧既禮謁，高閣複登臨。石壁倚松徑，山田多栗林。", "超遙盡巘崿，逼側仍嶇嶔。吾欲休世事，於焉聊自任。"]'),
('yuding-14','同群公宿開善寺，贈陳十六所居','高適','唐','御定全唐诗','yuding','','[]','駕車出人境，避暑投僧家。裴回龍象側，始見香林花。',72,'御定全唐詩/json/212.json','["駕車出人境，避暑投僧家。裴回龍象側，始見香林花。", "讀書不及經，飲酒不勝茶。知君悟此道，所未搜袈裟。", "談空忘外物，持誡破諸邪。則是無心地，相看唯月華。"]'),
('yuding-15','同韓四、薛三東亭玩月','高適','唐','御定全唐诗','yuding','','[]','遠遊悵不樂，茲賞吾道存。款曲故人意，辛勤清夜言。',96,'御定全唐詩/json/212.json','["遠遊悵不樂，茲賞吾道存。款曲故人意，辛勤清夜言。", "東亭何寥寥，佳境無朝昏。階墀近洲渚，戶牖當郊原。", "矧乃窮周旋，游時怡討論。樹陰蕩瑤瑟，月氣延清尊。", "明河帶飛雁，野火連荒村。對此更愁予，悠哉懷故園。"]'),
('yuding-16','同敬八、盧五泛河間清河','高適','唐','御定全唐诗','yuding','','[]','清川在城下，沿泛多所宜。同濟愜數公，玩物欣良時。',96,'御定全唐詩/json/212.json','["清川在城下，沿泛多所宜。同濟愜數公，玩物欣良時。", "飄颻波上興，燕婉舟中詞。昔陟乃平原，今來忽漣漪。", "東流達滄海，西流延滹池。雲樹共晦明，井邑相逶迤。", "稍隨歸月帆，若與沙鷗期。漁父更留我，前潭水未滋。"]'),
('yuding-17','同房侍禦山園新亭與邢判官同游','高適','唐','御定全唐诗','yuding','','[]','隱隱春城外，朦朧陳跡深。君子顧榛莽，興言傷古今。',120,'御定全唐詩/json/212.json','["隱隱春城外，朦朧陳跡深。君子顧榛莽，興言傷古今。", "決河導新流，疏徑蹤舊林。開亭俯川陸，時景宜招尋。", "肅穆逢使軒，夤緣事登臨。忝游芝蘭室，還對桃李陰。", "岸遠白波來，氣喧黃鳥吟。因睹歌頌作，始知經濟心。", "灌壇有遺風，單父多鳴琴。誰為久州縣，蒼生懷德音。"]'),
('yuding-18','同馬太守聽九思法師講金剛經','高適','唐','御定全唐诗','yuding','','[]','吾師晉陽寶，傑出山河最。途經世諦間，心到空王外。',120,'御定全唐詩/json/212.json','["吾師晉陽寶，傑出山河最。途經世諦間，心到空王外。", "鳴鐘山虎伏，說法天龍會。了義同建瓴，梵法若吹籟。", "深知億劫苦，善喻恒沙大。舍施割肌膚，攀緣去親愛。", "招提何清淨，良牧駐輕蓋。露冕眾香中，臨人覺苑內。", "心持佛印久，標割魔軍退。願開初地因，永奉彌天對。"]'),
('yuding-19','漣上題樊氏水亭','高適','唐','御定全唐诗','yuding','','[]','漣上非所趣，偶為世務牽。經時駐歸棹，日夕對平川。',132,'御定全唐詩/json/212.json','["漣上非所趣，偶為世務牽。經時駐歸棹，日夕對平川。", "莫論行子愁，且得主人賢。亭上酒初熟，廚中魚每鮮。", "自說宦遊來，因之居住偏。煮鹽滄海曲，種稻長淮邊。", "四時常晏如，百口無饑年。菱芋藩籬下，漁樵耳目前。", "異縣少朋從，我行複迍邅。向不逢此君，孤舟已言旋。", "明日又分首，風濤還眇然。"]'),
('yuding-20','同呂判官從哥舒大夫破洪濟城回登積石軍多福七級浮圖','高適','唐','御定全唐诗','yuding','','[]','塞口連濁河，轅門對山寺。寧知鞍馬上，獨有登臨事。',120,'御定全唐詩/json/212.json','["塞口連濁河，轅門對山寺。寧知鞍馬上，獨有登臨事。", "七級淩太清，千崖列蒼翠。飄飄方寓目，想像見深意。", "高興殊未平，涼風颯然至。拔城陣雲合，轉旆胡星墜。", "大將何英靈，官軍動天地。君懷生羽翼，本欲附騏驥。", "款段苦不前，青冥信難致。一歌陽春後，三歎終自愧。"]'),
('yuding-21','三君詠：魏鄭公','高適','唐','御定全唐诗','yuding','','[]','鄭公經綸日，隋氏風塵昏。濟代取高位，逢時敢直言。',48,'御定全唐詩/json/212.json','["鄭公經綸日，隋氏風塵昏。濟代取高位，逢時敢直言。", "道光先帝業，義激舊君恩。寂寞臥龍處，英靈千載魂。"]'),
('yuding-22','三君詠：郭代公','高適','唐','御定全唐诗','yuding','','[]','代公實英邁，津涯浩難識。擁兵抗矯征，仗節歸有德。',48,'御定全唐詩/json/212.json','["代公實英邁，津涯浩難識。擁兵抗矯征，仗節歸有德。", "縱橫負才智，顧盼安社稷。流落勿重陳，懷哉為淒惻。"]'),
('yuding-23','三君詠：狄梁公','高適','唐','御定全唐诗','yuding','','[]','梁公乃貞固，勳烈垂竹帛。昌言太后朝，潛運儲君策。',48,'御定全唐詩/json/212.json','["梁公乃貞固，勳烈垂竹帛。昌言太后朝，潛運儲君策。", "待賢開相府，共理登方伯。至今青雲人，猶是門下客。"]'),
('yuding-24','宓公琴台詩三首','高適','唐','御定全唐诗','yuding','','[]','宓子昔為政，鳴琴登此台。琴和人亦閑，千載稱其才。',144,'御定全唐詩/json/212.json','["宓子昔為政，鳴琴登此台。琴和人亦閑，千載稱其才。", "臨眺忽悽愴，人琴安在哉。悠悠此天壤，唯有頌聲來。", "邦伯感遺事，慨然建琴堂。乃知靜者心，千載猶相望。", "入室想其人，出門何茫茫。唯見白雲合，東臨鄒魯鄉。", "皤皤邑中老，自誇邑中理。何必升君堂，然後知君美。", "開門無犬吠，早臥常晏起。昔人不忍欺，今我還複爾。"]'),
('yuding-25','李雲南征蠻詩','高適','唐','御定全唐诗','yuding','','[]','聖人赫斯怒，詔伐西南戎。肅穆廟堂上，深沉節制雄。',228,'御定全唐詩/json/212.json','["聖人赫斯怒，詔伐西南戎。肅穆廟堂上，深沉節制雄。", "遂令感激士，得建非常功。料死不料敵，顧恩甯顧終。", "鼓行天海外，轉戰蠻夷中。梯巘近高鳥，穿林經毒蟲。", "鬼門無歸客，北戶多南風。蜂蠆隔萬里，雲雷隨九攻。", "長驅大浪破，急擊群山空。餉道忽已遠，懸軍垂欲窮。", "精誠動白日，憤薄連蒼穹。野食掘田鼠，晡餐兼僰僮。", "收兵列亭堠，拓地彌西東。臨事恥苟免，履危能飭躬。", "將星獨照耀，邊色何溟蒙。瀘水夜可涉，交州今始通。", "歸來長安道，召見甘泉宮。廉藺若未死，孫吳知暗同。", "相逢論意氣，慷慨謝深衷。"]'),
('yuding-26','題尉遲將軍新廟','高適','唐','御定全唐诗','yuding','','[]','周室既板蕩，賊臣立嬰兒。將軍獨激昂，誓欲酬恩私。',132,'御定全唐詩/json/212.json','["周室既板蕩，賊臣立嬰兒。將軍獨激昂，誓欲酬恩私。", "孤城日無援，高節終可悲。家國共淪亡，精魂空在斯。", "沉沉積冤氣，寂寂無人知。良牧懷深仁，與君建明祠。", "父子俱血食，軒車每逶迤。我來薦蘋蘩，感歎興此詞。", "晨光上階闥，殺氣翻旌旗。明明幽冥理，至誠信莫欺。", "唯夫二千石，多慶方自茲。"]'),
('yuding-27','觀李九少府翥樹宓子賤神祠碑','高適','唐','御定全唐诗','yuding','','[]','吾友吏茲邑，亦嘗懷宓公。安知夢寐間，忽與精靈通。',132,'御定全唐詩/json/212.json','["吾友吏茲邑，亦嘗懷宓公。安知夢寐間，忽與精靈通。", "一見興永歎，再來激深衷。賓從何逶迤，二十四老翁。", "於焉建層碑，突兀長林東。作者無愧色，行人感遺風。", "坐令高岸盡，獨對秋山空。片石勿謂輕，斯言固難窮。", "龍盤色絲外，鵲顧偃波中。形勝駐群目，堅貞指蒼穹。", "我非王仲宣，去矣徒發蒙。"]'),
('yuding-28','同觀陳十六史興碑','高適','唐','御定全唐诗','yuding','','[]','荊衡氣偏秀，江漢流不歇。此地多精靈，有時生才傑。',144,'御定全唐詩/json/212.json','["荊衡氣偏秀，江漢流不歇。此地多精靈，有時生才傑。", "伊人今獨步，逸思能間發。永懷掩風騷，千載常矻矻。", "新碑亦崔嵬，佳句懸日月。則是刊石經，終然繼檮杌。", "我來觀雅制，慷慨變毛髮。季主盡荒淫，前王徒貽厥。", "東周既削弱，兩漢更淪沒。西晉何披猖，五胡相唐突。", "作歌乃彰善，比物仍惡訐。感歎將謂誰，對之空咄咄。"]'),
('yuding-29','宋中十首','高適','唐','御定全唐诗','yuding','','[]','梁王昔全盛，賓客複多才。悠悠一千年，陳跡唯高臺。',360,'御定全唐詩/json/212.json','["梁王昔全盛，賓客複多才。悠悠一千年，陳跡唯高臺。", "寂寞向秋草，悲風千里來。", "朝臨孟諸上，忽見芒碭間。赤帝終已矣，白雲長不還。", "時清更何有，禾黍遍空山。", "景公德何廣，臨變莫能欺。三請皆不忍，妖星終自移。", "君心本如此，天道豈無知。", "梁苑白日暮，梁山秋草時。君王不可見，修竹令人悲。", "九月桑葉盡，寒風鳴樹枝。", "登高臨舊國，懷古對窮秋。落日鴻雁度，寒城砧杵愁。", "昔賢不復有，行矣莫淹留。", "出門望終古，獨立悲且歌。憶昔魯仲尼，淒淒此經過。", "眾人不可向，伐樹將如何。", "逍遙漆園吏，冥沒不知年。世事浮雲外，閒居大道邊。", "古來同一馬，今我亦忘筌。", "五霸遞征伐，宋人無戰功。解圍幸奇說，易子傷吾衷。", "唯見盧門外，蕭條多轉蓬。", "常愛宓子賤，鳴琴能自親。邑中靜無事，豈不由其身。", "何意千年後，寂寞無此人。", "閼伯去已久，高丘臨道傍。人皆有兄弟，爾獨為參商。", "終古猶如此。而今安可量。"]'),
('yuding-30','薊中作','高適','唐','御定全唐诗','yuding','','[]','策馬自沙漠，長驅登塞垣。邊城何蕭條，白日黃雲昏。',60,'御定全唐詩/json/212.json','["策馬自沙漠，長驅登塞垣。邊城何蕭條，白日黃雲昏。", "一到征戰處，每愁胡虜翻。豈無安邊書，諸將已承恩。", "惆悵孫吳事，歸來獨閉門。"]'),
('yuding-31','自淇涉黃河途中作十三首','高適','唐','御定全唐诗','yuding','','[]','川上常極目，世情今已閑。去帆帶落日，征路隨長山。',564,'御定全唐詩/json/212.json','["川上常極目，世情今已閑。去帆帶落日，征路隨長山。", "親友若雲霄，可望不可攀。于茲任所愜，浩蕩風波間。", "清晨泛中流，羽族滿汀渚。黃鵠何處來，昂藏寡儔侶。", "飛鳴無人見，飲啄豈得所。雲漢爾固知，胡為不輕舉。", "野人頭盡白，與我忽相訪。手持青竹竿，日暮淇水上。", "雖老美容色，雖貧亦閑放。釣魚三十年，中心無所向。", "南登滑臺上，卻望河淇間。竹樹夾流水，孤城對遠山。", "念茲川路闊，羨爾沙鷗閑。長想別離處，猶無音信還。", "東入黃河水，茫茫泛紆直。北望太行山，峨峨半天色。", "山河相映帶，深淺未可測。自昔有賢才，相逢不相識。", "秋日登滑台，台高秋已暮。獨行既未愜，懷土悵無趣。", "晉宋何蕭條，羌胡散馳鶩。當時無戰略，此地即邊戍。", "兵革徒自勤，山河孰雲固。乘閑喜臨眺，感物傷遊寓。", "惆悵落日前，飄颻遠帆處。北風吹萬里，南雁不知數。", "歸意方浩然，雲沙更回互。", "亂流自茲遠，倚楫時一望。遙見楚漢城，崔嵬高山上。", "天道昔未測，人心無所向。屠釣稱侯王，龍蛇爭霸王。", "緬懷多殺戮，顧此生慘愴。聖代休甲兵，吾其得閒放。", "茲川方悠邈，雲沙無前後。古堰對河壖，長林出淇口。", "獨行非吾意，東向日已久。憂來誰得知，且酌尊中酒。", "朝從北岸來，泊船南河滸。試共野人言，深覺農夫苦。", "去秋雖薄熟，今夏猶未雨。耕耘日勤勞，租稅兼舄鹵。", "園蔬空寥落，產業不足數。尚有獻芹心，無因見明主。", "茫茫濁河注，懷古臨河濱。禹功本豁達，漢跡方因循。"]'),
('yuding-32','宋中遇陳二','高適','唐','御定全唐诗','yuding','','[]','常忝鮑叔義，所期王佐才。如何守苦節，獨此無良媒。',96,'御定全唐詩/json/212.json','["常忝鮑叔義，所期王佐才。如何守苦節，獨此無良媒。", "離別十年外，飄颻千里來。安知罷官後，惟見柴門開。", "窮巷隱東郭，高堂詠南陔。籬根長花草，井上生莓苔。", "伊昔望霄漢，於今倦蒿萊。男兒命未達，且盡手中杯。"]'),
('yuding-33','宋中遇劉書記有別','高適','唐','御定全唐诗','yuding','','[]','何代無秀士，高門生此才。森然睹毛髮，若見河山來。',96,'御定全唐詩/json/212.json','["何代無秀士，高門生此才。森然睹毛髮，若見河山來。", "幾載困常調，一朝時運催。白身謁明主，待詔登雲台。", "相逢梁宋間，與我醉蒿萊。寒楚眇千里，雪天晝不開。", "末路終離別，不能強悲哀。男兒爭富貴，勸爾莫遲回。"]'),
('yuding-34','魯郡途中遇徐十八錄事','高適','唐','御定全唐诗','yuding','','[]','誰謂嵩潁客，遂經鄒魯鄉。前臨少昊墟，始覺東蒙長。',96,'御定全唐詩/json/212.json','["誰謂嵩潁客，遂經鄒魯鄉。前臨少昊墟，始覺東蒙長。", "獨行豈吾心，懷古激中腸。聖人久已矣，游夏遙相望。", "裴回野澤間，左右多悲傷。日出見闕裏，川平知汶陽。", "弱冠負高節，十年思自強。終然不得意，去去任行藏。"]'),
('yuding-35','遇沖和先生','高適','唐','御定全唐诗','yuding','','[]','沖和生何代，或謂遊東溟。三命謁金殿，一言拜銀青。',120,'御定全唐詩/json/212.json','["沖和生何代，或謂遊東溟。三命謁金殿，一言拜銀青。", "自雲多方術，往往通神靈。萬乘親問道，六宮無敢聽。", "昔去限霄漢，今來睹儀形。頭戴鶡鳥冠，手搖白鶴翎。", "終日飲醇酒，不醉複不醒。常憶雞鳴山，每誦西升經。", "拊背念離別，依然出戶庭。莫見今如此，曾為一客星。"]'),
('yuding-36','魯西至東平','高適','唐','御定全唐诗','yuding','','[]','沙岸拍不定，石橋水橫流。問津見魯俗，懷古傷家丘。',36,'御定全唐詩/json/212.json','["沙岸拍不定，石橋水橫流。問津見魯俗，懷古傷家丘。", "寥落千載後，空傳褒聖侯。"]'),
('yuding-37','東平路作三首','高適','唐','御定全唐诗','yuding','','[]','南圖適不就，東走豈吾心。索索涼風動，行行秋水深。',108,'御定全唐詩/json/212.json','["南圖適不就，東走豈吾心。索索涼風動，行行秋水深。", "蟬鳴木葉落，茲夕更愁霖。", "明時好畫策，動欲幹王公。今日無成事，依依親老農。", "扁舟向何處，吾愛汶陽中。", "清曠涼夜月，裴回孤客舟。渺然風波上，獨愛前山秋。", "秋至複搖落，空令行者愁。"]'),
('yuding-38','東平路中遇大水','高適','唐','御定全唐诗','yuding','','[]','天災自古有，昏墊彌今秋。霖霪溢川原，澒洞涵田疇。',168,'御定全唐詩/json/212.json','["天災自古有，昏墊彌今秋。霖霪溢川原，澒洞涵田疇。", "指途適汶陽，掛席經蘆洲。永望齊魯郊，白雲何悠悠。", "傍沿鉅野澤，大水縱橫流。蟲蛇擁獨樹，麋鹿奔行舟。", "稼穡隨波瀾，西成不可求。室居相枕藉，蛙黽聲啾啾。", "仍憐穴蟻漂，益羨雲禽遊。農夫無倚著，野老生殷憂。", "聖主當深仁，廟堂運良籌。倉廩終爾給，田租應罷收。", "我心胡郁陶，征旅亦悲愁。縱懷濟時策，誰肯論吾謀。"]'),
('yuding-39','登壟','高適','唐','御定全唐诗','yuding','','[]','壟頭遠行客，壟上分流水。流水無盡期，行人未雲已。',48,'御定全唐詩/json/212.json','["壟頭遠行客，壟上分流水。流水無盡期，行人未雲已。", "淺才登一命，孤劍通萬里。豈不思故鄉，從來感知己。"]'),
('yuding-40','苦雪四首','高適','唐','御定全唐诗','yuding','','[]','二月猶北風，天陰雪冥冥。寥落一室中，悵然慚百齡。',156,'御定全唐詩/json/212.json','["二月猶北風，天陰雪冥冥。寥落一室中，悵然慚百齡。", "苦愁正如此，門柳複青青。", "惠連發清興，袁安念高臥。餘故非斯人，為性兼懶惰。", "賴茲尊中酒，終日聊自過。", "濛濛灑平陸，淅瀝至幽居。且喜潤群物，焉能悲鬥儲。", "故交久不見，鳥雀投吾廬。", "孰雲久閑曠，本自保知寡。窮巷獨無成，春條只盈把。", "安能羨鵬舉，且欲歌牛下。乃知古時人，亦有如我者。"]'),
('yuding-41','哭單父梁九少府','高適','唐','御定全唐诗','yuding','','[]','開篋淚沾臆，見君前日書。夜台今寂寞，獨是子雲居。',144,'御定全唐詩/json/212.json','["開篋淚沾臆，見君前日書。夜台今寂寞，獨是子雲居。", "疇昔探雲奇，登臨賦山水。同舟南浦下，望月西江裏。", "契闊多別離，綢繆到生死。九原即何處，萬事皆如此。", "晉山徒峨峨，斯人已冥冥。常時祿且薄，歿後家複貧。", "妻子在遠道，弟兄無一人。十上多苦辛，一官恒自哂。", "青雲將可致，白日忽先盡。唯有身後名，空留無遠近。"]'),
('yuding-42','哭裴少府','高適','唐','御定全唐诗','yuding','','[]','世人誰不死，嗟君非生慮。扶病適到官，田園在何處。',48,'御定全唐詩/json/212.json','["世人誰不死，嗟君非生慮。扶病適到官，田園在何處。", "公才群吏感，葬事他人助。餘亦未識君，深悲哭君去。"]'),
('yuding-0','行路難二首','高適','唐','御定全唐诗','yuding','','[]','長安少年不少錢，能騎駿馬鳴金鞭。五侯相逢大道邊，',87,'御定全唐詩/json/213.json','["長安少年不少錢，能騎駿馬鳴金鞭。五侯相逢大道邊，", "安知憔悴讀書者，暮宿靈台私自憐。", "君不見富家翁，舊時貧賤誰比數。一朝金多結豪貴，", "自矜一身忽如此，卻笑傍人獨愁苦。東鄰少年安所如，"]'),
('yuding-1','秋胡行','高適','唐','御定全唐诗','yuding','','[]','妾本邯鄲未嫁時，容華倚翠人未知。一朝結髮從君子，',136,'御定全唐詩/json/213.json','["妾本邯鄲未嫁時，容華倚翠人未知。一朝結髮從君子，", "蕙樓獨臥頻度春，彩閣辭君幾徂暑。三月垂楊蠶未眠，", "妾家夫婿經離久，寸心誓與長相守。願言行路莫多情，", "勞心苦力終無恨，所冀君恩即可依。聞說行人已歸止，", "從來自隱無疑背，直為君情也相會。如何咫尺仍有情，", "莫道向來不得意，故欲留規誡後人。"]'),
('yuding-2','古大樑行','高適','唐','御定全唐诗','yuding','','[]','古城莽蒼饒荊榛，驅馬荒城愁殺人。魏王宮觀盡禾黍，',88,'御定全唐詩/json/213.json','["古城莽蒼饒荊榛，驅馬荒城愁殺人。魏王宮觀盡禾黍，", "軍容帶甲三十萬，國步連營一千里。全盛須臾那可論，", "暮天搖落傷懷抱，倚劍悲歌對秋草。俠客猶傳朱亥名，", "年代淒涼不可問，往來唯有水東流。"]'),
('yuding-3','邯鄲少年行','高適','唐','御定全唐诗','yuding','','[]','邯鄲城南遊俠子，自矜生長邯鄲裏。千場縱博家仍富，',65,'御定全唐詩/json/213.json','["邯鄲城南遊俠子，自矜生長邯鄲裏。千場縱博家仍富，", "未知肝膽向誰是，令人卻憶平原君。君不見今人交態薄，", "且與少年飲美酒，往來射獵西山頭。"]'),
('yuding-4','燕歌行','高適','唐','御定全唐诗','yuding','','[]','漢家煙塵在東北，漢將辭家破殘賊。男兒本自重橫行，',121,'御定全唐詩/json/213.json','["漢家煙塵在東北，漢將辭家破殘賊。男兒本自重橫行，", "校尉羽書飛瀚海，單于獵火照狼山。山川蕭條極邊土，", "大漠窮秋塞草腓，孤城落日鬥兵稀。身當恩遇恒輕敵，", "少婦城南欲斷腸，征人薊北空回首。邊庭飄颻那可度，", "相看白刃血紛紛，死節從來豈顧勳。君不見沙場征戰苦，"]'),
('yuding-5','古歌行','高適','唐','御定全唐诗','yuding','','[]','君不見漢家三葉從代至，高皇舊臣多富貴。',43,'御定全唐詩/json/213.json','["君不見漢家三葉從代至，高皇舊臣多富貴。", "天子垂衣方晏如，廟堂拱手無餘議。蒼生偃臥休征戰，"]'),
('yuding-6','人日寄杜二拾遺','高適','唐','御定全唐诗','yuding','','[]','人日題詩寄草堂，遙憐故人思故鄉。柳條弄色不忍見，',48,'御定全唐詩/json/213.json','["人日題詩寄草堂，遙憐故人思故鄉。柳條弄色不忍見，", "今年人日空相憶，明年人日知何處。一臥東山三十春，"]'),
('yuding-7','九日酬顏少府','高適','唐','御定全唐诗','yuding','','[]','簷前白日應可惜，籬下黃花為誰有。行子迎霜未授衣，',40,'御定全唐詩/json/213.json','["簷前白日應可惜，籬下黃花為誰有。行子迎霜未授衣，", "縱使登高只斷腸，不如獨坐空搔首。"]'),
('yuding-8','留別鄭三、韋九兼洛下諸公','高適','唐','御定全唐诗','yuding','','[]','憶昨相逢論久要，顧君哂我輕常調。羈旅雖同白社遊，',72,'御定全唐詩/json/213.json','["憶昨相逢論久要，顧君哂我輕常調。羈旅雖同白社遊，", "長歌達者杯中物，大笑前人身後名。幸逢明盛多招隱，", "犁牛釣竿不復見，縣人邑吏來相邀。遠路鳴蟬秋興發，"]'),
('yuding-9','送楊山人歸嵩陽','高適','唐','御定全唐诗','yuding','','[]','不到嵩陽動十年，舊時心事已徒然。一二故人不復見，',48,'御定全唐詩/json/213.json','["不到嵩陽動十年，舊時心事已徒然。一二故人不復見，", "鑿井耕田不我招，知君以此忘帝力。山人好去嵩陽路，"]'),
('yuding-10','送別','高適','唐','御定全唐诗','yuding','','[]','昨夜離心正郁陶，三更白露西風高。螢飛木落何淅瀝，',40,'御定全唐詩/json/213.json','["昨夜離心正郁陶，三更白露西風高。螢飛木落何淅瀝，", "攬衣出戶一相送，唯見歸雲縱複橫。"]'),
('yuding-11','贈別晉三處士','高適','唐','御定全唐诗','yuding','','[]','有人家住清河源，渡河問我游梁園。手持道經注已畢，',48,'御定全唐詩/json/213.json','["有人家住清河源，渡河問我游梁園。手持道經注已畢，", "知己從來不易知，慕君為人與君好。別時九月桑葉疏，"]'),
('yuding-12','送渾將軍出塞','高適','唐','御定全唐诗','yuding','','[]','將軍族貴兵且強，漢家已是渾邪王。子孫相承在朝野，',96,'御定全唐詩/json/213.json','["將軍族貴兵且強，漢家已是渾邪王。子孫相承在朝野，", "銀鞍玉勒繡蝥弧，每逐嫖姚破骨都。李廣從來先將士，", "城頭畫角三四聲，匣裏寶刀晝夜鳴。意氣能甘萬里去，", "塞下應多俠少年，關西不見春楊柳。從軍借問所從誰，"]'),
('yuding-13','送蔡山人','高適','唐','御定全唐诗','yuding','','[]','東山布衣明古今，自言獨未逢知音。識者閱見一生事，',48,'御定全唐詩/json/213.json','["東山布衣明古今，自言獨未逢知音。識者閱見一生事，", "鬥酒相留醉複醒，悲歌數年淚如雨。丈夫遭遇不可知，"]'),
('yuding-14','封丘作','高適','唐','御定全唐诗','yuding','','[]','我本漁樵孟諸野，一生自是悠悠者。乍可狂歌草澤中，',72,'御定全唐詩/json/213.json','["我本漁樵孟諸野，一生自是悠悠者。乍可狂歌草澤中，", "拜迎官長心欲碎，鞭撻黎庶令人悲。歸來向家問妻子，", "夢想舊山安在哉，為銜君命且遲回。乃知梅福徒為爾，"]'),
('yuding-15','題李別駕壁','高適','唐','御定全唐诗','yuding','','[]','去鄉不遠逢知己，握手相歡得如此。禮樂遙傳魯伯禽，',40,'御定全唐詩/json/213.json','["去鄉不遠逢知己，握手相歡得如此。禮樂遙傳魯伯禽，", "一生稱意能幾人，今日從君問終始。"]'),
('yuding-16','寄宿田家','高適','唐','御定全唐诗','yuding','','[]','田家老翁住東陂，說道平生隱在茲。鬢白未曾記日月，',72,'御定全唐詩/json/213.json','["田家老翁住東陂，說道平生隱在茲。鬢白未曾記日月，", "牛壯日耕十畝地，人閑常掃一茅茨。客來滿酌清尊酒，", "村墟日落行人少，醉後無心怯路歧。今夜只應還寄宿，"]'),
('yuding-17','別韋參軍','高適','唐','御定全唐诗','yuding','','[]','二十解書劍，西游長安城。舉頭望君門，屈指取公卿。',96,'御定全唐詩/json/213.json','["二十解書劍，西游長安城。舉頭望君門，屈指取公卿。", "國風沖融邁三五，朝廷歡樂彌寰宇。白璧皆言賜近臣，", "兔苑為農歲不登，雁池垂釣心長苦。世人遇我同眾人，", "彈棋擊築白日晚，縱酒高歌楊柳春。歡娛未盡分散去，"]'),
('yuding-18','送田少府貶蒼梧','高適','唐','御定全唐诗','yuding','','[]','沉吟對遷客，惆悵西南天。昔為一官未得意，',44,'御定全唐詩/json/213.json','["沉吟對遷客，惆悵西南天。昔為一官未得意，", "遠樹應憐北地春，行人卻羨南歸雁。丈夫窮達未可知，"]'),
('yuding-19','平臺夜遇李景參有別','高適','唐','御定全唐诗','yuding','','[]','離心忽悵然，策馬對秋天。孟諸薄暮涼風起，',44,'御定全唐詩/json/213.json','["離心忽悵然，策馬對秋天。孟諸薄暮涼風起，", "歲物蕭條滿路歧，此行浩蕩令人悲。家貧羨爾有微祿，"]'),
('yuding-20','送郭處士往萊蕪，兼寄苟山人','高適','唐','御定全唐诗','yuding','','[]','君為東蒙客，往來東蒙畔。雲臥臨嶧陽，山行窮日觀。',64,'御定全唐詩/json/213.json','["君為東蒙客，往來東蒙畔。雲臥臨嶧陽，山行窮日觀。", "少年詞賦皆可聽，秀眉白麵風清泠。身上未曾染名利，", "歸見萊蕪九十翁，為論別後長相憶。"]'),
('yuding-21','賦得還山吟，送沈四山人','高適','唐','御定全唐诗','yuding','','[]','還山吟，天高日暮寒山深，送君還山識君心。',84,'御定全唐詩/json/213.json','["還山吟，天高日暮寒山深，送君還山識君心。", "人生老大須恣意，看君解作一生事，山間偃仰無不至。", "石泉淙淙若風雨，桂花松子常滿地。賣藥囊中應有錢，", "眠時憶問醒時事，夢魂可以相周旋。"]'),
('yuding-22','崔司錄宅燕大理李卿','高適','唐','御定全唐诗','yuding','','[]','多雨殊未已，秋雲更沉沉。洛陽故人初解印，',44,'御定全唐詩/json/213.json','["多雨殊未已，秋雲更沉沉。洛陽故人初解印，", "豁達常推海內賢，殷勤但酌尊中酒。飲醉欲言歸剡溪，"]'),
('yuding-23','同鮮于洛陽于畢員外宅觀畫馬歌','高適','唐','御定全唐诗','yuding','','[]','知君愛鳴琴，仍好千里馬。永日恒思單父中，',68,'御定全唐詩/json/213.json','["知君愛鳴琴，仍好千里馬。永日恒思單父中，", "主人娛賓畫障開，只言騏驥西極來。半壁䟃𧽼勢不住，", "始知物妙皆可憐，燕昭市駿豈徒然。縱令剪拂無所用，"]'),
('yuding-24','同河南李少尹畢員外宅夜飲時洛陽告捷遂作春酒歌','高適','唐','御定全唐诗','yuding','','[]','故人美酒勝濁醪，故人清詞合風騷。長歌滿酌惟吾曹，',66,'御定全唐詩/json/213.json','["故人美酒勝濁醪，故人清詞合風騷。長歌滿酌惟吾曹，", "武侯腰間印如鬥，郎官無事時飲酒。杯中綠蟻吹轉來，", "賴得飲君春酒數十杯，不然令我愁欲死。"]'),
('yuding-25','同李九士曹觀壁畫雲作','高適','唐','御定全唐诗','yuding','','[]','始知帝鄉客，能畫蒼梧雲。秋天萬里一片色，',20,'御定全唐詩/json/213.json','["始知帝鄉客，能畫蒼梧雲。秋天萬里一片色，"]'),
('yuding-26','見薛大臂鷹作','高適','唐','御定全唐诗','yuding','','[]','寒楚十二月，蒼鷹八九毛。寄言燕雀莫相啅，',20,'御定全唐詩/json/213.json','["寒楚十二月，蒼鷹八九毛。寄言燕雀莫相啅，"]'),
('yuding-27','畫馬篇','高適','唐','御定全唐诗','yuding','','[]','君侯櫪上驄，貌在丹青中。馬毛連錢蹄鐵色，',60,'御定全唐詩/json/213.json','["君侯櫪上驄，貌在丹青中。馬毛連錢蹄鐵色，", "感茲絕代稱妙手，遂令談者不容口。麒麟獨步自可珍，", "荷君剪拂與君用，一日千里如旋風。"]'),
('yuding-28','詠馬鞭','高適','唐','御定全唐诗','yuding','','[]','龍竹養根凡幾年，工人截之為長鞭，一節一目皆天然。',64,'御定全唐詩/json/213.json','["龍竹養根凡幾年，工人截之為長鞭，一節一目皆天然。", "珠重重，星連連。繞指柔，純金堅。繩不直，規不圓。", "把向空中捎一聲，良馬有心日馳千。"]'),
('yuding-29','塞下曲','高適','唐','御定全唐诗','yuding','','[]','君不見芳樹枝，春花落盡蜂不窺。君不見梁上泥，',38,'御定全唐詩/json/213.json','["君不見芳樹枝，春花落盡蜂不窺。君不見梁上泥，", "獨宿自然堪下淚，況複時聞鳥夜啼。"]'),
('yuding-30','漁父歌','高適','唐','御定全唐诗','yuding','','[]','曲岸深潭一山叟，駐眼看鉤不移手。世人欲得知姓名，',40,'御定全唐詩/json/213.json','["曲岸深潭一山叟，駐眼看鉤不移手。世人欲得知姓名，", "料得孤舟無定止，日暮持竿何處歸。"]'),
('yuding-0','部落曲','高適','唐','御定全唐诗','yuding','','[]','蕃軍傍塞游，代馬噴風秋。老將垂金甲，閼支著錦裘。',48,'御定全唐詩/json/214.json','["蕃軍傍塞游，代馬噴風秋。老將垂金甲，閼支著錦裘。", "雕戈蒙豹尾，紅旆插狼頭。日暮天山下，鳴笳漢使愁。"]'),
('yuding-1','贈杜二拾遺','高適','唐','御定全唐诗','yuding','','[]','傳道招提客，詩書自討論。佛香時入院，僧飯屢過門。',48,'御定全唐詩/json/214.json','["傳道招提客，詩書自討論。佛香時入院，僧飯屢過門。", "聽法還應難，尋經剩欲翻。草玄今已畢，此外複何言。"]'),
('yuding-2','醉後贈張九旭','高適','唐','御定全唐诗','yuding','','[]','世上謾相識，此翁殊不然。興來書自聖，醉後語尤顛。',48,'御定全唐詩/json/214.json','["世上謾相識，此翁殊不然。興來書自聖，醉後語尤顛。", "白髮老閒事，青雲在目前。床頭一壺酒，能更幾回眠。"]'),
('yuding-3','途中寄徐錄事','高適','唐','御定全唐诗','yuding','','[]','落日風雨至，秋天鴻雁初。離憂不堪比，旅館複何如。',48,'御定全唐詩/json/214.json','["落日風雨至，秋天鴻雁初。離憂不堪比，旅館複何如。", "君又幾時去，我知音信疏。空多篋中贈，長見右軍書。"]'),
('yuding-4','酬衛八雪中見寄','高適','唐','御定全唐诗','yuding','','[]','季冬憶淇上，落日歸山樊。舊宅帶流水，平田臨古村。',48,'御定全唐詩/json/214.json','["季冬憶淇上，落日歸山樊。舊宅帶流水，平田臨古村。", "雪中望來信，醉裏開衡門。果得希代寶，緘之那可論。"]'),
('yuding-5','送白少府送兵之隴右','高適','唐','御定全唐诗','yuding','','[]','踐更登隴首，遠別指臨洮。為問關山事，何如州縣勞。',48,'御定全唐詩/json/214.json','["踐更登隴首，遠別指臨洮。為問關山事，何如州縣勞。", "軍容隨赤羽，樹色引青袍。誰斷單于臂，今年太白高。"]'),
('yuding-6','河西送李十七','高適','唐','御定全唐诗','yuding','','[]','邊城多遠別，此去莫徒然。問禮知才子，登科及少年。',48,'御定全唐詩/json/214.json','["邊城多遠別，此去莫徒然。問禮知才子，登科及少年。", "出門看落日，驅馬向秋天。高價人爭重，行當早著鞭。"]'),
('yuding-7','送張瑤貶五溪尉','高適','唐','御定全唐诗','yuding','','[]','他日維楨幹，明時懸鏌鋣。江山遙去國，妻子獨還家。',48,'御定全唐詩/json/214.json','["他日維楨幹，明時懸鏌鋣。江山遙去國，妻子獨還家。", "離別無嫌遠，沉浮勿強嗟。南登有詞賦，知爾吊長沙。"]'),
('yuding-8','別韋五','高適','唐','御定全唐诗','yuding','','[]','徒然酌杯酒，不覺散人愁。相識仍遠別，欲歸翻旅遊。',48,'御定全唐詩/json/214.json','["徒然酌杯酒，不覺散人愁。相識仍遠別，欲歸翻旅遊。", "夏雲滿郊甸，明月照河洲。莫恨征途遠，東看漳水流。"]'),
('yuding-9','別劉大校書','高適','唐','御定全唐诗','yuding','','[]','昔日京華去，知君才望新。應猶作賦好，莫歎在官貧。',48,'御定全唐詩/json/214.json','["昔日京華去，知君才望新。應猶作賦好，莫歎在官貧。", "且複傷遠別，不然愁此身。清風幾萬里，江上一歸人。"]'),
('yuding-10','宋中別司功叔，各賦一物得商丘','高適','唐','御定全唐诗','yuding','','[]','商丘試一望，隱隱帶秋天。地與辰星在，城將大路遷。',48,'御定全唐詩/json/214.json','["商丘試一望，隱隱帶秋天。地與辰星在，城將大路遷。", "干戈悲昔事，墟落對窮年。即此傷離緒，淒淒賦酒筵。"]'),
('yuding-11','送蔡十二之海上','高適','唐','御定全唐诗','yuding','','[]','黯然何所為，相對但悲酸。季弟念離別，賢兄救急難。',48,'御定全唐詩/json/214.json','["黯然何所為，相對但悲酸。季弟念離別，賢兄救急難。", "河流冰處盡，海路雪中寒。尚有南飛雁，知君不忍看。"]'),
('yuding-12','別韋兵曹','高適','唐','御定全唐诗','yuding','','[]','離別長千里，相逢數十年。此心應不變，他事已徒然。',48,'御定全唐詩/json/214.json','["離別長千里，相逢數十年。此心應不變，他事已徒然。", "惆悵春光裏，蹉跎柳色前。逢時當自取，看爾欲先鞭。"]'),
('yuding-13','獨孤判官部送兵','高適','唐','御定全唐诗','yuding','','[]','餞君嗟遠別，為客念周旋。征路今如此，前軍猶眇然。',48,'御定全唐詩/json/214.json','["餞君嗟遠別，為客念周旋。征路今如此，前軍猶眇然。", "出關逢漢壁，登隴望胡天。亦是封侯地，期君早著鞭。"]'),
('yuding-14','別從甥萬盈','高適','唐','御定全唐诗','yuding','','[]','諸生曰萬盈，四十乃知名。宅相予偏重，家丘人莫輕。',48,'御定全唐詩/json/214.json','["諸生曰萬盈，四十乃知名。宅相予偏重，家丘人莫輕。", "美才應自料，苦節豈無成。莫以山田薄，今春又不耕。"]'),
('yuding-15','別崔少府','高適','唐','御定全唐诗','yuding','','[]','知君少得意，汶上掩柴扉。寒食仍留火，春風未授衣。',48,'御定全唐詩/json/214.json','["知君少得意，汶上掩柴扉。寒食仍留火，春風未授衣。", "皆言黃綬屈，早向青雲飛。借問他鄉事，今年歸不歸。"]'),
('yuding-16','別馮判官','高適','唐','御定全唐诗','yuding','','[]','碣石遼西地，漁陽薊北天。關山唯一道，雨雪盡三邊。',48,'御定全唐詩/json/214.json','["碣石遼西地，漁陽薊北天。關山唯一道，雨雪盡三邊。", "才子方為客，將軍正渴賢。遙知幕府下，書記日翩翩。"]'),
('yuding-17','淇上送韋司倉往滑台','高適','唐','御定全唐诗','yuding','','[]','飲酒莫辭醉，醉多適不愁。孰知非遠別，終念對窮秋。',48,'御定全唐詩/json/214.json','["飲酒莫辭醉，醉多適不愁。孰知非遠別，終念對窮秋。", "滑台門外見，淇水眼前流。君去應回首，風波滿渡頭。"]'),
('yuding-18','送崔功曹赴越','高適','唐','御定全唐诗','yuding','','[]','傳有東南別，題詩報客居。江山知不厭，州縣複何如。',48,'御定全唐詩/json/214.json','["傳有東南別，題詩報客居。江山知不厭，州縣複何如。", "莫恨吳歈曲，嘗看越絕書。今朝欲乘興，隨爾食鱸魚。"]'),
('yuding-19','送蹇秀才赴臨洮','高適','唐','御定全唐诗','yuding','','[]','悵望日千里，如何今二毛。猶思陽谷去，莫厭隴山高。',48,'御定全唐詩/json/214.json','["悵望日千里，如何今二毛。猶思陽谷去，莫厭隴山高。", "倚馬見雄筆，隨身唯寶刀。料君終自致，勳業在臨洮。"]'),
('yuding-20','廣陵別鄭處士','高適','唐','御定全唐诗','yuding','','[]','落日知分手，春風莫斷腸。興來無不愜，才在亦何傷。',48,'御定全唐詩/json/214.json','["落日知分手，春風莫斷腸。興來無不愜，才在亦何傷。", "溪水堪垂釣，江田耐插秧。人生只為此，亦足傲羲皇。"]'),
('yuding-21','別孫欣','高適','唐','御定全唐诗','yuding','','[]','離人去複留，白馬黑貂裘。屈指論前事，停鞭惜舊遊。',48,'御定全唐詩/json/214.json','["離人去複留，白馬黑貂裘。屈指論前事，停鞭惜舊遊。", "帝鄉那可忘，旅館日堪愁。誰念無知己，年年睢水流。"]'),
('yuding-22','送劉評事充朔方判官，賦得征馬嘶','高適','唐','御定全唐诗','yuding','','[]','征馬向邊州，蕭蕭嘶不休。思深應帶別，聲斷為兼秋。',48,'御定全唐詩/json/214.json','["征馬向邊州，蕭蕭嘶不休。思深應帶別，聲斷為兼秋。", "歧路風將遠，關山月共愁。贈君從此去，何日大刀頭。"]'),
('yuding-23','送魏八','高適','唐','御定全唐诗','yuding','','[]','更沽淇上酒，還泛驛前舟。為惜故人去，複憐嘶馬愁。',48,'御定全唐詩/json/214.json','["更沽淇上酒，還泛驛前舟。為惜故人去，複憐嘶馬愁。", "雲山行處合，風雨興中秋。此路無知己，明珠莫暗投。"]'),
('yuding-24','贈別褚山人','高適','唐','御定全唐诗','yuding','','[]','攜手贈將行，山人道姓名。光陰薊子訓，才術褚先生。',48,'御定全唐詩/json/214.json','["攜手贈將行，山人道姓名。光陰薊子訓，才術褚先生。", "牆上梨花白，尊中桂酒清。洛陽無二價，猶是慕風聲。"]'),
('yuding-25','別王八','高適','唐','御定全唐诗','yuding','','[]','征馬嘶長路，離人挹佩刀。客來東道遠，歸去北風高。',48,'御定全唐詩/json/214.json','["征馬嘶長路，離人挹佩刀。客來東道遠，歸去北風高。", "時候何蕭索，鄉心正郁陶。傳君遇知己，行日有綈袍。"]'),
('yuding-26','送董判官','高適','唐','御定全唐诗','yuding','','[]','逢君說行邁，倚劍別交親。幕府為才子，將軍作主人。',48,'御定全唐詩/json/214.json','["逢君說行邁，倚劍別交親。幕府為才子，將軍作主人。", "近關多雨雪，出塞有風塵。長策須當用，男兒莫顧身。"]'),
('yuding-27','送鄭侍禦謫閩中','高適','唐','御定全唐诗','yuding','','[]','謫去君無恨，閩中我舊過。大都秋雁少，只是夜猿多。',48,'御定全唐詩/json/214.json','["謫去君無恨，閩中我舊過。大都秋雁少，只是夜猿多。", "東路雲山合，南天瘴癘和。自當逢雨露，行矣慎風波。"]'),
('yuding-28','送李侍禦赴安西','高適','唐','御定全唐诗','yuding','','[]','行子對飛蓬，金鞭指鐵驄。功名萬里外，心事一杯中。',48,'御定全唐詩/json/214.json','["行子對飛蓬，金鞭指鐵驄。功名萬里外，心事一杯中。", "虜障燕支北，秦城太白東。離魂莫惆悵，看取寶刀雄。"]'),
('yuding-29','送裴別將之安西','高適','唐','御定全唐诗','yuding','','[]','絕域眇難躋，悠然信馬蹄。風塵經跋涉，搖落怨暌攜。',48,'御定全唐詩/json/214.json','["絕域眇難躋，悠然信馬蹄。風塵經跋涉，搖落怨暌攜。", "地出流沙外，天長甲子西。少年無不可，行矣莫淒淒。"]'),
('yuding-30','宴郭校書，因之有別','高適','唐','御定全唐诗','yuding','','[]','彩服趨庭訓，分交載酒過。芸香名早著，蓬轉事仍多。',48,'御定全唐詩/json/214.json','["彩服趨庭訓，分交載酒過。芸香名早著，蓬轉事仍多。", "苦戰知機息，窮愁奈別何。雲霄莫相待，年鬢已蹉跎。"]'),
('yuding-31','同李太守北池泛舟，宴高平鄭太守','高適','唐','御定全唐诗','yuding','','[]','每揖龔黃事，還陪李郭舟。雲從四岳起，水向百城流。',48,'御定全唐詩/json/214.json','["每揖龔黃事，還陪李郭舟。雲從四岳起，水向百城流。", "幽意隨登陟，嘉言即獻酬。乃知縫掖貴，今日對諸侯。"]'),
('yuding-32','同崔員外、綦毋拾遺九日宴京兆府李士曹','高適','唐','御定全唐诗','yuding','','[]','今日好相見，群賢仍廢曹。晚晴催翰墨，秋興引風騷。',48,'御定全唐詩/json/214.json','["今日好相見，群賢仍廢曹。晚晴催翰墨，秋興引風騷。", "絳葉擁虛砌，黃花隨濁醪。閉門無不可，何事更登高。"]'),
('yuding-33','同群公十月朝宴李太守宅','高適','唐','御定全唐诗','yuding','','[]','良牧征高賞，褰帷問考盤。歲時當正月，甲子入初寒。',48,'御定全唐詩/json/214.json','["良牧征高賞，褰帷問考盤。歲時當正月，甲子入初寒。", "已聽甘棠頌，欣陪旨酒歡。仍憐門下客，不作布衣看。"]'),
('yuding-34','武威同諸公過楊七山人，得藤字','高適','唐','御定全唐诗','yuding','','[]','幕府日多暇，田家歲複登。相知恨不早，乘興乃無恒。',48,'御定全唐詩/json/214.json','["幕府日多暇，田家歲複登。相知恨不早，乘興乃無恒。", "窮巷在喬木，深齋垂古藤。邊城唯有醉，此外更何能。"]'),
('yuding-35','同群公登濮陽聖佛寺閣','高適','唐','御定全唐诗','yuding','','[]','落日登臨處，悠然意不窮。佛因初地識，人覺四天空。',48,'御定全唐詩/json/214.json','["落日登臨處，悠然意不窮。佛因初地識，人覺四天空。", "來雁清霜後，孤帆遠樹中。裴回傷寓目，蕭索對寒風。"]'),
('yuding-36','同衛八題陸少府書齋','高適','唐','御定全唐诗','yuding','','[]','知君薄州縣，好靜無冬春。散帙至棲鳥，明燈留故人。',48,'御定全唐詩/json/214.json','["知君薄州縣，好靜無冬春。散帙至棲鳥，明燈留故人。", "深房臘酒熟，高院梅花新。若是周旋地，當令風義親。"]'),
('yuding-37','淇上別業','高適','唐','御定全唐诗','yuding','','[]','依依西山下，別業桑林邊。庭鴨喜多雨，鄰雞知暮天。',48,'御定全唐詩/json/214.json','["依依西山下，別業桑林邊。庭鴨喜多雨，鄰雞知暮天。", "野人種秋菜，古老開原田。且向世情遠，吾今聊自然。"]'),
('yuding-38','入昌松東界山行','高適','唐','御定全唐诗','yuding','','[]','鳥道幾登頓，馬蹄無暫閑。崎嶇出長阪，合遝猶前山。',48,'御定全唐詩/json/214.json','["鳥道幾登頓，馬蹄無暫閑。崎嶇出長阪，合遝猶前山。", "石激水流處，天寒松色間。王程應未盡，且莫顧刀環。"]'),
('yuding-39','使青夷軍入居庸三首','高適','唐','御定全唐诗','yuding','','[]','匹馬行將久，征途去轉難。不知邊地別，只訝客衣單。',144,'御定全唐詩/json/214.json','["匹馬行將久，征途去轉難。不知邊地別，只訝客衣單。", "溪冷泉聲苦，山空木葉幹。莫言關塞極，雲雪尚漫漫。", "古鎮青山口，寒風落日時。岩巒鳥不過，冰雪馬堪遲。", "出塞應無策，還家賴有期。東山足松桂，歸去結茅茨。", "登頓驅征騎，棲遲愧寶刀。遠行今若此，微祿果徒勞。", "絕阪水連下，群峰雲共高。自堪成白首，何事一青袍。"]'),
('yuding-40','自薊北歸','高適','唐','御定全唐诗','yuding','','[]','驅馬薊門北，北風邊馬哀。蒼茫遠山口，豁達胡天開。',48,'御定全唐詩/json/214.json','["驅馬薊門北，北風邊馬哀。蒼茫遠山口，豁達胡天開。", "五將已深入，前軍止半回。誰憐不得意，長劍獨歸來。"]'),
('yuding-41','東平別前衛縣李寀少府','高適','唐','御定全唐诗','yuding','','[]','黃鳥翩翩楊柳垂，春風送客使人悲。怨別自驚千裏外，',40,'御定全唐詩/json/214.json','["黃鳥翩翩楊柳垂，春風送客使人悲。怨別自驚千裏外，", "此地從來可乘興，留君不住益淒其。"]'),
('yuding-42','夜別韋司士，得城字','高適','唐','御定全唐诗','yuding','','[]','高館張燈酒複清，夜鐘殘月雁歸聲。只言啼鳥堪求侶，',40,'御定全唐詩/json/214.json','["高館張燈酒複清，夜鐘殘月雁歸聲。只言啼鳥堪求侶，", "莫怨他鄉暫離別，知君到處有逢迎。"]'),
('yuding-43','送李少府貶峽中，王少府貶長沙','高適','唐','御定全唐诗','yuding','','[]','嗟君此別意何如，駐馬銜杯問謫居。巫峽啼猿數行淚，',40,'御定全唐詩/json/214.json','["嗟君此別意何如，駐馬銜杯問謫居。巫峽啼猿數行淚，", "聖代即今多雨露，暫時分手莫躊躇。"]'),
('yuding-44','同陳留崔司戶早春宴蓬池','高適','唐','御定全唐诗','yuding','','[]','同官載酒出郊圻，晴日東馳雁北飛。隔岸春雲邀翰墨，',40,'御定全唐詩/json/214.json','["同官載酒出郊圻，晴日東馳雁北飛。隔岸春雲邀翰墨，", "州縣徒勞那可度，後時連騎莫相違。"]'),
('yuding-45','金城北樓','高適','唐','御定全唐诗','yuding','','[]','北樓西望滿晴空，積水連山勝畫中。湍上急流聲若箭，',40,'御定全唐詩/json/214.json','["北樓西望滿晴空，積水連山勝畫中。湍上急流聲若箭，", "為問邊庭更何事，至今羌笛怨無窮。"]'),
('yuding-46','同顏六少府旅宦秋中之作','高適','唐','御定全唐诗','yuding','','[]','傳君昨夜悵然悲，獨坐新齋木落時。逸氣舊來淩燕雀，',40,'御定全唐詩/json/214.json','["傳君昨夜悵然悲，獨坐新齋木落時。逸氣舊來淩燕雀，", "不是鬼神無正直，從來州縣有瑕疵。"]'),
('yuding-47','重陽','高適','唐','御定全唐诗','yuding','','[]','節物驚心兩鬢華，東籬空繞未開花。百年將半仕三已，',40,'御定全唐詩/json/214.json','["節物驚心兩鬢華，東籬空繞未開花。百年將半仕三已，", "真成獨坐空搔首，門柳蕭蕭噪暮鴉。"]'),
('yuding-48','古樂府飛龍曲，留上陳左相','高適','唐','御定全唐诗','yuding','','[]','德以精靈降，時膺夢寐求。蒼生謝安石，天子富平侯。',192,'御定全唐詩/json/214.json','["德以精靈降，時膺夢寐求。蒼生謝安石，天子富平侯。", "尊俎資高論，岩廊挹大猷。相門連戶牖，卿族嗣弓裘。", "豁達雲開霽，清明月映秋。能為吉甫頌，善用子房籌。", "階砌思攀陟，門闌尚阻修。高山不易仰，大匠本難投。", "跡與松喬合，心緣啟沃留。公才山吏部，書癖杜荊州。", "幸沐千年聖，何辭一尉休。折腰知寵辱，回首見沉浮。", "天地莊生馬，江湖範蠡舟。逍遙堪自樂，浩蕩信無憂。", "去此從黃綬，歸歟任白頭。風塵與霄漢，瞻望日悠悠。"]'),
('yuding-49','留上李右相','高適','唐','御定全唐诗','yuding','','[]','風俗登淳古，君臣挹大庭。深沉謀九德，密勿契千齡。',192,'御定全唐詩/json/214.json','["風俗登淳古，君臣挹大庭。深沉謀九德，密勿契千齡。", "獨立調元氣，清心豁窅冥。本枝連帝系，長策冠生靈。", "傅說明殷道，蕭何律漢刑。鈞衡持國柄，柱石總朝經。", "隱軫江山藻，氛氳鼎鼐銘。興中皆白雪，身外即丹青。", "江海呼窮鳥，詩書問聚螢。吹噓成羽翼，提握動芳馨。", "倚伏悲還笑，棲遲醉複醒。恩榮初就列，含育忝宵形。", "有竊丘山惠，無時枕席寧。壯心瞻落景，生事感浮萍。", "莫以才難用，終期善易聽。未為門下客，徒謝少微星。"]'),
('yuding-50','同李員外賀哥舒大夫破九曲之作','高適','唐','御定全唐诗','yuding','','[]','遙傳副丞相，昨日破西蕃。作氣群山動，揚軍大旆翻。',144,'御定全唐詩/json/214.json','["遙傳副丞相，昨日破西蕃。作氣群山動，揚軍大旆翻。", "奇兵邀轉戰，連孥絕歸奔。泉噴諸戎血，風驅死虜魂。", "頭飛攢萬戟，面縛聚轅門。鬼哭黃埃暮，天愁白日昏。", "石城與岩險，鐵騎皆雲屯。長策一言決，高蹤百代存。", "威棱懾沙漠，忠義感乾坤。老將黯無色，儒生安敢論。", "解圍憑廟算，止殺報君恩。唯有關河渺，蒼茫空樹墩。"]'),
('yuding-51','信安王幕府詩','高適','唐','御定全唐诗','yuding','','[]','雲紀軒皇代，星高太白年。廟堂咨上策，幕府制中權。',360,'御定全唐詩/json/214.json','["雲紀軒皇代，星高太白年。廟堂咨上策，幕府制中權。", "磐石藩維固，升壇禮樂先。國章榮印綬，公服貴貂蟬。", "樂善旌深德，輸忠格上玄。剪桐光寵錫，題劍美貞堅。", "聖祚雄圖廣，師貞武德虔。雷霆七校發，旌旆五營連。", "華省征群乂，霜台舉二賢。豈伊公望遠，曾是茂才遷。", "並秉韜鈐術，兼該翰墨筵。帝思麟閣像，臣獻柏梁篇。", "振玉登遼甸，摐金曆薊壖。度河飛羽檄，橫海泛樓船。", "北伐聲逾邁，東征務以專。講戎喧涿野，料敵靜居延。", "軍勢持三略，兵戎自九天。朝瞻授鉞去，時聽偃戈旋。", "大漠風沙裏，長城雨雪邊。雲端臨碣石，波際隱朝鮮。", "夜壁沖高鬥，寒空駐彩旃。倚弓玄兔月，飲馬白狼川。", "庶物隨交泰，蒼生解倒懸。四郊增氣象，萬里絕風煙。", "關塞鴻勳著，京華甲第全。落梅橫吹後，春色凱歌前。", "直道常兼濟，微才獨棄捐。曳裾誠已矣，投筆尚淒然。", "作賦同元淑，能詩匪仲宣。雲霄不可望，空欲仰神仙。"]'),
('yuding-52','東平旅遊，奉贈薛太守二十四韻','高適','唐','御定全唐诗','yuding','','[]','頌美馳千古，欽賢仰大猷。晉公標逸氣，汾水注長流。',288,'御定全唐詩/json/214.json','["頌美馳千古，欽賢仰大猷。晉公標逸氣，汾水注長流。", "神與公忠節，天生將相儔。青雲本自負，赤縣獨推尤。", "禦史風逾勁，郎官草屢修。鵷鸞粉署起，鷹隼柏台秋。", "出入交三事，飛鳴揖五侯。軍書陳上策，廷議借前籌。", "肅肅趨朝列，雍雍引帝求。一麾俄出守，千里再分憂。", "不改任棠水，仍傳晏子裘。歌謠隨舉扇，旌旆逐鳴騶。", "郡國長河繞，川原大野幽。地連堯泰岳，山向禹青州。", "汶上春帆渡，秦亭晚日愁。遺墟當少昊，懸象逼奎婁。", "即此逢清鑒，終然喜暗投。叨承解榻禮，更得問縑遊。", "高興陪登陟，嘉言忝獻酬。觀棋知戰勝，探象會冥搜。", "眺聽情何限，沖融惠勿休。只應齊語默，寧肯問沉浮。", "然諾長懷季，棲遑輒累丘。平生感知己，方寸豈悠悠。"]'),
('yuding-53','真定即事，奉贈韋使君二十八韻','高適','唐','御定全唐诗','yuding','','[]','飄泊懷書客，遲回此路隅。問津驚棄置，投刺忽踟躕。',336,'御定全唐詩/json/214.json','["飄泊懷書客，遲回此路隅。問津驚棄置，投刺忽踟躕。", "方伯恩彌重，蒼生詠已蘇。郡稱廉叔度，朝議管夷吾。", "乃繼三台側，仍將四嶽俱。江山澄氣象，崖谷倚冰壺。", "詔寵金門策，官榮葉縣鳧。擢才登粉署，飛步躡雲衢。", "起草徵調墨，焚香即宴娛。光華揚盛矣，霄漢在茲乎。", "隱軫推公望，逶迤協帝俞。軒車辭魏闕，旌節副幽都。", "始佩仙郎印，俄兼太守符。尤多蜀郡理，更得潁川謨。", "城邑推雄鎮，山川列簡圖。舊燕當絕漠，全趙對平蕪。", "曠野何彌漫，長亭複鬱紆。始泉遺俗近，活水戰場無。", "月換思鄉陌，星回記鬥樞。歲容歸萬象，和氣發鴻爐。", "淪落而誰遇，棲遑有是夫。不才羞擁腫，幹祿謝侏儒。", "契闊慚行邁，羈離憶友于。田園同季子，儲蓄異陶朱。", "方欲呈高義，吹噓揖大巫。永懷吐肝膽，猶憚阻榮枯。", "解榻情何限，忘言道未殊。從來貴縫掖，應是念窮途。"]'),
('yuding-54','和竇侍禦登涼州七級浮圖之作','高適','唐','御定全唐诗','yuding','','[]','化塔屹中起，孤高宜上躋。鐵冠雄賞眺，金界寵招攜。',72,'御定全唐詩/json/214.json','["化塔屹中起，孤高宜上躋。鐵冠雄賞眺，金界寵招攜。", "空色在軒戶，邊聲連鼓鼙。天寒萬里北，地豁九州西。", "清興揖才彥，峻風和端倪。始知陽春後，具物皆筌蹄。"]'),
('yuding-55','酬河南節度使賀蘭大夫見贈之作','高適','唐','御定全唐诗','yuding','','[]','高閣憑欄檻，中軍倚旆旌。感時常激切，於己即忘情。',144,'御定全唐詩/json/214.json','["高閣憑欄檻，中軍倚旆旌。感時常激切，於己即忘情。", "河華屯妖氣，伊瀍有戰聲。愧無戡難策，多謝出師名。", "秉鉞知恩重，臨戎覺命輕。股肱瞻列岳，唇齒賴長城。", "隱隱摧鋒勢，光光弄印榮。魯連真義士，陸遜豈書生。", "直道甯殊智，先鞭忽抗行。楚雲隨去馬，淮月尚連營。", "撫劍堪投分，悲歌益不平。從來重然諾，況值欲橫行。"]'),
('yuding-56','奉酬睢陽路太守見贈之作','高適','唐','御定全唐诗','yuding','','[]','盛才膺命代，高價動良時。帝簡登藩翰，人和發詠思。',168,'御定全唐詩/json/214.json','["盛才膺命代，高價動良時。帝簡登藩翰，人和發詠思。", "神仙去華省，鵷鷺憶丹墀。清淨能無事，優遊即賦詩。", "江山紛想像，雲物共萎蕤。逸氣劉公幹，玄言向子期。", "多慚汲引速，翻愧激昂遲。相馬知何限，登龍反自疑。", "風塵吏道迫，行邁旅心悲。拙疾徒為爾，窮愁欲問誰。", "秋庭一片葉，朝鏡數莖絲。州縣甘無取，丘園悔莫追。", "瓊瑤生篋笥，光景借茅茨。他日青霄裏，猶應訪所知。"]'),
('yuding-57','奉酬睢陽李太守','高適','唐','御定全唐诗','yuding','','[]','公族稱王佐，朝經允帝求。本枝疆我李，磐石冠諸劉。',384,'御定全唐詩/json/214.json','["公族稱王佐，朝經允帝求。本枝疆我李，磐石冠諸劉。", "禮樂光輝盛，山河氣象幽。系高周柱史，名重晉陽秋。", "華省膺推擇，青雲寵宴遊。握蘭多具美，前席有嘉謀。", "賦得黃金賜，言皆白璧酬。著鞭驅駟馬，操刃解全牛。", "出鎮兼方伯，承家複列侯。朝瞻孔北海，時用杜荊州。", "廣固才登陟，毗陵忽阻修。三台冀入夢，四岳尚分憂。", "郡邑連京口，山川望石頭。海門當建節，江路引鳴騶。", "俗見中興理，人逢至道休。先移白額橫，更息赭衣偷。", "梁國歌來晚，徐方怨不留。豈伊齊政術，將以變澆浮。", "訟簡知能吏，刑寬察要囚。坐堂風偃草，行縣雨隨輈。", "地是蒙莊宅，城遺閼伯丘。孝王餘井徑，微子故田疇。", "冬至招搖轉，天寒螮蝀收。猿岩飛雨雪，兔苑落梧楸。", "列戟霜侵戶，褰幃月在鉤。好賢常解榻，乘興每登樓。", "逸足橫千里，高談注九流。詩題青玉案，衣贈黑貂裘。", "窮巷軒車靜，閑齋耳目愁。未能方管樂，翻欲慕巢由。", "講德良難敵，觀風豈易儔。寸心仍有適，江海一扁舟。"]'),
('yuding-58','送柴司戶充劉卿判官之嶺外','高適','唐','御定全唐诗','yuding','','[]','嶺外資雄鎮，朝端寵節旄。月卿臨幕府，星使出詞曹。',72,'御定全唐詩/json/214.json','["嶺外資雄鎮，朝端寵節旄。月卿臨幕府，星使出詞曹。", "海對羊城闊，山連象郡高。風霜驅瘴癘，忠信涉波濤。", "別恨隨流水，交情脫寶刀。有才無不適，行矣莫徒勞。"]'),
('yuding-59','送蔡少府赴登州推事','高適','唐','御定全唐诗','yuding','','[]','膠東連即墨，萊水入滄溟。國小常多事，人訛屢抵刑。',96,'御定全唐詩/json/214.json','["膠東連即墨，萊水入滄溟。國小常多事，人訛屢抵刑。", "公才征郡邑，詔使出郊坰。標格誰當犯，風謠信可聽。", "崢嶸大峴口，邐迤汶陽亭。地迥雲偏白，天秋山更青。", "祖筵方卜晝，王事急侵星。勸爾將為德，斯言蓋有聽。"]'),
('yuding-60','秦中送李九赴越','高適','唐','御定全唐诗','yuding','','[]','攜手望千里，於今將十年。如何每離別，心事複迍邅。',96,'御定全唐詩/json/214.json','["攜手望千里，於今將十年。如何每離別，心事複迍邅。", "適越雖有以，出關終耿然。愁霖不可向，長路或難前。", "吳會獨行客，山陰秋夜船。謝家征故事，禹穴訪遺編。", "鏡水君所憶，蓴羹餘舊便。歸來莫忘此，兼示濟江篇。"]'),
('yuding-61','餞宋八充彭中丞判官之嶺南','高適','唐','御定全唐诗','yuding','','[]','睹君濟時略，使我氣填膺。長策竟不用，高才徒見稱。',192,'御定全唐詩/json/214.json','["睹君濟時略，使我氣填膺。長策竟不用，高才徒見稱。", "一朝知己達，累日詔書征。羽翮忽然就，風飆誰敢淩。", "舉鞭趨嶺嶠，屈指冒炎蒸。北雁送馳驛，南人思飲冰。", "彼邦本倔強，習俗多驕矜。翠羽幹平法，黃金撓直繩。", "若將除害馬，慎勿信蒼蠅。魑魅甯無患，忠貞適有憑。", "猿啼山不斷，鳶跕路難登。海岸出交趾，江城連始興。", "繡衣當節制，幕府盛威棱。勿憚九嶷險，須令百越澄。", "立談多感激，行李即嚴凝。離別胡為者，雲霄遲爾升。"]'),
('yuding-62','陪竇侍禦泛靈雲池','高適','唐','御定全唐诗','yuding','','[]','白露時先降，清川思不窮。江湖仍塞上，舟楫在軍中。',72,'御定全唐詩/json/214.json','["白露時先降，清川思不窮。江湖仍塞上，舟楫在軍中。", "舞換臨津樹，歌饒向迥風。夕陽連積水，邊色滿秋空。", "乘興宜投轄，邀歡莫避驄。誰憐持弱羽，猶欲伴鵷鴻。"]'),
('yuding-63','陪竇侍禦靈雲南亭宴，詩得雷字','高適','唐','御定全唐诗','yuding','','[]','人幽宜眺聽，目極喜亭台。風景知愁在，關山憶夢回。',96,'御定全唐詩/json/214.json','["人幽宜眺聽，目極喜亭台。風景知愁在，關山憶夢回。", "只言殊語默，何意忝遊陪。連唱波瀾動，冥搜物象開。", "新秋歸遠樹，殘雨擁輕雷。簷外長天盡，尊前獨鳥來。", "常吟塞下曲，多謝幕中才。河漢徒相望，嘉期安在哉。"]'),
('yuding-64','同熊少府題盧主簿茅齋','高適','唐','御定全唐诗','yuding','','[]','虛院野情在，茅齋秋興存。孝廉趨下位，才子出高門。',72,'御定全唐詩/json/214.json','["虛院野情在，茅齋秋興存。孝廉趨下位，才子出高門。", "乃繼幽人靜，能令學者尊。江山歸謝客，神鬼下劉根。", "階樹時攀折，窗書任討論。自堪成獨往，何必武陵源。"]'),
('yuding-65','同朱五題盧使君義井','高適','唐','御定全唐诗','yuding','','[]','高義唯良牧，深仁自下車。寧知鑿井處，還是飲冰餘。',72,'御定全唐詩/json/214.json','["高義唯良牧，深仁自下車。寧知鑿井處，還是飲冰餘。", "地即泉源久，人當汲引初。體清能鑒物，色洞每含虛。", "上善滋來往，中和浹裏閭。濟時應未竭，懷惠複何如。"]'),
('yuding-66','同郭十題楊主簿新廳','高適','唐','御定全唐诗','yuding','','[]','華館曙沉沉，惟良正在今。用材兼柱石，聞物象高深。',72,'御定全唐詩/json/214.json','["華館曙沉沉，惟良正在今。用材兼柱石，聞物象高深。", "更得芝蘭地，兼營枳棘林。向風扃戟戶，當署近棠陰。", "勿改安卑節，聊閑理劇心。多君有知己，一和郢中吟。"]'),
('yuding-67','秋日作','高適','唐','御定全唐诗','yuding','','[]','端居值秋節，此日更愁辛。寂寞無一事，蒿萊通四鄰。',72,'御定全唐詩/json/214.json','["端居值秋節，此日更愁辛。寂寞無一事，蒿萊通四鄰。", "閉門生白髮，回首憶青春。歲月不相待，交遊隨眾人。", "雲霄何處托，愚直有誰親。舉酒聊自勸，窮通信爾身。"]'),
('yuding-68','辟陽城','高適','唐','御定全唐诗','yuding','','[]','荒城在高岸，淩眺俯清淇。傳道漢天子，而封審食其。',72,'御定全唐詩/json/214.json','["荒城在高岸，淩眺俯清淇。傳道漢天子，而封審食其。", "姦淫且不戮，茅土孰雲宜。何得英雄主，返令兒女欺。", "母儀良已失，臣節豈如斯。太息一朝事，乃令人所嗤。"]'),
('yuding-69','赴彭州山行之作','高適','唐','御定全唐诗','yuding','','[]','峭壁連崆峒，攢峰疊翠微。鳥聲堪駐馬，林色可忘機。',72,'御定全唐詩/json/214.json','["峭壁連崆峒，攢峰疊翠微。鳥聲堪駐馬，林色可忘機。", "怪石時侵徑，輕蘿乍拂衣。路長愁作客，年老更思歸。", "且悅岩巒勝，寧嗟意緒違。山行應未盡，誰與玩芳菲。"]'),
('yuding-70','詠史','高適','唐','御定全唐诗','yuding','','[]','尚有綈袍贈，應憐范叔寒。不知天下士，猶作布衣看。',24,'御定全唐詩/json/214.json','["尚有綈袍贈，應憐范叔寒。不知天下士，猶作布衣看。"]'),
('yuding-71','送兵到薊北','高適','唐','御定全唐诗','yuding','','[]','積雪與天迥，屯軍連塞愁。誰知此行邁，不為覓封侯。',24,'御定全唐詩/json/214.json','["積雪與天迥，屯軍連塞愁。誰知此行邁，不為覓封侯。"]'),
('yuding-72','同群公題張處士菜園','高適','唐','御定全唐诗','yuding','','[]','耕地桑柘間，地肥菜常熟。為問葵藿資，何如廟堂肉。',24,'御定全唐詩/json/214.json','["耕地桑柘間，地肥菜常熟。為問葵藿資，何如廟堂肉。"]'),
('yuding-73','逢謝偃','高適','唐','御定全唐诗','yuding','','[]','紅顏愴為別，白髮始相逢。唯餘昔時淚，無復舊時容。',24,'御定全唐詩/json/214.json','["紅顏愴為別，白髮始相逢。唯餘昔時淚，無復舊時容。"]'),
('yuding-74','田家春望','高適','唐','御定全唐诗','yuding','','[]','出門何所見，春色滿平蕪。可歎無知己，高陽一酒徒。',24,'御定全唐詩/json/214.json','["出門何所見，春色滿平蕪。可歎無知己，高陽一酒徒。"]'),
('yuding-75','閒居','高適','唐','御定全唐诗','yuding','','[]','柳色驚心事，春風厭索居。方知一杯酒，猶勝百家書。',24,'御定全唐詩/json/214.json','["柳色驚心事，春風厭索居。方知一杯酒，猶勝百家書。"]'),
('yuding-76','封丘作','高適','唐','御定全唐诗','yuding','','[]','州縣才難適，雲山道欲窮。揣摩慚黠吏，棲隱謝愚公。',24,'御定全唐詩/json/214.json','["州縣才難適，雲山道欲窮。揣摩慚黠吏，棲隱謝愚公。"]'),
('yuding-77','九曲詞三首','高適','唐','御定全唐诗','yuding','','[]','許國從來徹廟堂，連年不為在疆場。',96,'御定全唐詩/json/214.json','["許國從來徹廟堂，連年不為在疆場。", "將軍天上封侯印，禦史臺上異姓王。", "萬騎爭歌楊柳春，千場對舞繡騏驎。", "到處盡逢歡洽事，相看總是太平人。", "鐵騎橫行鐵嶺頭，西看邏逤取封侯。", "青海只今將飲馬，黃河不用更防秋。"]'),
('yuding-78','營州歌','高適','唐','御定全唐诗','yuding','','[]','營州少年厭原野，狐裘蒙茸獵城下。',32,'御定全唐詩/json/214.json','["營州少年厭原野，狐裘蒙茸獵城下。", "虜酒千鐘不醉人，胡兒十歲能騎馬。"]'),
('yuding-79','玉真公主歌','高適','唐','御定全唐诗','yuding','','[]','常言龍德本天仙，誰謂仙人每學仙。',64,'御定全唐詩/json/214.json','["常言龍德本天仙，誰謂仙人每學仙。", "更道玄元指李日，多於王母種桃年。", "仙宮仙府有真仙，天寶天仙秘莫傳。", "為問軒皇三百歲，何如大道一千年。"]'),
('yuding-80','和王七玉門關聽吹笛','高適','唐','御定全唐诗','yuding','','[]','胡人吹笛戍樓間，樓上蕭條海月閑。',32,'御定全唐詩/json/214.json','["胡人吹笛戍樓間，樓上蕭條海月閑。", "借問落梅凡幾曲，從風一夜滿關山。"]'),
('yuding-81','別董大二首','高適','唐','御定全唐诗','yuding','','[]','十裏黃雲白日曛，北風吹雁雪紛紛。',64,'御定全唐詩/json/214.json','["十裏黃雲白日曛，北風吹雁雪紛紛。", "莫愁前路無知己，天下誰人不識君。", "六翮飄颻私自憐，一離京洛十餘年。", "丈夫貧踐應未足，今日相逢無酒錢。"]'),
('yuding-82','送桂陽孝廉','高適','唐','御定全唐诗','yuding','','[]','桂陽年少西入秦，數經甲科猶白身。',32,'御定全唐詩/json/214.json','["桂陽年少西入秦，數經甲科猶白身。", "即今江海一歸客，他日雲霄萬里人。"]'),
('yuding-83','送李少府，時在客舍作','高適','唐','御定全唐诗','yuding','','[]','相逢旅館意多違，暮雪初晴候雁飛。',32,'御定全唐詩/json/214.json','["相逢旅館意多違，暮雪初晴候雁飛。", "主人酒盡君未醉，薄暮途遙歸不歸。"]'),
('yuding-84','聽張立本女吟','高適','唐','御定全唐诗','yuding','','[]','危冠廣袖楚宮妝，獨步閒庭逐夜涼。',32,'御定全唐詩/json/214.json','["危冠廣袖楚宮妝，獨步閒庭逐夜涼。", "自把玉釵敲砌竹，清歌一曲月如霜。"]'),
('yuding-85','初至封丘作','高適','唐','御定全唐诗','yuding','','[]','可憐薄暮宦遊子，獨臥虛齋思無已。',32,'御定全唐詩/json/214.json','["可憐薄暮宦遊子，獨臥虛齋思無已。", "去家百里不得歸，到官數日秋風起。"]'),
('yuding-86','除夜作','高適','唐','御定全唐诗','yuding','','[]','旅館寒燈獨不眠，客心何事轉淒然。',32,'御定全唐詩/json/214.json','["旅館寒燈獨不眠，客心何事轉淒然。", "故鄉今夜思千里，愁鬢明朝又一年。"]'),
('yuding-0','劍池','李峴','唐','御定全唐诗','yuding','','[]','闔閭葬日勞人力，嬴政穿來役鬼功。',32,'御定全唐詩/json/215.json','["闔閭葬日勞人力，嬴政穿來役鬼功。", "澄碧尚疑神物在，等閒雷雨起潭中。"]'),
('yuding-1','張公洞','李棲筠','唐','御定全唐诗','yuding','','[]','一徑深窈窕，上升翠微中。忽然靈洞前，日月開仙宮。',132,'御定全唐詩/json/215.json','["一徑深窈窕，上升翠微中。忽然靈洞前，日月開仙宮。", "道士十二人，往還馭清風。焚香入深洞，巨石如虛空。", "夙夜備蘋藻，詔書祠張公。五雲何裴回，玄鶴下蒼穹。", "我本道門子，願言出塵籠。掃除方寸間，幾與神靈通。", "宿昔勤夢想，契之在深衷。遲回將不還，章綬系我躬。", "稽首謝真侶，辭滿歸崆峒。"]'),
('yuding-2','投宋大夫','李棲筠','唐','御定全唐诗','yuding','','[]','十處投人九處違，家鄉萬里又空歸。',32,'御定全唐詩/json/215.json','["十處投人九處違，家鄉萬里又空歸。", "嚴霜昨夜侵人骨，誰念高堂未授衣。"]'),
('yuding-3','寶林寺作','徐浩','唐','御定全唐诗','yuding','','[]','茲山昔飛來，遠自琅琊台。孤岫龜形在，深泉鰻井開。',156,'御定全唐詩/json/215.json','["茲山昔飛來，遠自琅琊台。孤岫龜形在，深泉鰻井開。", "越王屢登陟，何相傳詞才。塔廟崇其巔，規模稱壯哉。", "禪堂清溽潤，高閣無恢炱。照耀珠吐月，鏗轟鐘隱雷。", "揆餘久纓弁，末路遭邅回。一棄滄海曲，六年稽嶺隈。", "逝川惜東駛，馳景憐西頹。腰帶愁疾減，容顏衰悴催。", "賴居茲寺中，法士多瑰能。洗心聽經論，禮足蠲凶災。", "永願依勝侶，清江乘度杯。"]'),
('yuding-4','謁禹廟','徐浩','唐','御定全唐诗','yuding','','[]','畝澮敷四海，川源滌九州。既膺九命錫，乃建洪範疇。',240,'御定全唐詩/json/215.json','["畝澮敷四海，川源滌九州。既膺九命錫，乃建洪範疇。", "鼎革固天啟，運興匪人謀。肇開宅土業，永庇昏墊憂。", "山足靈廟在，門前清鏡流。象筵陳玉帛，容衛儼戈矛。", "探穴圖書朽，卑宮堂殿修。梅梁今不壞，松祏古仍留。", "負責故鄉近，朅來申俎羞。為魚知造化，歎鳳仰徽猷。", "不復聞夏樂，唯餘奏楚幽。婆娑非舞羽，鏜鞳異鳴球。", "盛德吾無間，高功誰與儔。災淫破凶慝，祚聖擁神休。", "出谷鶯初語，空山猿獨愁。春暉生草樹，柳色暖汀州。", "恩貸題輿重，榮殊衣錦遊。宦情同械系，生理任桴浮。", "地極臨滄海，天遙過鬥牛。精誠如可諒，他日寄冥搜。"]'),
('yuding-5','自悼','薛令之','唐','御定全唐诗','yuding','','[]','朝日上團團，照見先生盤。盤中何所有，苜蓿長闌幹。',48,'御定全唐詩/json/215.json','["朝日上團團，照見先生盤。盤中何所有，苜蓿長闌幹。", "飯澀匙難綰，羹稀箸易寬。只可謀朝夕，何由保歲寒。"]'),
('yuding-6','靈岩寺','薛令之','唐','御定全唐诗','yuding','','[]','草堂棲在靈山谷，勤苦詩書向燈燭。',32,'御定全唐詩/json/215.json','["草堂棲在靈山谷，勤苦詩書向燈燭。", "柴門半掩寂無人，惟有白雲相伴宿。"]'),
('yuding-7','湘夫人','鄒紹先','唐','御定全唐诗','yuding','','[]','楓葉下秋渚，二妃愁渡湘。疑山空杳藹，何處望君王。',36,'御定全唐詩/json/215.json','["楓葉下秋渚，二妃愁渡湘。疑山空杳藹，何處望君王。", "日落水雲裏，悠悠心自傷。"]'),
('yuding-8','寄妻父劉長卿','李穆','唐','御定全唐诗','yuding','','[]','處處雲山無盡時，桐廬南望轉參差。',32,'御定全唐詩/json/215.json','["處處雲山無盡時，桐廬南望轉參差。", "舟人莫道新安近，欲上潺湲行自遲。"]'),
('yuding-9','短歌行','馮著','唐','御定全唐诗','yuding','','[]','寂寞草中蘭，亭亭山上松。貞芳日有分，生長耐相容。',60,'御定全唐詩/json/215.json','["寂寞草中蘭，亭亭山上松。貞芳日有分，生長耐相容。", "結根各得地，幸沾雨露功。參辰無停泊，且顧一西東。", "君但開懷抱，猜恨莫匆匆。"]'),
('yuding-10','洛陽道','馮著','唐','御定全唐诗','yuding','','[]','洛陽宮中花柳春，洛陽道上無行人。皮裘氈帳不相識，',64,'御定全唐詩/json/215.json','["洛陽宮中花柳春，洛陽道上無行人。皮裘氈帳不相識，", "春雨灑，春雨灑，周南一望堪淚下。蓬萊殿中寢胡人，", "天津橋上多胡塵，洛陽道上愁殺人。"]'),
('yuding-11','行路難','馮著','唐','御定全唐诗','yuding','','[]','男兒轗軻徒搔首，入市脫衣且沽酒。行路難，',20,'御定全唐詩/json/215.json','["男兒轗軻徒搔首，入市脫衣且沽酒。行路難，"]'),
('yuding-12','燕銜泥','馮著','唐','御定全唐诗','yuding','','[]','雙燕碌碌飛入屋，屋中老人喜燕歸，裴回繞我床頭飛。',65,'御定全唐詩/json/215.json','["雙燕碌碌飛入屋，屋中老人喜燕歸，裴回繞我床頭飛。", "去年為爾逐黃雀，雨多屋漏泥土落。爾莫厭老翁茅屋低，", "井旁寫水泥自足，銜泥上屋隨爾欲。"]'),
('yuding-13','同孟浩然宴賦','王迥','唐','御定全唐诗','yuding','','[]','屈宋英聲今止已，江山繼嗣多才子。作者於今盡相似，',24,'御定全唐詩/json/215.json','["屈宋英聲今止已，江山繼嗣多才子。作者於今盡相似，"]'),
('yuding-14','尚書都堂瓦松','李曄2','唐','御定全唐诗','yuding','','[]','華省秘仙蹤，高堂露瓦松。葉因春後長，花為雨來濃。',72,'御定全唐詩/json/215.json','["華省秘仙蹤，高堂露瓦松。葉因春後長，花為雨來濃。", "影混鴛鴦色，光含翡翠容。天然斯所寄，地勢太無從。", "接棟臨雙闕，連甍近九重。寧知深澗底，霜雪歲兼封。"]'),
('yuding-15','省試七月流火','敬括','唐','御定全唐诗','yuding','','[]','前庭一葉下，言念忽悲秋。變節金初至，分寒火正流。',72,'御定全唐詩/json/215.json','["前庭一葉下，言念忽悲秋。變節金初至，分寒火正流。", "氣含涼夜早，光拂夏雲收。助月微明散，沿河麗景浮。", "禮標時令爽，詩興國風幽。自此觀邦正，深知王業休。"]'),
('yuding-0','奉贈韋左丞丈二十二韻','杜甫','唐','御定全唐诗','yuding','','[]','紈袴不餓死，儒冠多誤身。丈人試靜聽，賤子請具陳。',264,'御定全唐詩/json/216.json','["紈袴不餓死，儒冠多誤身。丈人試靜聽，賤子請具陳。", "甫昔少年日，早充觀國賓。讀書破萬卷，下筆如有神。", "賦料揚雄敵，詩看子建親。李邕求識面，王翰願卜鄰。", "自謂頗挺出，立登要路津。致君堯舜上，再使風俗淳。", "此意竟蕭條，行歌非隱淪。騎驢三十載，旅食京華春。", "朝扣富兒門，暮隨肥馬塵。殘杯與冷炙，到處潛悲辛。", "主上頃見征，欻然欲求伸。青冥卻垂翅，蹭蹬無縱鱗。", "甚愧丈人厚，甚知丈人真。每於百僚上，猥誦佳句新。", "竊效貢公喜，難甘原憲貧。焉能心怏怏，只是走踆踆。", "今欲東入海，即將西去秦。尚憐終南山，回首清渭濱。", "常擬報一飯，況懷辭大臣。白鷗沒浩蕩，萬里誰能馴。"]'),
('yuding-1','送高三十五書記','杜甫','唐','御定全唐诗','yuding','','[]','崆峒小麥熟，且願休王師。請公問主將，焉用窮荒為。',192,'御定全唐詩/json/216.json','["崆峒小麥熟，且願休王師。請公問主將，焉用窮荒為。", "饑鷹未飽肉，側翅隨人飛。高生跨鞍馬，有似幽並兒。", "脫身簿尉中，始與捶楚辭。借問今何官，觸熱向武威。", "答雲一書記，所愧國士知。人實不易知，更須慎其儀。", "十年出幕府，自可持旌麾。此行既特達，足以慰所思。", "男兒功名遂，亦在老大時。常恨結歡淺，各在天一涯。", "又如參與商，慘慘中腸悲。驚風吹鴻鵠，不得相追隨。", "黃塵翳沙漠，念子何當歸。邊城有餘力，早寄從軍詩。"]'),
('yuding-2','贈李白','杜甫','唐','御定全唐诗','yuding','','[]','二年客東都，所曆厭機巧。野人對膻腥，蔬食常不飽。',72,'御定全唐詩/json/216.json','["二年客東都，所曆厭機巧。野人對膻腥，蔬食常不飽。", "豈無青精飯，使我顏色好。苦乏大藥資，山林跡如掃。", "李侯金閨彥，脫身事幽討。亦有梁宋游，方期拾瑤草。"]'),
('yuding-3','游龍門奉先寺','杜甫','唐','御定全唐诗','yuding','','[]','已從招提遊，更宿招提境。陰壑生虛籟，月林散清影。',48,'御定全唐詩/json/216.json','["已從招提遊，更宿招提境。陰壑生虛籟，月林散清影。", "天闕象緯逼，雲臥衣裳冷。欲覺聞晨鐘，令人發深省。"]'),
('yuding-4','望岳','杜甫','唐','御定全唐诗','yuding','','[]','岱宗夫如何，齊魯青未了。造化鐘神秀，陰陽割昏曉。',48,'御定全唐詩/json/216.json','["岱宗夫如何，齊魯青未了。造化鐘神秀，陰陽割昏曉。", "蕩胸生曾雲，決眥入歸鳥。會當淩絕頂，一覽眾山小。"]'),
('yuding-5','陪李北海宴曆下亭','杜甫','唐','御定全唐诗','yuding','','[]','東藩駐皂蓋，北渚淩青荷。海內此亭古，濟南名士多。',72,'御定全唐詩/json/216.json','["東藩駐皂蓋，北渚淩青荷。海內此亭古，濟南名士多。", "雲山已發興，玉佩仍當歌。修竹不受暑，交流空湧波。", "蘊真愜所遇，落日將如何。貴賤俱物役，從公難重過。"]'),
('yuding-6','同李太守登曆下古城員外新亭，亭對鵲湖','杜甫','唐','御定全唐诗','yuding','','[]','新亭結構罷，隱見清湖陰。跡籍台觀舊，氣溟海嶽深。',72,'御定全唐詩/json/216.json','["新亭結構罷，隱見清湖陰。跡籍台觀舊，氣溟海嶽深。", "圓荷想自昔，遺堞感至今。芳宴此時具，哀絲千古心。", "主稱壽尊客，筵秩宴北林。不阻蓬蓽興，得兼梁甫吟。"]'),
('yuding-7','玄都壇歌，寄元逸人','杜甫','唐','御定全唐诗','yuding','','[]','故人昔隱東蒙峰，已佩含景蒼精龍。故人今居子午穀，',48,'御定全唐詩/json/216.json','["故人昔隱東蒙峰，已佩含景蒼精龍。故人今居子午穀，", "子規夜啼山竹裂，王母晝下雲旗翻。知君此計成長往，"]'),
('yuding-8','今夕行','杜甫','唐','御定全唐诗','yuding','','[]','今夕何夕歲雲徂，更長燭明不可孤。咸陽客舍一事無，',59,'御定全唐詩/json/216.json','["今夕何夕歲雲徂，更長燭明不可孤。咸陽客舍一事無，", "英雄有時亦如此，邂逅豈即非良圖。", "君莫笑劉毅從來布衣願，家無儋石輸百萬。"]'),
('yuding-9','貧交行','杜甫','唐','御定全唐诗','yuding','','[]','翻手作雲覆手雨，紛紛輕薄何須數。君不見管鮑貧時交，',25,'御定全唐詩/json/216.json','["翻手作雲覆手雨，紛紛輕薄何須數。君不見管鮑貧時交，"]'),
('yuding-10','兵車行','杜甫','唐','御定全唐诗','yuding','','[]','車轔轔，馬蕭蕭，行人弓箭各在腰。耶娘妻子走相送，',167,'御定全唐詩/json/216.json','["車轔轔，馬蕭蕭，行人弓箭各在腰。耶娘妻子走相送，", "道傍過者問行人，行人但云點行頻。或從十五北防河，", "邊亭流血成海水，武皇開邊意未已。", "君不聞漢家山東二百州，千村萬落生荊杞。", "縱有健婦把鋤犁，禾生隴畝無東西。況復秦兵耐苦戰，", "且如今年冬，未休關西卒。縣官急索租，租稅從何出。", "信知生男惡，反是生女好。生女猶是嫁比鄰，", "新鬼煩冤舊鬼哭，天陰雨濕聲啾啾。"]'),
('yuding-11','高都護驄馬行','杜甫','唐','御定全唐诗','yuding','','[]','安西都護胡青驄，聲價欻然來向東。此馬臨陣久無敵，',72,'御定全唐詩/json/216.json','["安西都護胡青驄，聲價欻然來向東。此馬臨陣久無敵，", "雄姿未受伏櫪恩，猛氣猶思戰場利。腕促蹄高如踣鐵，", "長安壯兒不敢騎，走過掣電傾城知。青絲絡頭為君老，"]'),
('yuding-12','天育驃騎歌','杜甫','唐','御定全唐诗','yuding','','[]','吾聞天子之馬走千里，今之畫圖無乃是。',90,'御定全唐詩/json/216.json','["吾聞天子之馬走千里，今之畫圖無乃是。", "是何意態雄且傑，駿尾蕭梢朔風起。毛為綠縹兩耳黃，", "伊昔太僕張景順，監牧攻駒閱清峻。遂令大奴守天育，", "故獨寫真傳世人，見之座右久更新。年多物化空形影，"]'),
('yuding-13','白絲行','杜甫','唐','御定全唐诗','yuding','','[]','繅絲須長不須白，越羅蜀錦金粟尺。象床玉手亂殷紅，',73,'御定全唐詩/json/216.json','["繅絲須長不須白，越羅蜀錦金粟尺。象床玉手亂殷紅，", "美人細意熨帖平，裁縫滅盡針線跡。春天衣著為君舞，", "香汗輕塵汙顏色，開新合故置何許。君不見才士汲引難，"]'),
('yuding-14','秋雨歎三首','杜甫','唐','御定全唐诗','yuding','','[]','雨中百草秋爛死，階下決明顏色鮮。著葉滿枝翠羽蓋，',120,'御定全唐詩/json/216.json','["雨中百草秋爛死，階下決明顏色鮮。著葉滿枝翠羽蓋，", "堂上書生空白頭，臨風三嗅馨香泣。", "闌風長雨秋紛紛，四海八荒同一雲。去馬來牛不復辨，", "城中斗米換衾裯，相許寧論兩相直。", "長安布衣誰比數，反鎖衡門守環堵。老夫不出長蓬蒿，", "秋來未曾見白日，泥汙後土何時幹。"]'),
('yuding-15','歎庭前甘菊花','杜甫','唐','御定全唐诗','yuding','','[]','簷前甘菊移時晚，青蕊重陽不堪摘。明日蕭條醉盡醒，',40,'御定全唐詩/json/216.json','["簷前甘菊移時晚，青蕊重陽不堪摘。明日蕭條醉盡醒，", "念茲空長大枝葉，結根失所纏風霜。"]'),
('yuding-16','醉時歌','杜甫','唐','御定全唐诗','yuding','','[]','諸公袞袞登臺省，廣文先生官獨冷。甲第紛紛厭粱肉，',120,'御定全唐詩/json/216.json','["諸公袞袞登臺省，廣文先生官獨冷。甲第紛紛厭粱肉，", "德尊一代常轗軻，名垂萬古知何用。杜陵野客人更嗤，", "得錢即相覓，沽酒不復疑。忘形到爾汝，痛飲真吾師。", "清夜沉沉動春酌，燈前細雨簷花落。但覺高歌有鬼神，", "先生早賦歸去來，石田茅屋荒蒼苔。儒術于我何有哉，"]'),
('yuding-17','醉歌行','杜甫','唐','御定全唐诗','yuding','','[]','陸機二十作文賦，汝更小年能綴文。總角草書又神速，',96,'御定全唐詩/json/216.json','["陸機二十作文賦，汝更小年能綴文。總角草書又神速，", "詞源倒流三峽水，筆陣獨掃千人軍。只今年才十六七，", "偶然擢秀非難取，會是排風有毛質。汝身已見唾成珠，", "風吹客衣日杲杲，樹攪離思花冥冥。酒盡沙頭雙玉瓶，"]'),
('yuding-18','贈衛八處士','杜甫','唐','御定全唐诗','yuding','','[]','人生不相見，動如參與商。今夕複何夕，共此燈燭光。',144,'御定全唐詩/json/216.json','["人生不相見，動如參與商。今夕複何夕，共此燈燭光。", "少壯能幾時，鬢髮各已蒼。訪舊半為鬼，驚呼熱中腸。", "焉知二十載，重上君子堂。昔別君未婚，兒女忽成行。", "怡然敬父執，問我來何方。問答乃未已，兒女羅酒漿。", "夜雨翦春韭，新炊間黃粱。主稱會面難，一舉累十觴。", "十觴亦不醉，感子故意長。明日隔山嶽，世事兩茫茫。"]'),
('yuding-19','苦雨奉寄隴西公兼呈王征士','杜甫','唐','御定全唐诗','yuding','','[]','今秋乃淫雨，仲月來寒風。群木水光下，萬象雲氣中。',144,'御定全唐詩/json/216.json','["今秋乃淫雨，仲月來寒風。群木水光下，萬象雲氣中。", "所思礙行潦，九裏信不通。悄悄素滻路，迢迢天漢東。", "願騰六尺馬，背若孤征鴻。劃見公子面，超然歡笑同。", "奮飛既胡越，局促傷樊籠。一飯四五起，憑軒心力窮。", "嘉蔬沒混濁，時菊碎榛叢。鷹隼亦屈猛，烏鳶何所蒙。", "式瞻北鄰居，取適南巷翁。掛席釣川漲，焉知清興終。"]'),
('yuding-20','同諸公登慈恩寺塔','杜甫','唐','御定全唐诗','yuding','','[]','高標跨蒼天，烈風無時休。自非曠士懷，登茲翻百憂。',144,'御定全唐詩/json/216.json','["高標跨蒼天，烈風無時休。自非曠士懷，登茲翻百憂。", "方知象教力，足可追冥搜。仰穿龍蛇窟，始出枝撐幽。", "七星在北戶，河漢聲西流。羲和鞭白日，少昊行清秋。", "秦山忽破碎，涇渭不可求。俯視但一氣，焉能辨皇州。", "回首叫虞舜，蒼梧雲正愁。惜哉瑤池飲，日晏昆侖丘。", "黃鵠去不息，哀鳴何所投。君看隨陽雁，各有稻粱謀。"]'),
('yuding-21','示從孫濟','杜甫','唐','御定全唐诗','yuding','','[]','平明跨驢出，未知適誰門。權門多噂eR，且複尋諸孫。',133,'御定全唐詩/json/216.json','["平明跨驢出，未知適誰門。權門多噂eR，且複尋諸孫。", "諸孫貧無事，宅舍如荒村。堂前自生竹，堂後自生萱。", "萱草秋已死，竹枝霜不蕃。淘米少汲水，汲多井水渾。", "刈葵莫放手，放手傷葵根。阿翁懶惰久，覺兒行步奔。", "所來為宗族，亦不為盤飧。小人利口實，薄俗難可論。", "勿受外嫌猜，同姓古所敦。"]'),
('yuding-22','九日寄岑參','杜甫','唐','御定全唐诗','yuding','','[]','出門複入門，兩腳但如舊。所向泥活活，思君令人瘦。',144,'御定全唐詩/json/216.json','["出門複入門，兩腳但如舊。所向泥活活，思君令人瘦。", "沉吟坐西軒，飲食錯昏晝。寸步曲江頭，難為一相就。", "籲嗟呼蒼生，稼穡不可救。安得誅雲師，疇能補天漏。", "大明韜日月，曠野號禽獸。君子強逶迤，小人困馳驟。", "維南有崇山，恐與川浸溜。是節東籬菊，紛披為誰秀。", "岑生多新詩，性亦嗜醇酎。采采黃金花，何由滿衣袖。"]'),
('yuding-23','送孔巢父謝病歸游江東，兼呈李白','杜甫','唐','御定全唐诗','yuding','','[]','巢父掉頭不肯住，東將入海隨煙霧。詩卷長留天地間，',72,'御定全唐詩/json/216.json','["巢父掉頭不肯住，東將入海隨煙霧。詩卷長留天地間，", "蓬萊織女回雲車，指點虛無是征路。自是君身有仙骨，", "蔡侯靜者意有餘，清夜置酒臨前除。罷琴惆悵月照席，"]'),
('yuding-24','飲中八仙歌','杜甫','唐','御定全唐诗','yuding','','[]','知章騎馬似乘船，眼花落井水底眠。汝陽三鬥始朝天，',48,'御定全唐詩/json/216.json','["知章騎馬似乘船，眼花落井水底眠。汝陽三鬥始朝天，", "天子呼來不上船，自稱臣是酒中仙。張旭三杯草聖傳，"]'),
('yuding-25','曲江三章，章五句','杜甫','唐','御定全唐诗','yuding','','[]','曲江蕭條秋氣高，菱荷枯折隨風濤，遊子空嗟垂二毛。',120,'御定全唐詩/json/216.json','["曲江蕭條秋氣高，菱荷枯折隨風濤，遊子空嗟垂二毛。", "白石素沙亦相蕩，哀鴻獨叫求其曹。", "即事非今亦非古，長歌激越梢林莽，比屋豪華固難數。", "吾人甘作心似灰，弟侄何傷淚如雨。", "自斷此生休問天，杜曲幸有桑麻田，故將移住南山邊。", "短衣匹馬隨李廣，看射猛虎終殘年。"]'),
('yuding-26','麗人行','杜甫','唐','御定全唐诗','yuding','','[]','三月三日天氣新，長安水邊多麗人。態濃意遠淑且真，',109,'御定全唐詩/json/216.json','["三月三日天氣新，長安水邊多麗人。態濃意遠淑且真，", "頭上何所有，翠微zc葉垂鬢唇。背後何所見，", "紫駝之峰出翠釜，水精之盤行素鱗。犀箸厭飫久未下，", "簫鼓哀吟感鬼神，賓從雜遝實要津。後來鞍馬何逡巡，", "炙手可熱勢絕倫，慎莫近前丞相嗔。"]'),
('yuding-27','樂遊園歌','杜甫','唐','御定全唐诗','yuding','','[]','樂游古園崒森爽，煙綿碧草萋萋長。公子華筵勢最高，',88,'御定全唐詩/json/216.json','["樂游古園崒森爽，煙綿碧草萋萋長。公子華筵勢最高，", "青春波浪芙蓉園，白日雷霆夾城仗。閶闔晴開昳蕩蕩，", "卻憶年年人醉時，只今未醉已先悲。數莖白髮那拋得，", "此身飲罷無歸處，獨立蒼茫自詠詩。"]'),
('yuding-28','渼陂行','杜甫','唐','御定全唐诗','yuding','','[]','岑參兄弟皆好奇，攜我遠來遊渼陂。天地黤慘忽異色，',120,'御定全唐詩/json/216.json','["岑參兄弟皆好奇，攜我遠來遊渼陂。天地黤慘忽異色，", "鼉作鯨吞不復知，惡風白浪何嗟及。主人錦帆相為開，", "沈竿續蔓深莫測，菱葉荷花靜如拭。宛在中流渤澥清，", "船舷暝戛雲際寺，水面月出藍田關。此時驪龍亦吐珠，", "咫尺但愁雷雨至，蒼茫不曉神靈意。少壯幾時奈老何，"]'),
('yuding-29','渼陂西南台','杜甫','唐','御定全唐诗','yuding','','[]','高臺面蒼陂，六月風日冷。蒹葭離披去，天水相與永。',144,'御定全唐詩/json/216.json','["高臺面蒼陂，六月風日冷。蒹葭離披去，天水相與永。", "懷新目似擊，接要心已領。仿像識鮫人，空蒙辨魚艇。", "錯磨終南翠，顛倒白閣影。崷崒增光輝，乘陵惜俄頃。", "勞生愧嚴鄭，外物慕張邴。世複輕驊騮，吾甘雜蛙黽。", "知歸俗可忽，取適事莫並。身退豈待官，老來苦便靜。", "況資菱芡足，庶結茅茨迥。從此具扁舟，彌年逐清景。"]'),
('yuding-30','戲簡鄭廣文虔，兼呈蘇司業源明','杜甫','唐','御定全唐诗','yuding','','[]','廣文到官舍，系馬堂階下。醉則騎馬歸，頗遭官長罵。',48,'御定全唐詩/json/216.json','["廣文到官舍，系馬堂階下。醉則騎馬歸，頗遭官長罵。", "才名四十年，坐客寒無氈。賴有蘇司業，時時與酒錢。"]'),
('yuding-31','夏日李公見訪','杜甫','唐','御定全唐诗','yuding','','[]','遠林暑氣薄，公子過我游。貧居類村塢，僻近城南樓。',120,'御定全唐詩/json/216.json','["遠林暑氣薄，公子過我游。貧居類村塢，僻近城南樓。", "旁舍頗淳樸，所願亦易求。隔屋喚西家，借問有酒不。", "牆頭過濁醪，展席俯長流。清風左右至，客意已驚秋。", "巢多眾鳥鬥，葉密鳴蟬稠。苦道此物聒，孰謂吾廬幽。", "水花晚色靜，庶足充淹留。預恐尊中盡，更起為君謀。"]'),
('yuding-32','奉同郭給事湯東靈湫作','杜甫','唐','御定全唐诗','yuding','','[]','東山氣鴻蒙，宮殿居上頭。君來必十月，樹羽臨九州。',240,'御定全唐詩/json/216.json','["東山氣鴻蒙，宮殿居上頭。君來必十月，樹羽臨九州。", "陰火煮玉泉，噴薄漲岩幽。有時浴赤日，光抱空中樓。", "閬風入轍跡，曠原延冥搜。沸天萬乘動，觀水百丈湫。", "幽靈斯可佳，王命官屬休。初聞龍用壯，擘石摧林丘。", "中夜窟宅改，移因風雨秋。倒懸瑤池影，屈注蒼江流。", "味如甘露漿，揮弄滑且柔。翠旗澹偃蹇，雲車紛少留。", "簫鼓蕩四溟，異香泱漭浮。鮫人獻微綃，曾祝沈豪牛。", "百祥奔盛明，古先莫能儔。坡陀金蝦蟆，出見蓋有由。", "至尊顧之笑，王母不肯收。複歸虛無底，化作長黃虯。", "飄飄青瑣郎，文彩珊瑚鉤。浩歌淥水曲，清絕聽者愁。"]'),
('yuding-33','夜聽許十損誦詩愛而有作','杜甫','唐','御定全唐诗','yuding','','[]','許生五台賓，業白出石壁。余亦師粲可，身猶縛禪寂。',120,'御定全唐詩/json/216.json','["許生五台賓，業白出石壁。余亦師粲可，身猶縛禪寂。", "何階子方便，謬引為匹敵。離索晚相逢，包蒙欣有擊。", "誦詩渾遊衍，四座皆辟易。應手看捶鉤，清心聽鳴鏑。", "精微穿溟涬，飛動摧霹靂。陶謝不枝梧，風騷共推激。", "紫燕自超詣，翠駁誰剪剔。君意人莫知，人間夜寥闃。"]'),
('yuding-34','橋陵詩三十韻，因呈縣內諸官','杜甫','唐','御定全唐诗','yuding','','[]','先帝昔晏駕，茲山朝百靈。崇岡擁象設，沃野開天庭。',360,'御定全唐詩/json/216.json','["先帝昔晏駕，茲山朝百靈。崇岡擁象設，沃野開天庭。", "即事壯重險，論功超五丁。坡陀因厚地，卻略羅峻屏。", "雲闕虛冉冉，風松肅泠泠。石門霜露白，玉殿莓苔青。", "宮女晚知曙，祠官朝見星。空梁簇畫戟，陰井敲銅瓶。", "中使日夜繼，惟王心不寧。豈徒恤備享，尚謂求無形。", "孝理敦國政，神凝推道經。瑞芝產廟柱，好鳥鳴岩扃。", "高嶽前嵂崒，洪河左瀅濙。金城蓄峻址，沙苑交回汀。", "永與奧區固，川原紛眇冥。居然赤縣立，台榭爭岧亭。", "官屬果稱是，聲華真可聽。王劉美竹潤，裴李春蘭馨。", "鄭氏才振古，啖侯筆不停。遣辭必中律，利物常發硎。", "綺繡相輾轉，琳琅愈青熒。側聞魯恭化，秉德崔瑗銘。", "太史候鳧影，王喬隨鶴翎。朝儀限霄漢，容思回林坰。", "轗軻辭下杜，飄颻陵濁涇。諸生舊短褐，旅泛一浮萍。", "荒歲兒女瘦，暮途涕泗零。主人念老馬，廨署容秋螢。", "流寓理豈愜，窮愁醉未醒。何當擺俗累，浩蕩乘滄溟。"]'),
('yuding-35','沙苑行','杜甫','唐','御定全唐诗','yuding','','[]','君不見左輔白沙如白水，繚以周牆百餘裏。',115,'御定全唐詩/json/216.json','["君不見左輔白沙如白水，繚以周牆百餘裏。", "龍媒昔是渥窪生，汗血今稱獻於此。苑中騋牝三千匹，", "王有虎臣司苑門，入門天廄皆雲屯。驌驦一骨獨當禦，", "逸群絕足信殊傑，倜儻權奇難具論。累累塠阜藏奔突，", "泉出巨魚長比人，丹砂作尾黃金鱗。豈知異物同精氣，"]'),
('yuding-36','驄馬行','杜甫','唐','御定全唐诗','yuding','','[]','鄧公馬癖人共知，初得花驄大宛種。夙昔傳聞思一見，',96,'御定全唐詩/json/216.json','["鄧公馬癖人共知，初得花驄大宛種。夙昔傳聞思一見，", "隅目青熒夾鏡懸，肉駿碨礌連錢動。朝來久試華軒下，", "卿家舊賜公取之，天廄真龍此其亞。晝洗須騰涇渭深，", "豈有四蹄疾於鳥，不與八駿俱先鳴。時俗造次那得致，"]'),
('yuding-37','去矣行','杜甫','唐','御定全唐诗','yuding','','[]','君不見鞲上鷹，一飽則飛掣。焉能作堂上燕，',36,'御定全唐詩/json/216.json','["君不見鞲上鷹，一飽則飛掣。焉能作堂上燕，", "未試囊中餐玉法，明朝且入藍田山。"]'),
('yuding-38','自京赴奉先縣詠懷五百字','杜甫','唐','御定全唐诗','yuding','','[]','杜陵有布衣，老大意轉拙。許身一何愚，竊比稷與契。',576,'御定全唐詩/json/216.json','["杜陵有布衣，老大意轉拙。許身一何愚，竊比稷與契。", "居然成濩落，白首甘契闊。蓋棺事則已，此志常覬豁。", "窮年憂黎元，歎息腸內熱。取笑同學翁，浩歌彌激烈。", "非無江海志，蕭灑送日月。生逢堯舜君，不忍便永訣。", "當今廊廟具，構廈豈雲缺。葵藿傾太陽，物性固莫奪。", "顧惟螻蟻輩，但自求其穴。胡為慕大鯨，輒擬偃溟渤。", "以茲悟生理，獨恥事幹謁。兀兀遂至今，忍為塵埃沒。", "終愧巢與由，未能易其節。沈飲聊自適，放歌頗愁絕。", "歲暮百草零，疾風高岡裂。天衢陰崢嶸，客子中夜發。", "霜嚴衣帶斷，指直不得結。淩晨過驪山，禦榻在嵽嵲。", "蚩尤塞寒空，蹴蹋崖谷滑。瑤池氣郁律，羽林相摩戛。", "君臣留歡娛，樂動殷樛嶱。賜浴皆長纓，與宴非短褐。", "彤庭所分帛，本自寒女出。鞭撻其夫家，聚斂貢城闕。", "聖人筐篚恩，實欲邦國活。臣如忽至理，君豈棄此物。", "多士盈朝廷，仁者宜戰慄。況聞內金盤，盡在衛霍室。", "中堂舞神仙，煙霧散玉質。暖客貂鼠裘，悲管逐清瑟。", "勸客駝蹄羹，霜橙壓香橘。朱門酒肉臭，路有凍死骨。", "榮枯咫尺異，惆悵難再述。北轅就涇渭，官渡又改轍。", "群冰從西下，極目高崒兀。疑是崆峒來，恐觸天柱折。", "河梁幸未坼，枝撐聲窸窣。行旅相攀援，川廣不可越。", "老妻寄異縣，十口隔風雪。誰能久不顧，庶往共饑渴。", "入門聞號咷，幼子饑已卒。吾寧舍一哀，裏巷亦嗚咽。", "所愧為人父，無食致夭折。豈知秋未登，貧窶有倉卒。", "生常免租稅，名不隸征伐。撫跡猶酸辛，平人固騷屑。"]'),
('yuding-39','奉先劉少府新畫山水障歌','杜甫','唐','御定全唐诗','yuding','','[]','堂上不合生楓樹，怪底江山起煙霧。聞君掃卻赤縣圖，',168,'御定全唐詩/json/216.json','["堂上不合生楓樹，怪底江山起煙霧。聞君掃卻赤縣圖，", "對此融心神。知君重毫素。豈但祁岳與鄭虔，", "悄然坐我天姥下，耳邊已似聞清猿。反思前夜風雨急，", "野亭春還雜花遠，漁翁暝蹋孤舟立。滄浪水深青溟闊，", "劉侯天機精，愛畫入骨髓。自有兩兒郎，揮灑亦莫比。", "大兒聰明到，能添老樹巔崖裏。小兒心孔開。", "貌得山僧及童子。若耶溪，雲門寺。", "吾獨胡為在泥滓，青鞋布襪從此始。"]'),
('yuding-40','白水縣崔少府十九翁高齋三十韻','杜甫','唐','御定全唐诗','yuding','','[]','客從南縣來，浩蕩無與適。旅食白日長，況當朱炎赫。',360,'御定全唐詩/json/216.json','["客從南縣來，浩蕩無與適。旅食白日長，況當朱炎赫。", "高齋坐林杪，信宿遊衍闃。清晨陪躋攀，傲睨俯峭壁。", "崇岡相枕帶，曠野懷咫尺。始知賢主人，贈此遣愁寂。", "危階根青冥，曾冰生淅瀝。上有無心雲，下有欲落石。", "泉聲聞複急，動靜隨所擊。鳥呼藏其身，有似懼彈射。", "吏隱道性情，茲焉其窟宅。白水見舅氏，諸翁乃仙伯。", "杖藜長松陰，作尉窮穀僻。為我炊雕胡，逍遙展良覿。", "坐久風頗愁，晚來山更碧。相對十丈蛟，欻翻盤渦坼。", "何得空裏雷，殷殷尋地脈。煙氛藹崷崒，魍魎森慘戚。", "昆侖崆峒顛，回首如不隔。前軒頹反照，巉絕華嶽赤。", "兵氣漲林巒，川光雜鋒鏑。知是相公軍，鐵馬雲霧積。", "玉觴淡無味，胡羯豈強敵。長歌激屋樑，淚下流衽席。", "人生半哀樂，天地有順逆。慨彼萬國夫，休明備征狄。", "猛將紛填委，廟謀蓄長策。東郊何時開，帶甲且來釋。", "欲告清宴罷，難拒幽明迫。三歎酒食旁，何由似平昔。"]'),
('yuding-41','三川觀水漲二十韻','杜甫','唐','御定全唐诗','yuding','','[]','我經華原來，不復見平陸。北上唯土山，連山走窮穀。',276,'御定全唐詩/json/216.json','["我經華原來，不復見平陸。北上唯土山，連山走窮穀。", "火雲無時出，飛電常在目。自多窮岫雨，行潦相豗蹙。", "蓊匌川氣黃，群流會空曲。清晨望高浪，忽謂陰崖踣。", "恐泥竄蛟龍，登危聚麋鹿。枯查卷拔樹，礧磈共充塞。", "聲吹鬼神下，勢閱人代速。不有萬穴歸，何以尊四瀆。", "及觀泉源漲，反懼江海覆。漂沙坼岸去，漱壑松柏禿。", "乘陵破山門，回斡裂地軸。交洛赴洪河，及關豈信宿。", "應沈數州沒，如聽萬室哭。穢濁殊未清，風濤怒猶蓄。", "何時通舟車，陰氣不黲黷。浮生有蕩汩，吾道正羈束。", "人寰難容身，石壁滑側足。雲雷此不已，艱險路更局。", "普天無川梁，欲濟願水縮。因悲中林士，未脫眾魚腹。", "舉頭向蒼天，安得騎鴻鵠。"]'),
('yuding-42','悲陳陶','杜甫','唐','御定全唐诗','yuding','','[]','孟冬十郡良家子，血作陳陶澤中水。野曠天清無戰聲，',40,'御定全唐詩/json/216.json','["孟冬十郡良家子，血作陳陶澤中水。野曠天清無戰聲，", "都人回面向北啼，日夜更望官軍至。"]'),
('yuding-43','悲青阪','杜甫','唐','御定全唐诗','yuding','','[]','我軍青阪在東門，天寒飲馬太白窟。黃頭奚兒日向西，',40,'御定全唐詩/json/216.json','["我軍青阪在東門，天寒飲馬太白窟。黃頭奚兒日向西，", "焉得附書與我軍，忍待明年莫倉卒。"]'),
('yuding-44','哀江頭','杜甫','唐','御定全唐诗','yuding','','[]','少陵野老吞聲哭，春日潛行曲江曲。江頭宮殿鎖千門，',88,'御定全唐詩/json/216.json','["少陵野老吞聲哭，春日潛行曲江曲。江頭宮殿鎖千門，", "昭陽殿裏第一人，同輦隨君侍君側。輦前才人帶弓箭，", "明眸皓齒今何在，血污遊魂歸不得。清渭東流劍閣深，", "黃昏胡騎塵滿城，欲往城南忘南北。"]'),
('yuding-45','哀王孫','杜甫','唐','御定全唐诗','yuding','','[]','長安城頭頭白烏，夜飛延秋門上呼。又向人家啄大屋，',145,'御定全唐詩/json/216.json','["長安城頭頭白烏，夜飛延秋門上呼。又向人家啄大屋，", "腰下寶玦青珊瑚，可憐王孫泣路隅。問之不肯道姓名，", "高帝子孫盡隆准，龍種自與常人殊。豺狼在邑龍在野。", "王孫善保千金軀。不敢長語臨交衢，且為王孫立斯須。", "昨夜東風吹血腥，東來橐駝滿舊都。朔方健兒好身手，", "花門kO面請雪恥，慎勿出口他人狙。哀哉王孫慎勿疏，"]'),
('yuding-46','大雲寺贊公房四首','杜甫','唐','御定全唐诗','yuding','','[]','心在水精域，衣沾春雨時。洞門盡徐步，深院果幽期。',360,'御定全唐詩/json/216.json','["心在水精域，衣沾春雨時。洞門盡徐步，深院果幽期。", "到扉開複閉，撞鐘齋及茲。醍醐長髮性，飲食過扶衰。", "把臂有多日，開懷無愧辭。黃鸝度結構，紫鴿下罘罳。", "愚意會所適，花邊行自遲。湯休起我病，微笑索題詩。", "細軟青絲履，光明白氎巾。深藏供老宿，取用及吾身。", "自顧轉無趣，交情何尚新。道林才不世，惠遠德過人。", "雨瀉暮簷竹，風吹青井芹。天陰對圖畫，最覺潤龍鱗。", "燈影照無睡，心清聞妙香。夜深殿突兀，風動金鋃鐺。", "天黑閉春院，地清棲暗芳。玉繩回斷絕，鐵鳳森翱翔。", "梵放時出寺，鐘殘仍殷床。明朝在沃野，苦見塵沙黃。", "童兒汲井華，慣捷瓶上手。沾灑不濡地，掃除似無帚。", "明霞爛複閣，霽霧搴高牖。側塞被徑花，飄颻委墀柳。", "艱難世事迫，隱遁佳期後。晤語契深心，那能總箝口。", "奉辭還杖策，暫別終回首。泱泱泥汙人，聽聽國多狗。", "既未免羈絆，時來憩奔走。近公如白雪，執熱煩何有。"]'),
('yuding-0','蘇端、薛複筵簡薛華醉歌','杜甫','唐','御定全唐诗','yuding','','[]','文章有神交有道，端複得之名譽早。愛客滿堂盡豪翰，',120,'御定全唐詩/json/217.json','["文章有神交有道，端複得之名譽早。愛客滿堂盡豪翰，", "千里猶殘舊冰雪，百壺且試開懷抱。垂老惡聞戰鼓悲，", "坐中薛華善醉歌，歌辭自作風格老。近來海內為長句，", "諸生頗盡新知樂，萬事終傷不自保。氣酣日落西風來，", "忽憶雨時秋井塌，古人白骨生青苔，如何不飲令心哀。"]'),
('yuding-1','晦日尋崔戢、李封','杜甫','唐','御定全唐诗','yuding','','[]','朝光入甕牖，屍寢驚敝裘。起行視天宇，春氣漸和柔。',240,'御定全唐詩/json/217.json','["朝光入甕牖，屍寢驚敝裘。起行視天宇，春氣漸和柔。", "興來不暇懶，今晨梳我頭。出門無所待，徒步覺自由。", "杖藜複恣意，免值公與侯。晚定崔李交，會心真罕儔。", "每過得酒傾，二宅可淹留。喜結仁裏歡，況因令節求。", "李生園欲荒，舊竹頗修修。引客看掃除，隨時成獻酬。", "崔侯初筵色，已畏空尊愁。未知天下士，至性有此不。", "草牙既青出，蜂聲亦暖遊。思見農器陳，何當甲兵休。", "上古葛天民，不貽黃屋憂。至今阮籍等，熟醉為身謀。", "威鳳高其翔，長鯨吞九洲。地軸為之翻，百川皆亂流。", "當歌欲一放，淚下恐莫收。濁醪有妙理，庶用慰沈浮。"]'),
('yuding-2','雨過蘇端','杜甫','唐','御定全唐诗','yuding','','[]','雞鳴風雨交，久旱雲亦好。杖藜入春泥，無食起我早。',120,'御定全唐詩/json/217.json','["雞鳴風雨交，久旱雲亦好。杖藜入春泥，無食起我早。", "諸家憶所曆，一飯跡便掃。蘇侯得數過，歡喜每傾倒。", "也複可憐人，呼兒具梨棗。濁醪必在眼，盡醉攄懷抱。", "紅稠屋角花，碧委牆隅草。親賓縱談謔，喧鬧畏衰老。", "況蒙霈澤垂，糧粒或自保。妻孥隔軍壘，撥棄不擬道。"]'),
('yuding-3','喜晴','杜甫','唐','御定全唐诗','yuding','','[]','皇天久不雨，既雨晴亦佳。出郭眺西郊，肅肅春增華。',168,'御定全唐詩/json/217.json','["皇天久不雨，既雨晴亦佳。出郭眺西郊，肅肅春增華。", "青熒陵陂麥，窈窕桃李花。春夏各有實，我饑豈無涯。", "干戈雖橫放，慘澹鬥龍蛇。甘澤不猶愈，且耕今未賒。", "丈夫則帶甲，婦女終在家。力難及黍稷，得種菜與麻。", "千載商山芝，往者東門瓜。其人骨已朽，此道誰疵瑕。", "英賢遇轗軻，遠引蟠泥沙。顧慚昧所適，回首白日斜。", "漢陰有鹿門，滄海有靈查。焉能學眾口，咄咄空咨嗟。"]'),
('yuding-4','送率府程錄事還鄉','杜甫','唐','御定全唐诗','yuding','','[]','鄙夫行衰謝，抱病昏妄集。常時往還人，記一不識十。',168,'御定全唐詩/json/217.json','["鄙夫行衰謝，抱病昏妄集。常時往還人，記一不識十。", "程侯晚相遇，與語才傑立。熏然耳目開，頗覺聰明入。", "千載得鮑叔，末契有所及。意鐘老柏青，義動修蛇蟄。", "若人可數見，慰我垂白泣。告別無淹晷，百憂複相襲。", "內愧突不黔，庶羞以賙給。素絲挈長魚，碧酒隨玉粒。", "途窮見交態，世梗悲路澀。東風吹春冰，泱莽後土濕。", "念君惜羽翮，既飽更思戢。莫作翻雲鶻，聞呼向禽急。"]'),
('yuding-5','述懷一首','杜甫','唐','御定全唐诗','yuding','','[]','去年潼關破，妻子隔絕久。今夏草木長，脫身得西走。',192,'御定全唐詩/json/217.json','["去年潼關破，妻子隔絕久。今夏草木長，脫身得西走。", "麻鞋見天子，衣袖露兩肘。朝廷湣生還，親故傷老醜。", "涕淚授拾遺，流離主恩厚。柴門雖得去，未忍即開口。", "寄書問三川，不知家在否。比聞同罹禍，殺戮到雞狗。", "山中漏茅屋，誰複依戶牖。摧頹蒼松根，地冷骨未朽。", "幾人全性命，盡室豈相偶。嶔岑猛虎場，鬱結回我首。", "自寄一封書，今已十月後。反畏消息來，寸心亦何有。", "漢運初中興，生平老耽酒。沉思歡會處，恐作窮獨叟。"]'),
('yuding-6','送長孫九侍禦赴武威判官','杜甫','唐','御定全唐诗','yuding','','[]','驄馬新鑿蹄，銀鞍被來好。繡衣黃白郎，騎向交河道。',168,'御定全唐詩/json/217.json','["驄馬新鑿蹄，銀鞍被來好。繡衣黃白郎，騎向交河道。", "問君適萬里，取別何草草。天子憂涼州，嚴程到須早。", "去秋群胡反，不得無電掃。此行收遺甿，風俗方再造。", "族父領元戎，名聲國中老。奪我同官良，飄搖按城堡。", "使我不能餐，令我惡懷抱。若人才思闊，溟漲浸絕島。", "尊前失詩流，塞上得國寶。皇天悲送遠，雲雨白浩浩。", "東郊尚烽火，朝野色枯槁。西極柱亦傾，如何正穹昊。"]'),
('yuding-7','送樊二十三侍禦赴漢中判官','杜甫','唐','御定全唐诗','yuding','','[]','威弧不能弦，自爾無寧歲。川穀血橫流，豺狼沸相噬。',240,'御定全唐詩/json/217.json','["威弧不能弦，自爾無寧歲。川穀血橫流，豺狼沸相噬。", "天子從北來，長驅振凋敝。頓兵岐梁下，卻跨沙漠裔。", "二京陷未收，四極我得制。蕭索漢水清，緬通淮湖稅。", "使者紛星散，王綱尚旒綴。南伯從事賢，君行立談際。", "生知七曜曆，手畫三軍勢。冰雪淨聰明，雷霆走精銳。", "幕府輟諫官，朝廷無此例。至尊方旰食，仗爾布嘉惠。", "補闕暮征入，柱史晨征憩。正當艱難時，實藉長久計。", "回風吹獨樹，白日照執袂。慟哭蒼煙根，山門萬重閉。", "居人莽牢落，遊子方迢遞。裴回悲生離，局促老一世。", "陶唐歌遺民，後漢更列帝。恨無匡複姿，聊欲從此逝。"]'),
('yuding-8','送從弟亞赴安西判官','杜甫','唐','御定全唐诗','yuding','','[]','南風作秋聲，殺氣薄炎熾。盛夏鷹隼擊，時危異人至。',240,'御定全唐詩/json/217.json','["南風作秋聲，殺氣薄炎熾。盛夏鷹隼擊，時危異人至。", "令弟草中來，蒼然請論事。詔書引上殿，奮舌動天意。", "兵法五十家，爾腹為篋笥。應對如轉丸，疏通略文字。", "經綸皆新語，足以正神器。宗廟尚為灰，君臣俱下淚。", "崆峒地無軸，青海天軒輊。西極最瘡痍，連山暗烽燧。", "帝曰大布衣，藉卿佐元帥。坐看清流沙，所以子奉使。", "歸當再前席，適遠非曆試。須存武威郡，為畫長久利。", "孤峰石戴驛，快馬金纏轡。黃羊飫不膻，蘆酒多還醉。", "踴躍常人情，慘澹苦士志。安邊敵何有，反正計始遂。", "吾聞駕鼓車，不合用騏驥。龍吟回其頭，夾輔待所致。"]'),
('yuding-9','送韋十六評事充同谷郡防禦判官','杜甫','唐','御定全唐诗','yuding','','[]','昔沒賊中時，潛與子同遊。今歸行在所，王事有去留。',288,'御定全唐詩/json/217.json','["昔沒賊中時，潛與子同遊。今歸行在所，王事有去留。", "逼側兵馬間，主憂急良籌。子雖軀幹小，老氣橫九州。", "挺身艱難際，張目視寇讎。朝廷壯其節，奉詔令參謀。", "鑾輿駐鳳翔，同穀為咽喉。西扼弱水道，南鎮枹罕陬。", "此邦承平日，剽劫吏所羞。況乃胡未滅，控帶莽悠悠。", "府中韋使君，道足示懷柔。令侄才俊茂，二美又何求。", "受詞太白腳，走馬仇池頭。古色沙土裂，積陰雪雲稠。", "羌父豪豬靴，羌兒青兕裘。吹角向月窟，蒼山旌旆愁。", "鳥驚出死樹，龍怒拔老湫。古來無人境，今代橫戈矛。", "傷哉文儒士，憤激馳林丘。中原正格鬥，後會何緣由。", "百年賦命定，豈料沉與浮。且複戀良友，握手步道周。", "論兵遠壑淨，亦可縱冥搜。題詩得秀句，劄翰時相投。"]'),
('yuding-10','塞蘆子','杜甫','唐','御定全唐诗','yuding','','[]','五城何迢迢，迢迢隔河水。邊兵盡東征，城內空荊杞。',120,'御定全唐詩/json/217.json','["五城何迢迢，迢迢隔河水。邊兵盡東征，城內空荊杞。", "思明割懷衛，秀岩西未已。回略大荒來，崤函蓋虛爾。", "延州秦北戶，關防猶可倚。焉得一萬人，疾驅塞蘆子。", "岐有薛大夫，旁制山賊起。近聞昆戎徒，為退三百里。", "蘆關扼兩寇，深意實在此。誰能叫帝閽，胡行速如鬼。"]'),
('yuding-11','彭衙行','杜甫','唐','御定全唐诗','yuding','','[]','憶昔避賊初，北走經險艱。夜深彭衙道，月照白水山。',276,'御定全唐詩/json/217.json','["憶昔避賊初，北走經險艱。夜深彭衙道，月照白水山。", "盡室久徒步，逢人多厚顏。參差谷鳥吟，不見遊子還。", "癡女饑咬我，啼畏虎狼聞。懷中掩其口，反側聲愈嗔。", "小兒強解事，故索苦李餐。一旬半雷雨，泥濘相牽攀。", "既無禦雨備，徑滑衣又寒。有時經契闊，竟日數里間。", "野果充餱糧，卑枝成屋椽。早行石上水，暮宿天邊煙。", "少留周家窪，欲出蘆子關。故人有孫宰，高義薄曾雲。", "延客已曛黑，張燈啟重門。暖湯濯我足，翦紙招我魂。", "從此出妻孥，相視涕闌幹。眾雛爛熳睡，喚起沾盤餐。", "誓將與夫子，永結為弟昆。遂空所坐堂，安居奉我歡。", "誰肯艱難際，豁達露心肝。別來歲月周，胡羯仍構患。", "何當有翅翎，飛去墮爾前。"]'),
('yuding-12','北征','杜甫','唐','御定全唐诗','yuding','','[]','皇帝二載秋，閏八月初吉。杜子將北征，蒼茫問家室。',576,'御定全唐詩/json/217.json','["皇帝二載秋，閏八月初吉。杜子將北征，蒼茫問家室。", "維時遭艱虞，朝野少暇日。顧慚恩私被，詔許歸蓬蓽。", "拜辭詣闕下，怵惕久未出。雖乏諫諍姿，恐君有遺失。", "君誠中興主，經緯固密勿。東胡反未已，臣甫憤所切。", "揮涕戀行在，道途猶恍惚。乾坤含瘡痍，憂虞何時畢。", "靡靡逾阡陌，人煙眇蕭瑟。所遇多被傷，呻吟更流血。", "回首鳳翔縣，旌旗晚明滅。前登寒山重，屢得飲馬窟。", "邠郊入地底，涇水中蕩潏。猛虎立我前，蒼崖吼時裂。", "菊垂今秋花，石戴古車轍。青雲動高興，幽事亦可悅。", "山果多瑣細，羅生雜橡栗。或紅如丹砂，或黑如點漆。", "雨露之所濡，甘苦齊結實。緬思桃源內，益歎身世拙。", "坡陀望鄜畤，岩穀互出沒。我行已水濱，我僕猶木末。", "鴟鳥鳴黃桑，野鼠拱亂穴。夜深經戰場，寒月照白骨。", "潼關百萬師，往者散何卒。遂令半秦民，殘害為異物。", "況我墮胡塵，及歸盡華髮。經年至茅屋，妻子衣百結。", "慟哭松聲回，悲泉共幽咽。平生所嬌兒，顏色白勝雪。", "見耶背面啼，垢膩腳不襪。床前兩小女，補綻才過膝。", "海圖坼波濤，舊繡移曲折。天吳及紫鳳，顛倒在裋褐。", "老夫情懷惡，嘔泄臥數日。那無囊中帛，救汝寒凜栗。", "粉黛亦解苞，衾裯稍羅列。瘦妻面複光，癡女頭自櫛。", "學母無不為，曉妝隨手抹。移時施朱鉛，狼藉畫眉闊。", "生還對童稚，似欲忘饑渴。問事競挽須，誰能即嗔喝。", "翻思在賊愁，甘受雜亂聒。新歸且慰意，生理焉能說。", "至尊尚蒙塵，幾日休練卒。仰觀天色改，坐覺祆氣豁。"]'),
('yuding-13','得舍弟消息','杜甫','唐','御定全唐诗','yuding','','[]','風吹紫荊樹，色與春庭暮。花落辭故枝，風回返無處。',48,'御定全唐詩/json/217.json','["風吹紫荊樹，色與春庭暮。花落辭故枝，風回返無處。", "骨肉恩書重，漂泊難相遇。猶有淚成河，經天複東注。"]'),
('yuding-14','徒步歸行','杜甫','唐','御定全唐诗','yuding','','[]','明公壯年值時危，經濟實藉英雄姿。國之社稷今若是，',48,'御定全唐詩/json/217.json','["明公壯年值時危，經濟實藉英雄姿。國之社稷今若是，", "青袍朝士最困者，白頭拾遺徒步歸。人生交契無老少，"]'),
('yuding-15','玉華宮','杜甫','唐','御定全唐诗','yuding','','[]','溪回松風長，蒼鼠竄古瓦。不知何王殿，遺構絕壁下。',96,'御定全唐詩/json/217.json','["溪回松風長，蒼鼠竄古瓦。不知何王殿，遺構絕壁下。", "陰房鬼火青，壞道哀湍瀉。萬籟真笙竽，秋色正蕭灑。", "美人為黃土，況乃粉黛假。當時侍金輿，故物獨石馬。", "憂來藉草坐，浩歌淚盈把。冉冉征途間，誰是長年者。"]'),
('yuding-16','九成宮','杜甫','唐','御定全唐诗','yuding','','[]','蒼山入百里，崖斷如杵臼。曾宮憑風回，岌嶪土囊口。',145,'御定全唐詩/json/217.json','["蒼山入百里，崖斷如杵臼。曾宮憑風回，岌嶪土囊口。", "立神扶棟樑，鑿翠開戶牖。其陽產靈芝，其陰宿牛鬥。", "紛披長松倒，揭gG怪石走。哀猿啼一聲，客淚迸林藪。", "荒哉隋家帝，制此今頹朽。向使國不亡，焉為巨唐有。", "雖無新增修，尚置官居守。巡非瑤水遠，跡是雕牆後。", "我行屬時危，仰望嗟歎久。天王守太白，駐馬更搔首。"]'),
('yuding-17','羌村','杜甫','唐','御定全唐诗','yuding','','[]','崢嶸赤雲西，日腳下平地。柴門鳥雀噪，歸客千里至。',240,'御定全唐詩/json/217.json','["崢嶸赤雲西，日腳下平地。柴門鳥雀噪，歸客千里至。", "妻孥怪我在，驚定還拭淚。世亂遭飄蕩，生還偶然遂。", "鄰人滿牆頭，感歎亦歔欷。夜闌更秉燭，相對如夢寐。", "晚歲迫偷生，還家少歡趣。嬌兒不離膝，畏我複卻去。", "憶昔好追涼，故繞池邊樹。蕭蕭北風勁，撫事煎百慮。", "賴知禾黍收，已覺糟床注。如今足斟酌，且用慰遲暮。", "群雞正亂叫，客至雞鬥爭。驅雞上樹木，始聞叩柴荊。", "父老四五人，問我久遠行。手中各有攜，傾榼濁複清。", "苦辭酒味薄，黍地無人耕。兵革既未息，兒童盡東征。", "請為父老歌，艱難愧深情。歌罷仰天歎，四座淚縱橫。"]'),
('yuding-18','逼仄行，贈畢曜','杜甫','唐','御定全唐诗','yuding','','[]','逼仄何逼仄，我居巷南子巷北。可恨鄰里間，',107,'御定全唐詩/json/217.json','["逼仄何逼仄，我居巷南子巷北。可恨鄰里間，", "我貧無乘非無足，昔者相過今不得。實不是愛微軀，", "曉來急雨春風顛，睡美不聞鐘鼓傳。東家蹇驢許借我，", "焉能終日心拳拳，憶君誦詩神凜然。辛夷始花亦已落，", "速宜相就飲一鬥，恰有三百青銅錢。"]'),
('yuding-19','送李校書二十六韻','杜甫','唐','御定全唐诗','yuding','','[]','代北有豪鷹，生子毛盡赤。渥窪騏驥兒，尤異是龍脊。',312,'御定全唐詩/json/217.json','["代北有豪鷹，生子毛盡赤。渥窪騏驥兒，尤異是龍脊。", "李舟名父子，清峻流輩伯。人間好少年，不必須白晰。", "十五富文史，十八足賓客。十九授校書，二十聲輝赫。", "眾中每一見，使我潛動魄。自恐二男兒，辛勤養無益。", "幹元元年春，萬姓始安宅。舟也衣彩衣，告我欲遠適。", "倚門固有望，斂衽就行役。南登吟白華，已見楚山碧。", "藹藹咸陽都，冠蓋日雲積。何時太夫人，堂上會親戚。", "汝翁草明光，天子正前席。歸期豈爛漫，別意終感激。", "顧我蓬屋姿，謬通金閨籍。小來習性懶，晚節慵轉劇。", "每愁悔吝作，如覺天地窄。羨君齒發新，行己能夕惕。", "臨岐意頗切，對酒不能吃。回身視綠野，慘澹如荒澤。", "老雁春忍饑，哀號待枯麥。時哉高飛燕，絢練新羽翮。", "長雲濕褒斜，漢水饒巨石。無令軒車遲，衰疾悲夙昔。"]'),
('yuding-20','洗兵馬','杜甫','唐','御定全唐诗','yuding','','[]','中興諸將收山東，捷書日報清晝同。河廣傳聞一葦過，',192,'御定全唐詩/json/217.json','["中興諸將收山東，捷書日報清晝同。河廣傳聞一葦過，", "京師皆騎汗血馬，回紇喂肉葡萄宮。已喜皇威清海岱，", "成王功大心轉小，郭相謀深古來少。司徒清鑒懸明鏡，", "東走無複憶鱸魚，南飛覺有安巢鳥。青春複隨冠冕入，", "攀龍附鳳勢莫當，天下盡化為侯王。汝等豈知蒙帝力，", "張公一生江海客，身長九尺鬚眉蒼。征起適遇風雲會，", "寸地尺天皆入貢，奇祥異瑞爭來送。不知何國致白環，", "田家望望惜雨幹，布穀處處催春種。淇上健兒歸莫懶，"]'),
('yuding-21','留花門','杜甫','唐','御定全唐诗','yuding','','[]','北門天驕子，飽肉氣勇決。高秋馬肥健，挾矢射漢月。',168,'御定全唐詩/json/217.json','["北門天驕子，飽肉氣勇決。高秋馬肥健，挾矢射漢月。", "自古以為患，詩人厭薄伐。修德使其來，羈縻固不絕。", "胡為傾國至，出入暗金闕。中原有驅除，隱忍用此物。", "公主歌黃鵠，君王指白日。連雲屯左輔，百里見積雪。", "長戟鳥休飛，哀笳曙幽咽。田家最恐懼，麥倒桑枝折。", "沙苑臨清渭，泉香草豐潔。渡河不用船，千騎常撇烈。", "胡塵逾太行，雜種抵京室。花門既須留，原野轉蕭瑟。"]'),
('yuding-22','病後遇王倚飲，贈歌','杜甫','唐','御定全唐诗','yuding','','[]','麟角鳳觜世莫識，煎膠續弦奇自見。尚看王生抱此懷，',120,'御定全唐詩/json/217.json','["麟角鳳觜世莫識，煎膠續弦奇自見。尚看王生抱此懷，", "酷見凍餒不足恥，多病沈年苦無健。王生怪我顏色惡，", "頭白眼暗坐有胝，肉黃皮皺命如線。惟生哀我未平復，", "長安冬菹酸且綠，金城土酥靜如練。兼求富豪且割鮮，", "老馬為駒信不虛，當時得意況深眷。但使殘年飽吃飯，"]'),
('yuding-23','湖城東遇孟雲卿，複歸劉顥宅宿宴，飲散因為醉歌','杜甫','唐','御定全唐诗','yuding','','[]','疾風吹塵暗河縣，行子隔手不相見。湖城城南一開眼，',72,'御定全唐詩/json/217.json','["疾風吹塵暗河縣，行子隔手不相見。湖城城南一開眼，", "劉侯歎我攜客來，置酒張燈促華饌。且將款曲終今夕，", "天開地裂長安陌，寒盡春生洛陽殿。豈知驅車複同軌，"]'),
('yuding-24','閿鄉薑七少府設膾，戲贈長歌','杜甫','唐','御定全唐诗','yuding','','[]','姜侯設膾當嚴冬，昨日今日皆天風。河凍未漁不易得，',88,'御定全唐詩/json/217.json','["姜侯設膾當嚴冬，昨日今日皆天風。河凍未漁不易得，", "無聲細下飛碎雪，有骨已剁觜春蔥。偏勸腹腴愧年少，", "新歡便飽姜侯德，清觴異味情屢極。東歸貪路自覺難，", "不恨我衰子貴時，悵望且為今相憶。"]'),
('yuding-25','戲贈閿鄉秦少公短歌','杜甫','唐','御定全唐诗','yuding','','[]','去年行宮當太白，朝回君是同舍客。同心不減骨肉親，',40,'御定全唐詩/json/217.json','["去年行宮當太白，朝回君是同舍客。同心不減骨肉親，", "昨夜邀歡樂更無，多才依舊能潦倒。"]'),
('yuding-26','李鄠縣丈人胡馬行','杜甫','唐','御定全唐诗','yuding','','[]','丈人駿馬名胡騮，前年避胡過金牛。回鞭卻走見天子，',72,'御定全唐詩/json/217.json','["丈人駿馬名胡騮，前年避胡過金牛。回鞭卻走見天子，", "一聞說盡急難材，轉益愁向駑駘輩。頭上銳耳批秋竹，", "洛陽大道時再清，累日喜得俱東行。鳳臆龍鬐未易識，"]'),
('yuding-27','義鶻','杜甫','唐','御定全唐诗','yuding','','[]','陰崖有蒼鷹，養子黑柏顛。白蛇登其巢，吞噬恣朝餐。',216,'御定全唐詩/json/217.json','["陰崖有蒼鷹，養子黑柏顛。白蛇登其巢，吞噬恣朝餐。", "雄飛遠求食，雌者鳴辛酸。力強不可制，黃口無半存。", "其父從西歸，翻身入長煙。斯須領健鶻，痛憤寄所宣。", "鬥上捩孤影，噭哮來九天。修鱗脫遠枝，巨顙坼老拳。", "高空得蹭蹬，短草辭蜿蜒。折尾能一掉，飽腸皆已穿。", "生雖滅眾雛，死亦垂千年。物情有報復，快意貴目前。", "茲實鷙鳥最，急難心炯然。功成失所往，用舍何其賢。", "近經潏水湄，此事樵夫傳。飄蕭覺素發，凜欲沖儒冠。", "人生許與分，只在顧盼間。聊為義鶻行，用激壯士肝。"]'),
('yuding-28','畫鶻行','杜甫','唐','御定全唐诗','yuding','','[]','高堂見生鶻，颯爽動秋骨。初驚無拘攣，何得立突兀。',120,'御定全唐詩/json/217.json','["高堂見生鶻，颯爽動秋骨。初驚無拘攣，何得立突兀。", "乃知畫師妙，功刮造化窟。寫作神駿姿，充君眼中物。", "烏鵲滿樛枝，軒然恐其出。側腦看青霄，寧為眾禽沒。", "長翮如刀劍，人寰可超越。乾坤空崢嶸，粉墨且蕭瑟。", "緬思雲沙際，自有煙霧質。吾今意何傷，顧步獨紆鬱。"]'),
('yuding-29','瘦馬行','杜甫','唐','御定全唐诗','yuding','','[]','東郊瘦馬使我傷，骨骼硉兀如堵牆。絆之欲動轉欹側，',88,'御定全唐詩/json/217.json','["東郊瘦馬使我傷，骨骼硉兀如堵牆。絆之欲動轉欹側，", "皮幹剝落雜泥滓，毛暗蕭條連雪霜。去歲奔波逐餘寇，", "當時曆塊誤一蹶，委棄非汝能周防。見人慘澹若哀訴，", "誰家且養願終惠，更試明年春草長。"]'),
('yuding-30','新安吏','杜甫','唐','御定全唐诗','yuding','','[]','客行新安道，喧呼聞點兵。借問新安吏，縣小更無丁。',168,'御定全唐詩/json/217.json','["客行新安道，喧呼聞點兵。借問新安吏，縣小更無丁。", "府帖昨夜下，次選中男行。中男絕短小，何以守王城。", "肥男有母送，瘦男獨伶俜。白水暮東流，青山猶哭聲。", "莫自使眼枯，收汝淚縱橫。眼枯即見骨，天地終無情。", "我軍取相州，日夕望其平。豈意賊難料，歸軍星散營。", "就糧近故壘，練卒依舊京。掘壕不到水，牧馬役亦輕。", "況乃王師順，撫養甚分明。送行勿泣血，僕射如父兄。"]'),
('yuding-31','潼關吏','杜甫','唐','御定全唐诗','yuding','','[]','士卒何草草，築城潼關道。大城鐵不如，小城萬丈餘。',120,'御定全唐詩/json/217.json','["士卒何草草，築城潼關道。大城鐵不如，小城萬丈餘。", "借問潼關吏，修關還備胡。要我下馬行，為我指山隅。", "連雲列戰格，飛鳥不能逾。胡來但自守，豈複憂西都。", "丈人視要處，窄狹容單車。艱難奮長戟，萬古用一夫。", "哀哉桃林戰，百萬化為魚。請囑防關將，慎勿學哥舒。"]'),
('yuding-32','石壕吏','杜甫','唐','御定全唐诗','yuding','','[]','暮投石壕村，有吏夜捉人。老翁逾牆走，老婦出門看。',144,'御定全唐詩/json/217.json','["暮投石壕村，有吏夜捉人。老翁逾牆走，老婦出門看。", "吏呼一何怒，婦啼一何苦。聽婦前致詞，三男鄴城戍。", "一男附書至，二男新戰死。存者且偷生，死者長已矣。", "室中更無人，惟有乳下孫。有孫母未去，出入無完裙。", "老嫗力雖衰，請從吏夜歸。急應河陽役，猶得備晨炊。", "夜久語聲絕，如聞泣幽咽。天明登前途，獨與老翁別。"]'),
('yuding-33','新婚別','杜甫','唐','御定全唐诗','yuding','','[]','兔絲附蓬麻，引蔓故不長。嫁女與征夫，不如棄路旁。',192,'御定全唐詩/json/217.json','["兔絲附蓬麻，引蔓故不長。嫁女與征夫，不如棄路旁。", "結髮為妻子，席不暖君床。暮婚晨告別，無乃太匆忙。", "君行雖不遠，守邊赴河陽。妾身未分明，何以拜姑嫜。", "父母養我時，日夜令我藏。生女有所歸，雞狗亦得將。", "君今往死地，沈痛迫中腸。誓欲隨君去，形勢反蒼黃。", "勿為新婚念，努力事戎行。婦人在軍中，兵氣恐不揚。", "自嗟貧家女，久致羅襦裳。羅襦不復施，對君洗紅妝。", "仰視百鳥飛，大小必雙翔。人事多錯迕，與君永相望。"]'),
('yuding-34','垂老別','杜甫','唐','御定全唐诗','yuding','','[]','四郊未寧靜，垂老不得安。子孫陣亡盡，焉用身獨完。',192,'御定全唐詩/json/217.json','["四郊未寧靜，垂老不得安。子孫陣亡盡，焉用身獨完。", "投杖出門去，同行為辛酸。幸有牙齒存，所悲骨髓幹。", "男兒既介胄，長揖別上官。老妻臥路啼，歲暮衣裳單。", "孰知是死別，且複傷其寒。此去必不歸，還聞勸加餐。", "土門壁甚堅，杏園度亦難。勢異鄴城下，縱死時猶寬。", "人生有離合，豈擇衰老端。憶昔少壯日，遲回竟長歎。", "萬國盡征戍，烽火被岡巒。積屍草木腥，流血川原丹。", "何鄉為樂土，安敢尚盤桓。棄絕蓬室居，塌然摧肺肝。"]'),
('yuding-35','無家別','杜甫','唐','御定全唐诗','yuding','','[]','寂寞天寶後，園廬但蒿藜。我裏百餘家，世亂各東西。',192,'御定全唐詩/json/217.json','["寂寞天寶後，園廬但蒿藜。我裏百餘家，世亂各東西。", "存者無消息，死者為塵泥。賤子因陣敗，歸來尋舊蹊。", "人行見空巷，日瘦氣慘淒。但對狐與狸，豎毛怒我啼。", "四鄰何所有，一二老寡妻。宿鳥戀本枝，安辭且窮棲。", "方春獨荷鋤，日暮還灌畦。縣吏知我至，召令習鼓鞞。", "雖從本州役，內顧無所攜。近行止一身，遠去終轉迷。", "家鄉既蕩盡，遠近理亦齊。永痛長病母，五年委溝溪。", "生我不得力，終身兩酸嘶。人生無家別，何以為烝黎。"]'),
('yuding-36','夏日歎','杜甫','唐','御定全唐诗','yuding','','[]','夏日出東北，陵天經中街。朱光徹厚地，郁蒸何由開。',120,'御定全唐詩/json/217.json','["夏日出東北，陵天經中街。朱光徹厚地，郁蒸何由開。", "上蒼久無雷，無乃號令乖。雨降不濡物，良田起黃埃。", "飛鳥苦熱死，池魚涸其泥。萬人尚流冗，舉目唯蒿萊。", "至今大河北，化作虎與豺。浩蕩想幽薊，王師安在哉。", "對食不能餐，我心殊未諧。眇然貞觀初，難與數子偕。"]'),
('yuding-37','夏夜歎','杜甫','唐','御定全唐诗','yuding','','[]','永日不可暮，炎蒸毒我腸。安得萬里風，飄颻吹我裳。',144,'御定全唐詩/json/217.json','["永日不可暮，炎蒸毒我腸。安得萬里風，飄颻吹我裳。", "昊天出華月，茂林延疏光。仲夏苦夜短，開軒納微涼。", "虛明見纖毫，羽蟲亦飛揚。物情無巨細，自適固其常。", "念彼荷戈士，窮年守邊疆。何由一洗濯，執熱互相望。", "竟夕擊刁鬥，喧聲連萬方。青紫雖被體，不如早還鄉。", "北城悲笳發，鸛鶴號且翔。況複煩促倦，激烈思時康。"]'),
('yuding-38','立秋後題','杜甫','唐','御定全唐诗','yuding','','[]','日月不相饒，節序昨夜隔。玄蟬無停號，秋燕已如客。',48,'御定全唐詩/json/217.json','["日月不相饒，節序昨夜隔。玄蟬無停號，秋燕已如客。", "平生獨往願，惆悵年半百。罷官亦由人，何事拘形役。"]'),
('yuding-0','貽阮隱居','杜甫','唐','御定全唐诗','yuding','','[]','陳留風俗衰，人物世不數。塞上得阮生，迥繼先父祖。',96,'御定全唐詩/json/218.json','["陳留風俗衰，人物世不數。塞上得阮生，迥繼先父祖。", "貧知靜者性，自益毛髮古。車馬入鄰家，蓬蒿翳環堵。", "清詩近道要，識子用心苦。尋我草徑微，褰裳蹋寒雨。", "更議居遠村，避喧甘猛虎。足明箕潁客，榮貴如糞土。"]'),
('yuding-1','遣興三首','杜甫','唐','御定全唐诗','yuding','','[]','下馬古戰場，四顧但茫然。風悲浮雲去，黃葉墜我前。',216,'御定全唐詩/json/218.json','["下馬古戰場，四顧但茫然。風悲浮雲去，黃葉墜我前。", "朽骨穴螻蟻，又為蔓草纏。故老行歎息，今人尚開邊。", "漢虜互勝負，封疆不常全。安得廉恥將，三軍同晏眠。", "高秋登塞山，南望馬邑州。降虜東擊胡，壯健盡不留。", "穹廬莽牢落，上有行雲愁。老弱哭道路，願聞甲兵休。", "鄴中事反復，死人積如丘。諸將已茅土，載驅誰與謀。", "豐年孰雲遲，甘澤不在早。耕田秋雨足，禾黍已映道。", "春苗九月交，顏色同日老。勸汝衡門士，忽悲尚枯槁。", "時來展材力，先後無醜好。但訝鹿皮翁，忘機對芳草。"]'),
('yuding-2','昔游','杜甫','唐','御定全唐诗','yuding','','[]','昔謁華蓋君，深求洞宮腳。玉棺已上天，白日亦寂寞。',192,'御定全唐詩/json/218.json','["昔謁華蓋君，深求洞宮腳。玉棺已上天，白日亦寂寞。", "暮升艮岑頂，巾幾猶未卻。弟子四五人，入來淚俱落。", "余時遊名山，發軔在遠壑。良覿違夙願，含淒向寥廓。", "林昏罷幽磬，竟夜伏石閣。王喬下天壇，微月映皓鶴。", "晨溪向虛駃，歸徑行已昨。豈辭青鞋胝，悵望金匕藥。", "東蒙赴舊隱，尚憶同志樂。休事董先生，於今獨蕭索。", "胡為客關塞，道意久衰薄。妻子亦何人，丹砂負前諾。", "雖悲鬒發變，未憂筋力弱。扶藜望清秋，有興入廬霍。"]'),
('yuding-3','幽人','杜甫','唐','御定全唐诗','yuding','','[]','孤雲亦群遊，神物有所歸。麟鳳在赤霄，何當一來儀。',132,'御定全唐詩/json/218.json','["孤雲亦群遊，神物有所歸。麟鳳在赤霄，何當一來儀。", "往與惠荀輩，中年滄洲期。天高無消息，棄我忽若遺。", "內懼非道流，幽人見瑕疵。洪濤隱語笑，鼓枻蓬萊池。", "崔嵬扶桑日，照耀珊瑚枝。風帆倚翠蓋，暮把東皇衣。", "咽漱元和津，所思煙霞微。知名未足稱，局促商山芝。", "五湖複浩蕩，歲暮有餘悲。"]'),
('yuding-4','佳人','杜甫','唐','御定全唐诗','yuding','','[]','絕代有佳人，幽居在空穀。自雲良家子，零落依草木。',144,'御定全唐詩/json/218.json','["絕代有佳人，幽居在空穀。自雲良家子，零落依草木。", "關中昔喪敗，兄弟遭殺戮。官高何足論，不得收骨肉。", "世情惡衰歇，萬事隨轉燭。夫婿輕薄兒，新人已如玉。", "合昏尚知時，鴛鴦不獨宿。但見新人笑，那聞舊人哭。", "在山泉水清，出山泉水濁。侍婢賣珠回，牽蘿補茅屋。", "摘花不插發，采柏動盈掬。天寒翠袖薄，日暮倚修竹。"]'),
('yuding-5','赤穀西崦人家','杜甫','唐','御定全唐诗','yuding','','[]','躋險不自喧，出郊已清目。溪回日氣暖，徑轉山田熟。',48,'御定全唐詩/json/218.json','["躋險不自喧，出郊已清目。溪回日氣暖，徑轉山田熟。", "鳥雀依茅茨，藩籬帶松菊。如行武陵暮，欲問桃花宿。"]'),
('yuding-6','西枝村尋置草堂地，夜宿贊公土室二首','杜甫','唐','御定全唐诗','yuding','','[]','出郭眄細岑，披榛得微路。溪行一流水，曲折方屢渡。',240,'御定全唐詩/json/218.json','["出郭眄細岑，披榛得微路。溪行一流水，曲折方屢渡。", "贊公湯休徒，好靜心跡素。昨枉霞上作，盛論岩中趣。", "怡然共攜手，恣意同遠步。捫蘿澀先登，陟巘眩反顧。", "要求陽岡暖，苦陟陰嶺冱。惆悵老大藤，沈吟屈蟠樹。", "卜居意未展，杖策回且暮。層巔餘落日，早蔓已多露。", "天寒鳥已歸，月出人更靜。土室延白光，松門耿疏影。", "躋攀倦日短，語樂寄夜永。明燃林中薪，暗汲石底井。", "大師京國舊，德業天機秉。從來支許遊，興趣江湖迥。", "數奇謫關塞，道廣存箕潁。何知戎馬間，複接塵事屏。", "幽尋豈一路，遠色有諸嶺。晨光稍曚曨，更越西南頂。"]'),
('yuding-7','寄贊上人','杜甫','唐','御定全唐诗','yuding','','[]','一昨陪錫杖，卜鄰南山幽。年侵腰腳衰，未便陰崖秋。',120,'御定全唐詩/json/218.json','["一昨陪錫杖，卜鄰南山幽。年侵腰腳衰，未便陰崖秋。", "重岡北面起，竟日陽光留。茅屋買兼土，斯焉心所求。", "近聞西枝西，有穀杉黍稠。亭午頗和暖，石田又足收。", "當期塞雨幹，宿昔齒疾瘳。裴回虎穴上，面勢龍泓頭。", "柴荊具茶茗，徑路通林丘。與子成二老，來往亦風流。"]'),
('yuding-8','太平寺泉眼','杜甫','唐','御定全唐诗','yuding','','[]','招提憑高岡，疏散連草莽。出泉枯柳根，汲引歲月古。',144,'御定全唐詩/json/218.json','["招提憑高岡，疏散連草莽。出泉枯柳根，汲引歲月古。", "石間見海眼，天畔縈水府。廣深丈尺間，宴息敢輕侮。", "青白二小蛇，幽姿可時睹。如絲氣或上，爛熳為雲雨。", "山頭到山下，鑿井不盡土。取供十方僧，香美勝牛乳。", "北風起寒文，弱藻舒翠縷。明涵客衣淨，細蕩林影趣。", "何當宅下流，餘潤通藥圃。三春濕黃精，一食生毛羽。"]'),
('yuding-9','夢李白二首','杜甫','唐','御定全唐诗','yuding','','[]','死別已吞聲，生別常惻惻。江南瘴癘地，逐客無消息。',192,'御定全唐詩/json/218.json','["死別已吞聲，生別常惻惻。江南瘴癘地，逐客無消息。", "故人入我夢，明我長相憶。恐非平生魂，路遠不可測。", "魂來楓葉青，魂返關塞黑。君今在羅網，何以有羽翼。", "落月滿屋樑，猶疑照顏色。水深波浪闊，無使皎龍得。", "浮雲終日行，遊子久不至。三夜頻夢君，情親見君意。", "告歸常局促，苦道來不易。江湖多風波，舟楫恐失墜。", "出門搔白首，若負平生志。冠蓋滿京華，斯人獨憔悴。", "孰雲網恢恢，將老身反累。千秋萬歲名，寂寞身後事。"]'),
('yuding-10','有懷台州鄭十八司戶','杜甫','唐','御定全唐诗','yuding','','[]','天臺隔三江，風浪無晨暮。鄭公縱得歸，老病不識路。',144,'御定全唐詩/json/218.json','["天臺隔三江，風浪無晨暮。鄭公縱得歸，老病不識路。", "昔如水上鷗，今如罝中兔。性命由他人，悲辛但狂顧。", "山鬼獨一腳，蝮蛇長如樹。呼號傍孤城，歲月誰與度。", "從來禦魑魅，多為才名誤。夫子嵇阮流，更被時俗惡。", "海隅微小吏，眼暗發垂素。黃帽映青袍，非供折腰具。", "平生一杯酒，見我故人遇。相望無所成，乾坤莽回互。"]'),
('yuding-11','遣興五首','杜甫','唐','御定全唐诗','yuding','','[]','蟄龍三冬臥，老鶴萬里心。昔時賢俊人，未遇猶視今。',300,'御定全唐詩/json/218.json','["蟄龍三冬臥，老鶴萬里心。昔時賢俊人，未遇猶視今。", "嵇康不得死，孔明有知音。又如壟底松，用舍在所尋。", "大哉霜雪幹，歲久為枯林。", "昔者龐德公，未曾入州府。襄陽耆舊間，處士節獨苦。", "豈無濟時策，終竟畏羅罟。林茂鳥有歸，水深魚知聚。", "舉家依鹿門，劉表焉得取。", "我今日夜憂，諸弟各異方。不知死與生，何況道路長。", "避寇一分散，饑寒永相望。豈無柴門歸，欲出畏虎狼。", "仰看雲中雁，禽鳥亦有行。", "蓬生非無根，漂蕩隨高風。天寒落萬里，不復歸本叢。", "客子念故宅，三年門巷空。悵望但烽火，戎車滿關東。", "生涯能幾何，常在羈旅中。", "昔在洛陽時，親友相追攀。送客東郊道，遨遊宿南山。", "煙塵阻長河，樹羽成皋間。回首載酒地，豈無一日還。", "丈夫貴壯健，慘戚非朱顏。"]'),
('yuding-12','遣興五首','杜甫','唐','御定全唐诗','yuding','','[]','朔風飄胡雁，慘澹帶砂礫。長林何蕭蕭，秋草萋更碧。',240,'御定全唐詩/json/218.json','["朔風飄胡雁，慘澹帶砂礫。長林何蕭蕭，秋草萋更碧。", "北裏富熏天，高樓夜吹笛。焉知南鄰客，九月猶絺綌。", "長陵銳頭兒，出獵待明發。騂弓金爪鏑，白馬蹴微雪。", "未知所馳逐，但見暮光滅。歸來懸兩狼，門戶有旌節。", "漆有用而割，膏以明自煎。蘭摧白露下，桂折秋風前。", "府中羅舊尹，沙道尚依然。赫赫蕭京兆，今為時所憐。", "猛虎憑其威，往往遭急縛。雷吼徒咆哮，枝撐已在腳。", "忽看皮寢處，無複睛閃爍。人有甚於斯，足以勸元惡。", "朝逢富家葬，前後皆輝光。共指親戚大，緦麻百夫行。", "送者各有死，不須羨其強。君看束練去，亦得歸山岡。"]'),
('yuding-13','遣興五首','杜甫','唐','御定全唐诗','yuding','','[]','天用莫如龍，有時系扶桑。頓轡海徒湧，神人身更長。',240,'御定全唐詩/json/218.json','["天用莫如龍，有時系扶桑。頓轡海徒湧，神人身更長。", "性命苟不存，英雄徒自強。吞聲勿複道，真宰意茫茫。", "地用莫如馬，無良複誰記。此日千里鳴，追風可君意。", "君看渥窪種，態與駑駘異。不雜蹄齧間，逍遙有能事。", "陶潛避俗翁，未必能達道。觀其著詩集，頗亦恨枯槁。", "達生豈是足，默識蓋不早。有子賢與愚，何其掛懷抱。", "賀公雅吳語，在位常清狂。上疏乞骸骨，黃冠歸故鄉。", "爽氣不可致，斯人今則亡。山陰一茅宇，江海日淒涼。", "吾憐孟浩然，裋褐即長夜。賦詩何必多，往往淩鮑謝。", "清江空舊魚，春雨餘甘蔗。每望東南雲，令人幾悲吒。"]'),
('yuding-14','前出塞九首','杜甫','唐','御定全唐诗','yuding','','[]','戚戚去故里，悠悠赴交河。公家有程期，亡命嬰禍羅。',432,'御定全唐詩/json/218.json','["戚戚去故里，悠悠赴交河。公家有程期，亡命嬰禍羅。", "君已富土境，開邊一何多。棄絕父母恩，吞聲行負戈。", "出門日已遠，不受徒旅欺。骨肉恩豈斷，男兒死無時。", "走馬脫轡頭，手中挑青絲。捷下萬仞岡，俯身試搴旗。", "磨刀嗚咽水，水赤刃傷手。欲輕腸斷聲，心緒亂已久。", "丈夫誓許國，憤惋複何有。功名圖騏驎，戰骨當速朽。", "送徒既有長，遠戍亦有身。生死向前去，不勞吏怒嗔。", "路逢相識人，附書與六親。哀哉兩決絕，不復同苦辛。", "迢迢萬餘裏，領我赴三軍。軍中異苦樂，主將甯盡聞。", "隔河見胡騎，倏忽數百群。我始為奴僕，幾時樹功勳。", "挽弓當挽強，用箭當用長。射人先射馬，擒賊先擒王。", "殺人亦有限，列國自有疆。苟能制侵陵，豈在多殺傷。", "驅馬天雨雪，軍行入高山。徑危抱寒石，指落曾冰間。", "已去漢月遠，何時築城還。浮雲暮南征，可望不可攀。", "單于寇我壘，百里風塵昏。雄劍四五動，彼軍為我奔。", "虜其名王歸，系頸授轅門。潛身備行列，一勝何足論。", "從軍十年餘，能無分寸功。眾人貴苟得，欲語羞雷同。", "中原有鬥爭，況在狄與戎。丈夫四方志，安可辭固窮。"]'),
('yuding-15','後出塞五首','杜甫','唐','御定全唐诗','yuding','','[]','男兒生世間，及壯當封侯。戰伐有功業，焉能守舊丘。',372,'御定全唐詩/json/218.json','["男兒生世間，及壯當封侯。戰伐有功業，焉能守舊丘。", "召募赴薊門，軍動不可留。千金買馬鞭，百金裝刀頭。", "閭裏送我行，親戚擁道周。斑白居上列，酒酣進庶羞。", "少年別有贈，含笑看吳鉤。", "朝進東門營，暮上河陽橋。落日照大旗，馬鳴風蕭蕭。", "平沙列萬幕，部伍各見招。中天懸明月，令嚴夜寂寥。", "悲笳數聲動，壯士慘不驕。借問大將誰，恐是霍嫖姚。", "古人重守邊，今人重高勳。豈知英雄主，出師亙長雲。", "六合已一家，四夷且孤軍。遂使貔虎士，奮身勇所聞。", "拔劍擊大荒，日收胡馬群。誓開玄冥北，持以奉吾君。", "獻凱日繼踵，兩蕃靜無虞。漁陽豪俠地，擊鼓吹笙竽。", "雲帆轉遼海，粳稻來東吳。越羅與楚練，照耀輿台軀。", "主將位益崇，氣驕淩上都。邊人不敢議，議者死路衢。", "我本良家子，出師亦多門。將驕益愁思，身貴不足論。", "躍馬二十年，恐辜明主恩。坐見幽州騎，長驅河洛昏。", "中夜間道歸，故里但空村。惡名幸脫免，窮老無兒孫。"]'),
('yuding-16','別贊上人','杜甫','唐','御定全唐诗','yuding','','[]','百川日東流，客去亦不息。我生苦漂蕩，何時有終極。',144,'御定全唐詩/json/218.json','["百川日東流，客去亦不息。我生苦漂蕩，何時有終極。", "贊公釋門老，放逐來上國。還為世塵嬰，頗帶憔悴色。", "楊枝晨在手，豆子雨已熟。是身如浮雲，安可限南北。", "異縣逢舊友，初忻寫胸臆。天長關塞寒，歲暮饑凍逼。", "野風吹征衣，欲別向曛黑。馬嘶思故櫪，歸鳥盡斂翼。", "古來聚散地，宿昔長荊棘。相看俱衰年，出處各努力。"]'),
('yuding-17','萬丈潭','杜甫','唐','御定全唐诗','yuding','','[]','青溪合冥莫，神物有顯晦。龍依積水蟠，窟壓萬丈內。',168,'御定全唐詩/json/218.json','["青溪合冥莫，神物有顯晦。龍依積水蟠，窟壓萬丈內。", "局步淩垠堮，側身下煙靄。前臨洪濤寬，卻立蒼石大。", "山色一徑盡，崖絕兩壁對。削成根虛無，倒影垂澹瀩。", "黑如灣澴底，清見光炯碎。孤雲倒來深，飛鳥不在外。", "高蘿成帷幄，寒木累旌旆。遠川曲通流，嵌竇潛泄瀨。", "造幽無人境，發興自我輩。告歸遺恨多，將老斯遊最。", "閉藏修鱗蟄，出入巨石礙。何事暑天過，快意風雨會。"]'),
('yuding-18','兩當縣吳十侍禦江上宅','杜甫','唐','御定全唐诗','yuding','','[]','寒城朝煙澹，山谷落葉赤。陰風千里來，吹汝江上宅。',216,'御定全唐詩/json/218.json','["寒城朝煙澹，山谷落葉赤。陰風千里來，吹汝江上宅。", "鶤雞號枉渚，日色傍阡陌。借問持斧翁，幾年長沙客。", "哀哀失木狖，矯矯避弓翮。亦知故鄉樂，未敢思夙昔。", "昔在鳳翔都，共通金閨籍。天子猶蒙塵，東郊暗長戟。", "兵家忌間諜，此輩常接跡。台中領舉劾，君必慎剖析。", "不忍殺無辜，所以分白黑。上官權許與，失意見遷斥。", "仲尼甘旅人，向子識損益。朝廷非不知，閉口休歎息。", "余時忝諍臣，丹陛實咫尺。相看受狼狽，至死難塞責。", "行邁心多違，出門無與適。於公負明義，惆悵頭更白。"]'),
('yuding-19','發秦州','杜甫','唐','御定全唐诗','yuding','','[]','我衰更懶拙，生事不自謀。無食問樂土，無衣思南州。',192,'御定全唐詩/json/218.json','["我衰更懶拙，生事不自謀。無食問樂土，無衣思南州。", "漢源十月交，天氣涼如秋。草木未黃落，況聞山水幽。", "栗亭名更佳，下有良田疇。充腸多薯蕷，崖蜜亦易求。", "密竹複冬筍，清池可方舟。雖傷旅寓遠，庶遂平生遊。", "此邦俯要衝，實恐人事稠。應接非本性，登臨未銷憂。", "溪谷無異石，塞田始微收。豈複慰老夫，惘然難久留。", "日色隱孤戍，烏啼滿城頭。中宵驅車去，飲馬寒塘流。", "磊落星月高，蒼茫雲霧浮。大哉乾坤內，吾道長悠悠。"]'),
('yuding-20','赤谷','杜甫','唐','御定全唐诗','yuding','','[]','天寒霜雪繁，遊子有所之。豈但歲月暮，重來未有期。',96,'御定全唐詩/json/218.json','["天寒霜雪繁，遊子有所之。豈但歲月暮，重來未有期。", "晨發赤穀亭，險艱方自茲。亂石無改轍，我車已載脂。", "山深苦多風，落日童稚饑。悄然村墟迥，煙火何由追。", "貧病轉零落，故鄉不可思。常恐死道路，永為高人嗤。"]'),
('yuding-21','鐵堂峽','杜甫','唐','御定全唐诗','yuding','','[]','山風吹遊子，縹緲乘險絕。峽形藏堂隍，壁色立積鐵。',96,'御定全唐詩/json/218.json','["山風吹遊子，縹緲乘險絕。峽形藏堂隍，壁色立積鐵。", "徑摩穹蒼蟠，石與厚地裂。修纖無垠竹，嵌空太始雪。", "威遲哀壑底，徒旅慘不悅。水寒長冰橫，我馬骨正折。", "生涯抵弧矢，盜賊殊未滅。飄蓬逾三年，回首肝肺熱。"]'),
('yuding-22','鹽井','杜甫','唐','御定全唐诗','yuding','','[]','鹵中草木白，青者官鹽煙。官作既有程，煮鹽煙在川。',72,'御定全唐詩/json/218.json','["鹵中草木白，青者官鹽煙。官作既有程，煮鹽煙在川。", "汲井歲榾榾，出車日連連。自公鬥三百，轉致斛六千。", "君子慎止足，小人苦喧闐。我何良歎嗟，物理固自然。"]'),
('yuding-23','寒硤','杜甫','唐','御定全唐诗','yuding','','[]','行邁日悄悄，山谷勢多端。雲門轉絕岸，積阻霾天寒。',72,'御定全唐詩/json/218.json','["行邁日悄悄，山谷勢多端。雲門轉絕岸，積阻霾天寒。", "寒硤不可度，我實衣裳單。況當仲冬交，溯沿增波瀾。", "野人尋煙語，行子傍水餐。此生免荷殳，未敢辭路難。"]'),
('yuding-24','法鏡寺','杜甫','唐','御定全唐诗','yuding','','[]','身危適他州，勉強終勞苦。神傷山行深，愁破崖寺古。',96,'御定全唐詩/json/218.json','["身危適他州，勉強終勞苦。神傷山行深，愁破崖寺古。", "嬋娟碧鮮淨，蕭摵寒籜聚。回回山根水，冉冉松上雨。", "泄雲蒙清晨，初日翳複吐。朱甍半光炯，戶牖粲可數。", "拄策忘前期，出蘿已亭午。冥冥子規叫，微徑不復取。"]'),
('yuding-25','青陽峽','杜甫','唐','御定全唐诗','yuding','','[]','塞外苦厭山，南行道彌惡。岡巒相經亙，雲水氣參錯。',120,'御定全唐詩/json/218.json','["塞外苦厭山，南行道彌惡。岡巒相經亙，雲水氣參錯。", "林迥硤角來，天窄壁面削。溪西五裏石，奮怒向我落。", "仰看日車側，俯恐坤軸弱。魑魅嘯有風，霜霰浩漠漠。", "昨憶逾隴阪，高秋視吳嶽。東笑蓮華卑，北知崆峒薄。", "超然侔壯觀，已謂殷寥廓。突兀猶趁人，及茲歎冥莫。"]'),
('yuding-26','龍門鎮','杜甫','唐','御定全唐诗','yuding','','[]','細泉兼輕冰，沮洳棧道濕。不辭辛苦行，迫此短景急。',72,'御定全唐詩/json/218.json','["細泉兼輕冰，沮洳棧道濕。不辭辛苦行，迫此短景急。", "石門雪雲隘，古鎮峰巒集。旌竿暮慘澹，風水白刃澀。", "胡馬屯成皋，防虞此何及。嗟爾遠戍人，山寒夜中泣。"]'),
('yuding-27','石龕','杜甫','唐','御定全唐诗','yuding','','[]','熊羆哮我東，虎豹號我西。我後鬼長嘯，我前狨又啼。',96,'御定全唐詩/json/218.json','["熊羆哮我東，虎豹號我西。我後鬼長嘯，我前狨又啼。", "天寒昏無日，山遠道路迷。驅車石龕下，仲冬見虹霓。", "伐竹者誰子，悲歌上雲梯。為官采美箭，五歲供梁齊。", "苦雲直簳盡，無以充提攜。奈何漁陽騎，颯颯驚烝黎。"]'),
('yuding-28','積草嶺','杜甫','唐','御定全唐诗','yuding','','[]','連峰積長陰，白日遞隱見。颼颼林響交，慘慘石狀變。',96,'御定全唐詩/json/218.json','["連峰積長陰，白日遞隱見。颼颼林響交，慘慘石狀變。", "山分積草嶺，路異明水縣。旅泊吾道窮，衰年歲時倦。", "卜居尚百里，休駕投諸彥。邑有佳主人，情如已會面。", "來書語絕妙，遠客驚深眷。食蕨不願餘，茅茨眼中見。"]'),
('yuding-29','泥功山','杜甫','唐','御定全唐诗','yuding','','[]','朝行青泥上，暮在青泥中。泥濘非一時，版築勞人功。',72,'御定全唐詩/json/218.json','["朝行青泥上，暮在青泥中。泥濘非一時，版築勞人功。", "不畏道途永，乃將汩沒同。白馬為鐵驪，小兒成老翁。", "哀猿透卻墜，死鹿力所窮。寄語北來人，後來莫匆匆。"]'),
('yuding-30','鳳凰台','杜甫','唐','御定全唐诗','yuding','','[]','亭亭鳳凰台，北對西康州。西伯今寂寞，鳳聲亦悠悠。',168,'御定全唐詩/json/218.json','["亭亭鳳凰台，北對西康州。西伯今寂寞，鳳聲亦悠悠。", "山峻路絕蹤，石林氣高浮。安得萬丈梯，為君上上頭。", "恐有無母雛，饑寒日啾啾。我能剖心出，飲啄慰孤愁。", "心以當竹實，炯然無外求。血以當醴泉，豈徒比清流。", "所貴王者瑞，敢辭微命休。坐看彩翮長，舉意八極周。", "自天銜瑞圖，飛下十二樓。圖以奉至尊，鳳以垂鴻猷。", "再光中興業，一洗蒼生憂。深衷正為此，群盜何淹留。"]'),
('yuding-31','幹元中寓居同穀縣，作歌七首','杜甫','唐','御定全唐诗','yuding','','[]','有客有客字子美，白頭亂髮垂過耳。歲拾橡栗隨狙公，',289,'御定全唐詩/json/218.json','["有客有客字子美，白頭亂髮垂過耳。歲拾橡栗隨狙公，", "嗚呼一歌兮歌已哀，悲風為我從天來。", "長鑱長鑱白木柄，我生托子以為命。黃精無苗山雪盛，", "嗚呼二歌兮歌始放，鄰里為我色惆悵。", "有弟有弟在遠方，三人各瘦何人強。生別輾轉不相見，", "嗚呼三歌兮歌三發，汝歸何處收兄骨。", "有妹有妹在鐘離，良人早歿諸孤癡。長淮浪高蛟龍怒，", "嗚呼四歌兮歌四奏，林猿為我啼清晝。", "四山多風溪水急，寒雨颯颯枯樹濕。黃蒿古城雲不開，", "嗚呼五歌兮歌正長，魂招不來歸故鄉。", "南有龍兮在山湫，古木巃嵸枝相樛。木葉黃落龍正蟄，", "嗚呼六歌兮歌思遲，溪壑為我回春姿。", "男兒生不成名身已老，三年饑走荒山道。長安卿相多少年，", "嗚呼七歌兮悄終曲，仰視皇天白日速。"]'),
('yuding-32','發同穀縣','杜甫','唐','御定全唐诗','yuding','','[]','賢有不黔突，聖有不暖席。況我饑愚人，焉能尚安宅。',120,'御定全唐詩/json/218.json','["賢有不黔突，聖有不暖席。況我饑愚人，焉能尚安宅。", "始來茲山中，休駕喜地僻。奈何迫物累，一歲四行役。", "忡忡去絕境，杳杳更遠適。停驂龍潭雲，回首白崖石。", "臨岐別數子，握手淚再滴。交情無舊深，窮老多慘戚。", "平生懶拙意，偶值棲遁跡。去住與願違，仰慚林間翮。"]'),
('yuding-33','木皮嶺','杜甫','唐','御定全唐诗','yuding','','[]','首路栗亭西，尚想鳳凰村。季冬攜童稚，辛苦赴蜀門。',168,'御定全唐詩/json/218.json','["首路栗亭西，尚想鳳凰村。季冬攜童稚，辛苦赴蜀門。", "南登木皮嶺，艱險不易論。汗流被我體，祁寒為之暄。", "遠岫爭輔佐，千岩自崩奔。始知五嶽外，別有他山尊。", "仰幹塞大明，俯入裂厚坤。再聞虎豹鬥，屢局風水昏。", "高有廢閣道，摧折如短轅。下有冬青林，石上走長根。", "西崖特秀髮，煥若靈芝繁。潤聚金碧氣，清無沙土痕。", "憶觀昆侖圖，目擊懸圃存。對此欲何適，默傷垂老魂。"]'),
('yuding-34','白沙渡','杜甫','唐','御定全唐诗','yuding','','[]','畏途隨長江，渡口下絕岸。差池上舟楫，杳窕入雲漢。',96,'御定全唐詩/json/218.json','["畏途隨長江，渡口下絕岸。差池上舟楫，杳窕入雲漢。", "天寒荒野外，日暮中流半。我馬向北嘶，山猿飲相喚。", "水清石礧礧，沙白灘漫漫。迥然洗愁辛，多病一疏散。", "高壁抵嶔崟，洪濤越淩亂。臨風獨回首，攬轡複三歎。"]'),
('yuding-35','水會渡','杜甫','唐','御定全唐诗','yuding','','[]','山行有常程，中夜尚未安。微月沒已久，崖傾路何難。',96,'御定全唐詩/json/218.json','["山行有常程，中夜尚未安。微月沒已久，崖傾路何難。", "大江動我前，洶若溟渤寬。篙師暗理楫，歌笑輕波瀾。", "霜濃木石滑，風急手足寒。入舟已千憂，陟巘仍萬盤。", "迥眺積水外，始知眾星幹。遠遊令人瘦，衰疾慚加餐。"]'),
('yuding-36','飛仙閣','杜甫','唐','御定全唐诗','yuding','','[]','土門山行窄，微徑緣秋毫。棧雲闌幹峻，梯石結構牢。',96,'御定全唐詩/json/218.json','["土門山行窄，微徑緣秋毫。棧雲闌幹峻，梯石結構牢。", "萬壑欹疏林，積陰帶奔濤。寒日外澹泊，長風中怒號。", "歇鞍在地底，始覺所曆高。往來雜坐臥，人馬同疲勞。", "浮生有定分，饑飽豈可逃。歎息謂妻子，我何隨汝曹。"]'),
('yuding-37','五盤','杜甫','唐','御定全唐诗','yuding','','[]','五盤雖雲險，山色佳有餘。仰淩棧道細，俯映江木疏。',96,'御定全唐詩/json/218.json','["五盤雖雲險，山色佳有餘。仰淩棧道細，俯映江木疏。", "地僻無網罟，水清反多魚。好鳥不妄飛，野人半巢居。", "喜見淳樸俗，坦然心神舒。東郊尚格鬥，巨猾何時除。", "故鄉有弟妹，流落隨丘墟。成都萬事好，豈若歸吾廬。"]'),
('yuding-38','龍門閣','杜甫','唐','御定全唐诗','yuding','','[]','清江下龍門，絕壁無尺土。長風駕高浪，浩浩自太古。',96,'御定全唐詩/json/218.json','["清江下龍門，絕壁無尺土。長風駕高浪，浩浩自太古。", "危途中縈盤，仰望垂線縷。滑石欹誰鑿，浮梁嫋相拄。", "目眩隕雜花，頭風吹過雨。百年不敢料，一墜那得取。", "飽聞經瞿塘，足見度大庾。終身曆艱險，恐懼從此數。"]'),
('yuding-39','石櫃閣','杜甫','唐','御定全唐诗','yuding','','[]','季冬日已長，山晚半天赤。蜀道多早花，江間饒奇石。',96,'御定全唐詩/json/218.json','["季冬日已長，山晚半天赤。蜀道多早花，江間饒奇石。", "石櫃曾波上，臨虛蕩高壁。清暉回群鷗，暝色帶遠客。", "羈棲負幽意，感歎向絕跡。信甘孱懦嬰，不獨凍餒迫。", "優遊謝康樂，放浪陶彭澤。吾衰未自安，謝爾性所適。"]'),
('yuding-40','桔柏渡','杜甫','唐','御定全唐诗','yuding','','[]','青冥寒江渡，駕竹為長橋。竿濕煙漠漠，江永風蕭蕭。',96,'御定全唐詩/json/218.json','["青冥寒江渡，駕竹為長橋。竿濕煙漠漠，江永風蕭蕭。", "連笮動嫋娜，征衣颯飄颻。急流鴇鷁散，絕岸黿鼉驕。", "西轅自茲異，東逝不可要。高通荊門路，闊會滄海潮。", "孤光隱顧眄，遊子悵寂寥。無以洗心胸，前登但山椒。"]'),
('yuding-41','劍門','杜甫','唐','御定全唐诗','yuding','','[]','惟天有設險，劍門天下壯。連山抱西南，石角皆北向。',132,'御定全唐詩/json/218.json','["惟天有設險，劍門天下壯。連山抱西南，石角皆北向。", "兩崖崇墉倚，刻畫城郭狀。一夫怒臨關，百萬未可傍。", "珠玉走中原，岷峨氣悽愴。三皇五帝前，雞犬各相放。", "後王尚柔遠，職貢道已喪。至今英雄人，高視見霸王。", "併吞與割據，極力不相讓。吾將罪真宰，意欲鏟疊嶂。", "恐此複偶然，臨風默惆悵。"]'),
('yuding-42','鹿頭山','杜甫','唐','御定全唐诗','yuding','','[]','鹿頭何亭亭，是日慰饑渴。連山西南斷，俯見千里豁。',144,'御定全唐詩/json/218.json','["鹿頭何亭亭，是日慰饑渴。連山西南斷，俯見千里豁。", "遊子出京華，劍門不可越。及茲險阻盡，始喜原野闊。", "殊方昔三分，霸氣曾間發。天下今一家，雲端失雙闕。", "悠然想揚馬，繼起名硉兀。有文令人傷，何處埋爾骨。", "紆餘脂膏地，慘澹豪俠窟。仗鉞非老臣，宣風豈專達。", "冀公柱石姿，論道邦國活。斯人亦何幸，公鎮逾歲月。"]'),
('yuding-43','成都府','杜甫','唐','御定全唐诗','yuding','','[]','翳翳桑榆日，照我征衣裳。我行山川異，忽在天一方。',120,'御定全唐詩/json/218.json','["翳翳桑榆日，照我征衣裳。我行山川異，忽在天一方。", "但逢新人民，未蔔見故鄉。大江東流去，遊子去日長。", "曾城填華屋，季冬樹木蒼。喧然名都會，吹簫間笙簧。", "信美無與適，側身望川梁。鳥雀夜各歸，中原杳茫茫。", "初月出不高，眾星尚爭光。自古有羈旅，我何苦哀傷。"]'),
('yuding-0','石筍行','杜甫','唐','御定全唐诗','yuding','','[]','君不見益州城西門，陌上石筍雙高蹲。古來相傳是海眼，',73,'御定全唐詩/json/219.json','["君不見益州城西門，陌上石筍雙高蹲。古來相傳是海眼，", "恐是昔時卿相墓，立石為表今仍存。惜哉俗態好蒙蔽，", "嗟爾石筍擅虛名，後來未識猶駿奔。安得壯士擲天外，"]'),
('yuding-1','石犀行','杜甫','唐','御定全唐诗','yuding','','[]','君不見秦時蜀太守，刻石立作三犀牛。自古雖有厭勝法，',73,'御定全唐詩/json/219.json','["君不見秦時蜀太守，刻石立作三犀牛。自古雖有厭勝法，", "今年灌口損戶口，此事或恐為神羞。終藉堤防出眾力，", "嗟爾三犀不經濟，缺訛只與長川逝。但見元氣常調和，"]'),
('yuding-2','杜鵑行','杜甫','唐','御定全唐诗','yuding','','[]','君不見昔日蜀天子，化作杜鵑似老烏。寄巢生子不自啄，',73,'御定全唐詩/json/219.json','["君不見昔日蜀天子，化作杜鵑似老烏。寄巢生子不自啄，", "業工竄伏深樹裏，四月五月偏號呼。其聲哀痛口流血，", "蒼天變化誰料得，萬事反復何所無。萬事反復何所無，"]'),
('yuding-3','贈蜀僧閭丘師兄','杜甫','唐','御定全唐诗','yuding','','[]','大師銅梁秀，籍籍名家孫。嗚呼先博士，炳靈精氣奔。',264,'御定全唐詩/json/219.json','["大師銅梁秀，籍籍名家孫。嗚呼先博士，炳靈精氣奔。", "惟昔武皇后，臨軒禦乾坤。多士盡儒冠，墨客藹雲屯。", "當時上紫殿，不獨卿相尊。世傳閭丘筆，峻極逾昆侖。", "鳳藏丹霄暮，龍去白水渾。青熒雪嶺東，碑碣舊制存。", "斯文散都邑，高價越璵璠。晚看作者意，妙絕與誰論。", "吾祖詩冠古，同年蒙主恩。豫章夾日月，歲久空深根。", "小子思疏闊，豈能達詞門。窮愁一揮淚，相遇即諸昆。", "我住錦官城，兄居祇樹園。地近慰旅愁，往來當丘樊。", "天涯歇滯雨，粳稻臥不翻。漂然薄遊倦，始與道侶敦。", "景晏步修廊，而無車馬喧。夜闌接軟語，落月如金盆。", "漠漠世界黑，驅車爭奪繁。惟有摩尼珠，可照濁水源。"]'),
('yuding-4','泛溪','杜甫','唐','御定全唐诗','yuding','','[]','落景下高堂，進舟泛回溪。誰謂築居小，未盡喬木西。',144,'御定全唐詩/json/219.json','["落景下高堂，進舟泛回溪。誰謂築居小，未盡喬木西。", "遠郊信荒僻，秋色有餘淒。練練峰上雪，纖纖雲表霓。", "童戲左右岸，罟弋畢提攜。翻倒荷芰亂，指揮徑路迷。", "得魚已割鱗，采藕不洗泥。人情逐鮮美，物賤事已睽。", "吾村靄暝姿，異舍雞亦棲。蕭條欲何適，出處無可齊。", "衣上見新月，霜中登故畦。濁醪自初熟，東城多鼓鼙。"]'),
('yuding-5','題壁畫馬歌','杜甫','唐','御定全唐诗','yuding','','[]','韋侯別我有所適，知我憐君畫無敵。戲拈禿筆掃驊騮，',40,'御定全唐詩/json/219.json','["韋侯別我有所適，知我憐君畫無敵。戲拈禿筆掃驊騮，", "時危安得真致此，與人同生亦同死。"]'),
('yuding-6','戲題畫山水圖歌','杜甫','唐','御定全唐诗','yuding','','[]','十日畫一水，五日畫一石。能事不受相促迫，',68,'御定全唐詩/json/219.json','["十日畫一水，五日畫一石。能事不受相促迫，", "巴陵洞庭日本東，赤岸水與銀河通，中有雲氣隨飛龍。", "舟人漁子入浦漵，山木盡亞洪濤風。尤工遠勢古莫比，"]'),
('yuding-7','題李尊師松樹障子歌','杜甫','唐','御定全唐诗','yuding','','[]','老夫清晨梳白頭，玄都道士來相訪。握發呼兒延入戶，',72,'御定全唐詩/json/219.json','["老夫清晨梳白頭，玄都道士來相訪。握發呼兒延入戶，", "陰崖卻承霜雪幹，偃蓋反走虯龍形。老夫平生好奇古，", "松下丈人巾屨同，偶坐似是商山翁。悵望聊歌紫芝曲，"]'),
('yuding-8','戲為雙松圖歌','杜甫','唐','御定全唐诗','yuding','','[]','天下幾人畫古松，畢宏已老韋偃少。絕筆長風起纖末，',88,'御定全唐詩/json/219.json','["天下幾人畫古松，畢宏已老韋偃少。絕筆長風起纖末，", "白摧朽骨龍虎死，黑入太陰雷雨垂，松根胡僧憩寂寞，", "韋侯韋侯數相見，我有一匹好東絹，重之不減錦繡段。", "已令拂拭光淩亂，請公放筆為直幹。"]'),
('yuding-9','投簡成、華兩縣諸子','杜甫','唐','御定全唐诗','yuding','','[]','赤縣官曹擁材傑，軟裘快馬當冰雪。長安苦寒誰獨悲，',65,'御定全唐詩/json/219.json','["赤縣官曹擁材傑，軟裘快馬當冰雪。長安苦寒誰獨悲，", "鄉里兒童項領成，朝廷故舊禮數絕。自然棄擲與時異，", "君不見空牆日色晚，此老無聲淚垂血。"]'),
('yuding-10','徐卿二子歌','杜甫','唐','御定全唐诗','yuding','','[]','君不見徐卿二子生絕奇，感應吉夢相追隨。',78,'御定全唐詩/json/219.json','["君不見徐卿二子生絕奇，感應吉夢相追隨。", "孔子釋氏親抱送，並是天上麒麟兒。大兒九齡色清澈，", "吾知徐公百不憂，積善袞袞生公侯。", "丈夫生兒有如此二雛者，名位豈肯卑微休。"]'),
('yuding-11','病柏','杜甫','唐','御定全唐诗','yuding','','[]','有柏生崇岡，童童狀車蓋。偃蹙龍虎姿，主當風雲會。',120,'御定全唐詩/json/219.json','["有柏生崇岡，童童狀車蓋。偃蹙龍虎姿，主當風雲會。", "神明依正直，故老多再拜。豈知千年根，中路顏色壞。", "出非不得地，蟠據亦高大。歲寒忽無憑，日夜柯葉改。", "丹鳳領九雛，哀鳴翔其外。鴟鴞志意滿，養子穿穴內。", "客從何鄉來，佇立久籲怪。靜求元精理，浩蕩難倚賴。"]'),
('yuding-12','病橘','杜甫','唐','御定全唐诗','yuding','','[]','群橘少生意，雖多亦奚為。惜哉結實小，酸澀如棠梨。',144,'御定全唐詩/json/219.json','["群橘少生意，雖多亦奚為。惜哉結實小，酸澀如棠梨。", "剖之盡蠹蟲，采掇爽其宜。紛然不適口，豈只存其皮。", "蕭蕭半死葉，未忍別故枝。玄冬霜雪積，況乃回風吹。", "嘗聞蓬萊殿，羅列瀟湘姿。此物歲不稔，玉食失光輝。", "寇盜尚憑陵，當君減膳時。汝病是天意，吾諗罪有司。", "憶昔南海使，奔騰獻荔支。百馬死山谷，到今耆舊悲。"]'),
('yuding-13','枯棕','杜甫','唐','御定全唐诗','yuding','','[]','蜀門多棕櫚，高者十八九。其皮割剝甚，雖眾亦易朽。',120,'御定全唐詩/json/219.json','["蜀門多棕櫚，高者十八九。其皮割剝甚，雖眾亦易朽。", "徒布如雲葉，青黃歲寒後。交橫集斧斤，凋喪先蒲柳。", "傷時苦軍乏，一物官盡取。嗟爾江漢人，生成複何有。", "有同枯棕木，使我沈歎久。死者即已休，生者何自守。", "啾啾黃雀啅，側見寒蓬走。念爾形影幹，摧殘沒藜莠。"]'),
('yuding-14','枯楠','杜甫','唐','御定全唐诗','yuding','','[]','楩楠枯崢嶸，鄉党皆莫記。不知幾百歲，慘慘無生意。',120,'御定全唐詩/json/219.json','["楩楠枯崢嶸，鄉党皆莫記。不知幾百歲，慘慘無生意。", "上枝摩皇天，下根蟠厚地。巨圍雷霆坼，萬孔蟲蟻萃。", "凍雨落流膠，沖風奪佳氣。白鵠遂不來，天雞為愁思。", "猶含棟樑具，無複霄漢志。良工古昔少，識者出涕淚。", "種榆水中央，成長何容易。截承金露盤，嫋嫋不自畏。"]'),
('yuding-15','麗春','杜甫','唐','御定全唐诗','yuding','','[]','百草競春華，麗春應最勝。少須好顏色，多漫枝條剩。',48,'御定全唐詩/json/219.json','["百草競春華，麗春應最勝。少須好顏色，多漫枝條剩。", "紛紛桃李枝，處處總能移。如何貴此重，卻怕有人知。"]'),
('yuding-16','丈人山','杜甫','唐','御定全唐诗','yuding','','[]','自為青城客，不唾青城地。為愛丈人山，丹梯近幽意。',48,'御定全唐詩/json/219.json','["自為青城客，不唾青城地。為愛丈人山，丹梯近幽意。", "丈人祠西佳氣濃，緣雲擬住最高峰。掃除白髮黃精在，"]'),
('yuding-17','百憂集行','杜甫','唐','御定全唐诗','yuding','','[]','憶年十五心尚孩，健如黃犢走複來。庭前八月梨棗熟，',48,'御定全唐詩/json/219.json','["憶年十五心尚孩，健如黃犢走複來。庭前八月梨棗熟，", "強將笑語供主人，悲見生涯百憂集。入門依舊四壁空，"]'),
('yuding-18','戲作花卿歌','杜甫','唐','御定全唐诗','yuding','','[]','成都猛將有花卿，學語小兒知姓名。用如快鶻風火生，',48,'御定全唐詩/json/219.json','["成都猛將有花卿，學語小兒知姓名。用如快鶻風火生，", "子章髑髏血模糊，手提擲還崔大夫。李侯重有此節度，"]'),
('yuding-19','入奏行，贈西山檢察使竇侍禦','杜甫','唐','御定全唐诗','yuding','','[]','竇侍禦，驥之子，鳳之雛。年未三十忠義俱，骨鯁絕代無。',152,'御定全唐詩/json/219.json','["竇侍禦，驥之子，鳳之雛。年未三十忠義俱，骨鯁絕代無。", "炯如一段清冰出萬壑，置在迎風寒露之玉壺。", "蔗漿歸廚金碗凍，洗滌煩熱足以寧君軀。", "政用疏通合典則，戚聯豪貴耽文儒。兵革未息人未蘇，", "運糧繩橋壯士喜，斬木火井窮猿呼。八州刺史思一戰，", "繡衣春當霄漢立，彩服日向庭闈趨。省郎京尹必俯拾，", "為君酤酒滿眼酤，與奴白飯馬青芻。"]'),
('yuding-20','楠樹為風雨所拔歎','杜甫','唐','御定全唐诗','yuding','','[]','倚江楠樹草堂前，故老相傳二百年。誅茅卜居總為此，',72,'御定全唐詩/json/219.json','["倚江楠樹草堂前，故老相傳二百年。誅茅卜居總為此，", "幹排雷雨猶力爭，根斷泉源豈天意。滄波老樹性所愛，", "虎倒龍顛委榛棘，淚痕血點垂胸臆。我有新詩何處吟，"]'),
('yuding-21','茅屋為秋風所破歌','杜甫','唐','御定全唐诗','yuding','','[]','八月秋高風怒號，卷我屋上三重茅。茅飛度江灑江郊，',96,'御定全唐詩/json/219.json','["八月秋高風怒號，卷我屋上三重茅。茅飛度江灑江郊，", "布衾多年冷似鐵，驕兒惡臥踏裏裂。床床屋漏無干處，", "安得廣廈千萬間，大庇天下寒士俱歡顏，風雨不動安如山。", "嗚呼何時眼前突兀見此屋，吾廬獨破受凍死亦足。"]'),
('yuding-22','大雨','杜甫','唐','御定全唐诗','yuding','','[]','西蜀冬不雪，春農尚嗷嗷。上天回哀眷，朱夏雲郁陶。',144,'御定全唐詩/json/219.json','["西蜀冬不雪，春農尚嗷嗷。上天回哀眷，朱夏雲郁陶。", "執熱乃沸鼎，纖絺成縕袍。風雷颯萬里，霈澤施蓬蒿。", "敢辭茅葦漏，已喜黍豆高。三日無行人，二江聲怒號。", "流惡邑裏清，矧茲遠江皋。荒庭步鸛鶴，隱幾望波濤。", "沉屙聚藥餌，頓忘所進勞。則知潤物功，可以貸不毛。", "陰色靜隴畝，勸耕自官曹。四鄰耒耜出，何必吾家操。"]'),
('yuding-23','溪漲','杜甫','唐','御定全唐诗','yuding','','[]','當時浣花橋，溪水才尺餘。白石明可把，水中有行車。',120,'御定全唐詩/json/219.json','["當時浣花橋，溪水才尺餘。白石明可把，水中有行車。", "秋夏忽泛溢，豈惟入吾廬。蛟龍亦狼狽，況是鱉與魚。", "茲晨已半落，歸路跬步疏。馬嘶未敢動，前有深填淤。", "青青屋東麻，散亂床上書。不意遠山雨，夜來複何如。", "我遊都市間，晚憩必村墟。乃知久行客，終日思其居。"]'),
('yuding-24','戲贈友二首','杜甫','唐','御定全唐诗','yuding','','[]','元年建巳月，郎有焦校書。自誇足膂力，能騎生馬駒。',96,'御定全唐詩/json/219.json','["元年建巳月，郎有焦校書。自誇足膂力，能騎生馬駒。", "一朝被馬踏，唇裂版齒無。壯心不肯已，欲得東擒胡。", "元年建巳月，官有王司直。馬驚折左臂，骨折面如墨。", "駑駘漫深泥，何不避雨色。勸君休歎恨，未必不為福。"]'),
('yuding-25','遭田父泥飲美嚴中丞','杜甫','唐','御定全唐诗','yuding','','[]','步屟隨春風，村村自花柳。田翁逼社日，邀我嘗春酒。',192,'御定全唐詩/json/219.json','["步屟隨春風，村村自花柳。田翁逼社日，邀我嘗春酒。", "酒酣誇新尹，畜眼未見有。回頭指大男，渠是弓弩手。", "名在飛騎籍，長番歲時久。前日放營農，辛苦救衰朽。", "差科死則已，誓不舉家走。今年大作社，拾遺能住否。", "叫婦開大瓶，盆中為吾取。感此氣揚揚，須知風化首。", "語多雖雜亂，說尹終在口。朝來偶然出，自卯將及酉。", "久客惜人情，如何拒鄰叟。高聲索果栗，欲起時被肘。", "指揮過無禮，未覺村野醜。月出遮我留，仍嗔問升鬥。"]'),
('yuding-26','喜雨','杜甫','唐','御定全唐诗','yuding','','[]','春旱天地昏，日色赤如血。農事都已休，兵戈況騷屑。',96,'御定全唐詩/json/219.json','["春旱天地昏，日色赤如血。農事都已休，兵戈況騷屑。", "巴人困軍須，慟哭厚土熱。滄江夜來雨，真宰罪一雪。", "谷根小蘇息，沴氣終不滅。何由見甯歲，解我憂思結。", "崢嶸群山雲，交會未斷絕。安得鞭雷公，滂沱洗吳越。"]'),
('yuding-27','漁陽','杜甫','唐','御定全唐诗','yuding','','[]','漁陽突騎猶精銳，赫赫雍王都節制。猛將飄然恐後時，',40,'御定全唐詩/json/219.json','["漁陽突騎猶精銳，赫赫雍王都節制。猛將飄然恐後時，", "系書請問燕耆舊，今日何須十萬兵。"]'),
('yuding-28','天邊行','杜甫','唐','御定全唐诗','yuding','','[]','天邊老人歸未得，日暮東臨大江哭。隴右河源不種田，',40,'御定全唐詩/json/219.json','["天邊老人歸未得，日暮東臨大江哭。隴右河源不種田，", "九度附書向洛陽，十年骨肉無消息。"]'),
('yuding-29','大麥行','杜甫','唐','御定全唐诗','yuding','','[]','大麥乾枯小麥黃，婦女行泣夫走藏。東至集壁西梁洋，',40,'御定全唐詩/json/219.json','["大麥乾枯小麥黃，婦女行泣夫走藏。東至集壁西梁洋，", "安得如鳥有羽翅，托身白雲還故鄉。"]'),
('yuding-30','苦戰行','杜甫','唐','御定全唐诗','yuding','','[]','苦戰身死馬將軍，自雲伏波之子孫。干戈未定失壯士，',40,'御定全唐詩/json/219.json','["苦戰身死馬將軍，自雲伏波之子孫。干戈未定失壯士，", "別時孤雲今不飛，時獨看雲淚橫臆。"]'),
('yuding-31','去秋行','杜甫','唐','御定全唐诗','yuding','','[]','去秋涪江木落時，臂槍走馬誰家兒。到今不知白骨處，',40,'御定全唐詩/json/219.json','["去秋涪江木落時，臂槍走馬誰家兒。到今不知白骨處，", "戰場冤魂每夜哭，空令野營猛士悲。"]'),
('yuding-32','述古三首','杜甫','唐','御定全唐诗','yuding','','[]','赤驥頓長纓，非無萬里姿。悲鳴淚至地，為問馭者誰。',216,'御定全唐詩/json/219.json','["赤驥頓長纓，非無萬里姿。悲鳴淚至地，為問馭者誰。", "鳳凰從東來，何意複高飛。竹花不結實，念子忍朝饑。", "古時君臣合，可以物理推。賢人識定分，進退固其宜。", "市人日中集，於利競錐刀。置膏烈火上，哀哀自煎熬。", "農人望歲稔，相率除蓬蒿。所務穀為本，邪贏無乃勞。", "舜舉十六相，身尊道何高。秦時任商鞅，法令如牛毛。", "漢光得天下，祚永固有開。豈惟高祖聖，功自蕭曹來。", "經綸中興業，何代無長才。吾慕寇鄧勳，濟時信良哉。", "耿賈亦宗臣，羽翼共裴回。休運終四百，圖畫在雲台。"]'),
('yuding-0','觀打魚歌','杜甫','唐','御定全唐诗','yuding','','[]','綿州江水之東津，魴魚鱍鱍色勝銀。漁人漾舟沈大網，',73,'御定全唐詩/json/220.json','["綿州江水之東津，魴魚鱍鱍色勝銀。漁人漾舟沈大網，", "潛龍無聲老蛟怒，回風颯颯吹沙塵。饔子左右揮雙刀，", "魴魚肥美知第一，既飽歡娛亦蕭瑟。君不見朝來割素鬐，"]'),
('yuding-1','又觀打魚','杜甫','唐','御定全唐诗','yuding','','[]','蒼江魚子清晨集，設網提綱萬魚急。能者操舟疾若風，',72,'御定全唐詩/json/220.json','["蒼江魚子清晨集，設網提綱萬魚急。能者操舟疾若風，", "大魚傷損皆垂頭，屈強泥沙有時立。東津觀魚已再來，", "干戈兵革鬥未止，鳳凰麒麟安在哉。吾徒胡為縱此樂，"]'),
('yuding-2','越王樓歌','杜甫','唐','御定全唐诗','yuding','','[]','綿州州府何磊落，顯慶年中越王作。孤城西北起高樓，',40,'御定全唐詩/json/220.json','["綿州州府何磊落，顯慶年中越王作。孤城西北起高樓，", "君王舊跡今人賞，轉見千秋萬古情。"]'),
('yuding-3','海棕行','杜甫','唐','御定全唐诗','yuding','','[]','左綿公館清江濆，海棕一株高入雲。龍鱗犀甲相錯落，',40,'御定全唐詩/json/220.json','["左綿公館清江濆，海棕一株高入雲。龍鱗犀甲相錯落，", "移栽北辰不可得，時有西域胡僧識。"]'),
('yuding-4','姜楚公畫角鷹歌','杜甫','唐','御定全唐诗','yuding','','[]','楚公畫鷹鷹戴角，殺氣森森到幽朔。觀者貪愁掣臂飛，',40,'御定全唐詩/json/220.json','["楚公畫鷹鷹戴角，殺氣森森到幽朔。觀者貪愁掣臂飛，", "梁間燕雀休驚怕，亦未摶空上九天。"]'),
('yuding-5','相逢歌贈嚴二別駕','杜甫','唐','御定全唐诗','yuding','','[]','我行入東川，十步一回首。成都亂罷氣蕭颯，',92,'御定全唐詩/json/220.json','["我行入東川，十步一回首。成都亂罷氣蕭颯，", "把臂開尊飲我酒，酒酣擊劍蛟龍吼。烏帽拂塵青螺粟，", "黃昏始扣主人門，誰謂俄頃膠在漆。萬事盡付形骸外，", "高視乾坤又可愁，一軀交態同悠悠。垂老遇君未恨晚，"]'),
('yuding-6','光祿阪行','杜甫','唐','御定全唐诗','yuding','','[]','山行落日下絕壁，西望千山萬山赤。樹枝有鳥亂鳴時，',40,'御定全唐詩/json/220.json','["山行落日下絕壁，西望千山萬山赤。樹枝有鳥亂鳴時，", "安得更似開元中，道路即今多擁隔。"]'),
('yuding-7','冬到金華山觀，因得故拾遺陳公學堂遺跡','杜甫','唐','御定全唐诗','yuding','','[]','涪右眾山內，金華紫崔嵬。上有蔚藍天，垂光抱瓊台。',96,'御定全唐詩/json/220.json','["涪右眾山內，金華紫崔嵬。上有蔚藍天，垂光抱瓊台。", "系舟接絕壁，杖策窮縈回。四顧俯層巔，澹然川穀開。", "雪嶺日色死，霜鴻有餘哀。焚香玉女跪，霧裏仙人來。", "陳公讀書堂，石柱仄青苔。悲風為我起，激烈傷雄才。"]'),
('yuding-8','陳拾遺故宅','杜甫','唐','御定全唐诗','yuding','','[]','拾遺平昔居，大屋尚修椽。悠揚荒山日，慘澹故園煙。',120,'御定全唐詩/json/220.json','["拾遺平昔居，大屋尚修椽。悠揚荒山日，慘澹故園煙。", "位下曷足傷，所貴者聖賢。有才繼騷雅，哲匠不比肩。", "公生揚馬後，名與日月懸。同游英俊人，多秉輔佐權。", "彥昭超玉價，郭振起通泉。到今素壁滑，灑翰銀鉤連。", "盛事會一時，此堂豈千年。終古立忠義，感遇有遺編。"]'),
('yuding-9','謁文公上方','杜甫','唐','御定全唐诗','yuding','','[]','野寺隱喬木，山僧高下居。石門日色異，絳氣橫扶疏。',168,'御定全唐詩/json/220.json','["野寺隱喬木，山僧高下居。石門日色異，絳氣橫扶疏。", "窈窕入風磴，長蘆紛卷舒。庭前猛虎臥，遂得文公廬。", "俯視萬家邑，煙塵對階除。吾師雨花外，不下十年餘。", "長者自布金，禪龕只晏如。大珠脫玷翳，白月當空虛。", "甫也南北人，蕪蔓少耘鋤。久遭詩酒汙，何事忝簪裾。", "王侯與螻蟻，同盡隨丘墟。願聞第一義，回向心地初。", "金篦刮眼膜，價重百車渠。無生有汲引，茲理儻吹噓。"]'),
('yuding-10','奉贈射洪李四丈','杜甫','唐','御定全唐诗','yuding','','[]','丈人屋上烏，人好烏亦好。人生意氣豁，不在相逢早。',96,'御定全唐詩/json/220.json','["丈人屋上烏，人好烏亦好。人生意氣豁，不在相逢早。", "南京亂初定，所向邑枯槁。遊子無根株，茅齋付秋草。", "東征下月峽，掛席窮海島。萬里須十金，妻孥未相保。", "蒼茫風塵際，蹭蹬騏驎老。志士懷感傷，心胸已傾倒。"]'),
('yuding-11','早發射洪縣南途中作','杜甫','唐','御定全唐诗','yuding','','[]','將老憂貧窶，筋力豈能及。征途乃侵星，得使諸病入。',120,'御定全唐詩/json/220.json','["將老憂貧窶，筋力豈能及。征途乃侵星，得使諸病入。", "鄙人寡道氣，在困無獨立。俶裝逐徒旅，達曙淩險澀。", "寒日出霧遲，清江轉山急。僕夫行不進，駑馬若維縶。", "汀洲稍疏散，風景開怏悒。空慰所尚懷，終非曩遊集。", "衰顏偶一破，勝事難屢挹。茫然阮籍途，更灑楊朱泣。"]'),
('yuding-12','通泉驛南去通泉縣十五裏山水作','杜甫','唐','御定全唐诗','yuding','','[]','溪行衣自濕，亭午氣始散。冬溫蚊蚋在，人遠鳧鴨亂。',96,'御定全唐詩/json/220.json','["溪行衣自濕，亭午氣始散。冬溫蚊蚋在，人遠鳧鴨亂。", "登頓生曾陰，欹傾出高岸。驛樓衰柳側，縣郭輕煙畔。", "一川何綺麗，盡目窮壯觀。山色遠寂寞，江光夕滋漫。", "傷時愧孔父，去國同王粲。我生苦飄零，所曆有嗟歎。"]'),
('yuding-13','過郭代公故宅','杜甫','唐','御定全唐诗','yuding','','[]','豪俊初未遇，其跡或脫略。代公尉通泉，放意何自若。',132,'御定全唐詩/json/220.json','["豪俊初未遇，其跡或脫略。代公尉通泉，放意何自若。", "及夫登袞冕，直氣森噴薄。磊落見異人，豈伊常情度。", "定策神龍後，宮中翕清廓。俄頃辨尊親，指揮存顧托。", "群公有慚色，王室無削弱。迥出名臣上，丹青照台閣。", "我行得遺跡，池館皆疏鑿。壯公臨事斷，顧步涕橫落。", "高詠寶劍篇，神交付冥漠。"]'),
('yuding-14','觀薛稷少保書畫壁','杜甫','唐','御定全唐诗','yuding','','[]','少保有古風，得之陝郊篇。惜哉功名忤，但見書畫傳。',120,'御定全唐詩/json/220.json','["少保有古風，得之陝郊篇。惜哉功名忤，但見書畫傳。", "我遊梓州東，遺跡涪江邊。畫藏青蓮界，書入金榜懸。", "仰看垂露姿，不崩亦不騫。鬱鬱三大字，蛟龍岌相纏。", "又揮西方變，發地扶屋椽。慘澹壁飛動，到今色未填。", "此行疊壯觀，郭薛俱才賢。不知百載後，誰複來通泉。"]'),
('yuding-15','通泉縣署屋壁後薛少保畫鶴','杜甫','唐','御定全唐诗','yuding','','[]','薛公十一鶴，皆寫青田真。畫色久欲盡，蒼然猶出塵。',120,'御定全唐詩/json/220.json','["薛公十一鶴，皆寫青田真。畫色久欲盡，蒼然猶出塵。", "低昂各有意，磊落如長人。佳此志氣遠，豈惟粉墨新。", "萬里不以力，群遊森會神。威遲白鳳態，非是倉庚鄰。", "高堂未傾覆，常得慰嘉賓。曝露牆壁外，終嗟風雨頻。", "赤霄有真骨，恥飲洿池津。冥冥任所往，脫略誰能馴。"]'),
('yuding-16','陪王侍禦同登東山最高頂宴姚通泉，晚攜酒泛江','杜甫','唐','御定全唐诗','yuding','','[]','姚公美政誰與儔，不減昔時陳太丘。邑中上客有柱史，',88,'御定全唐詩/json/220.json','["姚公美政誰與儔，不減昔時陳太丘。邑中上客有柱史，", "清江白日落欲盡，複攜美人登彩舟。笛聲憤怨哀中流，", "三更風起寒浪湧，取樂喧呼覺船重。滿空星河光破碎，", "人生歡會豈有極，無使霜過沾人衣。"]'),
('yuding-17','春日戲題惱郝使君兄','杜甫','唐','御定全唐诗','yuding','','[]','使君意氣淩青霄，憶昨歡娛常見招。細馬時鳴金騕褭，',48,'御定全唐詩/json/220.json','["使君意氣淩青霄，憶昨歡娛常見招。細馬時鳴金騕褭，", "願攜王趙兩紅顏，再騁肌膚如素練。通泉百里近梓州，"]'),
('yuding-18','短歌行，贈王郎司直','杜甫','唐','御定全唐诗','yuding','','[]','王郎酒酣拔劍斫地歌莫哀，我能拔爾抑塞磊落之奇才。',64,'御定全唐詩/json/220.json','["王郎酒酣拔劍斫地歌莫哀，我能拔爾抑塞磊落之奇才。", "豫章翻風白日動，鯨魚跋浪滄溟開。且脫佩劍休裴回，", "青眼高歌望吾子，眼中之人吾老矣。"]'),
('yuding-19','短歌行，送祁錄事歸合州，因寄蘇使君','杜甫','唐','御定全唐诗','yuding','','[]','前者途中一相見，人事經年記君面。後生相動何寂寥，',40,'御定全唐詩/json/220.json','["前者途中一相見，人事經年記君面。後生相動何寂寥，", "幸為達書賢府主，江花未盡會江樓。"]'),
('yuding-20','陪章留後惠義寺餞嘉州崔都督赴州','杜甫','唐','御定全唐诗','yuding','','[]','中軍待上客，令肅事有恆。前驅入寶地，祖帳飄金繩。',120,'御定全唐詩/json/220.json','["中軍待上客，令肅事有恆。前驅入寶地，祖帳飄金繩。", "南陌既留歡，茲山亦深登。清聞樹杪磬，遠謁雲端僧。", "回策匪新岸，所攀仍舊藤。耳激洞門飆，目存寒穀冰。", "出塵閟軌躅，畢景遺炎蒸。永願坐長夏，將衰棲大乘。", "羈旅惜宴會，艱難懷友朋。勞生共幾何，離恨兼相仍。"]'),
('yuding-21','將適吳楚，留別章使君留後，兼幕府諸公，得柳字','杜甫','唐','御定全唐诗','yuding','','[]','我來入蜀門，歲月亦已久。豈惟長兒童，自覺成老醜。',216,'御定全唐詩/json/220.json','["我來入蜀門，歲月亦已久。豈惟長兒童，自覺成老醜。", "常恐性坦率，失身為杯酒。近辭痛飲徒，折節萬夫後。", "昔如縱壑魚，今如喪家狗。既無游方戀，行止複何有。", "相逢半新故，取別隨薄厚。不意青草湖，扁舟落吾手。", "眷眷章梓州，開筵俯高柳。樓前出騎馬，帳下羅賓友。", "健兒簸紅旗，此樂或難朽。日車隱昆侖，鳥雀噪戶牖。", "波濤未足畏，三峽徒雷吼。所憂盜賊多，重見衣冠走。", "中原消息斷，黃屋今安否。終作適荊蠻，安排用莊叟。", "隨雲拜東皇，掛席上南斗。有使即寄書，無使長回首。"]'),
('yuding-22','山寺','杜甫','唐','御定全唐诗','yuding','','[]','野寺根石壁，諸龕遍崔嵬。前佛不復辨，百身一莓苔。',168,'御定全唐詩/json/220.json','["野寺根石壁，諸龕遍崔嵬。前佛不復辨，百身一莓苔。", "雖有古殿存，世尊亦塵埃。如聞龍象泣，足令信者哀。", "使君騎紫馬，捧擁從西來。樹羽靜千里，臨江久裴回。", "山僧衣藍縷，告訴棟樑摧。公為顧賓徒，咄嗟檀施開。", "吾知多羅樹，卻倚蓮華台。諸天必歡喜，鬼物無嫌猜。", "以茲撫士卒，孰曰非周才。窮子失淨處，高人憂禍胎。", "歲晏風破肉，荒林寒可回。思量入道苦，自哂同嬰孩。"]'),
('yuding-23','棕拂子','杜甫','唐','御定全唐诗','yuding','','[]','棕拂且薄陋，豈知身效能。不堪代白羽，有足除蒼蠅。',96,'御定全唐詩/json/220.json','["棕拂且薄陋，豈知身效能。不堪代白羽，有足除蒼蠅。", "熒熒金錯刀，擢擢朱絲繩。非獨顏色好，亦用顧盼稱。", "吾老抱疾病，家貧臥炎蒸。咂膚倦撲滅，賴爾甘服膺。", "物微世競棄，義在誰肯征。三歲清秋至，未敢闕緘藤。"]'),
('yuding-24','桃竹杖引，贈章留後','杜甫','唐','御定全唐诗','yuding','','[]','江心蟠石生桃竹，蒼波噴浸尺度足。斬根削皮如紫玉，',66,'御定全唐詩/json/220.json','["江心蟠石生桃竹，蒼波噴浸尺度足。斬根削皮如紫玉，", "憐我老病贈兩莖，出入爪甲鏗有聲。老夫複欲東南征，", "重為告曰：杖兮杖兮，爾之生也甚正直，"]'),
('yuding-25','寄題江外草堂','杜甫','唐','御定全唐诗','yuding','','[]','我生性放誕，雅欲逃自然。嗜酒愛風竹，卜居必林泉。',192,'御定全唐詩/json/220.json','["我生性放誕，雅欲逃自然。嗜酒愛風竹，卜居必林泉。", "遭亂到蜀江，臥屙遣所便。誅茅初一畝，廣地方連延。", "經營上元始，斷手寶應年。敢謀土木麗，自覺面勢堅。", "台亭隨高下，敞豁當清川。雖有會心侶，數能同釣船。", "干戈未偃息，安得酣歌眠。蛟龍無定窟，黃鵠摩蒼天。", "古來達士志，寧受外物牽。顧惟魯鈍姿，豈識悔吝先。", "偶攜老妻去，慘澹淩風煙。事蹟無固必，幽貞愧雙全。", "尚念四小松，蔓草易拘纏。霜骨不甚長，永為鄰里憐。"]'),
('yuding-26','韋諷錄事宅觀曹將軍畫馬圖','杜甫','唐','御定全唐诗','yuding','','[]','國初已來畫鞍馬，神妙獨數江都王。將軍得名三十載，',155,'御定全唐詩/json/220.json','["國初已來畫鞍馬，神妙獨數江都王。將軍得名三十載，", "內府殷紅馬腦碗，婕妤傳詔才人索。碗賜將軍拜舞歸，", "昔日太宗拳毛騧，近時郭家師子花。今之新圖有二馬，", "其餘七匹亦殊絕，迥若寒空動煙雪。霜蹄蹴踏長楸間，", "借問苦心愛者誰，後有韋諷前支遁。憶昔巡幸新豐宮，", "自從獻寶朝河宗，無複射蛟江水中。", "君不見金粟堆前松柏裏，龍媒去盡鳥呼風。"]'),
('yuding-27','送韋諷上閬州錄事參軍','杜甫','唐','御定全唐诗','yuding','','[]','國步猶艱難，兵革未衰息。萬方哀嗷嗷，十載供軍食。',120,'御定全唐詩/json/220.json','["國步猶艱難，兵革未衰息。萬方哀嗷嗷，十載供軍食。", "庶官務割剝，不暇憂反側。誅求何多門，賢者貴為德。", "韋生富春秋，洞徹有清識。操持紀綱地，喜見朱絲直。", "當令豪奪吏，自此無顏色。必若救瘡痍，先應去蟊賊。", "揮淚臨大江，高天意淒惻。行行樹佳政，慰我深相憶。"]'),
('yuding-28','丹青引，贈曹將軍霸','杜甫','唐','御定全唐诗','yuding','','[]','將軍魏武之子孫，於今為庶為清門。英雄割據雖已矣，',168,'御定全唐詩/json/220.json','["將軍魏武之子孫，於今為庶為清門。英雄割據雖已矣，", "丹青不知老將至，富貴於我如浮雲。開元之中常引見，", "良相頭上進賢冠，猛將腰間大羽箭。褒公鄂公毛發動，", "是日牽來赤墀下，迥立閶闔生長風。詔謂將軍拂絹素，", "玉花卻在禦榻上，榻上庭前屹相向。至尊含笑催賜金，", "幹惟畫肉不畫骨，忍使驊騮氣凋喪。將軍畫善蓋有神，", "途窮反遭俗眼白，世上未有如公貧。但看古來盛名下，"]'),
('yuding-29','閬州東樓筵，奉送十一舅往青城縣，得昏字','杜甫','唐','御定全唐诗','yuding','','[]','曾城有高樓，制古丹雘存。迢迢百餘尺，豁達開四門。',120,'御定全唐詩/json/220.json','["曾城有高樓，制古丹雘存。迢迢百餘尺，豁達開四門。", "雖有車馬客，而無人世喧。游目俯大江，列筵慰別魂。", "是時秋冬交，節往顏色昏。天寒鳥獸休，霜露在草根。", "今我送舅氏，萬感集清尊。豈伊山川間，回首盜賊繁。", "高賢意不暇，王命久崩奔。臨風欲慟哭，聲出已複吞。"]'),
('yuding-30','嚴氏溪放歌行','杜甫','唐','御定全唐诗','yuding','','[]','天下甲馬未盡銷，豈免溝壑常漂漂。劍南歲月不可度，',72,'御定全唐詩/json/220.json','["天下甲馬未盡銷，豈免溝壑常漂漂。劍南歲月不可度，", "嗚呼古人已糞土，獨覺志士甘漁樵。況我飄轉無定所，", "東遊西還力實倦，從此將身更何許。知子松根長茯苓，"]'),
('yuding-31','南池','杜甫','唐','御定全唐诗','yuding','','[]','崢嶸巴閬間，所向盡山谷。安知有蒼池，萬頃浸坤軸。',192,'御定全唐詩/json/220.json','["崢嶸巴閬間，所向盡山谷。安知有蒼池，萬頃浸坤軸。", "呀然閬城南，枕帶巴江腹。芰荷入異縣，粳稻共比屋。", "皇天不無意，美利戒止足。高田失西成，此物頗豐熟。", "清源多眾魚，遠岸富喬木。獨歎楓香林，春時好顏色。", "南有漢王祠，終朝走巫祝。歌舞散靈衣，荒哉舊風俗。", "高堂亦明王，魂魄猶正直。不應空陂上，縹緲親酒食。", "淫祀自古昔，非唯一川瀆。干戈浩茫茫，地僻傷極目。", "平生江海興，遭亂身局促。駐馬問漁舟，躊躇慰羈束。"]'),
('yuding-32','發閬中','杜甫','唐','御定全唐诗','yuding','','[]','前有毒蛇後猛虎，溪行盡日無村塢。江風蕭蕭雲拂地，',40,'御定全唐詩/json/220.json','["前有毒蛇後猛虎，溪行盡日無村塢。江風蕭蕭雲拂地，", "別家三月一得書，避地何時免愁苦。"]'),
('yuding-33','寄韓諫議','杜甫','唐','御定全唐诗','yuding','','[]','今我不樂思岳陽，身欲奮飛病在床。美人娟娟隔秋水，',96,'御定全唐詩/json/220.json','["今我不樂思岳陽，身欲奮飛病在床。美人娟娟隔秋水，", "玉京群帝集北斗，或騎騏驎翳鳳凰。芙蓉旌旗煙霧樂，", "似聞昨者赤松子，恐是漢代韓張良。昔隨劉氏定長安，", "周南留滯古所惜，南極老人應壽昌。美人胡為隔秋水，"]'),
('yuding-34','憶昔二首','杜甫','唐','御定全唐诗','yuding','','[]','憶昔先皇巡朔方，千乘萬騎入咸陽。陰山驕子汗血馬，',160,'御定全唐詩/json/220.json','["憶昔先皇巡朔方，千乘萬騎入咸陽。陰山驕子汗血馬，", "我昔近侍叨奉引，出兵整肅不可當。為留猛士守未央，", "願見北地傅介子，老儒不用尚書郎。", "憶昔開元全盛日，小邑猶藏萬家室。稻米流脂粟米白，", "齊紈魯縞車班班，男耕女桑不相失。宮中聖人奏雲門，", "豈聞一絹直萬錢，有田種穀今流血。洛陽宮殿燒焚盡，", "小臣魯鈍無所能，朝廷記識蒙祿秩。周宣中興望我皇，"]'),
('yuding-35','冬狩行','杜甫','唐','御定全唐诗','yuding','','[]','君不見東川節度兵馬雄，校獵亦似觀成功。',124,'御定全唐詩/json/220.json','["君不見東川節度兵馬雄，校獵亦似觀成功。", "夜發猛士三千人，清晨合圍步驟同。禽獸已斃十七八，", "東西南北百里間，仿佛蹴踏寒山空。有鳥名鴝鵒，", "春搜冬狩侯得同，使君五馬一馬驄。況今攝行大將權，", "喜君士卒甚整肅，為我回轡擒西戎。草中狐兔盡何益，", "嗚呼，得不哀痛塵再蒙。"]'),
('yuding-36','自平','杜甫','唐','御定全唐诗','yuding','','[]','自平宮中呂太一，收珠南海千餘日。近供生犀翡翠稀，',40,'御定全唐詩/json/220.json','["自平宮中呂太一，收珠南海千餘日。近供生犀翡翠稀，", "蓬萊殿前諸主將，才如伏波不得驕。"]'),
('yuding-37','釋悶','杜甫','唐','御定全唐诗','yuding','','[]','四海十年不解兵，犬戎也複臨咸京。失道非關出襄野，',48,'御定全唐詩/json/220.json','["四海十年不解兵，犬戎也複臨咸京。失道非關出襄野，", "天子亦應厭奔走，群公固合思升平。但恐誅求不改轍，"]'),
('yuding-38','贈別賀蘭銛','杜甫','唐','御定全唐诗','yuding','','[]','黃雀飽野粟，群飛動荊榛。今君抱何恨，寂寞向時人。',96,'御定全唐詩/json/220.json','["黃雀飽野粟，群飛動荊榛。今君抱何恨，寂寞向時人。", "老驥倦驤首，蒼鷹愁易馴。高賢世未識，固合嬰饑貧。", "國步初返正，乾坤尚風塵。悲歌鬢髮白，遠赴湘吳春。", "我戀岷下芋，君思千里蓴。生離與死別，自古鼻酸辛。"]'),
('yuding-39','別唐十五誡，因寄禮部賈侍郎','杜甫','唐','御定全唐诗','yuding','','[]','九載一相逢，百年能幾何。複為萬里別，送子山之阿。',192,'御定全唐詩/json/220.json','["九載一相逢，百年能幾何。複為萬里別，送子山之阿。", "白鶴久同林，潛魚本同河。未知棲集期，衰老強高歌。", "歌罷兩淒惻，六龍忽蹉跎。相視發皓白，況難駐羲和。", "胡星墜燕地，漢將仍橫戈。蕭條四海內，人少豺虎多。", "少人慎莫投，多虎信所過。饑有易子食，獸猶畏虞羅。", "子負經濟才，天門鬱嵯峨。飄搖適東周，來往若崩波。", "南宮吾故人，白馬金盤陀。雄筆映千古，見賢心靡他。", "念子善師事，歲寒守舊柯。為吾謝賈公，病肺臥江沱。"]'),
('yuding-40','閬山歌','杜甫','唐','御定全唐诗','yuding','','[]','閬州城東靈山白，閬州城北玉台碧。松浮欲盡不盡雲，',40,'御定全唐詩/json/220.json','["閬州城東靈山白，閬州城北玉台碧。松浮欲盡不盡雲，", "中原格鬥且未歸，應結茅齋看青壁。"]'),
('yuding-41','閬水歌','杜甫','唐','御定全唐诗','yuding','','[]','嘉陵江色何所似，石黛碧玉相因依。正憐日破浪花出，',40,'御定全唐詩/json/220.json','["嘉陵江色何所似，石黛碧玉相因依。正憐日破浪花出，", "閬中勝事可腸斷，閬州城南天下稀。"]'),
('yuding-42','草堂','杜甫','唐','御定全唐诗','yuding','','[]','昔我去草堂，蠻夷塞成都。今我歸草堂，成都適無虞。',360,'御定全唐詩/json/220.json','["昔我去草堂，蠻夷塞成都。今我歸草堂，成都適無虞。", "請陳初亂時，反復乃須臾。大將赴朝廷，群小起異圖。", "中宵斬白馬，盟歃氣已粗。西取邛南兵，北斷劍閣隅。", "布衣數十人，亦擁專城居。其勢不兩大，始聞蕃漢殊。", "西卒卻倒戈，賊臣互相誅。焉知肘腋禍，自及梟獍徒。", "義士皆痛憤，紀綱亂相逾。一國實三公，萬人欲為魚。", "唱和作威福，孰肯辨無辜。眼前列杻械，背後吹笙竽。", "談笑行殺戮，濺血滿長衢。到今用鉞地，風雨聞號呼。", "鬼妾與鬼馬，色悲充爾娛。國家法令在，此又足驚籲。", "賤子且奔走，三年望東吳。弧矢暗江海，難為遊五湖。", "不忍竟舍此，複來薙榛蕪。入門四松在，步屟萬竹疏。", "舊犬喜我歸，低徊入衣裾。鄰舍喜我歸，酤酒攜胡蘆。", "大官喜我來，遣騎問所須。城郭喜我來，賓客隘村墟。", "天下尚未甯，健兒勝腐儒。飄搖風塵際，何地置老夫。", "于時見疣贅，骨髓幸未枯。飲啄愧殘生，食薇不敢餘。"]'),
('yuding-43','四松','杜甫','唐','御定全唐诗','yuding','','[]','四松初移時，大抵三尺強。別來忽三載，離立如人長。',168,'御定全唐詩/json/220.json','["四松初移時，大抵三尺強。別來忽三載，離立如人長。", "會看根不拔，莫計枝凋傷。幽色幸秀髮，疏柯亦昂藏。", "所插小藩籬，本亦有堤防。終然掁撥損，得吝千葉黃。", "敢為故林主，黎庶猶未康。避賊今始歸，春草滿空堂。", "覽物歎衰謝，及茲慰淒涼。清風為我起，灑面若微霜。", "足以送老姿，聊待偃蓋張。我生無根帶，配爾亦茫茫。", "有情且賦詩，事蹟可兩忘。勿矜千載後，慘澹蟠穹蒼。"]'),
('yuding-44','水檻','杜甫','唐','御定全唐诗','yuding','','[]','蒼江多風飆，雲雨晝夜飛。茅軒駕巨浪，焉得不低垂。',96,'御定全唐詩/json/220.json','["蒼江多風飆，雲雨晝夜飛。茅軒駕巨浪，焉得不低垂。", "遊子久在外，門戶無人持。高岸尚如谷，何傷浮柱欹。", "扶顛有勸誡，恐貽識者嗤。既殊大廈傾，可以一木支。", "臨川視萬里，何必闌檻為。人生感故物，慷慨有餘悲。"]'),
('yuding-45','破船','杜甫','唐','御定全唐诗','yuding','','[]','平生江海心，宿昔具扁舟。豈惟青溪上，日傍柴門遊。',96,'御定全唐詩/json/220.json','["平生江海心，宿昔具扁舟。豈惟青溪上，日傍柴門遊。", "蒼皇避亂兵，緬邈懷舊丘。鄰人亦已非，野竹獨修修。", "船舷不重扣，埋沒已經秋。仰看西飛翼，下愧東逝流。", "故者或可掘，新者亦易求。所悲數奔竄，白屋難久留。"]'),
('yuding-46','營屋','杜甫','唐','御定全唐诗','yuding','','[]','我有陰江竹，能令朱夏寒。陰通積水內，高入浮雲端。',120,'御定全唐詩/json/220.json','["我有陰江竹，能令朱夏寒。陰通積水內，高入浮雲端。", "甚疑鬼物憑，不顧翦伐殘。東偏若面勢，戶牖永可安。", "愛惜已六載，茲晨去千竿。蕭蕭見白日，洶洶開奔湍。", "度堂匪華麗，養拙異考盤。草茅雖薙葺，衰疾方少寬。", "洗然順所適，此足代加餐。寂無斤斧響，庶遂憩息歡。"]'),
('yuding-47','除草','杜甫','唐','御定全唐诗','yuding','','[]','草有害于人，曾何生阻修。其毒甚蜂蠆，其多彌道周。',120,'御定全唐詩/json/220.json','["草有害于人，曾何生阻修。其毒甚蜂蠆，其多彌道周。", "清晨步前林，江色未散憂。芒刺在我眼，焉能待高秋。", "霜露一沾凝，蕙葉亦難留。荷鋤先童稚，日入仍討求。", "轉致水中央，豈無雙釣舟。頑根易滋蔓，敢使依舊丘。", "自茲藩籬曠，更覺松竹幽。芟夷不可闕，疾惡信如讎。"]'),
('yuding-48','揚旗','杜甫','唐','御定全唐诗','yuding','','[]','江雨颯長夏，府中有餘清。我公會賓客，肅肅有異聲。',144,'御定全唐詩/json/220.json','["江雨颯長夏，府中有餘清。我公會賓客，肅肅有異聲。", "初筵閱軍裝，羅列照廣庭。庭空六馬入，駊騀揚旗旌。", "回回偃飛蓋，熠熠迸流星。來纏風飆急，去擘山嶽傾。", "材歸俯身盡，妙取略地平。虹霓就掌握，舒卷隨人輕。", "三州陷犬戎，但見西嶺青。公來練猛士，欲奪天邊城。", "此堂不易升，庸蜀日已寧。吾徒且加餐，休適蠻與荊。"]'),
('yuding-49','太子張舍人遺織成褥段','杜甫','唐','御定全唐诗','yuding','','[]','客從西北來，遺我翠織成。開緘風濤湧，中有掉尾鯨。',216,'御定全唐詩/json/220.json','["客從西北來，遺我翠織成。開緘風濤湧，中有掉尾鯨。", "逶迤羅水族，瑣細不足名。客雲充君褥，承君終宴榮。", "空堂魑魅走，高枕形神清。領客珍重意，顧我非公卿。", "留之懼不祥，施之混柴荊。服飾定尊卑，大哉萬古程。", "今我一賤老，裋褐更無營。煌煌珠宮物，寢處禍所嬰。", "歎息當路子，干戈尚縱橫。掌握有權柄，衣馬自肥輕。", "李鼎死岐陽，實以驕貴盈。來瑱賜自盡，氣豪直阻兵。", "皆聞黃金多，坐見悔吝生。奈何田舍翁，受此厚貺情。", "錦鯨卷還客，始覺心和平。振我粗席塵，愧客茹藜羹。"]'),
('yuding-50','莫相疑行','杜甫','唐','御定全唐诗','yuding','','[]','男兒生無所成頭皓白，牙齒欲落真可惜。憶獻三賦蓬萊宮，',50,'御定全唐詩/json/220.json','["男兒生無所成頭皓白，牙齒欲落真可惜。憶獻三賦蓬萊宮，", "往時文彩動人主，此日饑寒趨路旁。晚將末契托年少，"]'),
('yuding-51','別蔡十四著作','杜甫','唐','御定全唐诗','yuding','','[]','賈生慟哭後，寥落無其人。安知蔡夫子，高義邁等倫。',240,'御定全唐詩/json/220.json','["賈生慟哭後，寥落無其人。安知蔡夫子，高義邁等倫。", "獻書謁皇帝，志已清風塵。流涕灑丹極，萬乘為酸辛。", "天地則創痍，朝廷當正臣。異才複間出，周道日惟新。", "使蜀見知己，別顏始一伸。主人薨城府，扶櫬歸咸秦。", "巴道此相逢，會我病江濱。憶念鳳翔都，聚散俄十春。", "我衰不足道，但願子意陳。稍令社稷安，自契魚水親。", "我雖消渴甚，敢忘帝力勤。尚思未朽骨，複睹耕桑民。", "積水駕三峽，浮龍倚長津。揚舲洪濤間，仗子濟物身。", "鞍馬下秦塞，王城通北辰。玄甲聚不散，兵久食恐貧。", "窮穀無粟帛，使者來相因。若憑南轅吏，書劄到天垠。"]'),
('yuding-0','杜鵑','杜甫','唐','御定全唐诗','yuding','','[]','西川有杜鵑，東川無杜鵑。涪萬無杜鵑，雲安有杜鵑。',168,'御定全唐詩/json/221.json','["西川有杜鵑，東川無杜鵑。涪萬無杜鵑，雲安有杜鵑。", "我昔遊錦城，結廬錦水邊。有竹一頃餘，喬木上參天。", "杜鵑暮春至，哀哀叫其間。我見常再拜，重是古帝魂。", "生子百鳥巢，百鳥不敢嗔。仍為喂其子，禮若奉至尊。", "鴻雁及羔羊，有禮太古前。行飛與跪乳，識序如知恩。", "聖賢古法則，付與後世傳。君看禽鳥情，猶解事杜鵑。", "今忽暮春間，值我病經年。身病不能拜，淚下如迸泉。"]'),
('yuding-1','客居','杜甫','唐','御定全唐诗','yuding','','[]','客居所居堂，前江後山根。下塹萬尋岸，蒼濤鬱飛翻。',240,'御定全唐詩/json/221.json','["客居所居堂，前江後山根。下塹萬尋岸，蒼濤鬱飛翻。", "蔥青眾木梢，邪豎雜石痕。子規晝夜啼，壯士斂精魂。", "峽開四千里，水合數百源。人虎相半居，相傷終兩存。", "蜀麻久不來，吳鹽擁荊門。西南失大將，商旅自星奔。", "今又降元戎，已聞動行軒。舟子候利涉，亦憑節制尊。", "我在路中央，生理不得論。臥愁病腳廢，徐步視小園。", "短畦帶碧草，悵望思王孫。鳳隨其皇去，籬雀暮喧繁。", "覽物想故國，十年別荒村。日暮歸幾翼，北林空自昏。", "安得覆八溟，為君洗乾坤。稷契易為力，犬戎何足吞。", "儒生老無成，臣子憂四番。篋中有舊筆，情至時複援。"]'),
('yuding-2','客堂','杜甫','唐','御定全唐诗','yuding','','[]','憶昨離少城，而今異楚蜀。舍舟複深山，窅窕一林麓。',252,'御定全唐詩/json/221.json','["憶昨離少城，而今異楚蜀。舍舟複深山，窅窕一林麓。", "棲泊雲安縣，消中內相毒。舊疾甘載來，衰年得無足。", "死為殊方鬼，頭白免短促。老馬終望雲，南雁意在北。", "別家長兒女，欲起慚筋力。客堂序節改，具物對羈束。", "石暄蕨芽紫，渚秀蘆筍綠。巴鶯紛未稀，徼麥早向熟。", "悠悠日動江，漠漠春辭木。台郎選才俊，自顧亦已極。", "前輩聲名人，埋沒何所得。居然綰章紱，受性本幽獨。", "平生憩息地，必種數竿竹。事業只濁醪，營葺但草屋。", "上公有記者，累奏資薄祿。主憂豈濟時，身遠彌曠職。", "循文廟算正，獻可天衢直。尚想趨朝廷，毫髮裨社稷。", "形骸今若是，進退委行色。"]'),
('yuding-3','石研詩','杜甫','唐','御定全唐诗','yuding','','[]','平公今詩伯，秀髮吾所羨。奉使三峽中，長嘯得石研。',120,'御定全唐詩/json/221.json','["平公今詩伯，秀髮吾所羨。奉使三峽中，長嘯得石研。", "巨璞禹鑿餘，異狀君獨見。其滑乃波濤，其光或雷電。", "聯坳各盡墨，多水遞隱現。揮灑容數人，十手可對面。", "比公頭上冠，貞質未為賤。當公賦佳句，況得終清宴。", "公含起草姿，不遠明光殿。致于丹青地，知汝隨顧眄。"]'),
('yuding-4','水閣朝霽，奉簡嚴雲安','杜甫','唐','御定全唐诗','yuding','','[]','東城抱春岑，江閣鄰石面。崔嵬晨雲白，朝旭射芳甸。',72,'御定全唐詩/json/221.json','["東城抱春岑，江閣鄰石面。崔嵬晨雲白，朝旭射芳甸。", "雨檻臥花叢，風床展書卷。鉤簾宿鷺起，丸藥流鶯囀。", "呼婢取酒壺，續兒誦文選。晚交嚴明府，矧此數相見。"]'),
('yuding-5','贈鄭十八賁','杜甫','唐','御定全唐诗','yuding','','[]','溫溫士君子，令我懷抱盡。靈芝冠眾芳，安得闕親近。',168,'御定全唐詩/json/221.json','["溫溫士君子，令我懷抱盡。靈芝冠眾芳，安得闕親近。", "遭亂意不歸，竄身跡非隱。細人尚姑息，吾子色愈謹。", "高懷見物理，識者安肯哂。卑飛欲何待，捷徑應未忍。", "示我百篇文，詩家一標準。羈離交屈宋，牢落值顏閔。", "水陸迷畏途，藥餌駐修軫。古人日以遠，青史字不泯。", "步趾詠唐虞，追隨飯葵堇。數杯資好事，異味煩縣尹。", "心雖在朝謁，力與願矛盾。抱病排金門，衰容豈為敏。"]'),
('yuding-6','三韻三篇','杜甫','唐','御定全唐诗','yuding','','[]','高馬勿唾面，長魚無損鱗。辱馬馬毛焦，困魚魚有神。',108,'御定全唐詩/json/221.json','["高馬勿唾面，長魚無損鱗。辱馬馬毛焦，困魚魚有神。", "君看磊落士，不肯易其身。", "蕩蕩萬斛船，影若揚白虹。起檣必椎牛，掛席集眾功。", "自非風動天，莫置大水中。", "烈士惡多門，小人自同調。名利苟可取，殺身傍權要。", "何當官曹清，爾輩堪一笑。"]'),
('yuding-7','青絲','杜甫','唐','御定全唐诗','yuding','','[]','青絲白馬誰家子，粗豪且逐風塵起。不聞漢主放妃嬪，',40,'御定全唐詩/json/221.json','["青絲白馬誰家子，粗豪且逐風塵起。不聞漢主放妃嬪，", "未如面縛歸金闕，萬一皇恩下玉墀。"]'),
('yuding-8','近聞','杜甫','唐','御定全唐诗','yuding','','[]','近聞犬戎遠遁逃，牧馬不敢侵臨洮。渭水逶迤白日淨，',40,'御定全唐詩/json/221.json','["近聞犬戎遠遁逃，牧馬不敢侵臨洮。渭水逶迤白日淨，", "似聞贊普更求親，舅甥和好應難棄。"]'),
('yuding-9','蠶谷行','杜甫','唐','御定全唐诗','yuding','','[]','天下郡國向萬城，無有一城無甲兵。焉得鑄甲作農器，',24,'御定全唐詩/json/221.json','["天下郡國向萬城，無有一城無甲兵。焉得鑄甲作農器，"]'),
('yuding-10','折檻行','杜甫','唐','御定全唐诗','yuding','','[]','嗚呼房魏不復見，秦王學士時難羨。青衿胄子困泥塗，',40,'御定全唐詩/json/221.json','["嗚呼房魏不復見，秦王學士時難羨。青衿胄子困泥塗，", "婁公不語宋公語，尚憶先皇容直臣。"]'),
('yuding-11','引水','杜甫','唐','御定全唐诗','yuding','','[]','月峽瞿塘雲作頂，亂石崢嶸俗無井。雲安酤水奴僕悲，',40,'御定全唐詩/json/221.json','["月峽瞿塘雲作頂，亂石崢嶸俗無井。雲安酤水奴僕悲，", "人生留滯生理難，鬥水何直百憂寬。"]'),
('yuding-12','古柏行','杜甫','唐','御定全唐诗','yuding','','[]','孔明廟前有老柏，柯如青銅根如石。霜皮溜雨四十圍，',96,'御定全唐詩/json/221.json','["孔明廟前有老柏，柯如青銅根如石。霜皮溜雨四十圍，", "雲來氣接巫峽長，月出寒通雪山白。憶昨路繞錦亭東，", "落落盤踞雖得地，冥冥孤高多烈風。扶持自是神明力，", "不露文章世已驚，未辭翦伐誰能送。苦心豈免容螻蟻，"]'),
('yuding-13','縛雞行','杜甫','唐','御定全唐诗','yuding','','[]','小奴縛雞向市賣，雞被縛急相喧爭。家中厭雞食蟲蟻，',40,'御定全唐詩/json/221.json','["小奴縛雞向市賣，雞被縛急相喧爭。家中厭雞食蟲蟻，", "雞蟲得失無了時，注目寒江倚山閣。"]'),
('yuding-14','負薪行','杜甫','唐','御定全唐诗','yuding','','[]','夔州處女發半華，四十五十無夫家。更遭喪亂嫁不售，',72,'御定全唐詩/json/221.json','["夔州處女發半華，四十五十無夫家。更遭喪亂嫁不售，", "十猶八九負薪歸，賣薪得錢應供給。至老雙鬟只垂頸，", "面妝首飾雜啼痕，地褊衣寒困石根。若道巫山女粗醜，"]'),
('yuding-15','最能行','杜甫','唐','御定全唐诗','yuding','','[]','峽中丈夫絕輕死，少在公門多在水。富豪有錢駕大舸，',72,'御定全唐詩/json/221.json','["峽中丈夫絕輕死，少在公門多在水。富豪有錢駕大舸，", "欹帆側柁入波濤，撇漩捎濆無險阻。朝發白帝暮江陵，", "此鄉之人氣量窄，誤競南風疏北客。若道土無英俊才，"]'),
('yuding-16','寄裴施州','杜甫','唐','御定全唐诗','yuding','','[]','廊廟之具裴施州，宿昔一逢無此流。金鐘大鏞在東序，',72,'御定全唐詩/json/221.json','["廊廟之具裴施州，宿昔一逢無此流。金鐘大鏞在東序，", "堯有四嶽明至理，漢二千石真分憂。幾度寄書白鹽北，", "紫衣使者辭複命，再拜故人謝佳政。將老已失子孫憂，"]'),
('yuding-17','鄭典設自施州歸','杜甫','唐','御定全唐诗','yuding','','[]','吾憐滎陽秀，冒暑初有適。名賢慎所出，不肯妄行役。',300,'御定全唐詩/json/221.json','["吾憐滎陽秀，冒暑初有適。名賢慎所出，不肯妄行役。", "旅茲殊俗遠，竟以屢空迫。南謁裴施州，氣合無險僻。", "攀援懸根木，登頓入天石。青山自一川，城郭洗憂戚。", "聽子話此邦，令我心悅懌。其俗則純樸，不知有主客。", "溫溫諸侯門，禮亦如古昔。敕廚倍常羞，杯盤頗狼藉。", "時雖屬喪亂，事貴賞匹敵。中宵愜良會，裴鄭非遠戚。", "群書一萬卷，博涉供務隙。他日辱銀鉤，森疏見矛戟。", "倒屣喜旋歸，畫地求所曆。乃聞風土質，又重田疇辟。", "刺史似寇恂，列郡宜競惜。北風吹瘴癘，羸老思散策。", "渚拂蒹葭塞，嶠穿蘿蔦冪。此身仗兒僕，高興潛有激。", "孟冬方首路，強飯取崖壁。歎爾疲駑駘，汗溝血不赤。", "終然備外飾，駕馭何所益。我有平肩輿，前途猶准的。", "翩翩入鳥道，庶脫蹉跌厄。"]'),
('yuding-18','柴門','杜甫','唐','御定全唐诗','yuding','','[]','孤舟登瀼西，回首望兩崖。東城乾旱天，其氣如焚柴。',252,'御定全唐詩/json/221.json','["孤舟登瀼西，回首望兩崖。東城乾旱天，其氣如焚柴。", "長影沒窈窕，餘光散唅呀。大江蟠嵌根，歸海成一家。", "下沖割坤軸，竦壁攢鏌鋣。蕭颯灑秋色，氛昏霾日車。", "峽門自此始，最窄容浮查。禹功翊造化，疏鑿就欹斜。", "巨渠決太古，眾水為長蛇。風煙渺吳蜀，舟楫通鹽麻。", "我今遠遊子，飄轉混泥沙。萬物附本性，約身不願奢。", "茅棟蓋一床，清池有餘花。濁醪與脫粟，在眼無咨嗟。", "山荒人民少，地僻日夕佳。貧病固其常，富貴任生涯。", "老於干戈際，宅幸蓬蓽遮。石亂上雲氣，杉清延月華。", "賞妍又分外，理愜夫何誇。足了垂白年，敢居高士差。", "書此豁平昔，回首猶暮霞。"]'),
('yuding-19','貽華陽柳少府','杜甫','唐','御定全唐诗','yuding','','[]','系馬喬木間，問人野寺門。柳侯披衣笑，見我顏色溫。',240,'御定全唐詩/json/221.json','["系馬喬木間，問人野寺門。柳侯披衣笑，見我顏色溫。", "並坐石下堂，俯視大江奔。火雲洗月露，絕壁上朝暾。", "自非曉相訪，觸熱生病根。南方六七月，出入異中原。", "老少多暍死，汗逾水漿翻。俊才得之子，筋力不辭煩。", "指揮當世事，語及戎馬存。涕淚濺我裳，悲氣排帝閽。", "郁陶抱長策，義仗知者論。吾衰臥江漢，但愧識璵璠。", "文章一小技，於道未為尊。起予幸斑白，因是托子孫。", "俱客古信州，結廬依毀垣。相去四五裏，徑微山葉繁。", "時危挹佳士，況免軍旅喧。醉從趙女舞，歌鼓秦人盆。", "子壯顧我傷，我歡兼淚痕。餘生如過鳥，故里今空村。"]'),
('yuding-20','雷','杜甫','唐','御定全唐诗','yuding','','[]','大旱山嶽燋，密雲複無雨。南方瘴癘地，罹此農事苦。',192,'御定全唐詩/json/221.json','["大旱山嶽燋，密雲複無雨。南方瘴癘地，罹此農事苦。", "封內必舞雩，峽中喧擊鼓。真龍竟寂寞，土梗空俯僂。", "籲嗟公私病，稅斂缺不補。故老仰面啼，瘡痍向誰數。", "暴尪或前聞，鞭巫非稽古。請先偃甲兵，處分聽人主。", "萬邦但各業，一物休盡取。水旱其數然，堯湯免親睹。", "上天鑠金石，群盜亂豺虎。二者存一端，愆陽不猶愈。", "昨宵殷其雷，風過齊萬弩。複吹霾翳散，虛覺神靈聚。", "氣暍腸胃融，汗滋衣裳汙。吾衰尤拙計，失望築場圃。"]'),
('yuding-21','火','杜甫','唐','御定全唐诗','yuding','','[]','楚山經月火，大旱則斯舉。舊俗燒蛟龍，驚惶致雷雨。',168,'御定全唐詩/json/221.json','["楚山經月火，大旱則斯舉。舊俗燒蛟龍，驚惶致雷雨。", "爆嵌魑魅泣，崩凍嵐陰昈。羅落沸百泓，根源皆萬古。", "青林一灰燼，雲氣無處所。入夜殊赫然，新秋照牛女。", "風吹巨焰作，河棹騰煙柱。勢俗焚昆侖，光彌焮洲渚。", "腥至焦長蛇，聲吼纏猛虎。神物已高飛，不見石與土。", "爾寧要謗讟，憑此近熒侮。薄關長吏憂，甚昧至精主。", "遠遷誰撲滅，將恐及環堵。流汗臥江亭，更深氣如縷。"]'),
('yuding-22','七月三日亭午已後較熱退晚加小涼穩睡有詩因論壯年樂事戲呈元二十一曹長','杜甫','唐','御定全唐诗','yuding','','[]','今茲商用事，餘熱亦已末。衰年旅炎方，生意從此活。',264,'御定全唐詩/json/221.json','["今茲商用事，餘熱亦已末。衰年旅炎方，生意從此活。", "亭午減汗流，北鄰耐人聒。晚風爽烏匼，筋力蘇摧折。", "閉目逾十旬，大江不止渴。退藏恨雨師，健步聞旱魃。", "園蔬抱金玉，無以供采掇。密雲雖聚散，徂暑終衰歇。", "前聖慎焚巫，武王親救暍。陰陽相主客，時序遞回斡。", "灑落唯清秋，昏霾一空闊。蕭蕭紫塞雁，南向欲行列。", "欻思紅顏日，霜露凍階闥。胡馬挾雕弓，鳴弦不虛發。", "長鈚逐狡兔，突羽當滿月。惆悵白頭吟，蕭條遊俠窟。", "臨軒望山閣，縹緲安可越。高人煉丹砂，未念將朽骨。", "少壯跡頗疏，歡樂曾倏忽。杖藜風塵際，老醜難翦拂。", "吾子得神仙，本是池中物。賤夫美一睡，煩促嬰詞筆。"]'),
('yuding-23','牽牛織女','杜甫','唐','御定全唐诗','yuding','','[]','牽牛出河西，織女處其東。萬古永相望，七夕誰見同。',216,'御定全唐詩/json/221.json','["牽牛出河西，織女處其東。萬古永相望，七夕誰見同。", "神光意難候，此事終蒙朧。颯然精靈合，何必秋遂通。", "亭亭新妝立，龍駕具曾空。世人亦為爾，祈請走兒童。", "稱家隨豐儉，白屋達公宮。膳夫翊堂殿，鳴玉淒房櫳。", "曝衣遍天下，曳月揚微風。蛛絲小人態，曲綴瓜果中。", "初筵裛重露，日出甘所終。嗟汝未嫁女，秉心鬱忡忡。", "防身動如律，竭力機杼中。雖無姑舅事，敢昧織作功。", "明明君臣契，咫尺或未容。義無棄禮法，恩始夫婦恭。", "小大有佳期，戒之在至公。方圓苟齟齬，丈夫多英雄。"]'),
('yuding-24','毒熱寄簡崔評事十六弟','杜甫','唐','御定全唐诗','yuding','','[]','大暑運金氣，荊揚不知秋。林下有塌翼，水中無行舟。',168,'御定全唐詩/json/221.json','["大暑運金氣，荊揚不知秋。林下有塌翼，水中無行舟。", "千室但掃地，閉關人事休。老夫轉不樂，旅次兼百憂。", "蝮蛇暮偃蹇，空床難暗投。炎宵惡明燭，況乃懷舊丘。", "開襟仰內弟，執熱露白頭。束帶負芒刺，接居成阻修。", "何當清霜飛，會子臨江樓。載聞大易義，諷興詩家流。", "蘊藉異時輩，檢身非苟求。皇皇使臣體，信是德業優。", "楚材擇杞梓，漢苑歸驊騮。短章達我心，理為識者籌。"]'),
('yuding-25','殿中楊監見示張旭草書圖','杜甫','唐','御定全唐诗','yuding','','[]','斯人已雲亡，草聖秘難得。及茲煩見示，滿目一淒惻。',132,'御定全唐詩/json/221.json','["斯人已雲亡，草聖秘難得。及茲煩見示，滿目一淒惻。", "悲風生微綃，萬里起古色。鏘鏘鳴玉動，落落群松直。", "連山蟠其間，溟漲與筆力。有練實先書，臨池真盡墨。", "俊拔為之主，暮年思轉極。未知張王后，誰並百代則。", "嗚呼東吳精，逸氣感清識。楊公拂篋笥，舒卷忘寢食。", "念昔揮毫端，不獨觀酒德。"]'),
('yuding-26','楊監又出畫鷹十二扇','杜甫','唐','御定全唐诗','yuding','','[]','近時馮紹正，能畫鷙鳥樣。明公出此圖，無乃傳其狀。',120,'御定全唐詩/json/221.json','["近時馮紹正，能畫鷙鳥樣。明公出此圖，無乃傳其狀。", "殊姿各獨立，清絕心有向。疾禁千里馬，氣敵萬人將。", "憶昔驪山宮，冬移含元仗。天寒大羽獵，此物神俱王。", "當時無凡材，百中皆用壯。粉墨形似間，識者一惆悵。", "干戈少暇日，真骨老崖嶂。為君除狡兔，會是翻鞲上。"]'),
('yuding-27','送殿中楊監赴蜀見相公','杜甫','唐','御定全唐诗','yuding','','[]','去水絕還波，泄雲無定姿。人生在世間，聚散亦暫時。',144,'御定全唐詩/json/221.json','["去水絕還波，泄雲無定姿。人生在世間，聚散亦暫時。", "離別重相逢，偶然豈定期。送子清秋暮，風物長年悲。", "豪俊貴勳業，邦家頻出師。相公鎮梁益，軍事無孑遺。", "解榻再見今，用才複擇誰。況子已高位，為郡得固辭。", "難拒供給費，慎哀漁奪私。干戈未甚息，紀綱正所持。", "泛舟巨石橫，登陸草露滋。山門日易久，當念居者思。"]'),
('yuding-28','贈李十五丈別','杜甫','唐','御定全唐诗','yuding','','[]','峽人鳥獸居，其室附層顛。下臨不測江，中有萬里船。',252,'御定全唐詩/json/221.json','["峽人鳥獸居，其室附層顛。下臨不測江，中有萬里船。", "多病紛倚薄，少留改歲年。絕域誰慰懷，開顏喜名賢。", "孤陋忝末親，等級敢比肩。人生意頗合，相與襟袂連。", "一日兩遣僕，三日一共筵。揚論展寸心，壯筆過飛泉。", "玄成美價存，子山舊業傳。不聞八尺軀，常受眾目憐。", "且為辛苦行，蓋被生事牽。北回白帝棹，南入黔陽天。", "汧公制方隅，迥出諸侯先。封內如太古，時危獨蕭然。", "清高金莖露，正直朱絲弦。昔在堯四嶽，今之黃潁川。", "於邁恨不同，所思無由宣。山深水增波，解榻秋露懸。", "客遊雖雲久，主要月再圓。晨集風渚亭，醉操雲嶠篇。", "丈夫貴知己，歡罷念歸旋。"]'),
('yuding-29','西閣曝日','杜甫','唐','御定全唐诗','yuding','','[]','凜冽倦玄冬，負暄嗜飛閣。羲和流德澤，顓頊愧倚薄。',120,'御定全唐詩/json/221.json','["凜冽倦玄冬，負暄嗜飛閣。羲和流德澤，顓頊愧倚薄。", "毛髮具自和，肌膚潛沃若。太陽信深仁，衰氣欻有托。", "欹傾煩注眼，容易收病腳。流離木杪猿，翩躚山顛鶴。", "用知苦聚散，哀樂日已作。即事會賦詩，人生忽如昨。", "古來遭喪亂，賢聖盡蕭索。胡為將暮年，憂世心力弱。"]'),
('yuding-30','課伐木','杜甫','唐','御定全唐诗','yuding','','[]','長夏無所為，客居課奴僕。清晨飯其腹，持斧入白穀。',216,'御定全唐詩/json/221.json','["長夏無所為，客居課奴僕。清晨飯其腹，持斧入白穀。", "青冥曾巔後，十裏斬陰木。人肩四根已，亭午下山麓。", "尚聞丁丁聲，功課日各足。蒼皮成委積，素節相照燭。", "藉汝跨小籬，當仗苦虛竹。空荒咆熊羆，乳獸待人肉。", "不示知禁情，豈惟干戈哭。城中賢府主，處貴如白屋。", "蕭蕭理體淨，蜂蠆不敢毒。虎穴連裏閭，堤防舊風俗。", "泊舟滄江岸，久客慎所觸。舍西崖嶠壯，雷雨蔚含蓄。", "牆宇資屢修，衰年怯幽獨。爾曹輕執熱，為我忍煩促。", "秋光近青岑，季月當泛菊。報之以微寒，共給酒一斛。"]'),
('yuding-31','園人送瓜','杜甫','唐','御定全唐诗','yuding','','[]','江間雖炎瘴，瓜熟亦不早。柏公鎮夔國，滯務茲一掃。',120,'御定全唐詩/json/221.json','["江間雖炎瘴，瓜熟亦不早。柏公鎮夔國，滯務茲一掃。", "食新先戰士，共少及溪老。傾筐蒲鴿青，滿眼顏色好。", "竹竿接嵌竇，引注來鳥道。沈浮亂水玉，愛惜如芝草。", "落刃嚼冰霜，開懷慰枯槁。許以秋蒂除，仍看小童抱。", "東陵跡蕪絕，楚漢休征討。園人非故侯，種此何草草。"]'),
('yuding-32','信行遠修水筒','杜甫','唐','御定全唐诗','yuding','','[]','汝性不茹葷，清靜僕夫內。秉心識本源，於事少滯礙。',120,'御定全唐詩/json/221.json','["汝性不茹葷，清靜僕夫內。秉心識本源，於事少滯礙。", "雲端水筒坼，林表山石碎。觸熱藉子修，通流與廚會。", "往來四十裏，荒險崖谷大。日曛驚未餐，貌赤愧相對。", "浮瓜供老病，裂餅嘗所愛。於斯答恭謹，足以殊殿最。", "詎要方士符，何假將軍蓋。行諸直如筆，用意崎嶇外。"]'),
('yuding-33','槐葉冷淘','杜甫','唐','御定全唐诗','yuding','','[]','青青高槐葉，采掇付中廚。新面來近市，汁滓宛相俱。',120,'御定全唐詩/json/221.json','["青青高槐葉，采掇付中廚。新面來近市，汁滓宛相俱。", "入鼎資過熟，加餐愁欲無。碧鮮俱照箸，香飯兼苞蘆。", "經齒冷於雪，勸人投此珠。願隨金騕褭，走置錦屠蘇。", "路遠思恐泥，興深終不渝。獻芹則小小，薦藻明區區。", "萬里露寒殿，開冰清玉壺。君王納涼晚，此味亦時須。"]'),
('yuding-34','行官張望補稻畦水歸','杜甫','唐','御定全唐诗','yuding','','[]','東屯大江北，百頃平若案。六月青稻多，千畦碧泉亂。',144,'御定全唐詩/json/221.json','["東屯大江北，百頃平若案。六月青稻多，千畦碧泉亂。", "插秧適雲已，引溜加溉灌。更僕往方塘，決渠當斷岸。", "公私各地著，浸潤無天旱。主守問家臣，分明見溪伴。", "芊芊炯翠羽，剡剡生銀漢。鷗鳥鏡裏來，關山雲邊看。", "秋菰成黑米，精鑿傳白粲。玉粒足晨炊，紅鮮任霞散。", "終然添旅食，作苦期壯觀。遺穗及眾多，我倉戒滋蔓。"]'),
('yuding-35','催宗文樹雞柵','杜甫','唐','御定全唐诗','yuding','','[]','吾衰怯行邁，旅次展崩迫。愈風傳烏雞，秋卵方漫吃。',216,'御定全唐詩/json/221.json','["吾衰怯行邁，旅次展崩迫。愈風傳烏雞，秋卵方漫吃。", "自春生成者，隨母向百翮。驅趁制不禁，喧呼山腰宅。", "課奴殺青竹，終日憎赤幘。蹋藉盤案翻，塞蹊使之隔。", "牆東有隙地，可以樹高柵。避熱時來歸，問兒所為跡。", "織籠曹其內，令人不得擲。稀間可突過，觜爪還汙席。", "我寬螻蟻遭，彼免狐貉厄。應宜各長幼，自此均勍敵。", "籠柵念有修，近身見損益。明明領處分，一一當剖析。", "不昧風雨晨，亂離減憂戚。其流則凡鳥，其氣心匪石。", "倚賴窮歲晏，撥煩去冰釋。未似屍鄉翁，拘留蓋阡陌。"]'),
('yuding-36','園官送菜','杜甫','唐','御定全唐诗','yuding','','[]','清晨蒙菜把，常荷地主恩。守者愆實數，略有其名存。',156,'御定全唐詩/json/221.json','["清晨蒙菜把，常荷地主恩。守者愆實數，略有其名存。", "苦苣刺如針，馬齒葉亦繁。青青嘉蔬色，埋沒在中園。", "園吏未足怪，世事固堪論。嗚呼戰伐久，荊棘暗長原。", "乃知苦苣輩，傾奪蕙草根。小人塞道路，為態何喧喧。", "又如馬齒盛，氣擁葵荏昏。點染不易虞，絲麻雜羅紈。", "一經器物內，永掛粗刺痕。志士采紫芝，放歌避戎軒。", "畦丁負籠至，感動百慮端。"]'),
('yuding-37','上後園山腳','杜甫','唐','御定全唐诗','yuding','','[]','朱夏熱所嬰，清旭步北林。小園背高岡，挽葛上崎崟。',144,'御定全唐詩/json/221.json','["朱夏熱所嬰，清旭步北林。小園背高岡，挽葛上崎崟。", "曠望延駐目，飄搖散疏襟。潛鱗恨水壯，去翼依雲深。", "勿謂地無疆，劣于山有陰。石榞遍天下，水陸兼浮沈。", "自我登隴首，十年經碧岑。劍門來巫峽，薄倚浩至今。", "故園暗戎馬，骨肉失追尋。時危無消息，老去多歸心。", "志士惜白日，久客藉黃金。敢為蘇門嘯，庶作梁父吟。"]'),
('yuding-38','驅豎子摘蒼耳','杜甫','唐','御定全唐诗','yuding','','[]','江上秋已分，林中瘴猶劇。畦丁告勞苦，無以供日夕。',144,'御定全唐詩/json/221.json','["江上秋已分，林中瘴猶劇。畦丁告勞苦，無以供日夕。", "蓬莠獨不焦，野蔬暗泉石。卷耳況療風，童兒且時摘。", "侵星驅之去，爛熳任遠適。放筐亭午際，洗剝相蒙冪。", "登床半生熟，下箸還小益。加點瓜薤間，依稀橘奴跡。", "亂世誅求急，黎民糠籺窄。飽食複何心，荒哉膏粱客。", "富家廚肉臭，戰地骸骨白。寄語惡少年，黃金且休擲。"]'),
('yuding-39','秋行官張望督促東渚耗稻向畢清晨遣女奴阿稽豎子阿段往問','杜甫','唐','御定全唐诗','yuding','','[]','東渚雨今足，佇聞粳稻香。上天無偏頗，蒲稗各自長。',204,'御定全唐詩/json/221.json','["東渚雨今足，佇聞粳稻香。上天無偏頗，蒲稗各自長。", "人情見非類，田家戒其荒。功夫競搰搰，除草置岸旁。", "穀者命之本，客居安可忘。青春具所務，勤墾免亂常。", "吳牛力容易，並驅動莫當。豐苗亦已穊，雲水照方塘。", "有生固蔓延，靜一資堤防。督領不無人，提攜頗在綱。", "荊揚風土暖，肅肅候微霜。尚恐主守疏，用心未甚臧。", "清朝遣婢僕，寄語逾崇岡。西成聚必散，不獨陵我倉。", "豈要仁裏譽，感此亂世忙。北風吹蒹葭，蟋蟀近中堂。", "荏苒百工休，鬱紆遲暮傷。"]'),
('yuding-40','阻雨不得歸瀼西甘林','杜甫','唐','御定全唐诗','yuding','','[]','三伏適已過，驕陽化為霖。欲歸瀼西宅，阻此江浦深。',192,'御定全唐詩/json/221.json','["三伏適已過，驕陽化為霖。欲歸瀼西宅，阻此江浦深。", "壞舟百版坼，峻岸複萬尋。篙工初一棄，恐泥勞寸心。", "佇立東城隅，悵望高飛禽。草堂亂懸圃，不隔昆侖岑。", "昏渾衣裳外，曠絕同層陰。園甘長成時，三寸如黃金。", "諸侯舊上計，厥貢傾千林。邦人不足重，所迫豪吏侵。", "客居暫封殖，日夜偶瑤琴。虛徐五株態，側塞煩胸襟。", "焉得輟兩足，杖藜出嶇嶔。條流數翠實，偃息歸碧潯。", "拂拭烏皮幾，喜聞樵牧音。令兒快搔背，脫我頭上簪。"]'),
('yuding-41','雨','杜甫','唐','御定全唐诗','yuding','','[]','峽雲行清曉，煙霧相裴回。風吹蒼江樹，雨灑石壁來。',96,'御定全唐詩/json/221.json','["峽雲行清曉，煙霧相裴回。風吹蒼江樹，雨灑石壁來。", "淒淒生餘寒，殷殷兼出雷。白谷變氣候，朱炎安在哉。", "高鳥濕不下，居人門未開。楚宮久已滅，幽佩為誰哀。", "侍臣書王夢，賦有冠古才。冥冥翠龍駕，多自巫山台。"]'),
('yuding-42','雨二首','杜甫','唐','御定全唐诗','yuding','','[]','青山澹無姿，白露誰能數。片片水上雲，蕭蕭沙中雨。',192,'御定全唐詩/json/221.json','["青山澹無姿，白露誰能數。片片水上雲，蕭蕭沙中雨。", "殊俗狀巢居，曾台俯風渚。佳客適萬里，沈思情延佇。", "掛帆遠色外，驚浪滿吳楚。久陰蛟螭出，寇盜複幾許。", "空山中宵陰，微冷先枕席。回風起清曙，萬象萋已碧。", "落落出岫雲，渾渾倚天石。日假何道行，雨含長江白。", "連檣荊州船，有士荷矛戟。南防草鎮慘，沾濕赴遠役。", "群盜下辟山，總戎備強敵。水深雲光廓，鳴櫓各有適。", "漁艇息悠悠，夷歌負樵客。留滯一老翁，書時記朝夕。"]'),
('yuding-43','晚登瀼上堂','杜甫','唐','御定全唐诗','yuding','','[]','故躋瀼岸高，頗免崖石擁。開襟野堂豁，系馬林花動。',144,'御定全唐詩/json/221.json','["故躋瀼岸高，頗免崖石擁。開襟野堂豁，系馬林花動。", "雉堞粉如雲，山田麥無壟。春氣晚更生，江流靜猶湧。", "四序嬰我懷，群盜久相踵。黎民困逆節，天子渴垂拱。", "所思注東北，深峽轉修聳。衰老自成病，郎官未為冗。", "淒其望呂葛，不復夢周孔。濟世數向時，斯人各枯塚。", "楚星南天黑，蜀月西霧重。安得隨鳥翎，迫此懼將恐。"]'),
('yuding-44','又上後園山腳','杜甫','唐','御定全唐诗','yuding','','[]','昔我游山東，憶戲東岳陽。窮秋立日觀，矯首望八荒。',216,'御定全唐詩/json/221.json','["昔我游山東，憶戲東岳陽。窮秋立日觀，矯首望八荒。", "朱崖著毫髮，碧海吹衣裳。蓐收困用事，玄冥蔚強梁。", "逝水自朝宗，鎮名各其方。平原獨憔悴，農力廢耕桑。", "非關風露凋，曾是戍役傷。于時國用富，足以守邊疆。", "朝廷任猛將，遠奪戎虜場。到今事反復，故老淚萬行。", "龜蒙不復見，況乃懷舊鄉。肺萎屬久戰，骨出熱中腸。", "憂來杖匣劍，更上林北岡。瘴毒猿鳥落，峽幹南日黃。", "秋風亦已起，江漢始如湯。登高欲有往，蕩析川無梁。", "哀彼遠征人，去家死路旁。不及祖父塋，累累塚相當。"]'),
('yuding-45','雨','杜甫','唐','御定全唐诗','yuding','','[]','山雨不作泥，江雲薄為霧。晴飛半嶺鶴，風亂平沙樹。',192,'御定全唐詩/json/221.json','["山雨不作泥，江雲薄為霧。晴飛半嶺鶴，風亂平沙樹。", "明滅洲景微，隱見岩姿露。拘悶出門遊，曠絕經目趣。", "消中日伏枕，臥久塵及屨。豈無平肩輿，莫辨望鄉路。", "兵戈浩未息，蛇虺反相顧。悠悠邊月破，鬱鬱流年度。", "針灸阻朋曹，糠籺對童孺。一命須屈色，新知漸成故。", "窮荒益自卑，飄泊欲誰訴。尪羸愁應接，俄頃恐違迕。", "浮俗何萬端，幽人有獨步。龐公竟獨往，尚子終罕遇。", "宿留洞庭秋，天寒瀟湘素。杖策可入舟，送此齒發暮。"]'),
('yuding-46','甘林','杜甫','唐','御定全唐诗','yuding','','[]','舍舟越西岡，入林解我衣。青芻適馬性，好鳥知人歸。',192,'御定全唐詩/json/221.json','["舍舟越西岡，入林解我衣。青芻適馬性，好鳥知人歸。", "晨光映遠岫，夕露見日晞。遲暮少寢食，清曠喜荊扉。", "經過倦俗態，在野無所違。試問甘藜藿，未肯羨輕肥。", "喧靜不同科，出處各天機。勿矜朱門是，陋此白屋非。", "明朝步鄰里，長老可以依。時危賦斂數，脫粟為爾揮。", "相攜行豆田，秋花靄菲菲。子實不得吃，貨市送王畿。", "盡添軍旅用，迫此公家威。主人長跪問，戎馬何時稀。", "我衰易悲傷，屈指數賊圍。勸其死王命，慎莫遠奮飛。"]'),
('yuding-47','雨','杜甫','唐','御定全唐诗','yuding','','[]','行雲遞崇高，飛雨靄而至。潺潺石間溜，汩汩松上駛。',120,'御定全唐詩/json/221.json','["行雲遞崇高，飛雨靄而至。潺潺石間溜，汩汩松上駛。", "亢陽乘秋熱，百穀皆已棄。皇天德澤降，焦卷有生意。", "前雨傷卒暴，今雨喜容易。不可無雷霆，間作鼓增氣。", "佳聲達中宵，所望時一致。清霜九月天，仿佛見滯穗。", "郊扉及我私，我圃日蒼翠。恨無抱甕力，庶減臨江費。"]'),
('yuding-48','種萵苣','杜甫','唐','御定全唐诗','yuding','','[]','陰陽一錯亂，驕蹇不復理。枯旱于其中，炎方慘如毀。',252,'御定全唐詩/json/221.json','["陰陽一錯亂，驕蹇不復理。枯旱于其中，炎方慘如毀。", "植物半蹉跎，嘉生將已矣。雲雷欻奔命，師伯集所使。", "指麾赤白日，澒洞青光起。雨聲先已風，散足盡西靡。", "山泉落滄江，霹靂猶在耳。終朝紆颯遝，信宿罷瀟灑。", "堂下可以畦，呼童對經始。苣兮蔬之常，隨事藝其子。", "破塊數席間，荷鋤功易止。兩旬不甲坼，空惜埋泥滓。", "野莧迷汝來，宗生實於此。此輩豈無秋，亦蒙寒露委。", "翻然出地速，滋蔓戶庭毀。因知邪幹正，掩抑至沒齒。", "賢良雖得祿，守道不封己。擁塞敗芝蘭，眾多盛荊杞。", "中園陷蕭艾，老圃永為恥。登于白玉盤，藉以如霞綺。", "莧也無所施，胡顏入筐篚。"]'),
('yuding-49','暇日小園散病，將種秋菜，督勒耕牛，兼書觸目','杜甫','唐','御定全唐诗','yuding','','[]','不愛入州府，畏人嫌我真。及乎歸茅宇，旁舍未曾嗔。',180,'御定全唐詩/json/221.json','["不愛入州府，畏人嫌我真。及乎歸茅宇，旁舍未曾嗔。", "老病忌拘束，應接喪精神。江村意自放，林木心所欣。", "秋耕屬地濕，山雨近甚勻。冬菁飯之半，牛力晚來新。", "深耕種數畝，未甚後四鄰。嘉蔬既不一，名數頗具陳。", "荊巫非苦寒，採擷接青春。飛來兩白鶴，暮啄泥中芹。", "雄者左翮垂，損傷已露筋。一步再流血，尚經矰繳勤。", "三步六號叫，志屈悲哀頻。鸞皇不相待，側頸訴高旻。", "杖藜俯沙渚，為汝鼻酸辛。"]'),
('yuding-0','八哀詩：贈司空王公思禮','杜甫','唐','御定全唐诗','yuding','','[]','司空出東夷，童稚刷勁翮。追隨燕薊兒，穎銳物不隔。',384,'御定全唐詩/json/222.json','["司空出東夷，童稚刷勁翮。追隨燕薊兒，穎銳物不隔。", "服事哥舒翰，意無流沙磧。未甚拔行間，犬戎大充斥。", "短小精悍姿，屹然強寇敵。貫穿百萬眾，出入由咫尺。", "馬鞍懸將首，甲外控鳴鏑。洗劍青海水，刻銘天山石。", "九曲非外蕃，其王轉深壁。飛兔不近駕，鷙鳥資遠擊。", "曉達兵家流，飽聞春秋癖。胸襟日沈靜，肅肅自有適。", "潼關初潰散，萬乘猶辟易。偏裨無所施，元帥見手格。", "太子入朔方，至尊狩梁益。胡馬纏伊洛，中原氣甚逆。", "肅宗登寶位，塞望勢敦迫。公時徒步至，請罪將厚責。", "際會清河公，間道傳玉冊。天王拜跪畢，讜議果冰釋。", "翠華卷飛雪，熊虎亙阡陌。屯兵鳳凰山，帳殿涇渭辟。", "金城賊咽喉，詔鎮雄所搤。禁暴清無雙，爽氣春淅瀝。", "巷有從公歌，野多青青麥。及夫哭廟後，複領太原役。", "恐懼祿位高，悵望王土窄。不得見清時，嗚呼就窀穸。", "永系五湖舟，悲甚田橫客。千秋汾晉間，事與雲水白。", "昔觀文苑傳，豈述廉藺績。嗟嗟鄧大夫，士卒終倒戟。"]'),
('yuding-1','八哀詩：故司徒李公光弼','杜甫','唐','御定全唐诗','yuding','','[]','司徒天寶末，北收晉陽甲。胡騎攻吾城，愁寂意不愜。',240,'御定全唐詩/json/222.json','["司徒天寶末，北收晉陽甲。胡騎攻吾城，愁寂意不愜。", "人安若泰山，薊北斷右脅。朔方氣乃蘇，黎首見帝業。", "二宮泣西郊，九廟起頹壓。未散河陽卒，思明偽臣妾。", "複自碣石來，火焚乾坤獵。高視笑祿山，公又大獻捷。", "異王冊崇勳，小敵信所怯。擁兵鎮河汴，千里初妥帖。", "青蠅紛營營，風雨秋一葉。內省未入朝，死淚終映睫。", "大屋去高棟，長城掃遺堞。平生白羽扇，零落蛟龍匣。", "雅望與英姿，惻愴槐裏接。三軍晦光彩，烈士痛稠疊。", "直筆在史臣，將來洗箱篋。吾思哭孤塚，南紀阻歸楫。", "扶顛永蕭條，未濟失利涉。疲苶竟何人，灑涕巴東峽。"]'),
('yuding-2','八哀詩：贈左僕射鄭國公嚴公武','杜甫','唐','御定全唐诗','yuding','','[]','鄭公瑚璉器，華岳金天晶。昔在童子日，已聞老成名。',408,'御定全唐詩/json/222.json','["鄭公瑚璉器，華岳金天晶。昔在童子日，已聞老成名。", "嶷然大賢後，複見秀骨清。開口取將相，小心事友生。", "閱書百紙盡，落筆四座驚。曆職匪父任，嫉邪常力爭。", "漢儀尚整肅，胡騎忽縱橫。飛傳自河隴，逢人問公卿。", "不知萬乘出，雪涕風悲鳴。受詞劍閣道，謁帝蕭關城。", "寂寞雲台仗，飄颻沙塞旌。江山少使者，笳鼓凝皇情。", "壯士血相視，忠臣氣不平。密論貞觀體，揮發岐陽征。", "感激動四極，聯翩收二京。西郊牛酒再，原廟丹青明。", "匡汲俄寵辱，衛霍竟哀榮。四登會府地，三掌華陽兵。", "京兆空柳色，尚書無履聲。群烏自朝夕，白馬休橫行。", "諸葛蜀人愛，文翁儒化成。公來雪山重，公去雪山輕。", "記室得何遜，韜鈐延子荊。四郊失壁壘，虛館開逢迎。", "堂上指圖畫，軍中吹玉笙。豈無成都酒，憂國只細傾。", "時觀錦水釣，問俗終相並。意待犬戎滅，人藏紅粟盈。", "以茲報主願，庶或裨世程。炯炯一心在，沉沉二豎嬰。", "顏回竟短折，賈誼徒忠貞。飛旐出江漢，孤舟輕荊衡。", "虛無馬融笛，悵望龍驤塋。空餘老賓客，身上愧簪纓。"]'),
('yuding-3','八哀詩：贈太子太師汝陽郡王璡','杜甫','唐','御定全唐诗','yuding','','[]','汝陽讓帝子，眉宇真天人。虯須似太宗，色映塞外春。',312,'御定全唐詩/json/222.json','["汝陽讓帝子，眉宇真天人。虯須似太宗，色映塞外春。", "往者開元中，主恩視遇頻。出入獨非時，禮異見群臣。", "愛其謹潔極，倍此骨肉親。從容聽朝後，或在風雪晨。", "忽思格猛獸，苑囿騰清塵。羽旗動若一，萬馬肅駪駪。", "詔王來射雁，拜命已挺身。箭出飛鞚內，上又回翠麟。", "翻然紫塞翮，下拂明月輪。胡人雖獲多，天笑不為新。", "王每中一物，手自與金銀。袖中諫獵書，扣馬久上陳。", "竟無銜橛虞，聖聰矧多仁。官免供給費，水有在藻鱗。", "匪唯帝老大，皆是王忠勤。晚年務置醴，門引申白賓。", "道大容無能，永懷侍芳茵。好學尚貞烈，義形必沾巾。", "揮翰綺繡揚，篇什若有神。川廣不可溯，墓久狐兔鄰。", "宛彼漢中郡，文雅見天倫。何以開我悲，泛舟俱遠津。", "溫溫昔風味，少壯已書紳。舊游易磨滅，衰謝增酸辛。"]'),
('yuding-4','八哀詩：贈秘書監江夏李公邕','杜甫','唐','御定全唐诗','yuding','','[]','長嘯宇宙間，高才日陵替。古人不可見，前輩複誰繼。',516,'御定全唐詩/json/222.json','["長嘯宇宙間，高才日陵替。古人不可見，前輩複誰繼。", "憶昔李公存，詞林有根柢。聲華當健筆，灑落富清制。", "風流散金石，追琢山嶽銳。情窮造化理，學貫天人際。", "幹謁走其門，碑版照四裔。各滿深望還，森然起凡例。", "蕭蕭白楊路，洞徹寶珠惠。龍宮塔廟湧，浩劫浮雲衛。", "宗儒俎豆事，故吏去思計。眄睞已皆虛，跋涉曾不泥。", "向來映當時，豈獨勸後世。豐屋珊瑚鉤，騏驎織成罽。", "紫騮隨劍幾，義取無虛歲。分宅脫驂間，感激懷未濟。", "眾歸賙給美，擺落多藏穢。獨步四十年，風聽九皋唳。", "嗚呼江夏姿，竟掩宣尼袂。往者武后朝，引用多寵嬖。", "否臧太常議，面折二張勢。衰俗凜生風，排蕩秋旻霽。", "忠貞負冤恨，宮闕深旒綴。放逐早聯翩，低垂困炎厲。", "日斜鵩鳥入，魂斷蒼梧帝。榮枯走不暇，星駕無安稅。", "幾分漢廷竹，夙擁文侯篲。終悲洛陽獄，事近小臣敝。", "禍階初負謗，易力何深嚌。伊昔臨淄亭，酒酣托末契。", "重敘東都別，朝陰改軒砌。論文到崔蘇，指盡流水逝。", "近伏盈川雄，未甘特進麗。是非張相國，相扼一危脆。", "爭名古豈然，鍵捷欻不閉。例及吾家詩，曠懷掃氛翳。", "慷慨嗣真作，咨嗟玉山桂。鐘律儼高懸，鯤鯨噴迢遞。", "坡陀青州血，蕪沒汶陽瘞。哀贈竟蕭條，恩波延揭厲。", "子孫存如線，舊客舟凝滯。君臣尚論兵，將帥接燕薊。", "朗吟六公篇，憂來豁蒙蔽。"]'),
('yuding-5','八哀詩：故秘書少監武功蘇公源明','杜甫','唐','御定全唐诗','yuding','','[]','武功少也孤，徒步客徐兗。讀書東嶽中，十載考墳典。',361,'御定全唐詩/json/222.json','["武功少也孤，徒步客徐兗。讀書東嶽中，十載考墳典。", "時下萊蕪郭，忍饑浮雲巘。負米晚為身，每食臉必泫。", "夜字照爇薪，垢衣生碧蘚。庶以勤苦志，報茲劬勞顯。", "學蔚醇儒姿，文包舊史善。灑落辭幽人，歸來潛京輦。", "射君東堂策，宗匠集精選。制可題未幹，乙科已大闡。", "文章日自負，吏祿亦累踐。晨趨閶闔內，足蹋宿昔趼。", "一麾出守還，黃屋朔風卷。不暇陪八駿，虜庭悲所遣。", "平生滿尊酒，斷此朋知展。憂憤病二秋，有恨石可轉。", "肅宗複社稷，得無逆順辨。范曄顧其兒，李斯憶黃犬。", "秘書茂松意，溟漲本末淺。青熒芙蓉劍，犀兕豈獨剸。", "反為後輩褻，予實苦懷緬。煌煌齋房芝，事絕萬手搴。", "垂之俟來者，正始征勸勉。不要懸黃金，胡為投乳rP。", "結交三十載，吾與誰遊衍。滎陽複冥莫，罪罟已橫罥。", "嗚呼子逝日，始泰則終蹇。長安米萬錢，凋喪盡餘喘。", "戰伐何當解，歸帆阻清沔。尚纏漳水疾，永負蒿裏餞。"]'),
('yuding-6','八哀詩：故著作郎貶台州司戶滎陽鄭公虔','杜甫','唐','御定全唐诗','yuding','','[]','鶢鶋至魯門，不識鐘鼓饗。孔翠望赤霄，愁思雕籠養。',384,'御定全唐詩/json/222.json','["鶢鶋至魯門，不識鐘鼓饗。孔翠望赤霄，愁思雕籠養。", "滎陽冠眾儒，早聞名公賞。地崇士大夫，況乃氣精爽。", "天然生知姿，學立游夏上。神農極闕漏，黃石愧師長。", "藥纂西極名，兵流指諸掌。貫穿無遺恨，薈蕞何技癢。", "圭臬星經奧，蟲篆丹青廣。子雲窺未遍，方朔諧太枉。", "神翰顧不一，體變鐘兼兩。文傳天下口，大字猶在榜。", "昔獻書畫圖，新詩亦俱往。滄洲動玉陛，宣鶴誤一響。", "三絕自禦題，四方尤所仰。嗜酒益疏放，彈琴視天壤。", "形骸實土木，親近唯几杖。未曾寄官曹，突兀倚書幌。", "晚就芸香閣，胡塵昏坱莽。反復歸聖朝，點染無滌蕩。", "老蒙台州掾，泛泛浙江槳。覆穿四明雪，饑拾楢溪橡。", "空聞紫芝歌，不見杏壇丈。天長眺東南，秋色餘魍魎。", "別離慘至今，斑白徒懷曩。春深秦山秀，葉墜清渭朗。", "劇談王侯門，野稅林下鞅。操紙終夕酣，時物集遐想。", "詞場竟疏闊，平昔濫吹獎。百年見存歿，牢落吾安放。", "蕭條阮咸在，出處同世網。他日訪江樓，含淒述飄蕩。"]'),
('yuding-7','八哀詩：故右僕射相國張公九齡','杜甫','唐','御定全唐诗','yuding','','[]','相國生南紀，金璞無留礦。仙鶴下人間，獨立霜毛整。',288,'御定全唐詩/json/222.json','["相國生南紀，金璞無留礦。仙鶴下人間，獨立霜毛整。", "矯然江海思，複與雲路永。寂寞想土階，未遑等箕潁。", "上君白玉堂，倚君金華省。碣石歲崢嶸，天地日蛙黽。", "退食吟大庭，何心記榛梗。骨驚畏曩哲，鬒變負人境。", "雖蒙換蟬冠，右地恧多幸。敢忘二疏歸，痛迫蘇耽井。", "紫綬映暮年，荊州謝所領。庾公興不淺，黃霸鎮每靜。", "賓客引調同，諷詠在務屏。詩罷地有餘，篇終語清省。", "一陽發陰管，淑氣含公鼎。乃知君子心，用才文章境。", "散帙起翠螭，倚薄巫廬並。綺麗玄暉擁，箋誄任昉騁。", "自我一家則，未缺隻字警。千秋滄海南，名系朱鳥影。", "歸老守故林，戀闕悄延頸。波濤良史筆，蕪絕大庾嶺。", "向時禮數隔，制作難上請。再讀徐孺碑，猶思理煙艇。"]'),
('yuding-8','寫懷二首','杜甫','唐','御定全唐诗','yuding','','[]','勞生共乾坤，何處異風俗。冉冉自趨競，行行見羈束。',288,'御定全唐詩/json/222.json','["勞生共乾坤，何處異風俗。冉冉自趨競，行行見羈束。", "無貴賤不悲，無富貧亦足。萬古一骸骨，鄰家遞歌哭。", "鄙夫到巫峽，三歲如轉燭。全命甘留滯，忘情任榮辱。", "朝班及暮齒，日給還脫粟。編蓬石城東，采藥山北穀。", "用心霜雪間，不必條蔓綠。非關故安排，曾是順幽獨。", "達士如弦直，小人似鉤曲。曲直我不知，負暄候樵牧。", "夜深坐南軒，明月照我膝。驚風翻河漢，梁棟已出日。", "群生各一宿，飛動自儔匹。吾亦驅其兒，營營為私實。", "天寒行旅稀，歲暮日月疾。榮名忽中人，世亂如蟣虱。", "古者三皇前，滿腹志願畢。胡為有結繩，陷此膠與漆。", "禍首燧人氏，厲階董狐筆。君看燈燭張，轉使飛蛾密。", "放神八極外，俯仰俱蕭瑟。終契如往還，得匪合仙術。"]'),
('yuding-9','可歎','杜甫','唐','御定全唐诗','yuding','','[]','天上浮雲如白衣，斯須改變如蒼狗。古往今來共一時，',144,'御定全唐詩/json/222.json','["天上浮雲如白衣，斯須改變如蒼狗。古往今來共一時，", "丈夫正色動引經，酆城客子王季友。群書萬卷常暗誦，", "豫章太守高帝孫，引為賓客敬頗久。聞道三年未曾語，", "明月無瑕豈容易，紫氣鬱鬱猶沖鬥。時危可仗真豪俊，", "王生早曾拜顏色，高山之外皆培塿。用為羲和天為成，", "死為星辰終不滅，致君堯舜焉肯朽。吾輩碌碌飽飯行，"]'),
('yuding-10','觀公孫大娘弟子舞劍器行','杜甫','唐','御定全唐诗','yuding','','[]','昔有佳人公孫氏，一舞劍氣動四方。觀者如山色沮喪，',112,'御定全唐詩/json/222.json','["昔有佳人公孫氏，一舞劍氣動四方。觀者如山色沮喪，", "來如雷霆收震怒，罷如江海凝清光。絳唇珠袖兩寂寞，", "與餘問答既有以，感時撫事增惋傷。先帝侍女八千人，", "梨園子弟散如煙，女樂餘姿映寒日。金粟堆南木已拱，", "老夫不知其所往，足繭荒山轉愁疾。"]'),
('yuding-11','往在','杜甫','唐','御定全唐诗','yuding','','[]','往在西京日，胡來滿彤宮。中宵焚九廟，雲漢為之紅。',397,'御定全唐詩/json/222.json','["往在西京日，胡來滿彤宮。中宵焚九廟，雲漢為之紅。", "解瓦飛十裏，繐帷紛曾空。疚心惜木主，一一灰悲風。", "合昏排鐵騎，清旭散錦eL。賊臣表逆節，相賀以成功。", "是時妃嬪戮，連為糞土叢。當甯陷玉座，白間剝畫蟲。", "不知二聖處，私泣百歲翁。車駕既雲還，楹桷欻穹崇。", "故老複涕泗，祠官樹椅桐。宏壯不如初，已見帝力雄。", "前春禮郊廟，祀事親聖躬。微軀忝近臣，景從陪群公。", "登階捧玉冊，峨冕耿金鐘。侍祠恧先露，掖垣邇濯龍。", "天子惟孝孫，五雲起九重。鏡奩換粉黛，翠羽猶蔥朧。", "前者厭羯胡，後來遭犬戎。俎豆腐膻肉，罘罳行角弓。", "安得自西極，申命空山東。盡驅詣闕下，士庶塞關中。", "主將曉逆順，元元歸始終。一朝自罪己，萬里車書通。", "鋒鏑供鋤犁，征戍聽所從。冗官各複業，土著還力農。", "君臣節儉足，朝野歡呼同。中興似國初，繼體如太宗。", "端拱納諫諍，和風日沖融。赤墀櫻桃枝，隱映銀絲籠。", "千春薦陵寢，永永垂無窮。京都不再火，涇渭開愁容。", "歸號故松柏，老去苦飄蓬。"]'),
('yuding-12','昔游','杜甫','唐','御定全唐诗','yuding','','[]','昔者與高李，晚登單父台。寒蕪際碣石，萬里風雲來。',216,'御定全唐詩/json/222.json','["昔者與高李，晚登單父台。寒蕪際碣石，萬里風雲來。", "桑柘葉如雨，飛藿去裴回。清霜大澤凍，禽獸有餘哀。", "是時倉廩實，洞達寰區開。猛士思滅胡，將帥望三台。", "君王無所惜，駕馭英雄材。幽燕盛用武，供給亦勞哉。", "吳門轉粟帛，泛海陵蓬萊。肉食三十萬，獵射起黃埃。", "隔河憶長眺，青歲已摧頹。不及少年日，無複故人杯。", "賦詩獨流涕，亂世想賢才。有能市駿骨，莫恨少龍媒。", "商山議得失，蜀主脫嫌猜。呂尚封國邑，傅說已鹽梅。", "景晏楚山深，水鶴去低回。龐公任本性，攜子臥蒼苔。"]'),
('yuding-13','壯游','杜甫','唐','御定全唐诗','yuding','','[]','往昔十四五，出遊翰墨場。斯文崔魏徒，以我似班揚。',576,'御定全唐詩/json/222.json','["往昔十四五，出遊翰墨場。斯文崔魏徒，以我似班揚。", "七齡思即壯，開口詠鳳凰。九齡書大字，有作成一囊。", "性豪業嗜酒，嫉惡懷剛腸。脫略小時輩，結交皆老蒼。", "飲酣視八極，俗物都茫茫。東下姑蘇台，已具浮海航。", "到今有遺恨，不得窮扶桑。王謝風流遠，闔廬丘墓荒。", "劍池石壁仄，長洲荷芰香。嵯峨閶門北，清廟映回塘。", "每趨吳太伯，撫事淚浪浪。枕戈憶勾踐，渡浙想秦皇。", "蒸魚聞匕首，除道哂要章。越女天下白，鑒湖五月涼。", "剡溪蘊秀異，欲罷不能忘。歸帆拂天姥，中歲貢舊鄉。", "氣劘屈賈壘，目短曹劉牆。忤下考功第，獨辭京尹堂。", "放蕩齊趙間，裘馬頗清狂。春歌叢臺上，冬獵青丘旁。", "呼鷹皂櫪林，逐獸雲雪岡。射飛曾縱鞚，引臂落鶖鶬。", "蘇侯據鞍喜，忽如攜葛強。快意八九年，西歸到咸陽。", "許與必詞伯，賞游實賢王。曳裾置醴地，奏賦入明光。", "天子廢食召，群公會軒裳。脫身無所愛，痛飲信行藏。", "黑貂不免敝，斑鬢兀稱觴。杜曲晚耆舊，四郊多白楊。", "坐深鄉黨敬，日覺死生忙。朱門任傾奪，赤族迭罹殃。", "國馬竭粟豆，官雞輸稻粱。舉隅見煩費，引古惜興亡。", "河朔風塵起，岷山行幸長。兩宮各警蹕，萬里遙相望。", "崆峒殺氣黑，少海旌旗黃。禹功亦命子，涿鹿親戎行。", "翠華擁英嶽，螭虎啖豺狼。爪牙一不中，胡兵更陸梁。", "大軍載草草，凋瘵滿膏肓。備員竊補袞，憂憤心飛揚。", "上感九廟焚，下憫萬民瘡。斯時伏青蒲，廷爭守禦床。", "君辱敢愛死，赫怒幸無傷。聖哲體仁恕，宇縣複小康。"]'),
('yuding-14','遣懷','杜甫','唐','御定全唐诗','yuding','','[]','昔我游宋中，惟梁孝王都。名今陳留亞，劇則貝魏俱。',252,'御定全唐詩/json/222.json','["昔我游宋中，惟梁孝王都。名今陳留亞，劇則貝魏俱。", "邑中九萬家，高棟照通衢。舟車半天下，主客多歡娛。", "白刃讎不義，黃金傾有無。殺人紅塵裏，報答在斯須。", "憶與高李輩，論交入酒壚。兩公壯藻思，得我色敷腴。", "氣酣登吹台，懷古視平蕪。芒碭雲一去，雁鶩空相呼。", "先帝正好武，寰海未凋枯。猛將收西域，長戟破林胡。", "百萬攻一城，獻捷不雲輸。組練棄如泥，尺土負百夫。", "拓境功未已，元和辭大爐。亂離朋友盡，合遝歲月徂。", "吾衰將焉托，存歿再嗚呼。蕭條益堪愧，獨在天一隅。", "乘黃已去矣，凡馬徒區區。不復見顏鮑，系舟臥荊巫。", "臨餐吐更食，常恐違撫孤。"]'),
('yuding-15','同元使君舂陵行','杜甫','唐','御定全唐诗','yuding','','[]','遭亂髮盡白，轉衰病相嬰。沈綿盜賊際，狼狽江漢行。',264,'御定全唐詩/json/222.json','["遭亂髮盡白，轉衰病相嬰。沈綿盜賊際，狼狽江漢行。", "歎時藥力薄，為客羸瘵成。吾人詩家秀，博采世上名。", "粲粲元道州，前聖畏後生。觀乎舂陵作，欻見俊哲情。", "複覽賊退篇，結也實國楨。賈誼昔流慟，匡衡常引經。", "道州憂黎庶，詞氣浩縱橫。兩章對秋月，一字偕華星。", "致君唐虞際，純樸憶大庭。何時降璽書，用爾為丹青。", "獄訟永衰息，豈唯偃甲兵。淒惻念誅求，薄斂近休明。", "乃知正人意，不苟飛長纓。涼飆振南嶽，之子寵若驚。", "色阻金印大，興含滄浪清。我多長卿病，日夕思朝廷。", "肺枯渴太甚，漂泊公孫城。呼兒具紙筆，隱幾臨軒楹。", "作詩呻吟內，墨澹字欹傾。感彼危苦詞，庶幾知者聽。"]'),
('yuding-16','李潮八分小篆歌','杜甫','唐','御定全唐诗','yuding','','[]','蒼頡鳥跡既茫昧，字體變化如浮雲。陳倉石鼓又已訛，',112,'御定全唐詩/json/222.json','["蒼頡鳥跡既茫昧，字體變化如浮雲。陳倉石鼓又已訛，", "嶧山之碑野火焚，棗木傳刻肥失真。苦縣光和尚骨立，", "尚書韓擇木，騎曹蔡有鄰。開元已來數八分，", "八分一字直百金，蛟龍盤拏肉屈強。吳郡張顛誇草書，", "巴東逢李潮，逾月求我歌。我今衰老才力薄，"]'),
('yuding-17','覽柏中允兼子侄數人除官制詞因述父子兄弟四美載歌絲綸','杜甫','唐','御定全唐诗','yuding','','[]','紛然喪亂際，見此忠孝門。蜀中寇亦甚，柏氏功彌存。',180,'御定全唐詩/json/222.json','["紛然喪亂際，見此忠孝門。蜀中寇亦甚，柏氏功彌存。", "深誠補王室，戮力自元昆。三止錦江沸，獨清玉壘昏。", "高名入竹帛，新渥照乾坤。子弟先卒伍，芝蘭疊璵璠。", "同心注師律，灑血在戎軒。絲綸實具載，紱冕已殊恩。", "奉公舉骨肉，誅叛經寒溫。金甲雪猶凍，朱旗塵不翻。", "每聞戰場說，欻激懦氣奔。聖主國多盜，賢臣官則尊。", "方當節鉞用，必絕祲沴根。吾病日回首，雲台誰再論。", "作歌挹盛事，推轂期孤鶱。"]'),
('yuding-18','聽楊氏歌','杜甫','唐','御定全唐诗','yuding','','[]','佳人絕代歌，獨立發皓齒。滿堂慘不樂，響下清虛裏。',96,'御定全唐詩/json/222.json','["佳人絕代歌，獨立發皓齒。滿堂慘不樂，響下清虛裏。", "江城帶素月，況乃清夜起。老夫悲暮年，壯士淚如水。", "玉杯久寂寞，金管迷宮征。勿雲聽者疲，愚智心盡死。", "古來傑出士，豈待一知己。吾聞昔秦青，傾側天下耳。"]'),
('yuding-19','荊南兵馬使太常卿趙公大食刀歌','杜甫','唐','御定全唐诗','yuding','','[]','太常樓船聲嗷嘈，問兵刮寇趨下牢。牧出令奔飛百艘，',112,'御定全唐詩/json/222.json','["太常樓船聲嗷嘈，問兵刮寇趨下牢。牧出令奔飛百艘，", "壯士短衣頭虎毛，憑軒拔鞘天為高。翻風轉日木怒號，", "芮公回首顏色勞，分閫救世用賢豪。趙公玉立高歌起，", "魑魅魍魎徒為耳，妖腰亂領敢欣喜。用之不高亦不庳，", "丹青宛轉麒麟裏，光芒六合無泥滓。"]'),
('yuding-20','王兵馬使二角鷹','杜甫','唐','御定全唐诗','yuding','','[]','悲台蕭颯石巃嵸，哀壑杈椏浩呼洶。中有萬里之長江，',96,'御定全唐詩/json/222.json','["悲台蕭颯石巃嵸，哀壑杈椏浩呼洶。中有萬里之長江，", "二鷹猛腦徐侯穟，目如愁胡視天地。杉雞竹兔不自惜，", "將軍樹勳起安西，昆侖虞泉入馬蹄。白羽曾肉三狻猊，", "惡鳥飛飛啄金屋，安得爾輩開其群，驅出六合梟鸞分。"]'),
('yuding-21','狄明府','杜甫','唐','御定全唐诗','yuding','','[]','梁公曾孫我姨弟，不見十年官濟濟。大賢之後竟陵遲，',132,'御定全唐詩/json/222.json','["梁公曾孫我姨弟，不見十年官濟濟。大賢之後竟陵遲，", "今者兄弟一百人，幾人卓絕秉周禮。在汝更用文章為，", "狄公執政在末年，濁河終不汙清濟。國嗣初將付諸武，", "太宗社稷一朝正，漢官威儀重昭洗。時危始識不世才，", "胡為漂泊岷漢間，幹謁王侯頗曆抵。況乃山高水有波，", "早歸來，黃土泥衣眼易眯。"]'),
('yuding-22','秋風二首','杜甫','唐','御定全唐诗','yuding','','[]','秋風淅淅吹巫山，上牢下牢修水關。吳檣楚柁牽百丈，',80,'御定全唐詩/json/222.json','["秋風淅淅吹巫山，上牢下牢修水關。吳檣楚柁牽百丈，", "中巴不曾消息好，暝傳戍鼓長雲間。", "秋風淅淅吹我衣，東流之外西日微。天清小城搗練急，", "會將白髮倚庭樹，故園池台今是非。"]'),
('yuding-23','久雨期王將軍不至','杜甫','唐','御定全唐诗','yuding','','[]','天雨蕭蕭滯茅屋，空山無以慰幽獨。銳頭將軍來何遲，',96,'御定全唐詩/json/222.json','["天雨蕭蕭滯茅屋，空山無以慰幽獨。銳頭將軍來何遲，", "泉源泠泠雜猿狖，泥濘漠漠饑鴻鵠。歲暮窮陰耿未已，", "前者坐皮因問毛，知子歷險人馬勞。異獸如飛星宿落，", "走平亂世相催促，一豁明主正郁陶。憶昔範增碎玉鬥，"]'),
('yuding-24','別李秘書始興寺所居','杜甫','唐','御定全唐诗','yuding','','[]','不見秘書心若失，及見秘書失心疾。安為動主理信然，',40,'御定全唐詩/json/222.json','["不見秘書心若失，及見秘書失心疾。安為動主理信然，", "妻兒待我且歸去，他日杖藜來細聽。"]'),
('yuding-25','虎牙行','杜甫','唐','御定全唐诗','yuding','','[]','秋風欻吸吹南國，天地慘慘無顏色。洞庭揚波江漢回，',72,'御定全唐詩/json/222.json','["秋風欻吸吹南國，天地慘慘無顏色。洞庭揚波江漢回，", "杜鵑不來猿狖寒，山鬼幽憂雪霜逼。楚老長嗟憶炎瘴，", "漁陽突騎獵青丘，犬戎鎖甲聞丹極。八荒十年防盜賊，"]'),
('yuding-26','錦樹行','杜甫','唐','御定全唐诗','yuding','','[]','今日苦短昨日休，歲雲暮矣增離憂。霜凋碧樹待錦樹。',112,'御定全唐詩/json/222.json','["今日苦短昨日休，歲雲暮矣增離憂。霜凋碧樹待錦樹。", "萬壑東逝無停留。荒戍之城石色古，東郭老人住青丘。", "飛書白帝營鬥粟，琴瑟几杖柴門幽。青草萋萋盡枯死，", "故國三年一消息。終南渭水寒悠悠。五陵豪貴反顛倒，", "莫愁父母少黃金，天下風塵兒亦得。"]'),
('yuding-27','赤霄行','杜甫','唐','御定全唐诗','yuding','','[]','孔雀未知牛有角，渴飲寒泉逢抵觸。赤霄懸圃須往來，',48,'御定全唐詩/json/222.json','["孔雀未知牛有角，渴飲寒泉逢抵觸。赤霄懸圃須往來，", "皇孫猶曾蓮勺困，衛莊見貶傷其足。老翁慎莫怪少年，"]'),
('yuding-28','前苦寒行二首','杜甫','唐','御定全唐诗','yuding','','[]','漢時長安雪一丈，牛馬毛寒縮如蝟。楚江巫峽冰入懷，',80,'御定全唐詩/json/222.json','["漢時長安雪一丈，牛馬毛寒縮如蝟。楚江巫峽冰入懷，", "玄冥祝融氣或交，手持白羽未敢釋。", "去年白帝雪在山，今年白帝雪在地。凍埋蛟龍南浦縮，", "三足之烏足恐斷，羲和送將何所歸。"]'),
('yuding-29','後苦寒行二首','杜甫','唐','御定全唐诗','yuding','','[]','南紀巫廬瘴不絕，太古以來無尺雪。蠻夷長老怨苦寒，',56,'御定全唐詩/json/222.json','["南紀巫廬瘴不絕，太古以來無尺雪。蠻夷長老怨苦寒，", "安得春泥補地裂。", "晚來江門失大木，猛風中夜吹白屋。天兵斬斷青海戎，"]'),
('yuding-30','晚晴','杜甫','唐','御定全唐诗','yuding','','[]','高唐暮冬雪壯哉，舊瘴無複似塵埃。崖沉穀沒白皚皚，',48,'御定全唐詩/json/222.json','["高唐暮冬雪壯哉，舊瘴無複似塵埃。崖沉穀沒白皚皚，", "未怪及時少年子，揚眉結義黃金台。洎乎吾生何飄零，"]'),
('yuding-31','複陰','杜甫','唐','御定全唐诗','yuding','','[]','方冬合遝玄陰塞，昨日晚晴今日黑。萬里飛蓬映天過，',43,'御定全唐詩/json/222.json','["方冬合遝玄陰塞，昨日晚晴今日黑。萬里飛蓬映天過，", "君不見夔子之國杜陵翁，牙齒半落左耳聾。"]'),
('yuding-32','夜歸','杜甫','唐','御定全唐诗','yuding','','[]','夜來歸來沖虎過，山黑家中已眠臥。傍見北斗向江低，',40,'御定全唐詩/json/222.json','["夜來歸來沖虎過，山黑家中已眠臥。傍見北斗向江低，", "白頭老罷舞複歌，杖藜不睡誰能那。"]'),
('yuding-33','寄柏學士林居','杜甫','唐','御定全唐诗','yuding','','[]','自胡之反持干戈，天下學士亦奔波。歎彼幽棲載典籍，',72,'御定全唐詩/json/222.json','["自胡之反持干戈，天下學士亦奔波。歎彼幽棲載典籍，", "亂代飄零餘到此，古人成敗子如何。荊揚春冬異風土，", "盜賊縱橫甚密邇，形神寂寞甘辛苦。幾時高議排金門，"]'),
('yuding-34','寄從孫崇簡','杜甫','唐','御定全唐诗','yuding','','[]','嵯峨白帝城東西，南有龍湫北虎溪。吾孫騎曹不騎馬，',48,'御定全唐詩/json/222.json','["嵯峨白帝城東西，南有龍湫北虎溪。吾孫騎曹不騎馬，", "與汝林居未相失，近身藥裹酒長攜。牧豎樵童亦無賴，"]'),
('yuding-35','奉酬薛十二丈判官見贈','杜甫','唐','御定全唐诗','yuding','','[]','忽忽峽中睡，悲風方一醒。西來有好鳥，為我下青冥。',336,'御定全唐詩/json/222.json','["忽忽峽中睡，悲風方一醒。西來有好鳥，為我下青冥。", "羽毛淨白雪，慘澹飛雲汀。既蒙主人顧，舉翮唳孤亭。", "持以比佳士，及此慰揚舲。清文動哀玉，見道發新硎。", "欲學鴟夷子，待勒燕山銘。誰重斷蛇劍，致君君未聽。", "志在麒麟閣，無心雲母屏。卓氏近新寡，豪家朱門扃。", "相如才調逸，銀漢會雙星。客來洗粉黛，日暮拾流螢。", "不是無膏火，勸郎勤六經。老夫自汲澗，野水日泠泠。", "我歎黑頭白，君看銀印青。臥病識山鬼，為農知地形。", "誰矜坐錦帳，苦厭食魚腥。東西兩岸坼，橫水注滄溟。", "碧色忽惆悵，風雷搜百靈。空中右白虎，赤節引娉婷。", "自雲帝裏女，噀雨鳳凰翎。襄王薄行跡，莫學冷如丁，", "丈人但安坐，休辨渭與涇。龍蛇尚格鬥，灑血暗郊坰。", "吾聞聰明主，治國用輕刑。銷兵鑄農器，今古歲方寧。", "文王日儉德，俊乂始盈庭。榮華貴少壯，豈食楚江萍。"]'),
('yuding-36','醉為馬墜，諸公攜酒相看','杜甫','唐','御定全唐诗','yuding','','[]','甫也諸侯老賓客，罷酒酣歌拓金戟。騎馬忽憶少年時，',120,'御定全唐詩/json/222.json','["甫也諸侯老賓客，罷酒酣歌拓金戟。騎馬忽憶少年時，", "粉堞電轉紫遊韁，東得平岡出天壁。江村野堂爭入眼，", "安知決臆追風足，朱汗驂驔猶噴玉。不虞一蹶終損傷，", "明知來問腆我顏，杖藜強起依僮僕。語盡還成開口笑，", "共指西日不相貸，喧呼且覆杯中淥。何必走馬來為問，"]'),
('yuding-37','別李義','杜甫','唐','御定全唐诗','yuding','','[]','神堯十八子，十七王其門。道國洎舒國，督唯親弟昆。',276,'御定全唐詩/json/222.json','["神堯十八子，十七王其門。道國洎舒國，督唯親弟昆。", "中外貴賤殊，余亦忝諸孫。丈人嗣三葉，之子白玉溫。", "道國繼德業，請從丈人論。丈人領宗卿，肅穆古制敦。", "先朝納諫諍，直氣橫乾坤。子建文筆壯，河間經術存。", "爾克富詩禮，骨清慮不喧。洗然遇知己，談論淮湖奔。", "憶昔初見時，小襦繡芳蓀。長成忽會面，慰我久疾魂。", "三峽春冬交，江山雲霧昏。正宜且聚集，恨此當離尊。", "莫怪執杯遲，我衰涕唾煩。重問子何之，西上岷江源。", "願子少幹謁，蜀都足戎軒。誤失將帥意，不如親故恩。", "少年早歸來，梅花已飛翻。努力慎風水，豈惟數盤飧。", "猛虎臥在岸，蛟螭出無痕。王子自愛惜，老夫困石根。", "生別古所嗟，發聲為爾吞。"]'),
('yuding-38','送高司直尋封閬州','杜甫','唐','御定全唐诗','yuding','','[]','丹雀銜書來，暮棲何鄉樹。驊騮事天子，辛苦在道路。',240,'御定全唐詩/json/222.json','["丹雀銜書來，暮棲何鄉樹。驊騮事天子，辛苦在道路。", "司直非冗官，荒山甚無趣。借問泛舟人，胡為入雲霧。", "與子姻婭間，既親亦有故。萬里長江邊，邂逅一相遇。", "長卿消渴再，公幹沉綿屢。清談慰老夫，開卷得佳句。", "時見文章士，欣然澹情素。伏枕聞別離，疇能忍漂寓。", "良會苦短促，溪行水奔注。熊羆咆空林，遊子慎馳騖。", "西謁巴中侯，艱險如跬步。主人不世才，先帝常特顧。", "拔為天軍佐，崇大王法度。淮海生清風，南翁尚思慕。", "公宮造廣廈，木石乃無數。初聞伐松柏，猶臥天一柱。", "我瘦書不成，成字讀亦誤。為我問故人，勞心練征戍。"]'),
('yuding-39','君不見，簡蘇徯','杜甫','唐','御定全唐诗','yuding','','[]','君不見道邊廢棄池，君不見前者摧折桐。百年死樹中琴瑟，',26,'御定全唐詩/json/222.json','["君不見道邊廢棄池，君不見前者摧折桐。百年死樹中琴瑟，"]'),
('yuding-40','贈蘇四徯','杜甫','唐','御定全唐诗','yuding','','[]','異縣昔同遊，各雲厭轉蓬。別離已五年，尚在行李中。',180,'御定全唐詩/json/222.json','["異縣昔同遊，各雲厭轉蓬。別離已五年，尚在行李中。", "戎馬日衰息，乘輿安九重。有才何棲棲，將老委所窮。", "為郎未為賤，其奈疾病攻。子何面黧黑，不得豁心胸。", "巴蜀倦剽掠，下愚成土風。幽薊已削平，荒徼尚彎弓。", "斯人脫身來，豈非吾道東。乾坤雖寬大，所適裝囊空。", "肉食哂菜色，少壯欺老翁。況乃主客間，古來逼側同。", "君今下荊揚，獨帆如飛鴻。二州豪俠場，人馬皆自雄。", "一請甘饑寒，再請甘養蒙。"]'),
('yuding-41','寄薛三郎中','杜甫','唐','御定全唐诗','yuding','','[]','人生無賢愚，飄颻若埃塵。自非得神仙，誰免危其身。',312,'御定全唐詩/json/222.json','["人生無賢愚，飄颻若埃塵。自非得神仙，誰免危其身。", "與子俱白頭，役役常苦辛。雖為尚書郎，不及村野人。", "憶昔村野人，其樂難具陳。藹藹桑麻交，公侯為等倫。", "天未厭戎馬，我輩本常貧。子尚客荊州，我亦滯江濱。", "峽中一臥病，瘧癘終冬春。春複加肺氣，此病蓋有因。", "早歲與蘇鄭，痛飲情相親。二公化為土，嗜酒不失真。", "余今委修短，豈得恨命屯。聞子心甚壯，所過信席珍。", "上馬不用扶，每扶必怒嗔。賦詩賓客間，揮灑動八垠。", "乃知蓋代手，才力老益神。青草洞庭湖，東浮滄海漘。", "君山可避暑，況足采白蘋。子豈無扁舟，往復江漢津。", "我未下瞿塘，空念禹功勤。聽說松門峽，吐藥攬衣巾。", "高秋卻束帶，鼓枻視青旻。鳳池日澄碧，濟濟多士新。", "餘病不能起，健者勿逡巡。上有明哲君，下有行化臣。"]'),
('yuding-42','大覺高僧蘭若','杜甫','唐','御定全唐诗','yuding','','[]','巫山不見廬山遠，松林蘭若秋風晚。一老猶鳴日暮鐘，',40,'御定全唐詩/json/222.json','["巫山不見廬山遠，松林蘭若秋風晚。一老猶鳴日暮鐘，", "飛錫去年啼邑子，獻花何日許門徒。"]'),
('yuding-0','宿青溪驛奉懷張員外十五兄之緒','杜甫','唐','御定全唐诗','yuding','','[]','漾舟千山內，日入泊枉渚。我生本飄飄，今複在何許。',72,'御定全唐詩/json/223.json','["漾舟千山內，日入泊枉渚。我生本飄飄，今複在何許。", "石根青楓林，猿鳥聚儔侶。月明遊子靜，畏虎不得語。", "中夜懷友朋，乾坤此深阻。浩蕩前後間，佳期付荊楚。"]'),
('yuding-1','敬寄族弟唐十八使君','杜甫','唐','御定全唐诗','yuding','','[]','與君陶唐後，盛族多其人。聖賢冠史籍，枝派羅源津。',192,'御定全唐詩/json/223.json','["與君陶唐後，盛族多其人。聖賢冠史籍，枝派羅源津。", "在今氣磊落，巧偽莫敢親。介立實吾弟，濟時肯殺身。", "物白諱受玷，行高無汙真。得罪永泰末，放之五溪濱。", "鸞鳳有鎩翮，先儒曾抱麟。雷霆霹長松，骨大卻生筋。", "一失不足傷，念子孰自珍。泊舟楚宮岸，戀闕浩酸辛。", "除名配清江，厥土巫峽鄰。登陸將首途，筆劄枉所申。", "歸朝局病肺，敘舊思重陳。春風洪濤壯，穀轉頗彌旬。", "我能泛中流，搪突鼉獺瞋。長年已省柁，慰此貞良臣。"]'),
('yuding-2','憶昔行','杜甫','唐','御定全唐诗','yuding','','[]','憶昔北尋小有洞，洪河怒濤過輕舸。辛勤不見華蓋君，',96,'御定全唐詩/json/223.json','["憶昔北尋小有洞，洪河怒濤過輕舸。辛勤不見華蓋君，", "秋山眼冷魂未歸，仙賞心違淚交墮。弟子誰依白茅室，", "懸圃滄洲莽空闊，金節羽衣飄婀娜。落日初霞閃餘映，", "徒然咨嗟撫遺跡，至今夢想仍猶佐。秘訣隱文須內教，"]'),
('yuding-3','魏將軍歌','杜甫','唐','御定全唐诗','yuding','','[]','將軍昔著從事衫，鐵馬馳突重兩銜。披堅執銳略西極，',96,'御定全唐詩/json/223.json','["將軍昔著從事衫，鐵馬馳突重兩銜。披堅執銳略西極，", "五年起家列霜戟，一日過海收風帆。平生流輩徒蠢蠢，", "星躔寶校金盤陀，夜騎天駟超天河。欃槍熒惑不敢動，", "鉤陳蒼蒼風玄武，萬歲千秋奉明主，臨江節士安足數。"]'),
('yuding-4','北風','杜甫','唐','御定全唐诗','yuding','','[]','北風破南極，朱鳳日威垂。洞庭秋欲雪，鴻雁將安歸。',48,'御定全唐詩/json/223.json','["北風破南極，朱鳳日威垂。洞庭秋欲雪，鴻雁將安歸。", "十年殺氣盛，六合人煙稀。吾慕漢初老，時清猶茹芝。"]'),
('yuding-5','客從','杜甫','唐','御定全唐诗','yuding','','[]','客從南溟來，遺我泉客珠。珠中有隱字，欲辨不成書。',48,'御定全唐詩/json/223.json','["客從南溟來，遺我泉客珠。珠中有隱字，欲辨不成書。", "緘之篋笥久，以俟公家須。開視化為血，哀今征斂無。"]'),
('yuding-6','白馬','杜甫','唐','御定全唐诗','yuding','','[]','白馬東北來，空鞍貫雙箭。可憐馬上郎，意氣今誰見。',48,'御定全唐詩/json/223.json','["白馬東北來，空鞍貫雙箭。可憐馬上郎，意氣今誰見。", "近時主將戮，中夜商于戰。喪亂死多門，嗚呼淚如霰。"]'),
('yuding-7','白鳧行','杜甫','唐','御定全唐诗','yuding','','[]','君不見黃鵠高於五尺童，化為白鳧似老翁。',43,'御定全唐詩/json/223.json','["君不見黃鵠高於五尺童，化為白鳧似老翁。", "故畦遺穗已蕩盡，天寒歲暮波濤中。鱗介腥膻素不食，"]'),
('yuding-8','朱鳳行','杜甫','唐','御定全唐诗','yuding','','[]','君不見瀟湘之山衡山高，山巔朱鳳聲嗷嗷。',43,'御定全唐詩/json/223.json','["君不見瀟湘之山衡山高，山巔朱鳳聲嗷嗷。", "側身長顧求其群，翅垂口噤心甚勞。下湣百鳥在羅網，"]'),
('yuding-9','惜別行，送向卿進奉端午禦衣之上都','杜甫','唐','御定全唐诗','yuding','','[]','肅宗昔在靈武城，指揮猛將收咸京。向公泣血灑行殿，',72,'御定全唐詩/json/223.json','["肅宗昔在靈武城，指揮猛將收咸京。向公泣血灑行殿，", "麒麟圖畫鴻雁行，紫極出入黃金印。尚書勳業超千古，", "向卿將命寸心赤，青山落日江潮白。卿到朝廷說老翁，"]'),
('yuding-10','醉歌行，贈公安顏少府請顧八題壁','杜甫','唐','御定全唐诗','yuding','','[]','神仙中人不易得，顏氏之子才孤標。天馬長鳴待駕馭，',48,'御定全唐詩/json/223.json','["神仙中人不易得，顏氏之子才孤標。天馬長鳴待駕馭，", "是日霜風凍七澤，烏蠻落照銜赤壁。酒酣耳熱忘頭白，"]'),
('yuding-11','夜聞觱篥','杜甫','唐','御定全唐诗','yuding','','[]','夜聞觱篥滄江上，衰年側耳情所向。鄰舟一聽多感傷，',40,'御定全唐詩/json/223.json','["夜聞觱篥滄江上，衰年側耳情所向。鄰舟一聽多感傷，", "君知天地干戈滿，不見江湖行路難。"]'),
('yuding-12','發劉郎浦','杜甫','唐','御定全唐诗','yuding','','[]','掛帆早發劉郎浦，疾風颯颯昏亭午。舟中無日不沙塵，',40,'御定全唐詩/json/223.json','["掛帆早發劉郎浦，疾風颯颯昏亭午。舟中無日不沙塵，", "白頭厭伴漁人宿，黃帽青鞋歸去來。"]'),
('yuding-13','別董頲','杜甫','唐','御定全唐诗','yuding','','[]','窮冬急風水，逆浪開帆難。士子甘旨闕，不知道裏寒。',120,'御定全唐詩/json/223.json','["窮冬急風水，逆浪開帆難。士子甘旨闕，不知道裏寒。", "有求彼樂土，南適小長安。到我舟楫去，覺君衣裳單。", "素聞趙公節，兼盡賓主歡。已結門廬望，無令霜雪殘。", "老夫纜亦解，脫粟朝未餐。飄蕩兵甲際，幾時懷抱寬。", "漢陽頗寧靜，峴首試考盤。當念著白帽，采薇青雲端。"]'),
('yuding-14','送重表侄王砅評事使南海','杜甫','唐','御定全唐诗','yuding','','[]','我之曾祖姑，爾之高祖母。爾祖未顯時，歸為尚書婦。',456,'御定全唐詩/json/223.json','["我之曾祖姑，爾之高祖母。爾祖未顯時，歸為尚書婦。", "隋朝大業末，房杜俱交友。長者來在門，荒年自糊口。", "家貧無供給，客位但箕帚。俄頃羞頗珍，寂寥人散後。", "入怪鬢髮空，籲嗟為之久。自陳翦髻鬟，鬻市充杯酒。", "上雲天下亂，宜與英俊厚。向竊窺數公，經綸亦俱有。", "次問最少年，虯髯十八九。子等成大名，皆因此人手。", "下雲風雲合，龍虎一吟吼。願展丈夫雄，得辭兒女醜。", "秦王時在坐，真氣驚戶牖。及乎貞觀初，尚書踐台鬥。", "夫人常肩輿，上殿稱萬壽。六宮師柔順，法則化妃後。", "至尊均嫂叔，盛事垂不朽。鳳雛無凡毛，五色非爾曹。", "往者胡作逆，乾坤沸嗷嗷。吾客左馮翊，爾家同遁逃。", "爭奪至徒步，塊獨委蓬蒿。逗留熱爾腸，十裏卻呼號。", "自下所騎馬，右持腰間刀。左牽紫遊韁，飛走使我高。", "苟活到今日，寸心銘佩牢。亂離又聚散，宿昔恨滔滔。", "水花笑白首，春草隨青袍。廷評近要津，節制收英髦。", "北驅漢陽傳，南泛上瀧舠。家聲肯墜地，利器當秋毫。", "番禺親賢領，籌運神功操。大夫出盧宋，寶貝休脂膏。", "洞主降接武，海胡舶千艘。我欲就丹砂，跋涉覺身勞。", "安能陷糞土，有志乘鯨鼇。或驂鸞騰天，聊作鶴鳴皋。"]'),
('yuding-15','詠懷二首','杜甫','唐','御定全唐诗','yuding','','[]','人生貴是男，丈夫重天機。未達善一身，得志行所為。',432,'御定全唐詩/json/223.json','["人生貴是男，丈夫重天機。未達善一身，得志行所為。", "嗟餘竟轗軻，將老逢艱危。胡雛逼神器，逆節同所歸。", "河雒化為血，公侯草間啼。西京複陷沒，翠蓋蒙塵飛。", "萬姓悲赤子，兩宮棄紫微。倏忽向二紀，奸雄多是非。", "本朝再樹立，未及貞觀時。日給在軍儲，上官督有司。", "高賢迫形勢，豈暇相扶持。疲苶苟懷策，棲屑無所施。", "先王實罪己，愁痛正為茲。歲月不我與，蹉跎病於斯。", "夜看豐城氣，回首蛟龍池。齒發已自料，意深陳苦詞。", "邦危壞法則，聖遠益愁慕。飄颻桂水遊，悵望蒼梧暮。", "潛魚不銜鉤，走鹿無反顧。皦皦幽曠心，拳拳異平素。", "衣食相拘閡，朋知限流寓。風濤上春沙，千里侵江樹。", "逆行少吉日，時節空複度。井灶任塵埃，舟航煩數具。", "牽纏加老病，瑣細隘俗務。萬古一死生，胡為足名數。", "多憂汙桃源，拙計泥銅柱。未辭炎瘴毒，擺落跋涉懼。", "虎狼窺中原，焉得所曆住。葛洪及許靖，避世常此路。", "賢愚誠等差，自愛各馳騖。羸瘠且如何，魄奪針灸屢。", "擁滯僮僕慵，稽留篙師怒。終當掛帆席，天意難告訴。", "南為祝融客，勉強親杖屨。結托老人星，羅浮展衰步。"]'),
('yuding-16','送顧八分文學適洪吉州','杜甫','唐','御定全唐诗','yuding','','[]','中郎石經後，八分蓋憔悴。顧侯運爐錘，筆力破餘地。',372,'御定全唐詩/json/223.json','["中郎石經後，八分蓋憔悴。顧侯運爐錘，筆力破餘地。", "昔在開元中，韓蔡同贔屭。玄宗妙其書，是以數子至。", "禦劄早流傳，揄揚非造次。三人併入直，恩澤各不二。", "顧于韓蔡內，辨眼工小字。分日示諸王，鉤深法更秘。", "文學與我游，蕭疏外聲利。追隨二十載，浩蕩長安醉。", "高歌卿相宅，文翰飛省寺。視我揚馬間，白首不相棄。", "驊騮入窮巷，必脫黃金轡。一論朋友難，遲暮敢失墜。", "古來事反復，相見橫涕泗。向者玉珂人，誰是青雲器。", "才盡傷形體，病渴汙官位。故舊獨依然，時危話顛躓。", "我甘多病老，子負憂世志。胡為困衣食，顏色少稱遂。", "遠作辛苦行，順從眾多意。舟楫無根蒂，蛟鼉好為祟。", "況兼水賊繁，特戒風飆駛。崩騰戎馬際，往往殺長吏。", "子幹東諸侯，勸勉防縱恣。邦以民為本，魚饑費香餌。", "請哀瘡痍深，告訴皇華使。使臣精所擇，進德知曆試。", "惻隱誅求情，固應賢愚異。列士惡苟得，俊傑思自致。", "贈子猛虎行，出郊載酸鼻。"]'),
('yuding-17','上水遣懷','杜甫','唐','御定全唐诗','yuding','','[]','我衰太平時，身病戎馬後。蹭蹬多拙為，安得不皓首。',264,'御定全唐詩/json/223.json','["我衰太平時，身病戎馬後。蹭蹬多拙為，安得不皓首。", "驅馳四海內，童稚日糊口。但遇新少年，少逢舊親友。", "低顏下色地，故人知善誘。後生血氣豪，舉動見老醜。", "窮迫挫曩懷，常如中風走。一紀出西蜀，於今向南斗。", "孤舟亂春華，暮齒依蒲柳。冥冥九疑葬，聖者骨亦朽。", "蹉跎陶唐人，鞭撻日月久。中間屈賈輩，讒毀竟自取。", "鬱沒二悲魂，蕭條猶在否。崷崒清湘石，逆行雜林藪。", "篙工密逞巧，氣若酣杯酒。歌謳互激遠，回斡明受授。", "善知應觸類，各藉穎脫手。古來經濟才，何事獨罕有。", "蒼蒼眾色晚，熊掛玄蛇吼。黃羆在樹顛，正為群虎守。", "羸骸將何適，履險顏益厚。庶與達者論，吞聲混瑕垢。"]'),
('yuding-18','遣遇','杜甫','唐','御定全唐诗','yuding','','[]','磬折辭主人，開帆駕洪濤。春水滿南國，朱崖雲日高。',132,'御定全唐詩/json/223.json','["磬折辭主人，開帆駕洪濤。春水滿南國，朱崖雲日高。", "舟子廢寢食，飄風爭所操。我行匪利涉，謝爾從者勞。", "石間采蕨女，鬻菜輸官曹。丈夫死百役，暮返空村號。", "聞見事略同，刻剝及錐刀。貴人豈不仁，視汝如莠蒿。", "索錢多門戶，喪亂紛嗷嗷。奈何黠吏徒，漁奪成逋逃。", "自喜遂生理，花時甘縕袍。"]'),
('yuding-19','解憂','杜甫','唐','御定全唐诗','yuding','','[]','減米散同舟，路難思共濟。向來雲濤盤，眾力亦不細。',72,'御定全唐詩/json/223.json','["減米散同舟，路難思共濟。向來雲濤盤，眾力亦不細。", "呀坑瞥眼過，飛櫓本無蒂。得失瞬息間，致遠宜恐泥。", "百慮視安危，分明曩賢計。茲理庶可廣，拳拳期勿替。"]'),
('yuding-20','宿鑿石浦','杜甫','唐','御定全唐诗','yuding','','[]','早宿賓從勞，仲春江山麗。飄風過無時，舟楫敢不系。',84,'御定全唐詩/json/223.json','["早宿賓從勞，仲春江山麗。飄風過無時，舟楫敢不系。", "回塘澹暮色，日沒眾星嘒。缺月殊未生，青燈死分翳。", "窮途多俊異，亂世少恩惠。鄙夫亦放蕩，草草頻卒歲。", "斯文憂患餘，聖哲垂彖系。"]'),
('yuding-21','早行','杜甫','唐','御定全唐诗','yuding','','[]','歌哭俱在曉，行邁有期程。孤舟似昨日，聞見同一聲。',72,'御定全唐詩/json/223.json','["歌哭俱在曉，行邁有期程。孤舟似昨日，聞見同一聲。", "飛鳥數求食，潛魚亦獨驚。前王作網罟，設法害生成。", "碧藻非不茂，高帆終日征。干戈未揖讓，崩迫開其情。"]'),
('yuding-22','過津口','杜甫','唐','御定全唐诗','yuding','','[]','南嶽自茲近，湘流東逝深。和風引桂楫，春日漲雲岑。',84,'御定全唐詩/json/223.json','["南嶽自茲近，湘流東逝深。和風引桂楫，春日漲雲岑。", "回首過津口，而多楓樹林。白魚困密網，黃鳥喧嘉音。", "物微限通塞，惻隱仁者心。甕餘不盡酒，膝有無聲琴。", "聖賢兩寂寞，眇眇獨開襟。"]'),
('yuding-23','次空靈岸','杜甫','唐','御定全唐诗','yuding','','[]','沄沄逆素浪，落落展清眺。幸有舟楫遲，得盡所曆妙。',96,'御定全唐詩/json/223.json','["沄沄逆素浪，落落展清眺。幸有舟楫遲，得盡所曆妙。", "空靈霞石峻，楓栝隱奔峭。青春猶無私，白日亦偏照。", "可使營吾居，終焉托長嘯。毒瘴未足憂，兵戈滿邊徼。", "向者留遺恨，恥為達人誚。回帆覬賞延，佳處領其要。"]'),
('yuding-24','宿花石戍','杜甫','唐','御定全唐诗','yuding','','[]','午辭空靈岑，夕得花石戍。岸疏開闢水，木雜今古樹。',120,'御定全唐詩/json/223.json','["午辭空靈岑，夕得花石戍。岸疏開闢水，木雜今古樹。", "地蒸南風盛，春熱西日暮。四序本平分，氣候何回互。", "茫茫天造間，理亂豈恒數。系舟盤藤輪，策杖古樵路。", "罷人不在村，野圃泉自注。柴扉雖蕪沒，農器尚牢固。", "山東殘逆氣，吳楚守王度。誰能扣君門，下令減征賦。"]'),
('yuding-25','早發','杜甫','唐','御定全唐诗','yuding','','[]','有求常百慮，斯文亦吾病。以茲朋故多，窮老驅馳並。',144,'御定全唐詩/json/223.json','["有求常百慮，斯文亦吾病。以茲朋故多，窮老驅馳並。", "早行篙師怠，席掛風不正。昔人戒垂堂，今則奚奔命。", "濤翻黑蛟躍，日出黃霧映。煩促瘴豈侵，頹倚睡未醒。", "僕夫問盥櫛，暮顏靦青鏡。隨意簪葛巾，仰慚林花盛。", "側聞夜來寇，幸喜囊中淨。艱危作遠客，幹請傷直性。", "薇蕨餓首陽，粟馬資歷聘。賤子欲適從，疑誤此二柄。"]'),
('yuding-26','次晚洲','杜甫','唐','御定全唐诗','yuding','','[]','參錯雲石稠，坡陀風濤壯。晚洲適知名，秀色固異狀。',72,'御定全唐詩/json/223.json','["參錯雲石稠，坡陀風濤壯。晚洲適知名，秀色固異狀。", "棹經垂猿把，身在度鳥上。擺浪散帙妨，危沙折花當。", "羈離暫愉悅，羸老反惆悵。中原未解兵，吾得終疏放。"]'),
('yuding-27','望岳','杜甫','唐','御定全唐诗','yuding','','[]','南嶽配朱鳥，秩禮自百王。欻吸領地靈，鴻洞半炎方。',168,'御定全唐詩/json/223.json','["南嶽配朱鳥，秩禮自百王。欻吸領地靈，鴻洞半炎方。", "邦家用祀典，在德非馨香。巡守何寂寥，有虞今則亡。", "洎吾隘世網，行邁越瀟湘。渴日絕壁出，漾舟清光旁。", "祝融五峰尊，峰峰次低昂。紫蓋獨不朝，爭長嶪相望。", "恭聞魏夫人，群仙夾翱翔。有時五峰氣，散風如飛霜。", "牽迫限修途，未暇杖崇岡。歸來覬命駕，沐浴休玉堂。", "三歎問府主，曷以贊我皇。牲璧忍衰俗，神其思降祥。"]'),
('yuding-28','湘江宴餞裴二端公赴道州','杜甫','唐','御定全唐诗','yuding','','[]','白日照舟師，朱旗散廣川。群公餞南伯，肅肅秩初筵。',180,'御定全唐詩/json/223.json','["白日照舟師，朱旗散廣川。群公餞南伯，肅肅秩初筵。", "鄙人奉末眷，佩服自早年。義均骨肉地，懷抱罄所宣。", "盛名富事業，無取愧高賢。不以喪亂嬰，保愛金石堅。", "計拙百僚下，氣蘇君子前。會合苦不久，哀樂本相纏。", "交遊颯向盡，宿昔浩茫然。促觴激百慮，掩抑淚潺湲。", "熱雲集曛黑，缺月未生天。白團為我破，華燭蟠長煙。", "鴰鶡催明星，解袂從此旋。上請減兵甲，下請安井田。", "永念病渴老，附書遠山巔。"]'),
('yuding-29','清明','杜甫','唐','御定全唐诗','yuding','','[]','著處繁花務是日，長沙千人萬人出。渡頭翠柳豔明眉，',72,'御定全唐詩/json/223.json','["著處繁花務是日，長沙千人萬人出。渡頭翠柳豔明眉，", "馬援征行在眼前，葛強親近同心事。金鐙下山紅粉晚，", "弟侄雖存不得書，干戈未息苦離居。逢迎少壯非吾道，"]'),
('yuding-30','風雨看舟前落花，戲為新句','杜甫','唐','御定全唐诗','yuding','','[]','江上人家桃樹枝，春寒細雨出疏籬。影遭碧水潛勾引，',48,'御定全唐詩/json/223.json','["江上人家桃樹枝，春寒細雨出疏籬。影遭碧水潛勾引，", "赤憎輕薄遮入懷，珍重分明不來接。濕久飛遲半日高，"]'),
('yuding-31','岳麓山道林二寺行','杜甫','唐','御定全唐诗','yuding','','[]','玉泉之南麓山殊，道林林壑爭盤紆。寺門高開洞庭野，',136,'御定全唐詩/json/223.json','["玉泉之南麓山殊，道林林壑爭盤紆。寺門高開洞庭野，", "地靈步步雪山草，僧寶人人滄海珠。塔劫宮牆壯麗敵，", "方丈涉海費時節，懸圃尋河知有無。暮年且喜經行近，", "桃源人家易制度，橘洲田土仍膏腴。潭府邑中甚淳古，", "依止老宿亦未晚，富貴功名焉足圖。久為野客尋幽慣，", "宋公放逐曾題壁，物色分留與老夫。"]'),
('yuding-32','奉送魏六丈佑少府之交廣','杜甫','唐','御定全唐诗','yuding','','[]','賢豪贊經綸，功成空名垂。子孫不振耀，歷代皆有之。',312,'御定全唐詩/json/223.json','["賢豪贊經綸，功成空名垂。子孫不振耀，歷代皆有之。", "鄭公四葉孫，長大常苦饑。眾中見毛骨，猶是麒麟兒。", "磊落貞觀事，致君樸直詞。家聲蓋六合，行色何其微。", "遇我蒼梧陰，忽驚會面稀。議論有餘地，公侯來未遲。", "虛思黃金貴，自笑青雲期。長卿久病渴，武帝元同時。", "季子黑貂敝，得無妻嫂欺。尚為諸侯客，獨屈州縣卑。", "南遊炎海甸，浩蕩從此辭。窮途仗神道，世亂輕土宜。", "解帆歲雲暮，可與春風歸。出入朱門家，華屋刻蛟螭。", "玉食亞王者，樂張遊子悲。侍婢豔傾城，綃綺輕霧霏。", "掌中琥珀鐘，行酒雙逶迤。新歡繼明燭，梁棟星辰飛。", "兩情顧盼合，珠碧贈於斯。上貴見肝膽，下貴不相疑。", "心事披寫間，氣酣達所為。錯揮鐵如意，莫避珊瑚枝。", "始兼逸邁興，終慎賓主儀。戎馬暗天宇，嗚呼生別離。"]'),
('yuding-33','別張十三建封','杜甫','唐','御定全唐诗','yuding','','[]','嘗讀唐實錄，國家草昧初。劉裴建首義，龍見尚躊躇。',252,'御定全唐詩/json/223.json','["嘗讀唐實錄，國家草昧初。劉裴建首義，龍見尚躊躇。", "秦王撥亂姿，一劍總兵符。汾晉為豐沛，暴隋竟滌除。", "宗臣則廟食，後祀何疏蕪。彭城英雄種，宜膺將相圖。", "爾惟外曾孫，倜儻汗血駒。眼中萬少年，用意盡崎嶇。", "相逢長沙亭，乍問緒業餘。乃吾故人子，童丱聯居諸。", "揮手灑衰淚，仰看八尺軀。內外名家流，風神蕩江湖。", "范雲堪晚友，嵇紹自不孤。擇材征南幕，湖落回鯨魚。", "載感賈生慟，複聞樂毅書。主憂急盜賊，師老荒京都。", "舊丘豈稅駕，大廈傾宜扶。君臣各有分，管葛本時須。", "雖當霰雪嚴，未覺栝柏枯。高義在雲台，嘶鳴望天衢。", "羽人掃碧海，功業竟何如。"]'),
('yuding-34','暮秋枉裴道州手劄，率爾遣興，寄近呈蘇渙侍禦','杜甫','唐','御定全唐诗','yuding','','[]','久客多枉友朋書，素書一月凡一束。虛名但蒙寒溫問，',192,'御定全唐詩/json/223.json','["久客多枉友朋書，素書一月凡一束。虛名但蒙寒溫問，", "道州手劄適複至，紙長要自三過讀。盈把那須滄海珠，", "使我晝立煩兒孫，令我夜坐費燈燭。憶子初尉永嘉去，", "聖朝尚飛戰鬥塵，濟世宜引英俊人。黎元愁痛會蘇息，", "郭欽上書見大計，劉毅答詔驚群臣。他日更僕語不淺，", "宴筵曾語蘇季子，後來傑出雲孫比。茅齋定王城郭門，", "無數將軍西第成，早作丞相東山起。鳥雀苦肥秋粟菽，", "附書與裴因示蘇，此生已愧須人扶。致君堯舜付公等，"]'),
('yuding-35','奉贈李八丈判官','杜甫','唐','御定全唐诗','yuding','','[]','我丈時英特，宗枝神堯後。珊瑚市則無，騄驥人得有。',180,'御定全唐詩/json/223.json','["我丈時英特，宗枝神堯後。珊瑚市則無，騄驥人得有。", "早年見標格，秀氣沖星斗。事業富清機，官曹正獨守。", "頃來樹嘉政，皆已傳眾口。艱難體貴安，冗長吾敢取。", "區區猶曆試，炯炯更持久。討論實解頤，操割紛應手。", "篋書積諷諫，宮闕限奔走。入幕未展材，秉鈞孰為偶。", "所親問淹泊，泛愛惜衰朽。垂白亂南翁，委身希北叟。", "真成窮轍鮒，或似喪家狗。秋枯洞庭石，風颯長沙柳。", "高興激荊衡，知音為回首。"]'),
('yuding-36','歲晏行','杜甫','唐','御定全唐诗','yuding','','[]','歲雲暮矣多北風，瀟湘洞庭白雪中。漁父天寒網罟凍，',72,'御定全唐詩/json/223.json','["歲雲暮矣多北風，瀟湘洞庭白雪中。漁父天寒網罟凍，", "高馬達官厭酒肉，此輩杼軸茅茨空。楚人重魚不重鳥，", "往日用錢捉私鑄，今許鉛錫和青銅。刻泥為之最易得，"]'),
('yuding-37','追酬故高蜀州人日見寄','杜甫','唐','御定全唐诗','yuding','','[]','自蒙蜀州人日作，不意清詩久零落。今晨散帙眼忽開，',96,'御定全唐詩/json/223.json','["自蒙蜀州人日作，不意清詩久零落。今晨散帙眼忽開，", "歎我淒淒求友篇，感時鬱鬱匡君略。錦裏春光空爛熳，", "東西南北更誰論，白首扁舟病獨存。遙拱北辰纏寇盜，", "鼓瑟至今悲帝子，曳裾何處覓王門。文章曹植波瀾闊，"]'),
('yuding-38','蘇大侍禦訪江浦，賦八韻記異','杜甫','唐','御定全唐诗','yuding','','[]','龐公不浪出，蘇氏今有之。再聞誦新作，突過黃初詩。',84,'御定全唐詩/json/223.json','["龐公不浪出，蘇氏今有之。再聞誦新作，突過黃初詩。", "乾坤幾反復，揚馬宜同時。今晨清鏡中，勝食齋房芝。", "餘發喜卻變，白間生黑絲。昨夜舟火滅，湘娥簾外悲。", "百靈未敢散，風破寒江遲。"]'),
('yuding-39','題衡山縣文宣王廟新學堂，呈陸宰','杜甫','唐','御定全唐诗','yuding','','[]','旄頭彗紫微，無複俎豆事。金甲相排蕩，青衿一憔悴。',240,'御定全唐詩/json/223.json','["旄頭彗紫微，無複俎豆事。金甲相排蕩，青衿一憔悴。", "嗚呼已十年，儒服弊於地。征夫不遑息，學者淪素志。", "我行洞庭野，欻得文翁肆。侁侁胄子行，若舞風雩至。", "周室宜中興，孔門未應棄。是以資雅才，渙然立新意。", "衡山雖小邑，首唱恢大義。因見縣尹心，根源舊宮閟。", "講堂非曩構，大屋加塗墍。下可容百人，牆隅亦深邃。", "何必三千徒，始壓戎馬氣。林木在庭戶，密幹疊蒼翠。", "有井朱夏時，轆轤凍階戺。耳聞讀書聲，殺伐災仿佛。", "故國延歸望，衰顏減愁思。南紀改波瀾，西河共風味。", "采詩倦跋涉，載筆尚可記。高歌激宇宙，凡百慎失墜。"]'),
('yuding-40','入衡州','杜甫','唐','御定全唐诗','yuding','','[]','兵革自久遠，興衰看帝王。漢儀甚照耀，胡馬何倡狂。',528,'御定全唐詩/json/223.json','["兵革自久遠，興衰看帝王。漢儀甚照耀，胡馬何倡狂。", "老將一失律，清邊生戰場。君臣忍瑕垢，河岳空金湯。", "重鎮如割據，輕權絕紀綱。軍州體不一，寬猛性所將。", "嗟彼苦節士，素于圓鑿方。寡妻從為郡，兀者安堵牆。", "凋弊惜邦本，哀矜存事常。旌麾非其任，府庫實過防。", "恕己獨在此，多憂增內傷。偏裨限酒肉，卒伍單衣裳。", "元惡迷是似，聚謀泄康莊。竟流帳下血，大降湖南殃。", "烈火發中夜，高煙焦上蒼。至今分粟帛，殺氣吹沅湘。", "福善理顛倒，明征天莽茫。銷魂避飛鏑，累足穿豺狼。", "隱忍枳棘刺，遷延胝趼瘡。遠歸兒侍側，猶乳女在旁。", "久客幸脫免，暮年慚激昂。蕭條向水陸，汩沒隨魚商。", "報主身已老，入朝病見妨。悠悠委薄俗，鬱鬱回剛腸。", "參錯走洲渚，舂容轉林篁。片帆左郴岸，通郭前衡陽。", "華表雲鳥埤，名園花草香。旗亭壯邑屋，烽櫓蟠城隍。", "中有古刺史，盛才冠岩廊。扶顛待柱石，獨坐飛風霜。", "昨者間瓊樹，高談隨羽觴。無論再繾綣，已是安蒼黃。", "劇孟七國畏，馬卿四賦良。門闌蘇生在，勇銳白起強。", "問罪富形勢，凱歌懸否臧。氛埃期必掃，蚊蚋焉能當。", "橘井舊地宅，仙山引舟航。此行厭暑雨，厥土聞清涼。", "諸舅剖符近，開緘書劄光。頻繁命屢及，磊落字百行。", "江總外家養，謝安乘興長。下流匪珠玉，擇木羞鸞皇。", "我師嵇叔夜，世賢張子房。柴荊寄樂土，鵬路觀翱翔。"]'),
('yuding-41','舟中苦熱遣懷，奉呈陽中丞通簡台省諸公','杜甫','唐','御定全唐诗','yuding','','[]','愧為湖外客，看此戎馬亂。中夜混黎氓，脫身亦奔竄。',288,'御定全唐詩/json/223.json','["愧為湖外客，看此戎馬亂。中夜混黎氓，脫身亦奔竄。", "平生方寸心，反掌帳下難。嗚呼殺賢良，不叱白刃散。", "吾非丈夫特，沒齒埋冰炭。恥以風病辭，胡然泊湘岸。", "入舟雖苦熱，垢膩可溉灌。痛彼道邊人，形骸改昏旦。", "中丞連帥職，封內權得按。身當問罪先，縣實諸侯半。", "士卒既輯睦，啟行促精悍。似聞上游兵，稍逼長沙館。", "憐好彼克修，天機自明斷。南圖卷雲水，北拱戴霄漢。", "美名光史臣，長策何壯觀。驅馳數公子，咸願同伐叛。", "聲節哀有餘，夫何激衰懦。偏裨表三上，鹵莽同一貫。", "始謀誰其間，回首增憤惋。宗英李端公，守職甚昭煥。", "變通迫脅地，謀畫焉得算。王室不肯微，凶徒略無憚。", "此流須卒斬，神器資強幹。扣寂豁煩襟，皇天照嗟歎。"]'),
('yuding-42','聶耒陽以僕阻水書致酒肉療飢荒江詩得代懷興盡本韻至縣呈聶令陸路去方田驛四十里舟行一日時屬江漲泊於方田','杜甫','唐','御定全唐诗','yuding','','[]','耒陽馳尺素，見訪荒江眇。義士烈女家，風流吾賢紹。',156,'御定全唐詩/json/223.json','["耒陽馳尺素，見訪荒江眇。義士烈女家，風流吾賢紹。", "昨見狄相孫，許公人倫表。前期翰林後，屈跡縣邑小。", "知我礙湍濤，半旬獲浩溔。麾下殺元戎，湖邊有飛旐。", "孤舟增鬱鬱，僻路殊悄悄。側驚猿猱捷，仰羨鸛鶴矯。", "禮過宰肥羊，愁當置清醥。人非西喻蜀，興在北坑趙。", "方行郴岸靜，未話長沙擾。崔師乞已至，澧卒用矜少。", "問罪消息真，開顏憩亭沼。"]'),
('yuding-0','冬日洛城北謁玄元皇帝廟','杜甫','唐','御定全唐诗','yuding','','[]','配極玄都閟，憑虛禁禦長。守祧嚴具禮，掌節鎮非常。',168,'御定全唐詩/json/224.json','["配極玄都閟，憑虛禁禦長。守祧嚴具禮，掌節鎮非常。", "碧瓦初寒外，金莖一氣旁。山河扶繡戶，日月近雕梁。", "仙李盤根大，猗蘭奕葉光。世家遺舊史，道德付今王。", "畫手看前輩，吳生遠擅場。森羅移地軸，妙絕動宮牆。", "五聖聯龍袞，千官列雁行。冕旒俱秀髮，旌旆盡飛揚。", "翠柏深留景，紅梨迥得霜。風箏吹玉柱，露井凍銀床。", "身退卑周室，經傳拱漢皇。穀神如不死，養拙更何鄉。"]'),
('yuding-1','贈韋左丞丈','杜甫','唐','御定全唐诗','yuding','','[]','左轄頻虛位，今年得舊儒。相門韋氏在，經術漢臣須。',120,'御定全唐詩/json/224.json','["左轄頻虛位，今年得舊儒。相門韋氏在，經術漢臣須。", "時議歸前烈，天倫恨莫俱。鴒原荒宿草，鳳沼接亨衢。", "有客雖安命，衰容豈壯夫。家人憂几杖，甲子混泥途。", "不謂矜餘力，還來謁大巫。歲寒仍顧遇，日暮且踟躕。", "老驥思千里，饑鷹待一呼。君能微感激，亦足慰榛蕪。"]'),
('yuding-2','投贈哥舒開府二十韻','杜甫','唐','御定全唐诗','yuding','','[]','今代麒麟閣，何人第一功。君王自神武，駕馭必英雄。',240,'御定全唐詩/json/224.json','["今代麒麟閣，何人第一功。君王自神武，駕馭必英雄。", "開府當朝傑，論兵邁古風。先鋒百勝在，略地兩隅空。", "青海無傳箭，天山早掛弓。廉頗仍走敵，魏絳已和戎。", "每惜河湟棄，新兼節制通。智謀垂睿想，出入冠諸公。", "日月低秦樹，乾坤繞漢宮。胡人愁逐北，宛馬又從東。", "受命邊沙遠，歸來禦席同。軒墀曾寵鶴，畋獵舊非熊。", "茅土加名數，山河誓始終。策行遺戰伐，契合動昭融。", "勳業青冥上，交親氣概中。未為珠履客，已見白頭翁。", "壯節初題柱，生涯獨轉蓬。幾年春草歇，今日暮途窮。", "軍事留孫楚，行間識呂蒙。防身一長劍，將欲倚崆峒。"]'),
('yuding-3','上韋左相二十韻','杜甫','唐','御定全唐诗','yuding','','[]','鳳曆軒轅紀，龍飛四十春。八荒開壽域，一氣轉洪鈞。',240,'御定全唐詩/json/224.json','["鳳曆軒轅紀，龍飛四十春。八荒開壽域，一氣轉洪鈞。", "霖雨思賢佐，丹青憶老臣。應圖求駿馬，驚代得麒麟。", "沙汰江河濁，調和鼎鼐新。韋賢初相漢，范叔已歸秦。", "盛業今如此，傳經固絕倫。豫樟深出地，滄海闊無津。", "北斗司喉舌，東方領搢紳。持衡留藻鑒，聽履上星辰。", "獨步才超古，餘波德照鄰。聰明過管輅，尺牘倒陳遵。", "豈是池中物，由來席上珍。廟堂知至理，風俗盡還淳。", "才傑俱登用，愚蒙但隱淪。長卿多病久，子夏索居頻。", "回首驅流俗，生涯似眾人。巫咸不可問，鄒魯莫容身。", "感激時將晚，蒼茫興有神。為公歌此曲，涕淚在衣巾。"]'),
('yuding-4','奉贈太常張卿二十韻','杜甫','唐','御定全唐诗','yuding','','[]','方丈三韓外，昆侖萬國西。建標天地闊，詣絕古今迷。',240,'御定全唐詩/json/224.json','["方丈三韓外，昆侖萬國西。建標天地闊，詣絕古今迷。", "氣得神仙迥，恩承雨露低。相門清議眾，儒術大名齊。", "軒冕羅天闕，琳琅識介珪。伶官詩必誦，夔樂典猶稽。", "健筆淩鸚鵡，銛鋒瑩鸊鵜。友于皆挺拔，公望各端倪。", "通籍逾青瑣，亨衢照紫泥。靈虯傳夕箭，歸馬散霜蹄。", "能事聞重譯，嘉謨及遠黎。弼諧方一展，斑序更何躋。", "適越空顛躓，游梁竟慘淒。謬知終畫虎，微分是醯雞。", "萍泛無休日，桃陰想舊蹊。吹噓人所羨，騰躍事仍睽。", "碧海真難涉，青雲不可梯。顧深慚鍛煉，才小辱提攜。", "檻束哀猿叫，枝驚夜鵲棲。幾時陪羽獵，應指釣璜溪。"]'),
('yuding-5','敬贈鄭諫議十韻','杜甫','唐','御定全唐诗','yuding','','[]','諫官非不達，詩義早知名。破的由來事，先鋒孰敢爭。',120,'御定全唐詩/json/224.json','["諫官非不達，詩義早知名。破的由來事，先鋒孰敢爭。", "思飄雲物外，律中鬼神驚。毫髮無遺恨，波瀾獨老成。", "野人甯得所，天意薄浮生。多病休儒服，冥搜信客旌。", "築居仙縹緲，旅食歲崢嶸。使者求顏闔，諸公厭禰衡。", "將期一諾重，欻使寸心傾。君見途窮哭，宜憂阮步兵。"]'),
('yuding-6','奉贈鮮於京兆二十韻','杜甫','唐','御定全唐诗','yuding','','[]','王國稱多士，賢良複幾人。異才應間出，爽氣必殊倫。',240,'御定全唐詩/json/224.json','["王國稱多士，賢良複幾人。異才應間出，爽氣必殊倫。", "始見張京兆，宜居漢近臣。驊騮開道路，雕鶚離風塵。", "侯伯知何等，文章實致身。奮飛超等級，容易失沈淪。", "脫略磻溪釣，操持郢匠斤。雲霄今已逼，台袞更誰親。", "鳳穴雛皆好，龍門客又新。義聲紛感激，敗績自逡巡。", "途遠欲何向，天高難重陳。學詩猶孺子，鄉賦念嘉賓。", "不得同晁錯，籲嗟後郤詵。計疏疑翰墨，時過憶松筠。", "獻納紆皇眷，中間謁紫宸。且隨諸彥集，方覬薄才伸。", "破膽遭前政，陰謀獨秉鈞。微生沾忌刻，萬事益酸辛。", "交合丹青地，恩傾雨露辰。有儒愁餓死，早晚報平津。"]'),
('yuding-7','贈特進汝陽王二十韻','杜甫','唐','御定全唐诗','yuding','','[]','特進群公表，天人夙德升。霜蹄千里駿，風翮九霄鵬。',264,'御定全唐詩/json/224.json','["特進群公表，天人夙德升。霜蹄千里駿，風翮九霄鵬。", "服禮求毫髮，惟忠忘寢興。聖情常有眷，朝退若無憑。", "仙醴來浮蟻，奇毛或賜鷹。清關塵不雜，中使日相乘。", "晚節嬉游簡，平居孝義稱。自多親棣萼，誰敢問山陵。", "學業醇儒富，辭華哲匠能。筆飛鸞聳立，章罷鳳鶱騰。", "精理通談笑，忘形向友朋。寸長堪繾綣，一諾豈驕矜。", "已忝歸曹植，何知對李膺。招要恩屢至，崇重力難勝。", "披霧初歡夕，高秋爽氣澄。尊罍臨極浦，鳧雁宿張燈。", "花月窮遊宴，炎天避鬱蒸。研寒金井水，簷動玉壺冰。", "瓢飲唯三徑，岩棲在百層。且持蠡測海，況挹酒如澠。", "鴻寶甯全秘，丹梯庶可淩。淮王門有客，終不愧孫登。"]'),
('yuding-8','鄭駙馬宅宴洞中','杜甫','唐','御定全唐诗','yuding','','[]','主家陰洞細煙霧，留客夏簟清琅玕。春酒杯濃琥珀薄，',40,'御定全唐詩/json/224.json','["主家陰洞細煙霧，留客夏簟清琅玕。春酒杯濃琥珀薄，", "自是秦樓壓鄭谷，時聞雜佩聲珊珊。"]'),
('yuding-9','李監宅','杜甫','唐','御定全唐诗','yuding','','[]','尚覺王孫貴，豪家意頗濃。屏開金孔雀，褥隱繡芙蓉。',48,'御定全唐詩/json/224.json','["尚覺王孫貴，豪家意頗濃。屏開金孔雀，褥隱繡芙蓉。", "且食雙魚美，誰看異味重。門闌多喜色，女婿近乘龍。"]'),
('yuding-10','重題鄭氏東亭','杜甫','唐','御定全唐诗','yuding','','[]','華亭入翠微，秋日亂清暉。崩石欹山樹，清漣曳水衣。',48,'御定全唐詩/json/224.json','["華亭入翠微，秋日亂清暉。崩石欹山樹，清漣曳水衣。", "紫鱗沖岸躍，蒼隼護巢歸。向晚尋征路，殘雲傍馬飛。"]'),
('yuding-11','題張氏隱居二首','杜甫','唐','御定全唐诗','yuding','','[]','春山無伴獨相求，伐木丁丁山更幽。澗道餘寒曆冰雪，',88,'御定全唐詩/json/224.json','["春山無伴獨相求，伐木丁丁山更幽。澗道餘寒曆冰雪，", "乘興杳然迷出處，對君疑是泛虛舟。", "之子時相見，邀人晚興留。霽潭鱣發發，春草鹿呦呦。", "杜酒偏勞勸，張梨不外求。前村山路險，歸醉每無愁。"]'),
('yuding-12','天寶初南曹小司寇舅於我太夫人堂下累土為山一匱盈尺以代彼朽木承諸焚香瓷甌甌甚安矣旁植慈竹蓋茲數峰嶔岑嬋娟宛有塵外數致乃不知興之所至而作是詩','杜甫','唐','御定全唐诗','yuding','','[]','一匱功盈尺，三峰意出群。望中疑在野，幽處欲生雲。',48,'御定全唐詩/json/224.json','["一匱功盈尺，三峰意出群。望中疑在野，幽處欲生雲。", "慈竹春陰覆，香爐曉勢分。惟南將獻壽，佳氣日氛氳。"]'),
('yuding-13','龍門','杜甫','唐','御定全唐诗','yuding','','[]','龍門橫野斷，驛樹出城來。氣色皇居近，金銀佛寺開。',48,'御定全唐詩/json/224.json','["龍門橫野斷，驛樹出城來。氣色皇居近，金銀佛寺開。", "往還時屢改，川水日悠哉。相閱征途上，生涯盡幾回。"]'),
('yuding-14','奉寄河南韋尹丈人','杜甫','唐','御定全唐诗','yuding','','[]','有客傳河尹，逢人問孔融。青囊仍隱逸，章甫尚西東。',120,'御定全唐詩/json/224.json','["有客傳河尹，逢人問孔融。青囊仍隱逸，章甫尚西東。", "鼎食分門戶，詞場繼國風。尊榮瞻地絕，疏放憶途窮。", "濁酒尋陶令，丹砂訪葛洪。江湖漂短褐，霜雪滿飛蓬。", "牢落乾坤大，周流道術空。謬慚知薊子，真怯笑揚雄。", "盤錯神明懼，謳歌德義豐。屍鄉餘土室，難說祝雞翁。"]'),
('yuding-15','贈李白','杜甫','唐','御定全唐诗','yuding','','[]','秋來相顧尚飄蓬，未就丹砂愧葛洪。',32,'御定全唐詩/json/224.json','["秋來相顧尚飄蓬，未就丹砂愧葛洪。", "痛飲狂歌空度日，飛揚跋扈為誰雄。"]'),
('yuding-16','與任城許主簿游南池','杜甫','唐','御定全唐诗','yuding','','[]','秋水通溝洫，城隅進小船。晚涼看洗馬，森木亂鳴蟬。',48,'御定全唐詩/json/224.json','["秋水通溝洫，城隅進小船。晚涼看洗馬，森木亂鳴蟬。", "菱熟經時雨，蒲荒八月天。晨朝降白露，遙憶舊青氈。"]'),
('yuding-17','登兗州城樓','杜甫','唐','御定全唐诗','yuding','','[]','東郡趨庭日，南樓縱目初。浮雲連海岳，平野入青徐。',48,'御定全唐詩/json/224.json','["東郡趨庭日，南樓縱目初。浮雲連海岳，平野入青徐。", "孤嶂秦碑在，荒城魯殿餘。從來多古意，臨眺獨躊躇。"]'),
('yuding-18','劉九法曹、鄭瑕丘石門宴集','杜甫','唐','御定全唐诗','yuding','','[]','秋水清無底，蕭然靜客心。掾曹乘逸興，鞍馬去相尋。',48,'御定全唐詩/json/224.json','["秋水清無底，蕭然靜客心。掾曹乘逸興，鞍馬去相尋。", "能吏逢聯璧，華筵直一金。晚來橫吹好，泓下亦龍吟。"]'),
('yuding-19','暫如臨邑，至gh山湖亭奉懷李員外率爾成興','杜甫','唐','御定全唐诗','yuding','','[]','野亭逼湖水，歇馬高林間。鼉吼風奔浪，魚跳日映山。',48,'御定全唐詩/json/224.json','["野亭逼湖水，歇馬高林間。鼉吼風奔浪，魚跳日映山。", "暫游阻詞伯，卻望懷青關。靄靄生雲霧，唯應促駕還。"]'),
('yuding-20','對雨書懷，走邀許十一簿公','杜甫','唐','御定全唐诗','yuding','','[]','東嶽雲峰起，溶溶滿太虛。震雷翻幕燕，驟雨落河魚。',48,'御定全唐詩/json/224.json','["東嶽雲峰起，溶溶滿太虛。震雷翻幕燕，驟雨落河魚。", "座對賢人酒，門聽長者車。相邀愧泥濘，騎馬到階除。"]'),
('yuding-21','巳上人茅齋','杜甫','唐','御定全唐诗','yuding','','[]','巳公茅屋下，可以賦新詩。枕簟入林僻，茶瓜留客遲。',48,'御定全唐詩/json/224.json','["巳公茅屋下，可以賦新詩。枕簟入林僻，茶瓜留客遲。", "江蓮搖白羽，天棘夢青絲。空忝許詢輩，難酬支遁詞。"]'),
('yuding-22','房兵曹胡馬詩','杜甫','唐','御定全唐诗','yuding','','[]','胡馬大宛名，鋒棱瘦骨成。竹批雙耳峻，風入四蹄輕。',48,'御定全唐詩/json/224.json','["胡馬大宛名，鋒棱瘦骨成。竹批雙耳峻，風入四蹄輕。", "所向無空闊，真堪托死生。驍騰有如此，萬里可橫行。"]'),
('yuding-23','畫鷹','杜甫','唐','御定全唐诗','yuding','','[]','素練風霜起，蒼鷹畫作殊。身思狡兔，側目似愁胡。',48,'御定全唐詩/json/224.json','["素練風霜起，蒼鷹畫作殊。身思狡兔，側目似愁胡。", "絛镟光堪擿，軒楹勢可呼。何當擊凡鳥，毛血灑平蕪。"]'),
('yuding-24','與李十二白同尋範十隱居','杜甫','唐','御定全唐诗','yuding','','[]','李侯有佳句，往往似陰鏗。余亦東蒙客，憐君如弟兄。',96,'御定全唐詩/json/224.json','["李侯有佳句，往往似陰鏗。余亦東蒙客，憐君如弟兄。", "醉眠秋共被，攜手日同行。更想幽期處，還尋北郭生。", "入門高興發，侍立小童清。落景聞寒杵，屯雲對古城。", "向來吟橘頌，誰欲討蓴羹。不願論簪笏，悠悠滄海情。"]'),
('yuding-25','臨邑舍弟書至苦雨黃河泛溢隄防之患簿領所憂因寄此詩用寬其意','杜甫','唐','御定全唐诗','yuding','','[]','二儀積風雨，百谷漏波濤。聞道洪河坼，遙連滄海高。',144,'御定全唐詩/json/224.json','["二儀積風雨，百谷漏波濤。聞道洪河坼，遙連滄海高。", "職思憂悄悄，郡國訴嗷嗷。舍弟卑棲邑，防川領簿曹。", "尺書前日至，版築不時操。難假黿鼉力，空瞻烏鵲毛。", "燕南吹畎畝，濟上沒蓬蒿。螺蚌滿近郭，蛟螭乘九皋。", "徐關深水府，碣石小秋毫。白屋留孤樹，青天矢萬艘。", "吾衰同泛梗，利涉想蟠桃。倚賴天涯釣，猶能掣巨鼇。"]'),
('yuding-26','過宋員外之問舊莊','杜甫','唐','御定全唐诗','yuding','','[]','宋公舊池館，零落守陽阿。枉道祗從入，吟詩許更過。',48,'御定全唐詩/json/224.json','["宋公舊池館，零落守陽阿。枉道祗從入，吟詩許更過。", "淹留問耆老，寂寞向山河。更識將軍樹，悲風日暮多。"]'),
('yuding-27','夜宴左氏莊','杜甫','唐','御定全唐诗','yuding','','[]','風林纖月落，衣露淨琴張。暗水流花徑，春星帶草堂。',48,'御定全唐詩/json/224.json','["風林纖月落，衣露淨琴張。暗水流花徑，春星帶草堂。", "檢書燒燭短，看劍引杯長。詩罷聞吳詠，扁舟意不忘。"]'),
('yuding-28','送蔡希曾都尉還隴右，因寄高三十五書記','杜甫','唐','御定全唐诗','yuding','','[]','蔡子勇成癖，彎弓西射胡。健兒甯鬥死，壯士恥為儒。',120,'御定全唐詩/json/224.json','["蔡子勇成癖，彎弓西射胡。健兒甯鬥死，壯士恥為儒。", "官是先鋒得，材緣挑戰須。身輕一鳥過，槍急萬人呼。", "雲幕隨開府，春城赴上都。馬頭金狎帢，駝背錦模糊。", "咫尺雲山路，歸飛青海隅。上公猶寵錫，突將且前驅。", "漢使黃河遠，涼州白麥枯。因君問消息，好在阮元瑜。"]'),
('yuding-29','春日憶李白','杜甫','唐','御定全唐诗','yuding','','[]','白也詩無敵，飄然思不群。清新庾開府，俊逸鮑參軍。',48,'御定全唐詩/json/224.json','["白也詩無敵，飄然思不群。清新庾開府，俊逸鮑參軍。", "渭北春天樹，江東日暮雲。何時一尊酒，重與細論文。"]'),
('yuding-30','贈陳二補闕','杜甫','唐','御定全唐诗','yuding','','[]','世儒多汩沒，夫子獨聲名。獻納開東觀，君王問長卿。',48,'御定全唐詩/json/224.json','["世儒多汩沒，夫子獨聲名。獻納開東觀，君王問長卿。", "皂雕寒始急，天馬老能行。自到青冥裏，休看白髮生。"]'),
('yuding-31','寄高三十五書記','杜甫','唐','御定全唐诗','yuding','','[]','嘆惜高生老，新詩日又多。美名人不及，佳句法如何。',48,'御定全唐詩/json/224.json','["嘆惜高生老，新詩日又多。美名人不及，佳句法如何。", "主將收才子，崆峒足凱歌。聞君已朱紱，且得慰蹉跎。"]'),
('yuding-32','送裴二虯作尉永嘉','杜甫','唐','御定全唐诗','yuding','','[]','孤嶼亭何處，天涯水氣中。故人官就此，絕境興誰同。',48,'御定全唐詩/json/224.json','["孤嶼亭何處，天涯水氣中。故人官就此，絕境興誰同。", "隱吏逢梅福，游山憶謝公。扁舟吾已就，把釣待秋風。"]'),
('yuding-33','城西陂泛舟','杜甫','唐','御定全唐诗','yuding','','[]','青蛾皓齒在樓船，橫笛短簫悲遠天。春風自信牙檣動，',40,'御定全唐詩/json/224.json','["青蛾皓齒在樓船，橫笛短簫悲遠天。春風自信牙檣動，", "不有小舟能蕩槳，百壺那送酒如泉。"]'),
('yuding-34','贈田九判官','杜甫','唐','御定全唐诗','yuding','','[]','崆峒使節上青霄，河隴降王款聖朝。宛馬總肥春苜蓿，',40,'御定全唐詩/json/224.json','["崆峒使節上青霄，河隴降王款聖朝。宛馬總肥春苜蓿，", "麾下賴君才併入，獨能無意向漁樵。"]'),
('yuding-35','贈獻納使起居田舍人','杜甫','唐','御定全唐诗','yuding','','[]','獻納司存雨露邊，地分清切任才賢。舍人退食收封事，',40,'御定全唐詩/json/224.json','["獻納司存雨露邊，地分清切任才賢。舍人退食收封事，", "揚雄更有河東賦，唯待吹噓送上天。"]'),
('yuding-36','送韋書記赴安西','杜甫','唐','御定全唐诗','yuding','','[]','夫子欻通貴，雲泥相望懸。白頭無藉在，朱紱有哀憐。',48,'御定全唐詩/json/224.json','["夫子欻通貴，雲泥相望懸。白頭無藉在，朱紱有哀憐。", "書記赴三捷，公車留二年。欲浮江海去，此別意蒼然。"]'),
('yuding-37','陪鄭廣文游何將軍山林十首','杜甫','唐','御定全唐诗','yuding','','[]','不識南塘路，今知第五橋。名園依綠水，野竹上青霄。',481,'御定全唐詩/json/224.json','["不識南塘路，今知第五橋。名園依綠水，野竹上青霄。", "穀口舊相得，濠梁同見招。平生為幽興，未惜馬蹄遙。", "百頃風潭上，千重夏木清。卑枝低結子，接葉暗巢鶯。", "鮮鯽銀絲膾，香芹碧澗羹。翻疑柁樓底，晚飯越中行。", "萬里戎王子，何年別月支。異花開絕域，滋蔓匝清池。", "漢使徒空到，神農竟不知。露翻兼雨打，開坼日離披。", "旁舍連高竹，疏籬帶晚花。碾渦深沒馬，藤蔓曲藏蛇。", "詞賦工無益，山林跡未賒。盡撚書籍賣，來問爾東家。", "剩水滄江破，殘山碣石開。綠垂風折筍，紅綻雨肥梅。", "銀甲彈箏用，金魚換酒來。興移無灑掃，隨意坐莓苔。", "風磴吹陰雪，雲門吼瀑泉。酒醒思臥簟，衣冷欲裝綿。", "野老來看客，河魚不取錢。只疑淳樸處，自有一山川。", "棘樹寒雲色，茵蔯春藕香。脆添生菜美，陰益食單涼。", "野鶴清晨出，山精白日藏。石林蟠水府，百里獨蒼蒼。", "憶過楊柳渚，走馬定昆池。醉把青荷葉，狂遺白接z5。", "刺船思郢客，解水乞吳兒。坐對秦山晚，江湖興頗隨。", "床上書連屋，階前樹拂雲。將軍不好武，稚子總能文。", "醒酒微風入，聽詩靜夜分。絺衣掛蘿薜，涼月白紛紛。", "幽意忽不愜，歸期無奈何。出門流水注，回首白雲多。", "自笑燈前舞，誰憐醉後歌。祗應與朋好，風雨亦來過。"]'),
('yuding-38','重過何氏五首','杜甫','唐','御定全唐诗','yuding','','[]','問訊東橋竹，將軍有報書。倒衣還命駕，高枕乃吾廬。',240,'御定全唐詩/json/224.json','["問訊東橋竹，將軍有報書。倒衣還命駕，高枕乃吾廬。", "花妥鶯捎蝶，溪喧獺趁魚。重來休沐地，真作野人居。", "山雨尊仍在，沙沈榻未移。犬迎曾宿客，鴉護落巢兒。", "雲薄翠微寺，天清黃子陂。向來幽興極，步屣過東籬。", "落日平臺上，春風啜茗時。石闌斜點筆，桐葉坐題詩。", "翡翠鳴衣桁，蜻蜓立釣絲。自今幽興熟，來往亦無期。", "頗怪朝參懶，應耽野趣長。雨拋金鎖甲，苔臥綠沈槍。", "手自移蒲柳，家才足稻粱。看君用幽意，白日到羲皇。", "到此應常宿，相留可判年。蹉跎暮容色，悵望好林泉。", "何路沾微祿，歸山買薄田。斯遊恐不遂，把酒意茫然。"]'),
('yuding-39','冬日有懷李白','杜甫','唐','御定全唐诗','yuding','','[]','寂寞書齋裏，終朝獨爾思。更尋嘉樹傳，不忘角弓詩。',48,'御定全唐詩/json/224.json','["寂寞書齋裏，終朝獨爾思。更尋嘉樹傳，不忘角弓詩。", "短褐風霜入，還丹日月遲。未因乘興去，空有鹿門期。"]'),
('yuding-40','杜位宅守歲','杜甫','唐','御定全唐诗','yuding','','[]','守歲阿戎家，椒盤已頌花。盍簪喧櫪馬，列炬散林鴉。',48,'御定全唐詩/json/224.json','["守歲阿戎家，椒盤已頌花。盍簪喧櫪馬，列炬散林鴉。", "四十明朝過，飛騰暮景斜。誰能更拘束，爛醉是生涯。"]'),
('yuding-41','與鄠縣源大少府宴渼陂','杜甫','唐','御定全唐诗','yuding','','[]','應為西陂好，金錢罄一餐。飯抄雲子白，瓜嚼水精寒。',48,'御定全唐詩/json/224.json','["應為西陂好，金錢罄一餐。飯抄雲子白，瓜嚼水精寒。", "無計回船下，空愁避酒難。主人情爛熳，持答翠琅玕。"]'),
('yuding-42','崔駙馬山亭宴集','杜甫','唐','御定全唐诗','yuding','','[]','蕭史幽棲地，林間蹋鳳毛。洑流何處入，亂石閉門高。',48,'御定全唐詩/json/224.json','["蕭史幽棲地，林間蹋鳳毛。洑流何處入，亂石閉門高。", "客醉揮金碗，詩成得繡袍。清秋多宴會，終日困香醪。"]'),
('yuding-43','九日楊奉先會白水崔明府','杜甫','唐','御定全唐诗','yuding','','[]','今日潘懷縣，同時陸浚儀。坐開桑落酒，來把菊花枝。',48,'御定全唐詩/json/224.json','["今日潘懷縣，同時陸浚儀。坐開桑落酒，來把菊花枝。", "天宇清霜淨，公堂宿霧披。晚酣留客舞，鳧舄共差池。"]'),
('yuding-44','贈翰林張四學士','杜甫','唐','御定全唐诗','yuding','','[]','翰林逼華蓋，鯨力破滄溟。天上張公子，宮中漢客星。',96,'御定全唐詩/json/224.json','["翰林逼華蓋，鯨力破滄溟。天上張公子，宮中漢客星。", "賦詩拾翠殿，佐酒望雲亭。紫誥仍兼綰，黃麻似六經。", "內分金帶赤，恩與荔枝青。無複隨高鳳，空餘泣聚螢。", "此生任春草，垂老獨漂萍。倘憶山陽會，悲歌在一聽。"]'),
('yuding-45','送張二十參軍赴蜀州，因呈楊五侍禦','杜甫','唐','御定全唐诗','yuding','','[]','好去張公子，通家別恨添。兩行秦樹直，萬點蜀山尖。',48,'御定全唐詩/json/224.json','["好去張公子，通家別恨添。兩行秦樹直，萬點蜀山尖。", "禦史新驄馬，參軍舊紫髯。皇華吾善處，於汝定無嫌。"]'),
('yuding-46','陪諸貴公子丈八溝攜妓納涼，晚際遇雨二首','杜甫','唐','御定全唐诗','yuding','','[]','落日放船好，輕風生浪遲。竹深留客處，荷淨納涼時。',96,'御定全唐詩/json/224.json','["落日放船好，輕風生浪遲。竹深留客處，荷淨納涼時。", "公子調冰水，佳人雪藕絲。片雲頭上黑，應是雨催詩。", "雨來沾席上，風急打船頭。越女紅裙濕，燕姬翠黛愁。", "纜侵堤柳系，幔宛浪花浮。歸路翻蕭颯，陂塘五月秋。"]'),
('yuding-47','白水明府舅宅喜雨','杜甫','唐','御定全唐诗','yuding','','[]','吾舅政如此，古人誰複過。碧山晴又濕，白水雨偏多。',48,'御定全唐詩/json/224.json','["吾舅政如此，古人誰複過。碧山晴又濕，白水雨偏多。", "精禱既不昧，歡娛將謂何。湯年旱頗甚，今日醉弦歌。"]'),
('yuding-48','陪李金吾花下飲','杜甫','唐','御定全唐诗','yuding','','[]','勝地初相引，餘行得自娛。見輕吹鳥毳，隨意數花須。',48,'御定全唐詩/json/224.json','["勝地初相引，餘行得自娛。見輕吹鳥毳，隨意數花須。", "細草稱偏坐，香醪懶再酤。醉歸應犯夜，可怕李金吾。"]'),
('yuding-49','贈高式顏','杜甫','唐','御定全唐诗','yuding','','[]','昔別是何處，相逢皆老夫。故人還寂寞，削跡共艱虞。',48,'御定全唐詩/json/224.json','["昔別是何處，相逢皆老夫。故人還寂寞，削跡共艱虞。", "自失論文友，空知賣酒壚。平生飛動意，見爾不能無。"]'),
('yuding-50','贈比部蕭郎中十兄','杜甫','唐','御定全唐诗','yuding','','[]','有美生人傑，由來積德門。漢朝丞相系，梁日帝王孫。',120,'御定全唐詩/json/224.json','["有美生人傑，由來積德門。漢朝丞相系，梁日帝王孫。", "蘊藉為郎久，魁梧秉哲尊。詞華傾後輩，風雅藹孤鶱。", "宅相榮姻戚，兒童惠討論。見知真自幼，謀拙醜諸昆。", "漂蕩雲天闊，沈埋日月奔。致君時已晚，懷古意空存。", "中散山陽鍛，愚公野穀村。甯紆長者轍，歸老任乾坤。"]'),
('yuding-51','九日曲江','杜甫','唐','御定全唐诗','yuding','','[]','綴席茱萸好，浮舟菡萏衰。季秋時欲半，九日意兼悲。',48,'御定全唐詩/json/224.json','["綴席茱萸好，浮舟菡萏衰。季秋時欲半，九日意兼悲。", "江水清源曲，荊門此路疑。晚來高興盡，搖盪菊花期。"]'),
('yuding-52','承沈八丈東美除膳部員外，阻雨未遂馳賀，奉寄此詩','杜甫','唐','御定全唐诗','yuding','','[]','今日西京掾，多除內省郎。通家惟沈氏，謁帝似馮唐。',120,'御定全唐詩/json/224.json','["今日西京掾，多除內省郎。通家惟沈氏，謁帝似馮唐。", "詩律群公問，儒門舊史長。清秋便寓直，列宿頓輝光。", "未暇申宴慰，含情空激揚。司存何所比，膳部默淒傷。", "貧賤人事略，經過霖潦妨。禮同諸父長，恩豈布衣忘。", "天路牽騏驥，雲台引棟樑。徒懷貢公喜，颯颯鬢毛蒼。"]'),
('yuding-53','奉留贈集賢院崔、于二學士','杜甫','唐','御定全唐诗','yuding','','[]','昭代將垂白，途窮乃叫閽。氣沖星象表，詞感帝王尊。',120,'御定全唐詩/json/224.json','["昭代將垂白，途窮乃叫閽。氣沖星象表，詞感帝王尊。", "天老書題目，春官驗討論。倚風遺鶂路，隨水到龍門。", "竟與蛟螭雜，空聞燕雀喧。青冥猶契闊，陵厲不飛翻。", "儒術誠難起，家聲庶已存。故山多藥物，勝概憶桃源。", "欲整還鄉旆，長懷禁掖垣。謬稱三賦在，難述二公恩。"]'),
('yuding-54','故武衛將軍挽歌三首','杜甫','唐','御定全唐诗','yuding','','[]','嚴警當寒夜，前軍落大星。壯夫思感決，哀詔惜精靈。',144,'御定全唐詩/json/224.json','["嚴警當寒夜，前軍落大星。壯夫思感決，哀詔惜精靈。", "王者今無戰，書生已勒銘。封侯意疏闊，編簡為誰青。", "舞劍過人絕，鳴弓射獸能。銛鋒行愜順，猛噬失蹻騰。", "赤羽千夫膳，黃河十月冰。橫行沙漠外，神速至今稱。", "哀挽青門去，新阡絳水遙。路人紛雨泣，天意颯風飄。", "部曲精仍銳，匈奴氣不驕。無由睹雄略，大樹日蕭蕭。"]'),
('yuding-55','官定後戲贈','杜甫','唐','御定全唐诗','yuding','','[]','不作河西尉，淒涼為折腰。老夫怕趨走，率府且逍遙。',48,'御定全唐詩/json/224.json','["不作河西尉，淒涼為折腰。老夫怕趨走，率府且逍遙。", "耽酒須微祿，狂歌托聖朝。故山歸興盡，回首向風飆。"]'),
('yuding-56','九日藍田崔氏莊','杜甫','唐','御定全唐诗','yuding','','[]','老去悲秋強自寬，興來今日盡君歡。羞將短髮還吹帽，',40,'御定全唐詩/json/224.json','["老去悲秋強自寬，興來今日盡君歡。羞將短髮還吹帽，", "明年此會知誰健，醉把茱萸子細看。"]'),
('yuding-57','崔氏東山草堂','杜甫','唐','御定全唐诗','yuding','','[]','愛汝玉山草堂靜，高秋爽氣相鮮新。有時自發鐘磬響，',40,'御定全唐詩/json/224.json','["愛汝玉山草堂靜，高秋爽氣相鮮新。有時自發鐘磬響，", "何為西莊王給事，柴門空閉鎖松筠。"]'),
('yuding-58','對雪','杜甫','唐','御定全唐诗','yuding','','[]','戰哭多新鬼，愁吟獨老翁。亂雲低薄暮，急雪舞回風。',48,'御定全唐詩/json/224.json','["戰哭多新鬼，愁吟獨老翁。亂雲低薄暮，急雪舞回風。", "瓢棄尊無綠，爐存火似紅。數州消息斷，愁坐正書空。"]'),
('yuding-59','月夜','杜甫','唐','御定全唐诗','yuding','','[]','今夜鄜州月，閨中只獨看。遙憐小兒女，未解憶長安。',48,'御定全唐詩/json/224.json','["今夜鄜州月，閨中只獨看。遙憐小兒女，未解憶長安。", "香霧雲鬟濕，清輝玉臂寒。何時倚虛幌，雙照淚痕幹。"]'),
('yuding-60','遣興','杜甫','唐','御定全唐诗','yuding','','[]','驥子好男兒，前年學語時。問知人客姓，誦得老夫詩。',72,'御定全唐詩/json/224.json','["驥子好男兒，前年學語時。問知人客姓，誦得老夫詩。", "世亂憐渠小，家貧仰母慈。鹿門攜不遂，雁足系難期。", "天地軍麾滿，山河戰角悲。儻歸免相失，見日敢辭遲。"]'),
('yuding-61','元日寄韋氏妹','杜甫','唐','御定全唐诗','yuding','','[]','近聞韋氏妹，迎在漢鐘離。郎伯殊方鎮，京華舊國移。',48,'御定全唐詩/json/224.json','["近聞韋氏妹，迎在漢鐘離。郎伯殊方鎮，京華舊國移。", "春城回北斗，郢樹發南枝。不見朝正使，啼痕滿面垂。"]'),
('yuding-62','春望','杜甫','唐','御定全唐诗','yuding','','[]','國破山河在，城春草木深。感時花濺淚，恨別鳥驚心。',48,'御定全唐詩/json/224.json','["國破山河在，城春草木深。感時花濺淚，恨別鳥驚心。", "烽火連三月，家書抵萬金。白頭搔更短，渾欲不勝簪。"]'),
('yuding-63','憶幼子','杜甫','唐','御定全唐诗','yuding','','[]','驥子春猶隔，鶯歌暖正繁。別離驚節換，聰慧與誰論。',48,'御定全唐詩/json/224.json','["驥子春猶隔，鶯歌暖正繁。別離驚節換，聰慧與誰論。", "澗水空山道，柴門老樹村。憶渠愁只睡，炙背俯晴軒。"]'),
('yuding-64','一百五日夜對月','杜甫','唐','御定全唐诗','yuding','','[]','無家對寒食，有淚如金波。斫卻月中桂，清光應更多。',48,'御定全唐詩/json/224.json','["無家對寒食，有淚如金波。斫卻月中桂，清光應更多。", "仳離放紅蕊，想像嚬青蛾。牛女漫愁思，秋期猶渡河。"]'),
('yuding-0','喜達行在所三首','杜甫','唐','御定全唐诗','yuding','','[]','西憶岐陽信，無人遂卻回。眼穿當落日，心死著寒灰。',144,'御定全唐詩/json/225.json','["西憶岐陽信，無人遂卻回。眼穿當落日，心死著寒灰。", "霧樹行相引，蓮峰望忽開。所親驚老瘦，辛苦賊中來。", "愁思胡笳夕，淒涼漢苑春。生還今日事，間道暫時人。", "司隸章初睹，南陽氣已新。喜心翻倒極，嗚咽淚沾巾。", "死去憑誰報，歸來始自憐。猶瞻太白雪，喜遇武功天。", "影靜千官裏，心蘇七校前。今朝漢社稷，新數中興年。"]'),
('yuding-1','得家書','杜甫','唐','御定全唐诗','yuding','','[]','去憑遊客寄，來為附家書。今日知消息，他鄉且舊居。',96,'御定全唐詩/json/225.json','["去憑遊客寄，來為附家書。今日知消息，他鄉且舊居。", "熊兒幸無恙，驥子最憐渠。臨老羈孤極，傷時會合疏。", "二毛趨帳殿，一命侍鸞輿。北闕妖氛滿，西郊白露初。", "涼風新過雁，秋雨欲生魚。農事空山裏，眷言終荷鋤。"]'),
('yuding-2','奉贈嚴八閣老','杜甫','唐','御定全唐诗','yuding','','[]','扈聖登黃閣，明公獨妙年。蛟龍得雲雨，雕鶚在秋天。',48,'御定全唐詩/json/225.json','["扈聖登黃閣，明公獨妙年。蛟龍得雲雨，雕鶚在秋天。", "客禮容疏放，官曹可接聯。新詩句句好，應任老夫傳。"]'),
('yuding-3','奉送郭中丞兼太僕卿充隴右節度使三十韻','杜甫','唐','御定全唐诗','yuding','','[]','詔發西山將，秋屯隴右兵。淒涼餘部曲，燀赫舊家聲。',360,'御定全唐詩/json/225.json','["詔發西山將，秋屯隴右兵。淒涼餘部曲，燀赫舊家聲。", "雕鶚乘時去，驊騮顧主鳴。艱難須上策，容易即前程。", "斜日當軒蓋，高風卷旆旌。松悲天水冷，沙亂雪山清。", "和虜猶懷惠，防邊不敢驚。古來于異域，鎮靜示專征。", "燕薊奔封豕，周秦觸駭鯨。中原何慘黷，餘孽尚縱橫。", "箭入昭陽殿，笳吟細柳營。內人紅袖泣，王子白衣行。", "宸極祅星動，園陵殺氣平。空餘金碗出，無複穗帷輕。", "毀廟天飛雨，焚宮火徹明。罘罳朝共落，棆桷夜同傾。", "三月師逾整，群胡勢就烹。瘡痍親接戰，勇決冠垂成。", "妙譽期元宰，殊恩且列卿。幾時回節鉞，戮力掃欃槍。", "圭竇三千士，雲梯七十城。恥非齊說客，只似魯諸生。", "通籍微班忝，周行獨坐榮。隨肩趨漏刻，短髮寄簪纓。", "徑欲依劉表，還疑厭禰衡。漸衰那此別，忍淚獨含情。", "廢邑狐狸語，空村虎豹爭。人頻墜塗炭，公豈忘精誠。", "元帥調新律，前軍壓舊京。安邊仍扈從，莫作後功名。"]'),
('yuding-4','送楊六判官使西蕃','杜甫','唐','御定全唐诗','yuding','','[]','送遠秋風落，西征海氣寒。帝京氛祲滿，人世別離難。',144,'御定全唐詩/json/225.json','["送遠秋風落，西征海氣寒。帝京氛祲滿，人世別離難。", "絕域遙懷怒，和親願結歡。敕書憐贊普，兵甲望長安。", "宣命前程急，惟良待士寬。子雲清自守，今日起為官。", "垂淚方投筆，傷時即據鞍。儒衣山鳥怪，漢節野童看。", "邊酒排金醆，夷歌捧玉盤。草輕蕃馬健，雪重拂廬幹。", "慎爾參籌畫，從茲正羽翰。歸來權可取，九萬一朝摶。"]'),
('yuding-5','月','杜甫','唐','御定全唐诗','yuding','','[]','天上秋期近，人間月影清。入河蟾不沒，搗藥兔長生。',48,'御定全唐詩/json/225.json','["天上秋期近，人間月影清。入河蟾不沒，搗藥兔長生。", "只益丹心苦，能添白髮明。干戈知滿地，休照國西營。"]'),
('yuding-6','留別賈嚴二閣老兩院補闕','杜甫','唐','御定全唐诗','yuding','','[]','田園須暫往，戎馬惜離群。去遠留詩別，愁多任酒醺。',48,'御定全唐詩/json/225.json','["田園須暫往，戎馬惜離群。去遠留詩別，愁多任酒醺。", "一秋常苦雨，今日始無雲。山路時吹角，那堪處處聞。"]'),
('yuding-7','晚行口號','杜甫','唐','御定全唐诗','yuding','','[]','三川不可到，歸路晚山稠。落雁浮寒水，饑烏集戍樓。',48,'御定全唐詩/json/225.json','["三川不可到，歸路晚山稠。落雁浮寒水，饑烏集戍樓。", "市朝今日異，喪亂幾時休。遠愧梁江總，還家尚黑頭。"]'),
('yuding-8','獨酌成詩','杜甫','唐','御定全唐诗','yuding','','[]','燈花何太喜，酒綠正相親。醉裏從為客，詩成覺有神。',48,'御定全唐詩/json/225.json','["燈花何太喜，酒綠正相親。醉裏從為客，詩成覺有神。", "兵戈猶在眼，儒術豈謀身。共被微官縛，低頭愧野人。"]'),
('yuding-9','行次昭陵','杜甫','唐','御定全唐诗','yuding','','[]','舊俗疲庸主，群雄問獨夫。讖歸龍鳳質，威定虎狼都。',144,'御定全唐詩/json/225.json','["舊俗疲庸主，群雄問獨夫。讖歸龍鳳質，威定虎狼都。", "天屬尊堯典，神功協禹謨。風雲隨絕足，日月繼高衢。", "文物多師古，朝廷半老儒。直詞寧戮辱，賢路不崎嶇。", "往者災猶降，蒼生喘未蘇。指麾安率土，蕩滌撫洪爐。", "壯士悲陵邑，幽人拜鼎湖。玉衣晨自舉，鐵馬汗常趨。", "松柏瞻虛殿，塵沙立暝途。寂寥開國日，流恨滿山隅。"]'),
('yuding-10','重經昭陵','杜甫','唐','御定全唐诗','yuding','','[]','草昧英雄起，謳歌歷數歸。風塵三尺劍，社稷一戎衣。',72,'御定全唐詩/json/225.json','["草昧英雄起，謳歌歷數歸。風塵三尺劍，社稷一戎衣。", "翼亮貞文德，丕承戢武威。聖圖天廣大，宗祀日光輝。", "陵寢盤空曲，熊羆守翠微。再窺松柏路，還見五雲飛。"]'),
('yuding-11','喜聞官軍已臨賊境二十韻','杜甫','唐','御定全唐诗','yuding','','[]','胡虜潛京縣，官軍擁賊壕。鼎魚猶假息，穴蟻欲何逃。',240,'御定全唐詩/json/225.json','["胡虜潛京縣，官軍擁賊壕。鼎魚猶假息，穴蟻欲何逃。", "帳殿羅玄冕，轅門照白袍。秦山當警蹕，漢苑入旌旄。", "路失羊腸險，雲橫雉尾高。五原空壁壘，八水散風濤。", "今日看天意，遊魂貸爾曹。乞降那更得，尚詐莫徒勞。", "元帥歸龍種，司空握豹韜。前軍蘇武節，左將呂虔刀。", "兵氣回飛鳥，威聲沒巨鼇。戈鋋開雪色，弓矢尚秋毫。", "天步艱方盡，時和運更遭。誰雲遺毒螫，已是沃腥臊。", "睿想丹墀近，神行羽衛牢。花門騰絕漠，拓羯渡臨洮。", "此輩感恩至，羸俘何足操。鋒先衣染血，騎突劍吹毛。", "喜覺都城動，悲憐子女號。家家賣釵釧，只待獻春醪。"]'),
('yuding-12','收京三首','杜甫','唐','御定全唐诗','yuding','','[]','仙仗離丹極，妖星照玉除。須為下殿走，不可好樓居。',144,'御定全唐詩/json/225.json','["仙仗離丹極，妖星照玉除。須為下殿走，不可好樓居。", "暫屈汾陽駕，聊飛燕將書。依然七廟略，更與萬方初。", "生意甘衰白，天涯正寂寥。忽聞哀痛詔，又下聖明朝。", "羽翼懷商老，文思憶帝堯。叨逢罪己日，沾灑望青霄。", "汗馬收宮闕，春城鏟賊壕。賞應歌杕杜，歸及薦櫻桃。", "雜虜橫戈數，功臣甲第高。萬方頻送喜，無乃聖躬勞。"]'),
('yuding-13','臘日','杜甫','唐','御定全唐诗','yuding','','[]','臘日常年暖尚遙，今年臘日凍全消。侵陵雪色還萱草，',40,'御定全唐詩/json/225.json','["臘日常年暖尚遙，今年臘日凍全消。侵陵雪色還萱草，", "口脂面藥隨恩澤，翠管銀罌下九霄。"]'),
('yuding-14','紫宸殿退朝口號','杜甫','唐','御定全唐诗','yuding','','[]','戶外昭容紫袖垂，雙瞻御座引朝儀。香飄合殿春風轉，',40,'御定全唐詩/json/225.json','["戶外昭容紫袖垂，雙瞻御座引朝儀。香飄合殿春風轉，", "宮中每出歸東省，會送夔龍集鳳池。"]'),
('yuding-15','曲江二首','杜甫','唐','御定全唐诗','yuding','','[]','一片花飛減卻春，風飄萬點正愁人。且看欲盡花經眼，',80,'御定全唐詩/json/225.json','["一片花飛減卻春，風飄萬點正愁人。且看欲盡花經眼，", "細推物理須行樂，何用浮名絆此身。", "朝回日日典春衣，每日江頭盡醉歸。酒債尋常行處有，", "傳語風光共流轉，暫時相賞莫相違。"]'),
('yuding-16','曲江對酒','杜甫','唐','御定全唐诗','yuding','','[]','苑外江頭坐不歸，水精春殿轉霏微。桃花細逐楊花落，',40,'御定全唐詩/json/225.json','["苑外江頭坐不歸，水精春殿轉霏微。桃花細逐楊花落，", "吏情更覺滄洲遠，老大悲傷未拂衣。"]'),
('yuding-17','曲江對雨','杜甫','唐','御定全唐诗','yuding','','[]','城上春雲覆苑牆，江亭晚色靜年芳。林花著雨燕脂落，',40,'御定全唐詩/json/225.json','["城上春雲覆苑牆，江亭晚色靜年芳。林花著雨燕脂落，", "何時詔此金錢會，暫醉佳人錦瑟旁。"]'),
('yuding-18','奉和賈至舍人早朝大明宮','杜甫','唐','御定全唐诗','yuding','','[]','五夜漏聲催曉箭，九重春色醉仙桃。旌旗日暖龍蛇動，',40,'御定全唐詩/json/225.json','["五夜漏聲催曉箭，九重春色醉仙桃。旌旗日暖龍蛇動，", "欲知世掌絲綸美，池上於今有鳳毛。"]'),
('yuding-19','宣政殿退朝晚出左掖','杜甫','唐','御定全唐诗','yuding','','[]','天門日射黃金榜，春殿晴曛赤羽旗。宮草微微承委佩，',40,'御定全唐詩/json/225.json','["天門日射黃金榜，春殿晴曛赤羽旗。宮草微微承委佩，", "侍臣緩步歸青瑣，退食從容出每遲。"]'),
('yuding-20','題省中院壁','杜甫','唐','御定全唐诗','yuding','','[]','掖垣竹埤梧十尋，洞門對溜常陰陰。落花遊絲白日靜，',40,'御定全唐詩/json/225.json','["掖垣竹埤梧十尋，洞門對溜常陰陰。落花遊絲白日靜，", "袞職曾無一字補，許身愧比雙南金。"]'),
('yuding-21','春宿左省','杜甫','唐','御定全唐诗','yuding','','[]','花隱掖垣暮，啾啾棲鳥過。星臨萬戶動，月傍九霄多。',48,'御定全唐詩/json/225.json','["花隱掖垣暮，啾啾棲鳥過。星臨萬戶動，月傍九霄多。", "不寢聽金鑰，因風想玉珂。明朝有封事，數問夜如何。"]'),
('yuding-22','送翰林張司馬南海勒碑','杜甫','唐','御定全唐诗','yuding','','[]','冠冕通南極，文章落上臺。詔從三殿去，碑到百蠻開。',48,'御定全唐詩/json/225.json','["冠冕通南極，文章落上臺。詔從三殿去，碑到百蠻開。", "野館濃花發，春帆細雨來。不知滄海上，天遣幾時回。"]'),
('yuding-23','晚出左掖','杜甫','唐','御定全唐诗','yuding','','[]','晝刻傳呼淺，春旗簇仗齊。退朝花底散，歸院柳邊迷。',48,'御定全唐詩/json/225.json','["晝刻傳呼淺，春旗簇仗齊。退朝花底散，歸院柳邊迷。", "樓雪融城濕，宮雲去殿低。避人焚諫草，騎馬欲雞棲。"]'),
('yuding-24','曲江陪鄭八丈南史飲','杜甫','唐','御定全唐诗','yuding','','[]','雀啄江頭黃柳花，鵁鶄鸂鶒滿晴沙。自知白髮非春事，',40,'御定全唐詩/json/225.json','["雀啄江頭黃柳花，鵁鶄鸂鶒滿晴沙。自知白髮非春事，", "丈人文力猶強健，豈傍青門學種瓜。"]'),
('yuding-25','送賈閣老出汝州','杜甫','唐','御定全唐诗','yuding','','[]','西掖梧桐樹，空留一院陰。艱難歸故里，去住損春心。',48,'御定全唐詩/json/225.json','["西掖梧桐樹，空留一院陰。艱難歸故里，去住損春心。", "宮殿青門隔，雲山紫邏深。人生五馬貴，莫受二毛侵。"]'),
('yuding-26','鄭駙馬池台喜遇鄭廣文同飲','杜甫','唐','御定全唐诗','yuding','','[]','不謂生戎馬，何知共酒杯。然臍郿塢敗，握節漢臣回。',72,'御定全唐詩/json/225.json','["不謂生戎馬，何知共酒杯。然臍郿塢敗，握節漢臣回。", "白髮千莖雪，丹心一寸灰。別離經死地，披寫忽登臺。", "重對秦簫發，俱過阮宅來。留連春夜舞，淚落強裴回。"]'),
('yuding-27','送鄭十八虔貶台州司戶傷其臨老陷賊之故闕為面別情見於詩','杜甫','唐','御定全唐诗','yuding','','[]','鄭公樗散鬢成絲，酒後常稱老畫師。萬里傷心嚴譴日，',40,'御定全唐詩/json/225.json','["鄭公樗散鬢成絲，酒後常稱老畫師。萬里傷心嚴譴日，", "便與先生應永訣，九重泉路盡交期。"]'),
('yuding-28','題鄭十八著作虔','杜甫','唐','御定全唐诗','yuding','','[]','台州地闊海冥冥，雲水長和島嶼青。亂後故人雙別淚，',72,'御定全唐詩/json/225.json','["台州地闊海冥冥，雲水長和島嶼青。亂後故人雙別淚，", "第五橋東流恨水，皇陂岸北結愁亭。賈生對鵩傷王傅，", "禰衡實恐遭江夏，方朔虛傳是歲星。窮巷悄然車馬絕，"]'),
('yuding-29','端午日賜衣','杜甫','唐','御定全唐诗','yuding','','[]','宮衣亦有名，端午被恩榮。細葛含風軟，香羅疊雪輕。',48,'御定全唐詩/json/225.json','["宮衣亦有名，端午被恩榮。細葛含風軟，香羅疊雪輕。", "自天題處濕，當暑著來清。意內稱長短，終身荷聖情。"]'),
('yuding-30','贈畢四','杜甫','唐','御定全唐诗','yuding','','[]','才大今詩伯，家貧苦宦卑。饑寒奴僕賤，顏狀老翁為。',48,'御定全唐詩/json/225.json','["才大今詩伯，家貧苦宦卑。饑寒奴僕賤，顏狀老翁為。", "同調嗟誰惜，論文笑自知。流傳江鮑體，相顧免無兒。"]'),
('yuding-31','酬孟雲卿','杜甫','唐','御定全唐诗','yuding','','[]','樂極傷頭白，更長愛燭紅。相逢難袞袞，告別莫匆匆。',48,'御定全唐詩/json/225.json','["樂極傷頭白，更長愛燭紅。相逢難袞袞，告別莫匆匆。", "但恐天河落，寧辭酒盞空。明朝牽世務，揮淚各西東。"]'),
('yuding-32','奉贈王中允','杜甫','唐','御定全唐诗','yuding','','[]','中允聲名久，如今契闊深。共傳收庾信，不比得陳琳。',48,'御定全唐詩/json/225.json','["中允聲名久，如今契闊深。共傳收庾信，不比得陳琳。", "一病緣明主，三年獨此心。窮愁應有作，試誦白頭吟。"]'),
('yuding-33','奉陪鄭駙馬韋曲二首','杜甫','唐','御定全唐诗','yuding','','[]','韋曲花無賴，家家惱殺人。綠尊雖盡日，白髮好禁春。',96,'御定全唐詩/json/225.json','["韋曲花無賴，家家惱殺人。綠尊雖盡日，白髮好禁春。", "石角鉤衣破，藤枝刺眼新。何時占叢竹，頭戴小烏巾。", "野寺垂楊裏，春畦亂水間。美花多映竹，好鳥不歸山。", "城郭終何事，風塵豈駐顏。誰能共公子，薄暮欲俱還。"]'),
('yuding-34','奉答岑參補闕見贈','杜甫','唐','御定全唐诗','yuding','','[]','窈窕清禁闥，罷朝歸不同。君隨丞相後，我往日華東。',48,'御定全唐詩/json/225.json','["窈窕清禁闥，罷朝歸不同。君隨丞相後，我往日華東。", "冉冉柳枝碧，娟娟花蕊紅。故人得佳句，獨贈白頭翁。"]'),
('yuding-35','送許八拾遺歸江寧覲省甫昔時嘗客遊此縣於許生處乞瓦棺寺維摩圖樣志諸篇末','杜甫','唐','御定全唐诗','yuding','','[]','詔許辭中禁，慈顏赴北堂。聖朝新孝理，祖席倍輝光。',96,'御定全唐詩/json/225.json','["詔許辭中禁，慈顏赴北堂。聖朝新孝理，祖席倍輝光。", "內帛擎偏重，宮衣著更香。淮陰清夜驛，京口渡江航。", "春隔雞人晝，秋期燕子涼。賜書誇父老，壽酒樂城隍。", "看畫曾饑渴，追蹤恨淼茫。虎頭金粟影，神妙獨難忘。"]'),
('yuding-36','因許八奉寄江甯旻上人','杜甫','唐','御定全唐诗','yuding','','[]','不見旻公三十年，封書寄與淚潺湲。舊來好事今能否，',40,'御定全唐詩/json/225.json','["不見旻公三十年，封書寄與淚潺湲。舊來好事今能否，", "聞君話我為官在，頭白昏昏只醉眠。"]'),
('yuding-37','至德二載甫自京金光門出問道歸鳳翔乾元初從左拾遺移華州掾與親故別因出此門有悲往事','杜甫','唐','御定全唐诗','yuding','','[]','此道昔歸順，西郊胡正繁。至今殘破膽，應有未招魂。',48,'御定全唐詩/json/225.json','["此道昔歸順，西郊胡正繁。至今殘破膽，應有未招魂。", "近得歸京邑，移官豈至尊。無才日衰老，駐馬望千門。"]'),
('yuding-38','寄高三十五詹事','杜甫','唐','御定全唐诗','yuding','','[]','安穩高詹事，兵戈久索居。時來如宦達，歲晚莫情疏。',48,'御定全唐詩/json/225.json','["安穩高詹事，兵戈久索居。時來如宦達，歲晚莫情疏。", "天上多鴻雁，池中足鯉魚。相看過半百，不寄一行書。"]'),
('yuding-39','路逢襄陽楊少府入城，戲呈楊員外綰','杜甫','唐','御定全唐诗','yuding','','[]','寄語楊員外，山寒少茯苓。歸來稍暄暖，當為劚青冥。',48,'御定全唐詩/json/225.json','["寄語楊員外，山寒少茯苓。歸來稍暄暖，當為劚青冥。", "翻動神仙窟，封題鳥獸形。兼將老藤杖，扶汝醉初醒。"]'),
('yuding-40','題鄭縣亭子','杜甫','唐','御定全唐诗','yuding','','[]','鄭縣亭子澗之濱，戶牖憑高發興新。雲斷岳蓮臨大路，',40,'御定全唐詩/json/225.json','["鄭縣亭子澗之濱，戶牖憑高發興新。雲斷岳蓮臨大路，", "更欲題詩滿青竹，晚來幽獨恐傷神。"]'),
('yuding-41','早秋苦熱，堆案相仍','杜甫','唐','御定全唐诗','yuding','','[]','七月六日苦炎熱，對食暫餐還不能。每愁夜中自足蠍，',40,'御定全唐詩/json/225.json','["七月六日苦炎熱，對食暫餐還不能。每愁夜中自足蠍，", "南望青松架短壑，安得赤腳蹋層冰。"]'),
('yuding-42','望岳','杜甫','唐','御定全唐诗','yuding','','[]','西嶽崚嶒竦處尊，諸峰羅立如兒孫。安得仙人九節杖，',40,'御定全唐詩/json/225.json','["西嶽崚嶒竦處尊，諸峰羅立如兒孫。安得仙人九節杖，", "稍待西風涼冷後，高尋白帝問真源。"]'),
('yuding-43','至日遣興，奉寄北省舊閣老兩院故人二首','杜甫','唐','御定全唐诗','yuding','','[]','去歲茲辰捧禦床，五更三點入鵷行。欲知趨走傷心地，',80,'御定全唐詩/json/225.json','["去歲茲辰捧禦床，五更三點入鵷行。欲知趨走傷心地，", "何人錯憶窮愁日，愁日愁隨一線長。", "憶昨逍遙供奉班，去年今日侍龍顏。麒麟不動爐煙上，", "孤城此日堪腸斷，愁對寒雲雪滿山。"]'),
('yuding-44','得弟消息二首','杜甫','唐','御定全唐诗','yuding','','[]','近有平陰信，遙憐舍弟存。側身千里道，寄食一家村。',96,'御定全唐詩/json/225.json','["近有平陰信，遙憐舍弟存。側身千里道，寄食一家村。", "烽舉新酣戰，啼垂舊血痕。不知臨老日，招得幾人魂。", "汝懦歸無計，吾衰往未期。浪傳烏鵲喜，深負鶺鴒詩。", "生理何顏面，憂端且歲時。兩京三十口，雖在命如絲。"]'),
('yuding-45','憶弟二首','杜甫','唐','御定全唐诗','yuding','','[]','喪亂聞吾弟，饑寒傍濟州。人稀吾不到，兵在見何由。',96,'御定全唐詩/json/225.json','["喪亂聞吾弟，饑寒傍濟州。人稀吾不到，兵在見何由。", "憶昨狂催走，無時病去憂。即今千種恨，惟共水東流。", "且喜河南定，不問鄴城圍。百戰今誰在，三年望汝歸。", "故園花自發，春日鳥還飛。斷絕人煙久，東西消息稀。"]'),
('yuding-46','得舍弟消息','杜甫','唐','御定全唐诗','yuding','','[]','亂後誰歸得，他鄉勝故鄉。直為心厄苦，久念與存亡。',48,'御定全唐詩/json/225.json','["亂後誰歸得，他鄉勝故鄉。直為心厄苦，久念與存亡。", "汝書猶在壁，汝妾已辭房。舊犬知愁恨，垂頭傍我床。"]'),
('yuding-47','秦州雜詩二十首','杜甫','唐','御定全唐诗','yuding','','[]','滿目悲生事，因人作遠遊。遲回度隴怯，浩蕩及關愁。',576,'御定全唐詩/json/225.json','["滿目悲生事，因人作遠遊。遲回度隴怯，浩蕩及關愁。", "水落魚龍夜，山空鳥鼠秋。西征問烽火，心折此淹留。", "秦州山北寺，勝跡隗囂宮。苔蘚山門古，丹青野殿空。", "月明垂葉露，雲逐渡溪風。清渭無情極，愁時獨向東。", "州圖領同穀，驛道出流沙。降虜兼千帳，居人有萬家。", "馬驕珠汗落，胡舞白蹄斜。年少臨洮子，西來亦自誇。", "鼓角緣邊郡，川原欲夜時。秋聽殷地發，風散入雲悲。", "抱葉寒蟬靜，歸來獨鳥遲。萬方聲一概，吾道竟何之。", "南使宜天馬，由來萬匹強。浮雲連陣沒，秋草遍山長。", "聞說真龍種，仍殘老驌驦。哀鳴思戰鬥，迥立向蒼蒼。", "城上胡笳奏，山邊漢節歸。防河赴滄海，奉詔發金微。", "士苦形骸黑，旌疏鳥獸稀。那聞往來戍，恨解鄴城圍。", "莽莽萬重山，孤城山谷間。無風雲出塞，不夜月臨關。", "屬國歸何晚，樓蘭斬未還。煙塵獨長望，衰颯正摧顏。", "聞道尋源使，從天此路回。牽牛去幾許，宛馬至今來。", "一望幽燕隔，何時郡國開。東征健兒盡，羌笛暮吹哀。", "今日明人眼，臨池好驛亭。叢篁低地碧，高柳半天青。", "稠疊多幽事，喧呼閱使星。老夫如有此，不異在郊坰。", "雲氣接昆侖，涔涔塞雨繁。羌童看渭水，使客向河源。", "煙火軍中幕，牛羊嶺上村。所居秋草淨，正閉小蓬門。", "蕭蕭古塞冷，漠漠秋雲低。黃鵠翅垂雨，蒼鷹饑啄泥。", "薊門誰自北，漢將獨征西。不意書生耳，臨衰厭鼓鼙。", "山頭南郭寺，水號北流泉。老樹空庭得，清渠一邑傳。", "秋花危石底，晚景臥鐘邊。俯仰悲身世，溪風為颯然。"]'),
('yuding-48','月夜憶舍弟','杜甫','唐','御定全唐诗','yuding','','[]','戍鼓斷人行，秋邊一雁聲。露從今夜白，月是故鄉明。',48,'御定全唐詩/json/225.json','["戍鼓斷人行，秋邊一雁聲。露從今夜白，月是故鄉明。", "有弟皆分散，無家問死生。寄書長不避，況乃未休兵。"]'),
('yuding-49','宿贊公房','杜甫','唐','御定全唐诗','yuding','','[]','杖錫何來此，秋風已颯然。雨荒深院菊，霜倒半池蓮。',48,'御定全唐詩/json/225.json','["杖錫何來此，秋風已颯然。雨荒深院菊，霜倒半池蓮。", "放逐寧違性，虛空不離禪。相逢成夜宿，隴月向人圓。"]'),
('yuding-50','東樓','杜甫','唐','御定全唐诗','yuding','','[]','萬里流沙道，西征過北門。但添新戰骨，不返舊征魂。',48,'御定全唐詩/json/225.json','["萬里流沙道，西征過北門。但添新戰骨，不返舊征魂。", "樓角臨風迥，城陰帶水昏。傳聲看驛使，送節向河源。"]'),
('yuding-51','雨晴','杜甫','唐','御定全唐诗','yuding','','[]','天水秋雲薄，從西萬里風。今朝好晴景，久雨不妨農。',48,'御定全唐詩/json/225.json','["天水秋雲薄，從西萬里風。今朝好晴景，久雨不妨農。", "塞柳行疏翠，山梨結小紅。胡笳樓上發，一雁入高空。"]'),
('yuding-52','寓目','杜甫','唐','御定全唐诗','yuding','','[]','一縣蒲萄熟，秋山苜蓿多。關雲常帶雨，塞水不成河。',48,'御定全唐詩/json/225.json','["一縣蒲萄熟，秋山苜蓿多。關雲常帶雨，塞水不成河。", "羌女輕烽燧，胡兒制駱駝。自傷遲暮眼，喪亂飽經過。"]'),
('yuding-53','山寺','杜甫','唐','御定全唐诗','yuding','','[]','野寺殘僧少，山園細路高。麝香眠石竹，鸚鵡啄金桃。',48,'御定全唐詩/json/225.json','["野寺殘僧少，山園細路高。麝香眠石竹，鸚鵡啄金桃。", "亂石通人過，懸崖置屋牢。上方重閣晚，百里見秋毫。"]'),
('yuding-54','即事','杜甫','唐','御定全唐诗','yuding','','[]','聞道花門破，和親事卻非。人憐漢公主，生得渡河歸。',48,'御定全唐詩/json/225.json','["聞道花門破，和親事卻非。人憐漢公主，生得渡河歸。", "秋思拋雲髻，腰支勝寶衣。群凶猶索戰，回首意多違。"]'),
('yuding-55','遣懷','杜甫','唐','御定全唐诗','yuding','','[]','愁眼看霜露，寒城菊自花。天風隨斷柳，客淚墮清笳。',48,'御定全唐詩/json/225.json','["愁眼看霜露，寒城菊自花。天風隨斷柳，客淚墮清笳。", "水淨樓陰直，山昏塞日斜。夜來歸鳥盡，啼殺後棲鴉。"]'),
('yuding-56','天河','杜甫','唐','御定全唐诗','yuding','','[]','常時任顯晦，秋至輒分明。縱被微雲掩，終能永夜清。',48,'御定全唐詩/json/225.json','["常時任顯晦，秋至輒分明。縱被微雲掩，終能永夜清。", "含星動雙闕，伴月照邊城。牛女年年渡，何曾風浪生。"]'),
('yuding-57','初月','杜甫','唐','御定全唐诗','yuding','','[]','光細弦豈上，影斜輪未安。微升古塞外，已隱暮雲端。',48,'御定全唐詩/json/225.json','["光細弦豈上，影斜輪未安。微升古塞外，已隱暮雲端。", "河漢不改色，關山空自寒。庭前有白露，暗滿菊花團。"]'),
('yuding-58','歸燕','杜甫','唐','御定全唐诗','yuding','','[]','不獨避霜雪，其如儔侶稀。四時無失序，八月自知歸。',48,'御定全唐詩/json/225.json','["不獨避霜雪，其如儔侶稀。四時無失序，八月自知歸。", "春色豈相訪，眾雛還識機。故巢儻未毀，會傍主人飛。"]'),
('yuding-59','擣衣','杜甫','唐','御定全唐诗','yuding','','[]','亦知戍不返，秋至拭清砧。已近苦寒月，況經長別心。',48,'御定全唐詩/json/225.json','["亦知戍不返，秋至拭清砧。已近苦寒月，況經長別心。", "寧辭搗熨倦，一寄塞垣深。用盡閨中力，君聽空外音。"]'),
('yuding-60','促織','杜甫','唐','御定全唐诗','yuding','','[]','促織甚微細，哀音何動人。草根吟不穩，床下夜相親。',48,'御定全唐詩/json/225.json','["促織甚微細，哀音何動人。草根吟不穩，床下夜相親。", "久客得無淚，放妻難及晨。悲絲與急管，感激異天真。"]'),
('yuding-61','螢火','杜甫','唐','御定全唐诗','yuding','','[]','幸因腐草出，敢近太陽飛。未足臨書卷，時能點客衣。',48,'御定全唐詩/json/225.json','["幸因腐草出，敢近太陽飛。未足臨書卷，時能點客衣。", "隨風隔幔小，帶雨傍林微。十月清霜重，飄零何處歸。"]'),
('yuding-62','蒹葭','杜甫','唐','御定全唐诗','yuding','','[]','摧折不自守，秋風吹若何。暫時花戴雪，幾處葉沉波。',48,'御定全唐詩/json/225.json','["摧折不自守，秋風吹若何。暫時花戴雪，幾處葉沉波。", "體弱春風早，叢長夜露多。江湖後搖落，亦恐歲蹉跎。"]'),
('yuding-63','苦竹','杜甫','唐','御定全唐诗','yuding','','[]','青冥亦自守，軟弱強扶持。味苦夏蟲避，叢卑春鳥疑。',48,'御定全唐詩/json/225.json','["青冥亦自守，軟弱強扶持。味苦夏蟲避，叢卑春鳥疑。", "軒墀曾不重，翦伐欲無辭。幸近幽人屋，霜根結在茲。"]'),
('yuding-64','除架','杜甫','唐','御定全唐诗','yuding','','[]','束薪已零落，瓠葉轉蕭疏。幸結白花了，寧辭青蔓除。',48,'御定全唐詩/json/225.json','["束薪已零落，瓠葉轉蕭疏。幸結白花了，寧辭青蔓除。", "秋蟲聲不去，暮雀意何如。寒事今牢落，人生亦有初。"]'),
('yuding-65','廢畦','杜甫','唐','御定全唐诗','yuding','','[]','秋蔬擁霜露，豈敢惜凋殘。暮景數枝葉，天風吹汝寒。',48,'御定全唐詩/json/225.json','["秋蔬擁霜露，豈敢惜凋殘。暮景數枝葉，天風吹汝寒。", "綠沾泥滓盡，香與歲時闌。生意春如昨，悲君白玉盤。"]'),
('yuding-66','夕烽','杜甫','唐','御定全唐诗','yuding','','[]','夕烽來不近，每日報平安。塞上傳光小，雲邊落點殘。',48,'御定全唐詩/json/225.json','["夕烽來不近，每日報平安。塞上傳光小，雲邊落點殘。", "照秦通警急，過隴自艱難。聞道蓬萊殿，千門立馬看。"]'),
('yuding-67','秋笛','杜甫','唐','御定全唐诗','yuding','','[]','清商欲盡奏，奏苦血沾衣。他日傷心極，征人白骨歸。',48,'御定全唐詩/json/225.json','["清商欲盡奏，奏苦血沾衣。他日傷心極，征人白骨歸。", "相逢恐恨過，故作發聲微。不見秋雲動，悲風稍稍飛。"]'),
('yuding-68','送遠','杜甫','唐','御定全唐诗','yuding','','[]','帶甲滿天地，胡為君遠行。親朋盡一哭，鞍馬去孤城。',48,'御定全唐詩/json/225.json','["帶甲滿天地，胡為君遠行。親朋盡一哭，鞍馬去孤城。", "草木歲月晚，關河霜雪清。別離已昨日，因見古人情。"]'),
('yuding-69','觀兵','杜甫','唐','御定全唐诗','yuding','','[]','北庭送壯士，貔虎數尤多。精銳舊無敵，邊隅今若何。',48,'御定全唐詩/json/225.json','["北庭送壯士，貔虎數尤多。精銳舊無敵，邊隅今若何。", "妖氛擁白馬，元帥待雕戈。莫守鄴城下，斬鯨遼海波。"]'),
('yuding-70','不歸','杜甫','唐','御定全唐诗','yuding','','[]','河間尚征伐，汝骨在空城。從弟人皆有，終身恨不平。',48,'御定全唐詩/json/225.json','["河間尚征伐，汝骨在空城。從弟人皆有，終身恨不平。", "數金憐俊邁，總角愛聰明。面上三年土，春風草又生。"]'),
('yuding-71','天末懷李白','杜甫','唐','御定全唐诗','yuding','','[]','涼風起天末，君子意如何。鴻雁幾時到，江湖秋水多。',48,'御定全唐詩/json/225.json','["涼風起天末，君子意如何。鴻雁幾時到，江湖秋水多。", "文章憎命達，魑魅喜人過。應共冤魂語，投詩贈汨羅。"]'),
('yuding-72','獨立','杜甫','唐','御定全唐诗','yuding','','[]','空外一鷙鳥，河間雙白鷗。飄颻搏擊便，容易往來遊。',48,'御定全唐詩/json/225.json','["空外一鷙鳥，河間雙白鷗。飄颻搏擊便，容易往來遊。", "草露亦多濕，蛛絲仍未收。天機近人事，獨立萬端憂。"]'),
('yuding-73','日暮','杜甫','唐','御定全唐诗','yuding','','[]','日落風亦起，城頭鳥尾訛。黃雲高未動，白水已揚波。',48,'御定全唐詩/json/225.json','["日落風亦起，城頭鳥尾訛。黃雲高未動，白水已揚波。", "羌婦語還哭，胡兒行且歌。將軍別換馬，夜出擁雕戈。"]'),
('yuding-74','空囊','杜甫','唐','御定全唐诗','yuding','','[]','翠柏苦猶食，晨霞高可餐。世人共鹵莽，吾道屬艱難。',48,'御定全唐詩/json/225.json','["翠柏苦猶食，晨霞高可餐。世人共鹵莽，吾道屬艱難。", "不爨井晨凍，無衣床夜寒。囊空恐羞澀，留得一錢看。"]'),
('yuding-75','病馬','杜甫','唐','御定全唐诗','yuding','','[]','乘爾亦已久，天寒關塞深。塵中老盡力，歲晚病傷心。',48,'御定全唐詩/json/225.json','["乘爾亦已久，天寒關塞深。塵中老盡力，歲晚病傷心。", "毛骨豈殊眾，馴良猶至今。物微意不淺，感動一沉吟。"]'),
('yuding-76','蕃劍','杜甫','唐','御定全唐诗','yuding','','[]','致此自僻遠，又非珠玉裝。如何有奇怪，每夜吐光芒。',48,'御定全唐詩/json/225.json','["致此自僻遠，又非珠玉裝。如何有奇怪，每夜吐光芒。", "虎氣必騰踔，龍身甯久藏。風塵苦未息，持汝奉明王。"]'),
('yuding-77','銅瓶','杜甫','唐','御定全唐诗','yuding','','[]','亂後碧井廢，時清瑤殿深。銅瓶未失水，百丈有哀音。',48,'御定全唐詩/json/225.json','["亂後碧井廢，時清瑤殿深。銅瓶未失水，百丈有哀音。", "側想美人意，應非寒甃沉。蛟龍半缺落，猶得折黃金。"]'),
('yuding-78','觀安西兵過赴關中待命二首','杜甫','唐','御定全唐诗','yuding','','[]','四鎮富精銳，摧鋒皆絕倫。還聞獻士卒，足以靜風塵。',96,'御定全唐詩/json/225.json','["四鎮富精銳，摧鋒皆絕倫。還聞獻士卒，足以靜風塵。", "老馬夜知道，蒼鷹饑著人。臨危經久戰，用急始如神。", "奇兵不在眾，萬馬救中原。談笑無河北，心肝奉至尊。", "孤雲隨殺氣，飛鳥避轅門。竟日留歡樂，城池未覺喧。"]'),
('yuding-79','送人從軍','杜甫','唐','御定全唐诗','yuding','','[]','弱水應無地，陽關已近天。今君渡沙磧，累月斷人煙。',48,'御定全唐詩/json/225.json','["弱水應無地，陽關已近天。今君渡沙磧，累月斷人煙。", "好武寧論命，封侯不計年。馬寒防失道，雪沒錦鞍韉。"]'),
('yuding-80','野望','杜甫','唐','御定全唐诗','yuding','','[]','清秋望不極，迢遞起曾陰。遠水兼天淨，孤城隱霧深。',48,'御定全唐詩/json/225.json','["清秋望不極，迢遞起曾陰。遠水兼天淨，孤城隱霧深。", "葉稀風更落，山迥日初沈。獨鶴歸何晚，昏鴉已滿林。"]'),
('yuding-81','示侄佐','杜甫','唐','御定全唐诗','yuding','','[]','多病秋風落，君來慰眼前。自聞茅屋趣，只想竹林眠。',48,'御定全唐詩/json/225.json','["多病秋風落，君來慰眼前。自聞茅屋趣，只想竹林眠。", "滿穀山雲起，侵籬澗水懸。嗣宗諸子侄，早覺仲容賢。"]'),
('yuding-82','佐還山后寄三首','杜甫','唐','御定全唐诗','yuding','','[]','山晚浮雲合，歸時恐路迷。澗寒人欲到，村黑鳥應棲。',144,'御定全唐詩/json/225.json','["山晚浮雲合，歸時恐路迷。澗寒人欲到，村黑鳥應棲。", "野客茅茨小，田家樹木低。舊諳疏懶叔，須汝故相攜。", "白露黃粱熟，分張素有期。已應舂得細，頗覺寄來遲。", "味豈同金菊，香宜配綠葵。老人他日愛，正想滑流匙。", "幾道泉澆圃，交橫落慢坡。葳蕤秋葉少，隱映野雲多。", "隔沼連香芰，通林帶女蘿。甚聞霜薤白，重惠意如何。"]'),
('yuding-83','從人覓小胡孫許寄','杜甫','唐','御定全唐诗','yuding','','[]','人說南州路，山猿樹樹懸。舉家聞若駭，為寄小如拳。',48,'御定全唐詩/json/225.json','["人說南州路，山猿樹樹懸。舉家聞若駭，為寄小如拳。", "預哂愁胡面，初調見馬鞭。許求聰慧者，童稚捧應癲。"]'),
('yuding-84','秋日阮隱居致薤三十束','杜甫','唐','御定全唐诗','yuding','','[]','隱者柴門內，畦蔬繞舍秋。盈筐承露薤，不待致書求。',48,'御定全唐詩/json/225.json','["隱者柴門內，畦蔬繞舍秋。盈筐承露薤，不待致書求。", "束比青芻色，圓齊玉箸頭。衰年關鬲冷，味暖並無憂。"]'),
('yuding-85','秦州見敕目薛三璩授司議郎畢四曜除監察與二子有故遠喜遷官兼述索居凡三十韻','杜甫','唐','御定全唐诗','yuding','','[]','大雅何寥闊，斯人尚典刑。交期餘潦倒，材力爾精靈。',360,'御定全唐詩/json/225.json','["大雅何寥闊，斯人尚典刑。交期餘潦倒，材力爾精靈。", "二子聲同日，諸生困一經。文章開穾奧，遷擢潤朝廷。", "舊好何由展，新詩更憶聽。別來頭並白，相見眼終青。", "伊昔貧皆甚，同憂心不寧。棲遑分半菽，浩蕩逐流萍。", "俗態猶猜忌，妖氛忽杳冥。獨慚投漢閣，俱議哭秦庭。", "還蜀只無補，囚梁亦固扃。華夷相混合，宇宙一膻腥。", "帝力收三統，天威總四溟。舊都俄望幸，清廟肅惟馨。", "雜種雖高壘，長驅甚建瓴。焚香淑景殿，漲水望雲亭。", "法駕初還日，群公若會星。宮臣仍點染，柱史正零丁。", "官忝趨棲鳳，朝回歎聚螢。喚人看騕褭，不嫁惜娉婷。", "掘劍知埋獄，提刀見發硎。侏儒應共飽，漁父忌偏醒。", "旅泊窮清渭，長吟望濁涇。羽書還似急，烽火未全停。", "師老資殘寇，戎生及近坰。忠臣辭憤激，烈士涕飄零。", "上將盈邊鄙，元勳溢鼎銘。仰思調玉燭，誰定握青萍。", "隴俗輕鸚鵡，原情類鶺鴒。秋風動關塞，高臥想儀形。"]'),
('yuding-86','寄彭州高三十五使君適、虢州岑二十七長史參三十韻','杜甫','唐','御定全唐诗','yuding','','[]','故人何寂寞，今我獨淒涼。老去才難盡，秋來興甚長。',360,'御定全唐詩/json/225.json','["故人何寂寞，今我獨淒涼。老去才難盡，秋來興甚長。", "物情尤可見，辭客未能忘。海內知名士，雲端各異方。", "高岑殊緩步，沈鮑得同行。意愜關飛動，篇終接混茫。", "舉天悲富駱，近代惜盧王。似爾官仍貴，前賢命可傷。", "諸侯非棄擲，半刺已翱翔。詩好幾時見，書成無信將。", "男兒行處是，客子鬥身強。羈旅推賢聖，沈綿抵咎殃。", "三年猶瘧疾，一鬼不銷亡。隔日搜脂髓，增寒抱雪霜。", "徒然潛隙地，有靦屢鮮妝。何太龍鍾極，於今出處妨。", "無錢居帝裏，盡室在邊疆。劉表雖遺恨，龐公至死藏。", "心微傍魚鳥，肉瘦怯豺狼。隴草蕭蕭白，洮雲片片黃。", "彭門劍閣外，虢略鼎湖旁。荊玉簪頭冷，巴箋染翰光。", "烏麻蒸續曬，丹橘露應嘗。豈異神仙宅，俱兼山水鄉。", "竹齋燒藥灶，花嶼讀書床。更得清新否，遙知對屬忙。", "舊官寧改漢，淳俗本歸唐。濟世宜公等，安貧亦士常。", "蚩尤終戮辱，胡羯漫倡狂。會待襖氛靜，論文暫裹糧。"]'),
('yuding-87','寄岳州賈司馬六丈、巴州嚴八使君兩閣老五十韻','杜甫','唐','御定全唐诗','yuding','','[]','衡嶽啼猿裏，巴州鳥道邊。故人俱不利，謫宦兩悠然。',576,'御定全唐詩/json/225.json','["衡嶽啼猿裏，巴州鳥道邊。故人俱不利，謫宦兩悠然。", "開闢乾坤正，榮枯雨露偏。長沙才子遠，釣瀨客星懸。", "憶昨趨行殿，殷憂捧禦筵。討胡愁李廣，奉使待張騫。", "無複雲台仗，虛修水戰船。蒼茫城七十，流落劍三千。", "畫角吹秦晉，旄頭俯澗瀍。小儒輕董卓，有識笑苻堅。", "浪作禽填海，那將血射天。萬方思助順，一鼓氣無前。", "陰散陳倉北，晴熏太白巔。亂麻屍積衛，破竹勢臨燕。", "法駕還雙闕，王師下八川。此時沾奉引，佳氣拂周旋。", "貔虎開金甲，麒麟受玉鞭。侍臣諳入仗，廄馬解登仙。", "花動朱樓雪，城凝碧樹煙。衣冠心慘愴，故老淚潺湲。", "哭廟悲風急，朝正霽景鮮。月分梁漢米，春得水衡錢。", "內蕊繁于纈，宮莎軟勝綿。恩榮同拜手，出入最隨肩。", "晚著華堂醉，寒重繡被眠。轡齊兼秉燭，書枉滿懷箋。", "每覺升元輔，深期列大賢。秉鈞方咫尺，鎩翮再聯翩。", "禁掖朋從改，微班性命全。青蒲甘受戮，白髮竟誰憐。", "弟子貧原憲，諸生老伏虔。師資謙未達，鄉党敬何先。", "舊好腸堪斷，新愁眼欲穿。翠幹危棧竹，紅膩小湖蓮。", "賈筆論孤憤，嚴詩賦幾篇。定知深意苦，莫使眾人傳。", "貝錦無停織，朱絲有斷弦。浦鷗防碎首，霜鶻不空拳。", "地僻昏炎瘴，山稠隘石泉。且將棋度日，應用酒為年。", "典郡終微眇，治中實棄捐。安排求傲吏，比興展歸田。", "去去才難得，蒼蒼理又玄。古人稱逝矣，吾道蔔終焉。", "隴外翻投跡，漁陽複控弦。笑為妻子累，甘與歲時遷。", "親故行稀少，兵戈動接聯。他鄉饒夢寐，失侶自屯邅。"]'),
('yuding-88','寄張十二山人彪三十韻','杜甫','唐','御定全唐诗','yuding','','[]','獨臥嵩陽客，三違潁水春。艱難隨老母，慘澹向時人。',360,'御定全唐詩/json/225.json','["獨臥嵩陽客，三違潁水春。艱難隨老母，慘澹向時人。", "謝氏尋山屐，陶公漉酒巾。群凶彌宇宙，此物在風塵。", "曆下辭姜被，關西得孟鄰。早通交契密，晚接道流新。", "靜者心多妙，先生藝絕倫。草書何太苦，詩興不無神。", "曹植休前輩，張芝更後身。數篇吟可老，一字買堪貧。", "將恐曾防寇，深潛托所親。甯聞倚門夕，盡力潔飧晨。", "疏懶為名誤，驅馳喪我真。索居猶寂寞，相遇益悲辛。", "流轉依邊徼，逢迎念席珍。時來故舊少，亂後別離頻。", "世祖修高廟，文公賞從臣。商山猶入楚，源水不離秦。", "存想青龍秘，騎行白鹿馴。耕岩非穀口，結草即河濱。", "肘後符應驗，囊中藥未陳。旅懷殊不愜，良覿渺無因。", "自古皆悲恨，浮生有屈伸。此邦今尚武，何處且依仁。", "鼓角淩天籟，關山信月輪。官場羅鎮磧，賊火近洮岷。", "蕭索論兵地，蒼茫鬥將辰。大軍多處所，餘孽尚紛綸。", "高興知籠鳥，斯文起獲麟。窮秋正搖落，回首望松筠。"]'),
('yuding-89','寄李十二白二十韻','杜甫','唐','御定全唐诗','yuding','','[]','昔年有狂客，號爾謫仙人。筆落驚風雨，詩成泣鬼神。',240,'御定全唐詩/json/225.json','["昔年有狂客，號爾謫仙人。筆落驚風雨，詩成泣鬼神。", "聲名從此大，汩沒一朝伸。文彩承殊渥，流傳必絕倫。", "龍舟移棹晚，獸錦奪袍新。白日來深殿，青雲滿後塵。", "乞歸優詔許，遇我宿心親。未負幽棲志，兼全寵辱身。", "劇談憐野逸，嗜酒見天真。醉舞梁園夜，行歌泗水春。", "才高心不展，道屈善無鄰。處士禰衡俊，諸生原憲貧。", "稻粱求未足，薏苡謗何頻。五嶺炎蒸地，三危放逐臣。", "幾年遭鵩鳥，獨泣向麒麟。蘇武先還漢，黃公豈事秦。", "楚筵辭醴日，梁獄上書辰。已用當時法，誰將此義陳。", "老吟秋月下，病起暮江濱。莫怪恩波隔，乘槎與問津。"]'),
('yuding-0','蜀相','杜甫','唐','御定全唐诗','yuding','','[]','丞相祠堂何處尋，錦官城外柏森森。映階碧草自春色，',40,'御定全唐詩/json/226.json','["丞相祠堂何處尋，錦官城外柏森森。映階碧草自春色，", "出師未捷身先死，長使英雄淚滿襟。"]'),
('yuding-1','卜居','杜甫','唐','御定全唐诗','yuding','','[]','浣花流水水西頭，主人為卜林塘幽。已知出郭少塵事，',40,'御定全唐詩/json/226.json','["浣花流水水西頭，主人為卜林塘幽。已知出郭少塵事，", "東行萬里堪乘興，須向山陰上小舟。"]'),
('yuding-2','一室','杜甫','唐','御定全唐诗','yuding','','[]','一室他鄉遠，空林暮景懸。正愁聞塞笛，獨立見江船。',48,'御定全唐詩/json/226.json','["一室他鄉遠，空林暮景懸。正愁聞塞笛，獨立見江船。", "巴蜀來多病，荊蠻去幾年。應同王粲宅，留井峴山前。"]'),
('yuding-3','梅雨','杜甫','唐','御定全唐诗','yuding','','[]','南京西浦道，四月熟黃梅。湛湛長江去，冥冥細雨來。',48,'御定全唐詩/json/226.json','["南京西浦道，四月熟黃梅。湛湛長江去，冥冥細雨來。", "茅茨疏易濕，雲霧密難開。竟日蛟龍喜，盤渦與岸回。"]'),
('yuding-4','為農','杜甫','唐','御定全唐诗','yuding','','[]','錦裏煙塵外，江村八九家。圓荷浮小葉，細麥落輕花。',48,'御定全唐詩/json/226.json','["錦裏煙塵外，江村八九家。圓荷浮小葉，細麥落輕花。", "卜宅從茲老，為農去國賒。遠慚句漏令，不得問丹砂。"]'),
('yuding-5','有客','杜甫','唐','御定全唐诗','yuding','','[]','幽棲地僻經過少，老病人扶再拜難。豈有文章驚海內，',40,'御定全唐詩/json/226.json','["幽棲地僻經過少，老病人扶再拜難。豈有文章驚海內，", "不嫌野外無供給，乘興還來看藥欄。"]'),
('yuding-6','狂夫','杜甫','唐','御定全唐诗','yuding','','[]','萬里橋西一草堂，百花潭水即滄浪。風含翠筱娟娟靜，',40,'御定全唐詩/json/226.json','["萬里橋西一草堂，百花潭水即滄浪。風含翠筱娟娟靜，", "欲填溝壑唯疏放，自笑狂夫老更狂。"]'),
('yuding-7','賓至','杜甫','唐','御定全唐诗','yuding','','[]','患氣經時久，臨江卜宅新。喧卑方避俗，疏快頗宜人。',48,'御定全唐詩/json/226.json','["患氣經時久，臨江卜宅新。喧卑方避俗，疏快頗宜人。", "有客過茅宇，呼兒正葛巾。自鋤稀菜甲，小摘為情親。"]'),
('yuding-8','王十五司馬弟出郭相訪，兼遺營茅屋貲','杜甫','唐','御定全唐诗','yuding','','[]','客裏何遷次，江邊正寂寥。肯來尋一老，愁破是今朝。',48,'御定全唐詩/json/226.json','["客裏何遷次，江邊正寂寥。肯來尋一老，愁破是今朝。", "憂我營茅棟，攜錢過野橋。他鄉唯表弟，還往莫辭遙。"]'),
('yuding-9','堂成','杜甫','唐','御定全唐诗','yuding','','[]','背郭堂成蔭白茅，緣江路熟俯青郊。榿林礙日吟風葉，',40,'御定全唐詩/json/226.json','["背郭堂成蔭白茅，緣江路熟俯青郊。榿林礙日吟風葉，", "旁人錯比揚雄宅，懶惰無心作解嘲。"]'),
('yuding-10','田舍','杜甫','唐','御定全唐诗','yuding','','[]','田舍清江曲，柴門古道旁。草深迷市井，地僻懶衣裳。',48,'御定全唐詩/json/226.json','["田舍清江曲，柴門古道旁。草深迷市井，地僻懶衣裳。", "櫸柳枝枝弱，枇杷樹樹香。鸕鷀西日照，曬翅滿魚梁。"]'),
('yuding-11','進艇','杜甫','唐','御定全唐诗','yuding','','[]','南京久客耕南畝，北望傷神坐北窗。晝引老妻乘小艇，',40,'御定全唐詩/json/226.json','["南京久客耕南畝，北望傷神坐北窗。晝引老妻乘小艇，", "茗飲蔗漿攜所有，瓷罌無謝玉為缸。"]'),
('yuding-12','西郊','杜甫','唐','御定全唐诗','yuding','','[]','時出碧雞坊，西郊向草堂。市橋官柳細，江路野梅香。',48,'御定全唐詩/json/226.json','["時出碧雞坊，西郊向草堂。市橋官柳細，江路野梅香。", "傍架齊書帙，看題減藥囊。無人覺來往，疏懶意何長。"]'),
('yuding-13','所思','杜甫','唐','御定全唐诗','yuding','','[]','苦憶荊州醉司馬，謫官樽俎定常開。九江日落醒何處，',40,'御定全唐詩/json/226.json','["苦憶荊州醉司馬，謫官樽俎定常開。九江日落醒何處，", "故憑錦水將雙淚，好過瞿塘灩澦堆。"]'),
('yuding-14','江村','杜甫','唐','御定全唐诗','yuding','','[]','清江一曲抱村流，長夏江村事事幽。自去自來堂上燕，',40,'御定全唐詩/json/226.json','["清江一曲抱村流，長夏江村事事幽。自去自來堂上燕，", "多病所須唯藥物，微軀此外更何求。"]'),
('yuding-15','江漲','杜甫','唐','御定全唐诗','yuding','','[]','江漲柴門外，兒童報急流。下床高數尺，倚杖沒中洲。',48,'御定全唐詩/json/226.json','["江漲柴門外，兒童報急流。下床高數尺，倚杖沒中洲。", "細動迎風燕，輕搖逐浪鷗。漁人縈小楫，容易拔船頭。"]'),
('yuding-16','野老','杜甫','唐','御定全唐诗','yuding','','[]','野老籬前江岸回，柴門不正逐江開。漁人網集澄潭下，',40,'御定全唐詩/json/226.json','["野老籬前江岸回，柴門不正逐江開。漁人網集澄潭下，", "王師未報收東郡，城闕秋生畫角哀。"]'),
('yuding-17','雲山','杜甫','唐','御定全唐诗','yuding','','[]','京洛雲山外，音書靜不來。神交作賦客，力盡望鄉台。',48,'御定全唐詩/json/226.json','["京洛雲山外，音書靜不來。神交作賦客，力盡望鄉台。", "衰疾江邊臥，親朋日暮回。白鷗元水宿，何事有餘哀。"]'),
('yuding-18','遣興','杜甫','唐','御定全唐诗','yuding','','[]','干戈猶未定，弟妹各何之。拭淚沾襟血，梳頭滿面絲。',48,'御定全唐詩/json/226.json','["干戈猶未定，弟妹各何之。拭淚沾襟血，梳頭滿面絲。", "地卑荒野大，天遠暮江遲。衰疾那能久，應無見汝時。"]'),
('yuding-19','北鄰','杜甫','唐','御定全唐诗','yuding','','[]','明府豈辭滿，藏身方告勞。青錢買野竹，白幘岸江皋。',48,'御定全唐詩/json/226.json','["明府豈辭滿，藏身方告勞。青錢買野竹，白幘岸江皋。", "愛酒晉山簡，能詩何水曹。時來訪老疾，步屟到蓬蒿。"]'),
('yuding-20','南鄰','杜甫','唐','御定全唐诗','yuding','','[]','錦裏先生烏角巾，園收芋粟不全貧。慣看賓客兒童喜，',40,'御定全唐詩/json/226.json','["錦裏先生烏角巾，園收芋粟不全貧。慣看賓客兒童喜，", "白沙翠竹江村暮，相對柴門月色新。"]'),
('yuding-21','出郭','杜甫','唐','御定全唐诗','yuding','','[]','霜露晚淒淒，高天逐望低。遠煙鹽井上，斜景雪峰西。',48,'御定全唐詩/json/226.json','["霜露晚淒淒，高天逐望低。遠煙鹽井上，斜景雪峰西。", "故國猶兵馬，他鄉亦鼓鼙。江城今夜客，還與舊烏啼。"]'),
('yuding-22','過南鄰朱山人水亭','杜甫','唐','御定全唐诗','yuding','','[]','相近竹參差，相過人不知。幽花欹滿樹，小水細通池。',48,'御定全唐詩/json/226.json','["相近竹參差，相過人不知。幽花欹滿樹，小水細通池。", "歸客村非遠，殘樽席更移。看君多道氣，從此數追隨。"]'),
('yuding-23','恨別','杜甫','唐','御定全唐诗','yuding','','[]','洛城一別四千里，胡騎長驅五六年。草木變衰行劍外，',40,'御定全唐詩/json/226.json','["洛城一別四千里，胡騎長驅五六年。草木變衰行劍外，", "聞道河陽近乘勝，司徒急為破幽燕。"]'),
('yuding-24','寄賀蘭銛','杜甫','唐','御定全唐诗','yuding','','[]','朝野歡娛後，乾坤震盪中。相隨萬里日，總作白頭翁。',48,'御定全唐詩/json/226.json','["朝野歡娛後，乾坤震盪中。相隨萬里日，總作白頭翁。", "歲晚仍分袂，江邊更轉蓬。勿雲俱異域，飲啄幾回同。"]'),
('yuding-25','寄楊五桂州譚','杜甫','唐','御定全唐诗','yuding','','[]','五嶺皆炎熱，宜人獨桂林。梅花萬里外，雪片一冬深。',48,'御定全唐詩/json/226.json','["五嶺皆炎熱，宜人獨桂林。梅花萬里外，雪片一冬深。", "聞此寬相憶，為邦複好音。江邊送孫楚，遠附白頭吟。"]'),
('yuding-26','逢唐興劉主簿弟','杜甫','唐','御定全唐诗','yuding','','[]','分手開元末，連年絕尺書。江山且相見，戎馬未安居。',48,'御定全唐詩/json/226.json','["分手開元末，連年絕尺書。江山且相見，戎馬未安居。", "劍外官人冷，關中驛騎疏。輕舟下吳會，主簿意何如。"]'),
('yuding-27','和裴迪登新津寺寄王侍郎','杜甫','唐','御定全唐诗','yuding','','[]','何限倚山木，吟詩秋葉黃。蟬聲集古寺，鳥影度寒塘。',48,'御定全唐詩/json/226.json','["何限倚山木，吟詩秋葉黃。蟬聲集古寺，鳥影度寒塘。", "風物悲遊子，登臨憶侍郎。老夫貪佛日，隨意宿僧房。"]'),
('yuding-28','敬簡王明府','杜甫','唐','御定全唐诗','yuding','','[]','葉縣郎官宰，周南太史公。神仙才有數，流落意無窮。',48,'御定全唐詩/json/226.json','["葉縣郎官宰，周南太史公。神仙才有數，流落意無窮。", "驥病思偏秣，鷹愁怕苦籠。看君用高義，恥與萬人同。"]'),
('yuding-29','重簡王明府','杜甫','唐','御定全唐诗','yuding','','[]','甲子西南異，冬來隻薄寒。江雲何夜盡，蜀雨幾時幹。',48,'御定全唐詩/json/226.json','["甲子西南異，冬來隻薄寒。江雲何夜盡，蜀雨幾時幹。", "行李須相問，窮愁豈有寬。君聽鴻雁響，恐致稻粱難。"]'),
('yuding-30','建都十二韻','杜甫','唐','御定全唐诗','yuding','','[]','蒼生未蘇息，胡馬半乾坤。議在雲臺上，誰扶黃屋尊。',144,'御定全唐詩/json/226.json','["蒼生未蘇息，胡馬半乾坤。議在雲臺上，誰扶黃屋尊。", "建都分魏闕，下韶辟荊門。恐失東人望，其如西極存。", "時危當雪恥，計大豈輕論。雖倚三階正，終愁萬國翻。", "牽裾恨不死，漏網荷殊恩。永負漢庭哭，遙憐湘水魂。", "窮冬客江劍，隨事有田園。風斷青蒲節，霜埋翠竹根。", "衣冠空穰穰，關輔久昏昏。願枉長安日，光輝照北原。"]'),
('yuding-31','歲暮','杜甫','唐','御定全唐诗','yuding','','[]','歲暮遠為客，邊隅還用兵。煙塵犯雪嶺，鼓角動江城。',48,'御定全唐詩/json/226.json','["歲暮遠為客，邊隅還用兵。煙塵犯雪嶺，鼓角動江城。", "天地日流血，朝廷誰請纓。濟時敢愛死，寂寞壯心驚。"]'),
('yuding-32','和裴迪登蜀州東亭送客逢早梅相憶見寄','杜甫','唐','御定全唐诗','yuding','','[]','東閣官梅動詩興，還如何遜在揚州。此時對雪遙相憶，',40,'御定全唐詩/json/226.json','["東閣官梅動詩興，還如何遜在揚州。此時對雪遙相憶，", "江邊一樹垂垂發，朝夕催人自白頭。"]'),
('yuding-33','寄贈王十將軍承俊','杜甫','唐','御定全唐诗','yuding','','[]','將軍膽氣雄，臂懸兩角弓。纏結青驄馬，出入錦城中。',48,'御定全唐詩/json/226.json','["將軍膽氣雄，臂懸兩角弓。纏結青驄馬，出入錦城中。", "時危未授鉞，勢屈難為功。賓客滿堂上，何人高義同。"]'),
('yuding-34','暮登四安寺鐘樓寄裴十','杜甫','唐','御定全唐诗','yuding','','[]','暮倚高樓對雪峰，僧來不語自鳴鐘。孤城返照紅將斂，',40,'御定全唐詩/json/226.json','["暮倚高樓對雪峰，僧來不語自鳴鐘。孤城返照紅將斂，", "知君苦思緣詩瘦，大向交遊萬事慵。"]'),
('yuding-35','散愁二首','杜甫','唐','御定全唐诗','yuding','','[]','久客宜旋旆，興王未息戈。蜀星陰見少，江雨夜聞多。',96,'御定全唐詩/json/226.json','["久客宜旋旆，興王未息戈。蜀星陰見少，江雨夜聞多。", "百萬傳深入，寰區望匪它。司徒下燕趙，收取舊山河。", "聞道並州鎮，尚書訓士齊。幾時通薊北，當日報關西。", "戀闕丹心破，沾衣皓首啼。老魂招不得，歸路恐長迷。"]'),
('yuding-36','奉酬李都督表丈早春作','杜甫','唐','御定全唐诗','yuding','','[]','力疾坐清曉，來時悲早春。轉添愁伴客，更覺老隨人。',48,'御定全唐詩/json/226.json','["力疾坐清曉，來時悲早春。轉添愁伴客，更覺老隨人。", "紅入桃花嫩，青歸柳葉新。望鄉應未已，四海尚風塵。"]'),
('yuding-37','客至','杜甫','唐','御定全唐诗','yuding','','[]','舍南舍北皆春水，但見群鷗日日來。花徑不曾緣客掃，',40,'御定全唐詩/json/226.json','["舍南舍北皆春水，但見群鷗日日來。花徑不曾緣客掃，", "肯與鄰翁相對飲，隔籬呼取盡餘杯。"]'),
('yuding-38','遣意二首','杜甫','唐','御定全唐诗','yuding','','[]','囀枝黃鳥近，泛渚白鷗輕。一徑野花落，孤村春水生。',96,'御定全唐詩/json/226.json','["囀枝黃鳥近，泛渚白鷗輕。一徑野花落，孤村春水生。", "衰年催釀黍，細雨更移橙。漸喜交遊絕，幽居不用名。", "簷影微微落，津流脈脈斜。野船明細火，宿雁聚圓沙。", "雲掩初弦月，香傳小樹花。鄰人有美酒，稚子夜能賒。"]'),
('yuding-39','漫成二首','杜甫','唐','御定全唐诗','yuding','','[]','野日荒荒白，春流泯泯清。渚蒲隨地有，村徑逐門成。',96,'御定全唐詩/json/226.json','["野日荒荒白，春流泯泯清。渚蒲隨地有，村徑逐門成。", "只作披衣慣，常從漉酒生。眼前無俗物，多病也身輕。", "江皋已仲春，花下複清晨。仰面貪看鳥，回頭錯應人。", "讀書難字過，對酒滿壺頻。近識峨眉老，知予懶是真。"]'),
('yuding-40','春夜喜雨','杜甫','唐','御定全唐诗','yuding','','[]','好雨知時節，當春乃發生。隨風潛入夜，潤物細無聲。',48,'御定全唐詩/json/226.json','["好雨知時節，當春乃發生。隨風潛入夜，潤物細無聲。", "野徑雲俱黑，江船火獨明。曉看紅濕處，花重錦官城。"]'),
('yuding-41','春水','杜甫','唐','御定全唐诗','yuding','','[]','三月桃花浪，江流復舊痕。朝來沒沙尾，碧色動柴門。',48,'御定全唐詩/json/226.json','["三月桃花浪，江流復舊痕。朝來沒沙尾，碧色動柴門。", "接縷垂芳餌，連筒灌小園。已添無數鳥，爭浴故相喧。"]'),
('yuding-42','春水生二絕','杜甫','唐','御定全唐诗','yuding','','[]','二月六夜春水生，門前小灘渾欲平。',64,'御定全唐詩/json/226.json','["二月六夜春水生，門前小灘渾欲平。", "鸕鷀鸂鶒莫漫喜，吾與汝曹俱眼明。", "一夜水高二尺強，數日不可更禁當。", "南市津頭有船賣，無錢即買系籬旁。"]'),
('yuding-43','江亭','杜甫','唐','御定全唐诗','yuding','','[]','坦腹江亭暖，長吟野望時。水流心不競，雲在意俱遲。',48,'御定全唐詩/json/226.json','["坦腹江亭暖，長吟野望時。水流心不競，雲在意俱遲。", "寂寂春將晚，欣欣物自私。故林歸未得，排悶強裁詩。"]'),
('yuding-44','村夜','杜甫','唐','御定全唐诗','yuding','','[]','蕭蕭風色暮，江頭人不行。村舂雨外急，鄰火夜深明。',48,'御定全唐詩/json/226.json','["蕭蕭風色暮，江頭人不行。村舂雨外急，鄰火夜深明。", "胡羯何多難，漁樵寄此生。中原有兄弟，萬里正含情。"]'),
('yuding-45','早起','杜甫','唐','御定全唐诗','yuding','','[]','春來常早起，幽事頗相關。帖石防隤岸，開林出遠山。',48,'御定全唐詩/json/226.json','["春來常早起，幽事頗相關。帖石防隤岸，開林出遠山。", "一丘藏曲折，緩步有躋攀。童僕來城市，瓶中得酒還。"]'),
('yuding-46','可惜','杜甫','唐','御定全唐诗','yuding','','[]','花飛有底急，老去願春遲。可惜歡娛地，都非少壯時。',48,'御定全唐詩/json/226.json','["花飛有底急，老去願春遲。可惜歡娛地，都非少壯時。", "寬心應是酒，遣興莫過詩。此意陶潛解，吾生後汝期。"]'),
('yuding-47','落日','杜甫','唐','御定全唐诗','yuding','','[]','落日在簾鉤，溪邊春事幽。芳菲緣岸圃，樵爨倚灘舟。',48,'御定全唐詩/json/226.json','["落日在簾鉤，溪邊春事幽。芳菲緣岸圃，樵爨倚灘舟。", "啅雀爭枝墜，飛蟲滿院遊。濁醪誰造汝，一酌散千憂。"]'),
('yuding-48','獨酌','杜甫','唐','御定全唐诗','yuding','','[]','步屨深林晚，開樽獨酌遲。仰蜂黏落絮，行蟻上枯梨。',48,'御定全唐詩/json/226.json','["步屨深林晚，開樽獨酌遲。仰蜂黏落絮，行蟻上枯梨。", "薄劣慚真隱，幽偏得自怡。本無軒冕意，不是傲當時。"]'),
('yuding-49','徐步','杜甫','唐','御定全唐诗','yuding','','[]','整履步青蕪，荒庭日欲晡。芹泥隨燕觜，花蕊上蜂須。',48,'御定全唐詩/json/226.json','["整履步青蕪，荒庭日欲晡。芹泥隨燕觜，花蕊上蜂須。", "把酒從衣濕，吟詩信杖扶。敢論才見忌，實有醉如愚。"]'),
('yuding-50','寒食','杜甫','唐','御定全唐诗','yuding','','[]','寒食江村路，風花高下飛。汀煙輕冉冉，竹日靜暉暉。',48,'御定全唐詩/json/226.json','["寒食江村路，風花高下飛。汀煙輕冉冉，竹日靜暉暉。", "田父要皆去，鄰家鬧不違。地偏相識盡，雞犬亦忘歸。"]'),
('yuding-51','高楠','杜甫','唐','御定全唐诗','yuding','','[]','楠樹色冥冥，江邊一蓋青。近根開藥圃，接葉制茅亭。',48,'御定全唐詩/json/226.json','["楠樹色冥冥，江邊一蓋青。近根開藥圃，接葉制茅亭。", "落景陰猶合，微風韻可聽。尋常絕醉困，臥此片時醒。"]'),
('yuding-52','惡樹','杜甫','唐','御定全唐诗','yuding','','[]','獨繞虛齋徑，常持小斧柯。幽陰成頗雜，惡木剪還多。',48,'御定全唐詩/json/226.json','["獨繞虛齋徑，常持小斧柯。幽陰成頗雜，惡木剪還多。", "枸杞因吾有，雞棲奈汝何。方知不材者，生長漫婆娑。"]'),
('yuding-53','石鏡','杜甫','唐','御定全唐诗','yuding','','[]','蜀王將此鏡，送死置空山。冥寞憐香骨，提攜近玉顏。',48,'御定全唐詩/json/226.json','["蜀王將此鏡，送死置空山。冥寞憐香骨，提攜近玉顏。", "眾妃無複歎，千騎亦虛還。獨有傷心石，埋輪月宇間。"]'),
('yuding-54','琴台','杜甫','唐','御定全唐诗','yuding','','[]','茂陵多病後，尚愛卓文君。酒肆人間世，琴台日暮雲。',48,'御定全唐詩/json/226.json','["茂陵多病後，尚愛卓文君。酒肆人間世，琴台日暮雲。", "野花留寶靨，蔓草見羅裙。歸鳳求皇意，寥寥不復聞。"]'),
('yuding-55','聞斛斯六官未歸','杜甫','唐','御定全唐诗','yuding','','[]','故人南郡去，去索作碑錢。本賣文為活，翻令室倒懸。',48,'御定全唐詩/json/226.json','["故人南郡去，去索作碑錢。本賣文為活，翻令室倒懸。", "荊扉深蔓草，土銼冷疏煙。老甘休無賴，歸來省醉眠。"]'),
('yuding-56','游修覺寺','杜甫','唐','御定全唐诗','yuding','','[]','野寺江天豁，山扉花竹幽。詩應有神助，吾得及春遊。',48,'御定全唐詩/json/226.json','["野寺江天豁，山扉花竹幽。詩應有神助，吾得及春遊。", "徑石相縈帶，川雲自去留。禪枝宿眾鳥，漂轉暮歸愁。"]'),
('yuding-57','後游','杜甫','唐','御定全唐诗','yuding','','[]','寺憶新遊處，橋憐再渡時。江山如有待，花柳更無私。',48,'御定全唐詩/json/226.json','["寺憶新遊處，橋憐再渡時。江山如有待，花柳更無私。", "野潤煙光薄，沙暄日色遲。客愁全為減，舍此複何之。"]'),
('yuding-58','題新津北橋樓','杜甫','唐','御定全唐诗','yuding','','[]','望極春城上，開筵近鳥巢。白花簷外朵，青柳檻前梢。',48,'御定全唐詩/json/226.json','["望極春城上，開筵近鳥巢。白花簷外朵，青柳檻前梢。", "池水觀為政，廚煙覺遠庖。西川供客眼，唯有此江郊。"]'),
('yuding-59','江漲','杜甫','唐','御定全唐诗','yuding','','[]','江發蠻夷漲，山添雨雪流。大聲吹地轉，高浪蹴天浮。',48,'御定全唐詩/json/226.json','["江發蠻夷漲，山添雨雪流。大聲吹地轉，高浪蹴天浮。", "魚鱉為人得，蛟龍不自謀。輕帆好去便，吾道付滄洲。"]'),
('yuding-60','晚晴','杜甫','唐','御定全唐诗','yuding','','[]','村晚驚風度，庭幽過雨沾。夕陽熏細草，江色映疏簾。',48,'御定全唐詩/json/226.json','["村晚驚風度，庭幽過雨沾。夕陽熏細草，江色映疏簾。", "書亂誰能帙，懷幹可自添。時聞有餘論，未怪老夫潛。"]'),
('yuding-61','朝雨','杜甫','唐','御定全唐诗','yuding','','[]','涼氣晚蕭蕭，江雲亂眼飄。風鴛藏近渚，雨燕集深條。',48,'御定全唐詩/json/226.json','["涼氣晚蕭蕭，江雲亂眼飄。風鴛藏近渚，雨燕集深條。", "黃綺終辭漢，巢由不見堯。草堂樽酒在，幸得過清朝。"]'),
('yuding-62','江上值水如海勢，聊短述','杜甫','唐','御定全唐诗','yuding','','[]','為人性僻耽佳句，語不驚人死不休。老去詩篇渾漫興，',40,'御定全唐詩/json/226.json','["為人性僻耽佳句，語不驚人死不休。老去詩篇渾漫興，", "焉得思如陶謝手，令渠述作與同遊。"]'),
('yuding-63','送裴五赴東川','杜甫','唐','御定全唐诗','yuding','','[]','故人亦流落，高義動乾坤。何日通燕塞，相看老蜀門。',48,'御定全唐詩/json/226.json','["故人亦流落，高義動乾坤。何日通燕塞，相看老蜀門。", "東行應暫別，北望苦銷魂。凜凜悲秋意，非君誰與論。"]'),
('yuding-64','赴青城縣出成都，寄陶、王二少尹','杜甫','唐','御定全唐诗','yuding','','[]','老恥妻孥笑，貧嗟出入勞。客情投異縣，詩態憶吾曹。',48,'御定全唐詩/json/226.json','["老恥妻孥笑，貧嗟出入勞。客情投異縣，詩態憶吾曹。", "東郭滄江合，西山白雪高。文章差底病，回首興滔滔。"]'),
('yuding-65','因崔五侍禦寄高彭州','杜甫','唐','御定全唐诗','yuding','','[]','百年已過半，秋至轉饑寒。為問彭州牧，何時救急難。',24,'御定全唐詩/json/226.json','["百年已過半，秋至轉饑寒。為問彭州牧，何時救急難。"]'),
('yuding-66','野望因過常少仙','杜甫','唐','御定全唐诗','yuding','','[]','野橋齊度馬，秋望轉悠哉。竹覆青城合，江從灌口來。',48,'御定全唐詩/json/226.json','["野橋齊度馬，秋望轉悠哉。竹覆青城合，江從灌口來。", "入村樵徑引，嘗果栗皺開。落盡高天日，幽人未遣回。"]'),
('yuding-67','寄杜位','杜甫','唐','御定全唐诗','yuding','','[]','近聞寬法離新州，想見懷歸尚百憂。逐客雖皆萬里去，',40,'御定全唐詩/json/226.json','["近聞寬法離新州，想見懷歸尚百憂。逐客雖皆萬里去，", "玉壘題書心緒亂，何時更得曲江遊。"]'),
('yuding-68','奉簡高三十五使君','杜甫','唐','御定全唐诗','yuding','','[]','當代論才子，如公複幾人。驊騮開道路，鷹隼出風塵。',48,'御定全唐詩/json/226.json','["當代論才子，如公複幾人。驊騮開道路，鷹隼出風塵。", "行色秋將晚，交情老更親。天涯喜相見，披豁對吾真。"]'),
('yuding-69','送韓十四江東覲省','杜甫','唐','御定全唐诗','yuding','','[]','兵戈不見老萊衣，歎息人間萬事非。我已無家尋弟妹，',40,'御定全唐詩/json/226.json','["兵戈不見老萊衣，歎息人間萬事非。我已無家尋弟妹，", "此別應須各努力，故鄉猶恐未同歸。"]'),
('yuding-70','酬高使君相贈','杜甫','唐','御定全唐诗','yuding','','[]','古寺僧牢落，空房客寓居。故人供祿米，鄰舍與園蔬。',48,'御定全唐詩/json/226.json','["古寺僧牢落，空房客寓居。故人供祿米，鄰舍與園蔬。", "雙樹容聽法，三車肯載書。草玄吾豈敢，賦或似相如。"]'),
('yuding-71','草堂即事','杜甫','唐','御定全唐诗','yuding','','[]','荒村建子月，獨樹老夫家。霧裏江船渡，風前徑竹斜。',48,'御定全唐詩/json/226.json','["荒村建子月，獨樹老夫家。霧裏江船渡，風前徑竹斜。", "寒魚依密藻，宿鷺起圓沙。蜀酒禁愁得，無錢何處賒。"]'),
('yuding-72','魏十四侍禦就弊廬相別','杜甫','唐','御定全唐诗','yuding','','[]','有客騎驄馬，江邊問草堂。遠尋留藥價，惜別到文場。',48,'御定全唐詩/json/226.json','["有客騎驄馬，江邊問草堂。遠尋留藥價，惜別到文場。", "入幕旌旗動，歸軒錦繡香。時應念衰疾，書疏及滄浪。"]'),
('yuding-73','徐九少尹見過','杜甫','唐','御定全唐诗','yuding','','[]','晚景孤村僻，行軍數騎來。交新徒有喜，禮厚愧無才。',48,'御定全唐詩/json/226.json','["晚景孤村僻，行軍數騎來。交新徒有喜，禮厚愧無才。", "賞靜憐雲竹，忘歸步月臺。何當看花蕊，欲發照江梅。"]'),
('yuding-74','范二員外邈、吳十侍禦鬱特枉駕闕展待，聊寄此','杜甫','唐','御定全唐诗','yuding','','[]','暫往比鄰去，空聞二妙歸。幽棲誠簡略，衰白已光輝。',48,'御定全唐詩/json/226.json','["暫往比鄰去，空聞二妙歸。幽棲誠簡略，衰白已光輝。", "野外貧家遠，村中好客稀。論文或不愧，肯重款柴扉。"]'),
('yuding-75','王十七侍御掄許攜酒至草堂奉寄此詩便請邀高三十五使君同到','杜甫','唐','御定全唐诗','yuding','','[]','老夫臥穩朝慵起，白屋寒多暖始開。江鸛巧當幽徑浴，',40,'御定全唐詩/json/226.json','["老夫臥穩朝慵起，白屋寒多暖始開。江鸛巧當幽徑浴，", "戲假霜威促山簡，須成一醉習池回。"]'),
('yuding-76','王竟攜酒，高亦同過，共用寒字','杜甫','唐','御定全唐诗','yuding','','[]','臥病荒郊遠，通行小徑難。故人能領客，攜酒重相看。',48,'御定全唐詩/json/226.json','["臥病荒郊遠，通行小徑難。故人能領客，攜酒重相看。", "自愧無鮭菜，空煩卸馬鞍。移樽勸山簡，頭白恐風寒。"]'),
('yuding-77','陪李七司馬皂江上觀造竹橋即日成往來之人免冬寒入水聊題短作簡李公二首','杜甫','唐','御定全唐诗','yuding','','[]','伐竹為橋結構同，褰裳不涉往來通。天寒白鶴歸華表，',88,'御定全唐詩/json/226.json','["伐竹為橋結構同，褰裳不涉往來通。天寒白鶴歸華表，", "合歡卻笑千年事，驅石何時到海東。", "把燭成橋夜，回舟坐客時。天高雲去盡，江迥月來遲。", "衰謝多扶病，招邀屢有期。異方乘此興，樂罷不無悲。"]'),
('yuding-78','李司馬橋了承高使君自成都回','杜甫','唐','御定全唐诗','yuding','','[]','向來江上手紛紛，三日成功事出群。',32,'御定全唐詩/json/226.json','["向來江上手紛紛，三日成功事出群。", "已傳童子騎青竹，總擬橋東待使君。"]'),
('yuding-79','少年行二首','杜甫','唐','御定全唐诗','yuding','','[]','莫笑田家老瓦盆，自從盛酒長兒孫。',64,'御定全唐詩/json/226.json','["莫笑田家老瓦盆，自從盛酒長兒孫。", "傾銀注瓦驚人眼，共醉終同臥竹根。", "巢燕養雛渾去盡，江花結子已無多。", "黃衫年少來宜數，不見堂前東逝波。"]'),
('yuding-80','野人送朱櫻','杜甫','唐','御定全唐诗','yuding','','[]','西蜀櫻桃也自紅，野人相贈滿筠籠。數回細寫愁仍破，',40,'御定全唐詩/json/226.json','["西蜀櫻桃也自紅，野人相贈滿筠籠。數回細寫愁仍破，", "金盤玉箸無消息，此日嘗新任轉蓬。"]'),
('yuding-81','即事','杜甫','唐','御定全唐诗','yuding','','[]','百寶裝腰帶，真珠絡臂鞲。笑時花近眼，舞罷錦纏頭。',24,'御定全唐詩/json/226.json','["百寶裝腰帶，真珠絡臂鞲。笑時花近眼，舞罷錦纏頭。"]'),
('yuding-82','贈花卿','杜甫','唐','御定全唐诗','yuding','','[]','錦城絲管日紛紛，半入江風半入雲。',32,'御定全唐詩/json/226.json','["錦城絲管日紛紛，半入江風半入雲。", "此曲只應天上有，人間能得幾回聞。"]'),
('yuding-83','少年行','杜甫','唐','御定全唐诗','yuding','','[]','馬上誰家薄媚郎，臨階下馬坐人床。',32,'御定全唐詩/json/226.json','["馬上誰家薄媚郎，臨階下馬坐人床。", "不通姓字粗豪甚，指點銀瓶索酒嘗。"]'),
('yuding-84','觀李固請司馬弟山水圖三首','杜甫','唐','御定全唐诗','yuding','','[]','簡易高人意，匡床竹火爐。寒天留遠客，碧海掛新圖。',144,'御定全唐詩/json/226.json','["簡易高人意，匡床竹火爐。寒天留遠客，碧海掛新圖。", "雖對連山好，貪看絕島孤。群仙不愁思，冉冉下蓬壺。", "方丈渾連水，天臺總映雲。人間長見畫，老去恨空聞。", "範蠡舟偏小，王喬鶴不群。此生隨萬物，何路出塵氛。", "高浪垂翻屋，崩崖欲壓床。野橋分子細，沙岸繞微茫。", "紅浸珊瑚短，青懸薜荔長。浮查並坐得，仙老暫相將。"]'),
('yuding-85','題桃樹','杜甫','唐','御定全唐诗','yuding','','[]','小徑升堂舊不斜，五株桃樹亦從遮。高秋總喂貧人實，',40,'御定全唐詩/json/226.json','["小徑升堂舊不斜，五株桃樹亦從遮。高秋總喂貧人實，", "寡妻群盜非今日，天下車書正一家。"]'),
('yuding-86','蕭八明府堤處覓桃栽','杜甫','唐','御定全唐诗','yuding','','[]','奉乞桃栽一百根，春前為送浣花村。',32,'御定全唐詩/json/226.json','["奉乞桃栽一百根，春前為送浣花村。", "河陽縣裏雖無數，濯錦江邊未滿園。"]'),
('yuding-87','從韋二明府續處覓綿竹','杜甫','唐','御定全唐诗','yuding','','[]','華軒藹藹他年到，綿竹亭亭出縣高。',32,'御定全唐詩/json/226.json','["華軒藹藹他年到，綿竹亭亭出縣高。", "江上舍前無此物，幸分蒼翠拂波濤。"]'),
('yuding-88','憑何十一少府邕覓榿木栽','杜甫','唐','御定全唐诗','yuding','','[]','草堂塹西無樹林，非子誰複見幽心。',32,'御定全唐詩/json/226.json','["草堂塹西無樹林，非子誰複見幽心。", "飽聞榿木三年大，與致溪邊十畝陰。"]'),
('yuding-89','憑韋少府班覓松樹子','杜甫','唐','御定全唐诗','yuding','','[]','落落出群非櫸柳，青青不朽豈楊梅。',32,'御定全唐詩/json/226.json','["落落出群非櫸柳，青青不朽豈楊梅。", "欲存老蓋千年意，為覓霜根數寸栽。"]'),
('yuding-90','又于韋處乞大邑瓷碗','杜甫','唐','御定全唐诗','yuding','','[]','大邑燒瓷輕且堅，扣如哀玉錦城傳。',32,'御定全唐詩/json/226.json','["大邑燒瓷輕且堅，扣如哀玉錦城傳。", "君家白碗勝霜雪，急送茅齋也可憐。"]'),
('yuding-91','詣徐卿覓果栽','杜甫','唐','御定全唐诗','yuding','','[]','草堂少花今欲栽，不問綠李與黃梅。',32,'御定全唐詩/json/226.json','["草堂少花今欲栽，不問綠李與黃梅。", "石筍街中卻歸去，果園坊裏為求來。"]'),
('yuding-92','贈別何邕','杜甫','唐','御定全唐诗','yuding','','[]','生死論交地，何由見一人。悲君隨燕雀，薄宦走風塵。',48,'御定全唐詩/json/226.json','["生死論交地，何由見一人。悲君隨燕雀，薄宦走風塵。", "綿穀元通漢，沱江不向秦。五陵花滿眼，傳語故鄉春。"]'),
('yuding-93','贈別鄭煉赴襄陽','杜甫','唐','御定全唐诗','yuding','','[]','戎馬交馳際，柴門老病身。把君詩過日，念此別驚神。',48,'御定全唐詩/json/226.json','["戎馬交馳際，柴門老病身。把君詩過日，念此別驚神。", "地闊峨眉晚，天高峴首春。為於耆舊內，試覓姓龐人。"]'),
('yuding-94','重贈鄭煉','杜甫','唐','御定全唐诗','yuding','','[]','鄭子將行罷使臣，囊無一物獻尊親。',32,'御定全唐詩/json/226.json','["鄭子將行罷使臣，囊無一物獻尊親。", "江山路遠羈離日，裘馬誰為感激人。"]');
